window.KJV1769_STRONG_BOOKS["2Chr"] = {"osis":"2Chr","book":"역대하","verses":{"1:1":{"text":"And Solomon the son of David was strengthened in his kingdom, and the LORD his God was with him, and magnified him exceedingly.","words":[["H8010","And Solomon",0,11],["H1121","the son",12,19],["H1732","of David",20,28],["H2388","was strengthened",29,45],["H4438","in his kingdom",46,60],["H3068","and the LORD",62,74],["H0430","his God",75,82],["H1431","was with him, and magnified",83,110],["H4605","him exceedingly",111,126]]},"1:2":{"text":"Then Solomon spake unto all Israel, to the captains of thousands and of hundreds, and to the judges, and to every governor in all Israel, the chief of the fathers.","words":[["H8010","Then Solomon",0,12],["H0559","spake",13,18],["H3478","unto all Israel",19,34],["H8269","to the captains",36,51],["H0505","of thousands",52,64],["H3967","and of hundreds",65,80],["H8199","and to the judges",82,99],["H5387","and to every governor",101,122],["H3478","in all Israel",123,136],["H7218","the chief",138,147],["H0001","of the fathers",148,162]]},"1:3":{"text":"So Solomon, and all the congregation with him, went to the high place that was at Gibeon; for there was the tabernacle of the congregation of God, which Moses the servant of the LORD had made in the wilderness.","words":[["H8010","So Solomon",0,10],["H6951","and all the congregation",12,36],["H3212","with him, went",37,51],["H1116","to the high place",52,69],["H1391","that was at Gibeon",70,88],["H0168","for there was the tabernacle",90,118],["H4150","of the congregation",119,138],["H0430","of God",139,145],["H4872","which Moses",147,158],["H5650","the servant",159,170],["H3068","of the LORD",171,182],["H6213","had made",183,191],["H4057","in the wilderness",192,209]]},"1:4":{"text":"But the ark of God had David brought up from Kirjathjearim to the place which David had prepared for it: for he had pitched a tent for it at Jerusalem.","words":[["H0061","But",0,3],["H0727","the ark",4,11],["H0430","of God",12,18],["H1732","had David",19,28],["H5927","brought up",29,39],["H7157","from Kirjathjearim",40,58],["H1732","to the place which David",59,83],["H3559","had prepared",84,96],["H5186","for it: for he had pitched",97,123],["H0168","a tent",124,130],["H3389","for it at Jerusalem",131,150]]},"1:5":{"text":"Moreover the brasen altar, that Bezaleel the son of Uri, the son of Hur, had made, he put before the tabernacle of the LORD: and Solomon and the congregation sought unto it.","words":[["H5178","Moreover the brasen",0,19],["H4196","altar",20,25],["H1212","that Bezaleel",27,40],["H1121","the son",41,48],["H0221","of Uri",49,55],["H1121","the son",57,64],["H2354","of Hur",65,71],["H6213","had made",73,81],["H7760","he put",83,89],["H6440","before",90,96],["H4908","the tabernacle",97,111],["H3068","of the LORD",112,123],["H8010","and Solomon",125,136],["H6951","and the congregation",137,157],["H1875","sought",158,164]]},"1:6":{"text":"And Solomon went up thither to the brasen altar before the LORD, which was at the tabernacle of the congregation, and offered a thousand burnt offerings upon it.","words":[["H8010","And Solomon",0,11],["H5927","went up",12,19],["H5178","thither to the brasen",20,41],["H4196","altar",42,47],["H6440","before",48,54],["H3068","the LORD",55,63],["H0168","which was at the tabernacle",65,92],["H4150","of the congregation",93,112],["H5927","and offered",114,125],["H0505","a thousand",126,136],["H5930","burnt offerings",137,152]]},"1:7":{"text":"In that night did God appear unto Solomon, and said unto him, Ask what I shall give thee.","words":[["H3915","In that night",0,13],["H0430","did God",14,21],["H7200","appear",22,28],["H8010","unto Solomon",29,41],["H0559","and said",43,51],["H7592","unto him, Ask",52,65],["H5414","what I shall give",66,83]]},"1:8":{"text":"And Solomon said unto God, Thou hast shewed great mercy unto David my father, and hast made me to reign in his stead.","words":[["H8010","And Solomon",0,11],["H0559","said",12,16],["H0430","unto God",17,25],["H6213","Thou hast shewed",27,43],["H1419","great",44,49],["H2617","mercy",50,55],["H1732","unto David",56,66],["H0001","my father",67,76],["H4427","and hast made me to reign",78,103]]},"1:9":{"text":"Now, O LORD God, let thy promise unto David my father be established: for thou hast made me king over a people like the dust of the earth in multitude.","words":[["H3068","Now, O LORD",0,11],["H0430","God",12,15],["H1697","let thy promise",17,32],["H1732","unto David",33,43],["H0001","my father",44,53],["H0539","be established",54,68],["H4427","for thou hast made me king",70,96],["H5971","over a people",97,110],["H6083","like the dust",111,124],["H0776","of the earth",125,137],["H7227","in multitude",138,150]]},"1:10":{"text":"Give me now wisdom and knowledge, that I may go out and come in before this people: for who can judge this thy people, that is so great?","words":[["H5414","Give",0,4],["H2451","me now wisdom",5,18],["H4093","and knowledge",19,32],["H3318","that I may go out",34,51],["H0935","and come in",52,63],["H6440","before",64,70],["H5971","this people",71,82],["H8199","for who can judge",84,101],["H5971","this thy people",102,117],["H1419","that is so great",119,135]]},"1:11":{"text":"And God said to Solomon, Because this was in thine heart, and thou hast not asked riches, wealth, or honour, nor the life of thine enemies, neither yet hast asked long life; but hast asked wisdom and knowledge for thyself, that thou mayest judge my people, over whom I have made thee king:","words":[["H0430","And God",0,7],["H0559","said",8,12],["H8010","to Solomon",13,23],["H3824","Because this was in thine heart",25,56],["H7592","and thou hast not asked",58,81],["H6239","riches",82,88],["H5233","wealth",90,96],["H3519","or honour",98,107],["H5315","nor the life",109,121],["H8130","of thine enemies",122,138],["H7592","neither yet hast asked",140,162],["H7227","long",163,167],["H3117","life",168,172],["H7592","but hast asked",174,188],["H2451","wisdom",189,195],["H4093","and knowledge",196,209],["H8199","for thyself, that thou mayest judge",210,245],["H5971","my people",246,255],["H4427","over whom I have made thee king",257,288]]},"1:12":{"text":"Wisdom and knowledge is granted unto thee; and I will give thee riches, and wealth, and honour, such as none of the kings have had that have been before thee, neither shall there any after thee have the like.","words":[["H2451","Wisdom",0,6],["H4093","and knowledge",7,20],["H5414","is granted",21,31],["H5414","unto thee; and I will give",32,58],["H6239","thee riches",59,70],["H5233","and wealth",72,82],["H3519","and honour",84,94],["H4428","such as none of the kings",96,121],["H6440","have had that have been before",122,152],["H0310","thee, neither shall there any after",153,188]]},"1:13":{"text":"Then Solomon came from his journey to the high place that was at Gibeon to Jerusalem, from before the tabernacle of the congregation, and reigned over Israel.","words":[["H8010","Then Solomon",0,12],["H0935","came",13,17],["H1116","from his journey to the high place",18,52],["H1391","that was at Gibeon",53,71],["H3389","to Jerusalem",72,84],["H6440","from before",86,97],["H0168","the tabernacle",98,112],["H4150","of the congregation",113,132],["H4427","and reigned",134,145],["H3478","over Israel",146,157]]},"1:14":{"text":"And Solomon gathered chariots and horsemen: and he had a thousand and four hundred chariots, and twelve thousand horsemen, which he placed in the chariot cities, and with the king at Jerusalem.","words":[["H8010","And Solomon",0,11],["H0622","gathered",12,20],["H7393","chariots",21,29],["H6571","and horsemen",30,42],["H0505","and he had a thousand",44,65],["H0702","and four",66,74],["H3967","hundred",75,82],["H7393","chariots",83,91],["H8147","and twelve",93,103],["H6240","and twelve",93,103],["H0505","thousand",104,112],["H6571","horsemen",113,121],["H3240","which he placed",123,138],["H7393","in the chariot",139,153],["H5892","cities",154,160],["H4428","and with the king",162,179],["H3389","at Jerusalem",180,192]]},"1:15":{"text":"And the king made silver and gold at Jerusalem as plenteous as stones, and cedar trees made he as the sycomore trees that are in the vale for abundance.","words":[["H4428","And the king",0,12],["H5414","made",13,17],["H3701","silver",18,24],["H2091","and gold",25,33],["H3389","at Jerusalem",34,46],["H0068","as plenteous as stones",47,69],["H0730","and cedar trees",71,86],["H5414","made",87,91],["H8256","he as the sycomore trees",92,116],["H8219","that are in the vale",117,137],["H7230","for abundance",138,151]]},"1:16":{"text":"And Solomon had horses brought out of Egypt, and linen yarn: the king's merchants received the linen yarn at a price.","words":[["H8010","And Solomon",0,11],["H5483","had horses",12,22],["H4161","brought",23,30],["H4714","out of Egypt",31,43],["H4723","and linen yarn",45,59],["H4428","the king's",61,71],["H5503","merchants",72,81],["H3947","received",82,90],["H4723","the linen yarn",91,105],["H4242","at a price",106,116]]},"1:17":{"text":"And they fetched up, and brought forth out of Egypt a chariot for six hundred shekels of silver, and an horse for an hundred and fifty: and so brought they out horses for all the kings of the Hittites, and for the kings of Syria, by their means.","words":[["H5927","And they fetched up",0,19],["H3318","and brought forth",21,38],["H4714","out of Egypt",39,51],["H4818","a chariot",52,61],["H8337","for six",62,69],["H3967","hundred",70,77],["H3701","shekels of silver",78,95],["H5483","and an horse",97,109],["H3967","for an hundred",110,124],["H2572","and fifty",125,134],["H3318","and so brought they out",136,159],["H4428","horses for all the kings",160,184],["H2850","of the Hittites",185,200],["H4428","and for the kings",202,219],["H0758","of Syria",220,228],["H3027","by their means",230,244]]},"2:1":{"text":"And Solomon determined to build an house for the name of the LORD, and an house for his kingdom.","words":[["H8010","And Solomon",0,11],["H0559","determined",12,22],["H1129","to build",23,31],["H1004","an house",32,40],["H8034","for the name",41,53],["H3068","of the LORD",54,65],["H1004","and an house",67,79],["H4438","for his kingdom",80,95]]},"2:2":{"text":"And Solomon told out threescore and ten thousand men to bear burdens, and fourscore thousand to hew in the mountain, and three thousand and six hundred to oversee them.","words":[["H8010","And Solomon",0,11],["H5608","told out",12,20],["H7657","threescore and ten",21,39],["H0505","thousand",40,48],["H0376","men",49,52],["H5449","to bear burdens",53,68],["H8084","and fourscore",70,83],["H0505","thousand",84,92],["H0376","thousand",84,92],["H2672","to hew",93,99],["H2022","in the mountain",100,115],["H7969","and three",117,126],["H0505","thousand",127,135],["H8337","and six",136,143],["H3967","hundred",144,151],["H5329","to oversee",152,162]]},"2:3":{"text":"And Solomon sent to Huram the king of Tyre, saying, As thou didst deal with David my father, and didst send him cedars to build him an house to dwell therein, even so deal with me.","words":[["H8010","And Solomon",0,11],["H7971","sent",12,16],["H2361","to Huram",17,25],["H4428","the king",26,34],["H6865","of Tyre",35,42],["H0559","saying",44,50],["H6213","As thou didst deal",52,70],["H1732","with David",71,81],["H0001","my father",82,91],["H7971","and didst send",93,107],["H0730","him cedars",108,118],["H1129","to build",119,127],["H1004","him an house",128,140],["H3427","to dwell",141,149]]},"2:4":{"text":"Behold, I build an house to the name of the LORD my God, to dedicate it to him, and to burn before him sweet incense, and for the continual shewbread, and for the burnt offerings morning and evening, on the sabbaths, and on the new moons, and on the solemn feasts of the LORD our God. This is an ordinance for ever to Israel.","words":[["H1129","Behold, I build",0,15],["H1004","an house",16,24],["H8034","to the name",25,36],["H3068","of the LORD",37,48],["H0430","my God",49,55],["H6942","to dedicate",57,68],["H6999","it to him, and to burn",69,91],["H6440","before",92,98],["H5561","him sweet",99,108],["H7004","incense",109,116],["H8548","and for the continual",118,139],["H4635","shewbread",140,149],["H5930","and for the burnt offerings",151,178],["H1242","morning",179,186],["H6153","and evening",187,198],["H7676","on the sabbaths",200,215],["H2320","and on the new moons",217,237],["H4150","and on the solemn feasts",239,263],["H3068","of the LORD",264,275],["H0430","our God",276,283],["H5769","This is an ordinance for ever",285,314],["H3478","to Israel",315,324]]},"2:5":{"text":"And the house which I build is great: for great is our God above all gods.","words":[["H1004","And the house",0,13],["H1129","which I build",14,27],["H1419","is great",28,36],["H1419","for great",38,47],["H0430","is our God",48,58],["H0430","above all gods",59,73]]},"2:6":{"text":"But who is able to build him an house, seeing the heaven and heaven of heavens cannot contain him? who am I then, that I should build him an house, save only to burn sacrifice before him?","words":[["H6113","But who is able",0,15],["H3581","But who is able",0,15],["H1129","to build",16,24],["H1004","him an house",25,37],["H8064","seeing the heaven",39,56],["H8064","and heaven",57,67],["H8064","of heavens",68,78],["H3557","cannot contain",79,93],["H1129","him? who am I then, that I should build",94,133],["H1004","him an house",134,146],["H0518","save only",148,157],["H6999","to burn sacrifice",158,175],["H6440","before",176,182]]},"2:7":{"text":"Send me now therefore a man cunning to work in gold, and in silver, and in brass, and in iron, and in purple, and crimson, and blue, and that can skill to grave with the cunning men that are with me in Judah and in Jerusalem, whom David my father did provide.","words":[["H7971","Send",0,4],["H0376","me now therefore a man",5,27],["H2450","cunning",28,35],["H6213","to work",36,43],["H2091","in gold",44,51],["H3701","and in silver",53,66],["H5178","and in brass",68,80],["H1270","and in iron",82,93],["H0710","and in purple",95,108],["H3758","and crimson",110,121],["H8504","and blue",123,131],["H3045","and that can skill",133,151],["H6605","to grave",152,160],["H6603","to grave",152,160],["H2450","with the cunning men",161,181],["H3063","that are with me in Judah",182,207],["H3389","and in Jerusalem",208,224],["H1732","whom David",226,236],["H0001","my father",237,246],["H3559","did provide",247,258]]},"2:8":{"text":"Send me also cedar trees, fir trees, and algum trees, out of Lebanon: for I know that thy servants can skill to cut timber in Lebanon; and, behold, my servants shall be with thy servants,","words":[["H7971","Send",0,4],["H0730","me also cedar",5,18],["H6086","trees",19,24],["H1265","fir trees",26,35],["H0418","and algum trees",37,52],["H3844","out of Lebanon",54,68],["H3045","for I know",70,80],["H5650","that thy servants",81,98],["H3045","can skill",99,108],["H3772","to cut",109,115],["H6086","timber",116,122],["H3844","in Lebanon",123,133],["H5650","and, behold, my servants",135,159],["H5650","shall be with thy servants",160,186]]},"2:9":{"text":"Even to prepare me timber in abundance: for the house which I am about to build shall be wonderful great.","words":[["H3559","Even to prepare",0,15],["H6086","me timber",16,25],["H7230","in abundance",26,38],["H1004","for the house",40,53],["H1129","which I am about to build",54,79],["H6381","shall be wonderful",80,98],["H1419","great",99,104]]},"2:10":{"text":"And, behold, I will give to thy servants, the hewers that cut timber, twenty thousand measures of beaten wheat, and twenty thousand measures of barley, and twenty thousand baths of wine, and twenty thousand baths of oil.","words":[["H5414","And, behold, I will give",0,24],["H5650","to thy servants",25,40],["H2404","the hewers",42,52],["H3772","that cut",53,61],["H6086","timber",62,68],["H6242","twenty",70,76],["H0505","thousand",77,85],["H3734","measures",86,94],["H4347","of beaten",95,104],["H2406","wheat",105,110],["H6242","and twenty",112,122],["H0505","thousand",123,131],["H3734","measures",132,140],["H8184","of barley",141,150],["H6242","and twenty",152,162],["H0505","thousand",163,171],["H1324","baths",172,177],["H3196","of wine",178,185],["H6242","and twenty",187,197],["H0505","thousand",198,206],["H1324","baths",207,212],["H8081","of oil",213,219]]},"2:11":{"text":"Then Huram the king of Tyre answered in writing, which he sent to Solomon, Because the LORD hath loved his people, he hath made thee king over them.","words":[["H2361","Then Huram",0,10],["H4428","the king",11,19],["H6865","of Tyre",20,27],["H0559","answered",28,36],["H3791","in writing",37,47],["H7971","which he sent",49,62],["H8010","to Solomon",63,73],["H3068","Because the LORD",75,91],["H0160","hath loved",92,102],["H5971","his people",103,113],["H5414","he hath made",115,127],["H4428","thee king",128,137]]},"2:12":{"text":"Huram said moreover, Blessed be the LORD God of Israel, that made heaven and earth, who hath given to David the king a wise son, endued with prudence and understanding, that might build an house for the LORD, and an house for his kingdom.","words":[["H2361","Huram",0,5],["H0559","said",6,10],["H1288","moreover, Blessed",11,28],["H3068","be the LORD",29,40],["H0430","God",41,44],["H3478","of Israel",45,54],["H6213","that made",56,65],["H8064","heaven",66,72],["H0776","and earth",73,82],["H5414","who hath given",84,98],["H1732","to David",99,107],["H4428","the king",108,116],["H2450","a wise",117,123],["H1121","son",124,127],["H3045","endued",129,135],["H7922","with prudence",136,149],["H0998","and understanding",150,167],["H1129","that might build",169,185],["H1004","an house",186,194],["H3068","for the LORD",195,207],["H1004","and an house",209,221],["H4438","for his kingdom",222,237]]},"2:13":{"text":"And now I have sent a cunning man, endued with understanding, of Huram my father's,","words":[["H7971","And now I have sent",0,19],["H2450","a cunning",20,29],["H0376","man",30,33],["H3045","endued",35,41],["H0998","with understanding",42,60],["H2361","of Huram",62,70],["H0001","my father's",71,82]]},"2:14":{"text":"The son of a woman of the daughters of Dan, and his father was a man of Tyre, skilful to work in gold, and in silver, in brass, in iron, in stone, and in timber, in purple, in blue, and in fine linen, and in crimson; also to grave any manner of graving, and to find out every device which shall be put to him, with thy cunning men, and with the cunning men of my lord David thy father.","words":[["H1121","The son",0,7],["H0802","of a woman",8,18],["H1323","of the daughters",19,35],["H1835","of Dan",36,42],["H0001","and his father",44,58],["H0376","was a man",59,68],["H6876","of Tyre",69,76],["H3045","skilful",78,85],["H6213","to work",86,93],["H2091","in gold",94,101],["H3701","and in silver",103,116],["H5178","in brass",118,126],["H1270","in iron",128,135],["H0068","in stone",137,145],["H6086","and in timber",147,160],["H0713","in purple",162,171],["H8504","in blue",173,180],["H0948","and in fine linen",182,199],["H3758","and in crimson",201,215],["H6605","also to grave",217,230],["H6603","any manner of graving",231,252],["H2803","and to find out",254,269],["H4284","every device",270,282],["H5414","which shall be put",283,301],["H2450","to him, with thy cunning men",302,330],["H2450","and with the cunning men",332,356],["H0113","of my lord",357,367],["H1732","David",368,373],["H0001","thy father",374,384]]},"2:15":{"text":"Now therefore the wheat, and the barley, the oil, and the wine, which my lord hath spoken of, let him send unto his servants:","words":[["H2406","Now therefore the wheat",0,23],["H8184","and the barley",25,39],["H8081","the oil",41,48],["H3196","and the wine",50,62],["H0113","which my lord",64,77],["H0559","hath spoken",78,89],["H7971","of, let him send",90,106],["H5650","unto his servants",107,124]]},"2:16":{"text":"And we will cut wood out of Lebanon, as much as thou shalt need: and we will bring it to thee in floats by sea to Joppa; and thou shalt carry it up to Jerusalem.","words":[["H3772","And we will cut",0,15],["H6086","wood",16,20],["H3844","out of Lebanon",21,35],["H6878","as much as thou shalt need",37,63],["H0935","and we will bring",65,82],["H7513","it to thee in floats",83,103],["H3220","by sea",104,110],["H3305","to Joppa",111,119],["H5927","and thou shalt carry it up",121,147],["H3389","to Jerusalem",148,160]]},"2:17":{"text":"And Solomon numbered all the strangers that were in the land of Israel, after the numbering wherewith David his father had numbered them; and they were found an hundred and fifty thousand and three thousand and six hundred.","words":[["H8010","And Solomon",0,11],["H5608","numbered",12,20],["H0582","all the strangers",21,38],["H1616","all the strangers",21,38],["H0776","that were in the land",39,60],["H3478","of Israel",61,70],["H0310","after",72,77],["H5610","the numbering",78,91],["H1732","wherewith David",92,107],["H0001","his father",108,118],["H5608","had numbered",119,131],["H4672","them; and they were found",132,157],["H3967","an hundred",158,168],["H2572","and fifty",169,178],["H0505","thousand",179,187],["H7969","and three",188,197],["H0505","thousand",198,206],["H8337","and six",207,214],["H3967","hundred",215,222]]},"2:18":{"text":"And he set threescore and ten thousand of them to be bearers of burdens, and fourscore thousand to be hewers in the mountain, and three thousand and six hundred overseers to set the people a work.","words":[["H6213","And he set",0,10],["H7657","threescore and ten",11,29],["H0505","thousand",30,38],["H5449","of them to be bearers of burdens",39,71],["H8084","and fourscore",73,86],["H0505","thousand",87,95],["H2672","to be hewers",96,108],["H2022","in the mountain",109,124],["H7969","and three",126,135],["H0505","thousand",136,144],["H8337","and six",145,152],["H3967","hundred",153,160],["H5329","overseers",161,170],["H5647","to set",171,177],["H5971","the people",178,188],["H5647","a work",189,195]]},"3:1":{"text":"Then Solomon began to build the house of the LORD at Jerusalem in mount Moriah, where the LORD appeared unto David his father, in the place that David had prepared in the threshingfloor of Ornan the Jebusite.","words":[["H8010","Then Solomon",0,12],["H2490","began",13,18],["H1129","to build",19,27],["H1004","the house",28,37],["H3068","of the LORD",38,49],["H3389","at Jerusalem",50,62],["H2022","in mount",63,71],["H4179","Moriah",72,78],["H7200","where the LORD appeared",80,103],["H1732","unto David",104,114],["H0001","his father",115,125],["H4725","in the place",127,139],["H1732","that David",140,150],["H3559","had prepared",151,163],["H1637","in the threshingfloor",164,185],["H0771","of Ornan",186,194],["H2983","the Jebusite",195,207]]},"3:2":{"text":"And he began to build in the second day of the second month, in the fourth year of his reign.","words":[["H2490","And he began",0,12],["H1129","to build",13,21],["H8145","in the second",22,35],["H8145","day of the second",36,53],["H2320","month",54,59],["H0702","in the fourth",61,74],["H8141","year",75,79],["H4438","of his reign",80,92]]},"3:3":{"text":"Now these are the things wherein Solomon was instructed for the building of the house of God. The length by cubits after the first measure was threescore cubits, and the breadth twenty cubits.","words":[["H8010","Now these are the things wherein Solomon",0,40],["H3245","was instructed",41,55],["H1129","for the building",56,72],["H1004","of the house",73,85],["H0430","of God",86,92],["H0753","The length",94,104],["H0520","by cubits",105,114],["H7223","after the first",115,130],["H4060","measure",131,138],["H8346","was threescore",139,153],["H0520","cubits",154,160],["H7341","and the breadth",162,177],["H6242","twenty",178,184],["H0520","cubits",185,191]]},"3:4":{"text":"And the porch that was in the front of the house, the length of it was according to the breadth of the house, twenty cubits, and the height was an hundred and twenty: and he overlaid it within with pure gold.","words":[["H0197","And the porch",0,13],["H6440","that was in the front",14,35],["H0753","of the house, the length",36,60],["H7341","of it was according to the breadth",61,95],["H1004","of the house",96,108],["H6242","twenty",110,116],["H0520","cubits",117,123],["H1363","and the height",125,139],["H3967","was an hundred",140,154],["H6242","and twenty",155,165],["H6823","and he overlaid",167,182],["H6441","it within",183,192],["H2889","with pure",193,202],["H2091","gold",203,207]]},"3:5":{"text":"And the greater house he cieled with fir tree, which he overlaid with fine gold, and set thereon palm trees and chains.","words":[["H1419","And the greater",0,15],["H1004","house",16,21],["H2645","he cieled",22,31],["H1265","with fir",32,40],["H6086","tree",41,45],["H2645","which he overlaid",47,64],["H2896","with fine",65,74],["H2091","gold",75,79],["H5927","and set",81,88],["H8561","thereon palm trees",89,107],["H8333","and chains",108,118]]},"3:6":{"text":"And he garnished the house with precious stones for beauty: and the gold was gold of Parvaim.","words":[["H6823","And he garnished",0,16],["H1004","the house",17,26],["H3368","with precious",27,40],["H0068","stones",41,47],["H8597","for beauty",48,58],["H2091","and the gold",60,72],["H2091","was gold",73,81],["H6516","of Parvaim",82,92]]},"3:7":{"text":"He overlaid also the house, the beams, the posts, and the walls thereof, and the doors thereof, with gold; and graved cherubims on the walls.","words":[["H2645","He overlaid",0,11],["H1004","also the house",12,26],["H6982","the beams",28,37],["H5592","the posts",39,48],["H7023","and the walls",50,63],["H1817","thereof, and the doors",64,86],["H2091","thereof, with gold",87,105],["H6605","and graved",107,117],["H3742","cherubims",118,127],["H7023","on the walls",128,140]]},"3:8":{"text":"And he made the most holy house, the length whereof was according to the breadth of the house, twenty cubits, and the breadth thereof twenty cubits: and he overlaid it with fine gold, amounting to six hundred talents.","words":[["H6213","And he made",0,11],["H6944","the most",12,20],["H6944","holy",21,25],["H1004","house",26,31],["H0753","the length",33,43],["H6440","whereof was according to",44,68],["H7341","the breadth",69,80],["H1004","of the house",81,93],["H6242","twenty",95,101],["H0520","cubits",102,108],["H7341","and the breadth",110,125],["H6242","thereof twenty",126,140],["H0520","cubits",141,147],["H2645","and he overlaid",149,164],["H2896","it with fine",165,177],["H2091","gold",178,182],["H8337","amounting to six",184,200],["H3967","hundred",201,208],["H3603","talents",209,216]]},"3:9":{"text":"And the weight of the nails was fifty shekels of gold. And he overlaid the upper chambers with gold.","words":[["H4948","And the weight",0,14],["H4548","of the nails",15,27],["H2572","was fifty",28,37],["H8255","shekels",38,45],["H2091","of gold",46,53],["H2645","And he overlaid",55,70],["H5944","the upper chambers",71,89],["H2091","with gold",90,99]]},"3:10":{"text":"And in the most holy house he made two cherubims of image work, and overlaid them with gold.","words":[["H6944","And in the most",0,15],["H6944","holy",16,20],["H1004","house",21,26],["H6213","he made",27,34],["H8147","two",35,38],["H3742","cherubims",39,48],["H6816","of image",49,57],["H4639","work",58,62],["H6823","and overlaid",64,76],["H2091","them with gold",77,91]]},"3:11":{"text":"And the wings of the cherubims were twenty cubits long: one wing of the one cherub was five cubits, reaching to the wall of the house: and the other wing was likewise five cubits, reaching to the wing of the other cherub.","words":[["H3671","And the wings",0,13],["H3742","of the cherubims",14,30],["H6242","were twenty",31,42],["H0520","cubits",43,49],["H0753","long",50,54],["H0259","one",56,59],["H3671","wing",60,64],["H2568","of the one cherub was five",65,91],["H0520","cubits",92,98],["H5060","reaching",100,108],["H7023","to the wall",109,120],["H1004","of the house",121,133],["H0312","and the other",135,148],["H3671","wing",149,153],["H2568","was likewise five",154,171],["H0520","cubits",172,178],["H5060","reaching",180,188],["H3671","to the wing",189,200],["H0312","of the other",201,213],["H3742","cherub",214,220]]},"3:12":{"text":"And one wing of the other cherub was five cubits, reaching to the wall of the house: and the other wing was five cubits also, joining to the wing of the other cherub.","words":[["H3671","And one wing",0,12],["H0259","of the other",13,25],["H3742","cherub",26,32],["H2568","was five",33,41],["H0520","cubits",42,48],["H5060","reaching",50,58],["H7023","to the wall",59,70],["H1004","of the house",71,83],["H0312","and the other",85,98],["H3671","wing",99,103],["H2568","was five",104,112],["H0520","cubits",113,119],["H1695","also, joining",120,133],["H3671","to the wing",134,145],["H0312","of the other",146,158],["H3742","cherub",159,165]]},"3:13":{"text":"The wings of these cherubims spread themselves forth twenty cubits: and they stood on their feet, and their faces were inward.","words":[["H3671","The wings",0,9],["H3742","of these cherubims",10,28],["H6566","spread themselves forth",29,52],["H6242","twenty",53,59],["H0520","cubits",60,66],["H5975","and they stood",68,82],["H7272","on their feet",83,96],["H6440","and their faces",98,113],["H1004","were inward",114,125]]},"3:14":{"text":"And he made the vail of blue, and purple, and crimson, and fine linen, and wrought cherubims thereon.","words":[["H6213","And he made",0,11],["H6532","the vail",12,20],["H8504","of blue",21,28],["H0713","and purple",30,40],["H3758","and crimson",42,53],["H0948","and fine linen",55,69],["H5927","and wrought",71,82],["H3742","cherubims",83,92]]},"3:15":{"text":"Also he made before the house two pillars of thirty and five cubits high, and the chapiter that was on the top of each of them was five cubits.","words":[["H6213","Also he made",0,12],["H6440","before",13,19],["H1004","the house",20,29],["H8147","two",30,33],["H5982","pillars",34,41],["H7970","of thirty",42,51],["H2568","and five",52,60],["H0520","cubits",61,67],["H0753","high",68,72],["H6858","and the chapiter",74,90],["H7218","that was on the top",91,110],["H2568","of each of them was five",111,135],["H0520","cubits",136,142]]},"3:16":{"text":"And he made chains, as in the oracle, and put them on the heads of the pillars; and made an hundred pomegranates, and put them on the chains.","words":[["H6213","And he made",0,11],["H8333","chains",12,18],["H1687","as in the oracle",20,36],["H5414","and put",38,45],["H7218","them on the heads",46,63],["H5982","of the pillars",64,78],["H6213","and made",80,88],["H3967","an hundred",89,99],["H7416","pomegranates",100,112],["H5414","and put",114,121],["H8333","them on the chains",122,140]]},"3:17":{"text":"And he reared up the pillars before the temple, one on the right hand, and the other on the left; and called the name of that on the right hand Jachin, and the name of that on the left Boaz.","words":[["H6965","And he reared up",0,16],["H5982","the pillars",17,28],["H6440","before",29,35],["H1964","the temple",36,46],["H0259","one",48,51],["H3225","on the right hand",52,69],["H0259","and the other",71,84],["H8040","on the left",85,96],["H7121","and called",98,108],["H8034","the name",109,117],["H3233","of that on the right hand",118,143],["H3227","of that on the right hand",118,143],["H3199","Jachin",144,150],["H8034","and the name",152,164],["H8042","of that on the left",165,184],["H1162","Boaz",185,189]]},"4:1":{"text":"Moreover he made an altar of brass, twenty cubits the length thereof, and twenty cubits the breadth thereof, and ten cubits the height thereof.","words":[["H6213","Moreover he made",0,16],["H4196","an altar",17,25],["H5178","of brass",26,34],["H6242","twenty",36,42],["H0520","cubits",43,49],["H0753","the length",50,60],["H6242","thereof, and twenty",61,80],["H0520","cubits",81,87],["H7341","the breadth",88,99],["H6235","thereof, and ten",100,116],["H0520","cubits",117,123],["H6967","the height",124,134]]},"4:2":{"text":"Also he made a molten sea of ten cubits from brim to brim, round in compass, and five cubits the height thereof; and a line of thirty cubits did compass it round about.","words":[["H6213","Also he made",0,12],["H3332","a molten",13,21],["H3220","sea",22,25],["H6235","of ten",26,32],["H0520","cubits",33,39],["H8193","from brim",40,49],["H8193","to brim",50,57],["H5696","round",59,64],["H5439","in compass",65,75],["H2568","and five",77,85],["H0520","cubits",86,92],["H6967","the height",93,103],["H6957","thereof; and a line",104,123],["H7970","of thirty",124,133],["H0520","cubits",134,140],["H5437","did compass",141,152],["H5439","it round about",153,167]]},"4:3":{"text":"And under it was the similitude of oxen, which did compass it round about: ten in a cubit, compassing the sea round about. Two rows of oxen were cast, when it was cast.","words":[["H1823","And under it was the similitude",0,31],["H1241","of oxen",32,39],["H5437","which did compass",41,58],["H5439","it round about",59,73],["H6235","ten",75,78],["H0520","in a cubit",79,89],["H5362","compassing",91,101],["H3220","the sea",102,109],["H5439","round about",110,121],["H8147","Two",123,126],["H2905","rows",127,131],["H1241","of oxen",132,139],["H3332","were cast",140,149],["H4166","when it was cast",151,167]]},"4:4":{"text":"It stood upon twelve oxen, three looking toward the north, and three looking toward the west, and three looking toward the south, and three looking toward the east: and the sea was set above upon them, and all their hinder parts were inward.","words":[["H5975","It stood",0,8],["H8147","upon twelve",9,20],["H6240","upon twelve",9,20],["H1241","oxen",21,25],["H7969","three",27,32],["H6437","looking",33,40],["H6828","toward the north",41,57],["H7969","and three",59,68],["H6437","looking",69,76],["H3220","toward the west",77,92],["H7969","and three",94,103],["H6437","looking",104,111],["H5045","toward the south",112,128],["H7969","and three",130,139],["H6437","looking",140,147],["H4217","toward the east",148,163],["H3220","and the sea",165,176],["H4605","was set above",177,190],["H0268","upon them, and all their hinder parts",191,228],["H1004","were inward",229,240]]},"4:5":{"text":"And the thickness of it was an handbreadth, and the brim of it like the work of the brim of a cup, with flowers of lilies; and it received and held three thousand baths.","words":[["H5672","And the thickness",0,17],["H2947","of it was an handbreadth",18,42],["H8193","and the brim",44,56],["H4639","of it like the work",57,76],["H8193","of the brim",77,88],["H3563","of a cup",89,97],["H6525","with flowers",99,111],["H7799","of lilies",112,121],["H2388","and it received",123,138],["H3557","and held",139,147],["H7969","three",148,153],["H0505","thousand",154,162],["H1324","baths",163,168]]},"4:6":{"text":"He made also ten lavers, and put five on the right hand, and five on the left, to wash in them: such things as they offered for the burnt offering they washed in them; but the sea was for the priests to wash in.","words":[["H6213","He made",0,7],["H6235","also ten",8,16],["H3595","lavers",17,23],["H5414","and put",25,32],["H2568","five",33,37],["H3225","on the right hand",38,55],["H2568","and five",57,65],["H8040","on the left",66,77],["H7364","to wash",79,86],["H4639","in them: such things as they offered",87,123],["H5930","for the burnt offering",124,146],["H1740","they washed",147,158],["H3220","in them; but the sea",159,179],["H3548","was for the priests",180,199],["H7364","to wash in",200,210]]},"4:7":{"text":"And he made ten candlesticks of gold according to their form, and set them in the temple, five on the right hand, and five on the left.","words":[["H6213","And he made",0,11],["H6235","ten",12,15],["H4501","candlesticks",16,28],["H2091","of gold",29,36],["H4941","according to their form",37,60],["H5414","and set",62,69],["H1964","them in the temple",70,88],["H2568","five",90,94],["H3225","on the right hand",95,112],["H2568","and five",114,122],["H8040","on the left",123,134]]},"4:8":{"text":"He made also ten tables, and placed them in the temple, five on the right side, and five on the left. And he made an hundred basons of gold.","words":[["H6213","He made",0,7],["H6235","also ten",8,16],["H7979","tables",17,23],["H3240","and placed",25,35],["H1964","them in the temple",36,54],["H2568","five",56,60],["H3225","on the right side",61,78],["H2568","and five",80,88],["H8040","on the left",89,100],["H6213","And he made",102,113],["H3967","an hundred",114,124],["H4219","basons",125,131],["H2091","of gold",132,139]]},"4:9":{"text":"Furthermore he made the court of the priests, and the great court, and doors for the court, and overlaid the doors of them with brass.","words":[["H6213","Furthermore he made",0,19],["H2691","the court",20,29],["H3548","of the priests",30,44],["H1419","and the great",46,59],["H5835","court",60,65],["H1817","and doors",67,76],["H5835","for the court",77,90],["H6823","and overlaid",92,104],["H1817","the doors",105,114],["H5178","of them with brass",115,133]]},"4:10":{"text":"And he set the sea on the right side of the east end, over against the south.","words":[["H5414","And he set",0,10],["H3220","the sea",11,18],["H3233","on the right",19,31],["H3802","side",32,36],["H6924","of the east end",37,52],["H4136","over against",54,66],["H5045","the south",67,76]]},"4:11":{"text":"And Huram made the pots, and the shovels, and the basons. And Huram finished the work that he was to make for king Solomon for the house of God;","words":[["H2361","And Huram",0,9],["H6213","made",10,14],["H5518","the pots",15,23],["H3257","and the shovels",25,40],["H4219","and the basons",42,56],["H2361","And Huram",58,67],["H2438","And Huram",58,67],["H3615","finished",68,76],["H6213","finished",68,76],["H4399","the work",77,85],["H6213","that he was to make",86,105],["H4428","for king",106,114],["H8010","Solomon",115,122],["H1004","for the house",123,136],["H0430","of God",137,143]]},"4:12":{"text":"To wit, the two pillars, and the pommels, and the chapiters which were on the top of the two pillars, and the two wreaths to cover the two pommels of the chapiters which were on the top of the pillars;","words":[["H8147","To wit, the two",0,15],["H5982","pillars",16,23],["H1543","and the pommels",25,40],["H3805","and the chapiters",42,59],["H7218","which were on the top",60,81],["H5982","of the two pillars",82,100],["H8147","and the two",102,113],["H7639","wreaths",114,121],["H3680","to cover",122,130],["H8147","the two",131,138],["H1543","pommels",139,146],["H3805","of the chapiters",147,163],["H7218","which were on the top",164,185],["H5982","of the pillars",186,200]]},"4:13":{"text":"And four hundred pomegranates on the two wreaths; two rows of pomegranates on each wreath, to cover the two pommels of the chapiters which were upon the pillars.","words":[["H0702","And four",0,8],["H3967","hundred",9,16],["H7416","pomegranates",17,29],["H8147","on the two",30,40],["H7639","wreaths",41,48],["H8147","two",50,53],["H2905","rows",54,58],["H7416","of pomegranates",59,74],["H0259","on each",75,82],["H7639","wreath",83,89],["H3680","to cover",91,99],["H8147","the two",100,107],["H1543","pommels",108,115],["H3805","of the chapiters",116,132],["H6440","which were upon",133,148],["H5982","the pillars",149,160]]},"4:14":{"text":"He made also bases, and lavers made he upon the bases;","words":[["H6213","He made",0,7],["H4350","also bases",8,18],["H3595","and lavers",20,30],["H6213","made",31,35],["H4350","he upon the bases",36,53]]},"4:15":{"text":"One sea, and twelve oxen under it.","words":[["H0259","One",0,3],["H3220","sea",4,7],["H8147","and twelve",9,19],["H6240","and twelve",9,19],["H1241","oxen",20,24]]},"4:16":{"text":"The pots also, and the shovels, and the fleshhooks, and all their instruments, did Huram his father make to king Solomon for the house of the LORD of bright brass.","words":[["H5518","The pots",0,8],["H3257","also, and the shovels",9,30],["H4207","and the fleshhooks",32,50],["H3627","and all their instruments",52,77],["H2361","did Huram",79,88],["H0001","his father",89,99],["H6213","make",100,104],["H4428","to king",105,112],["H8010","Solomon",113,120],["H1004","for the house",121,134],["H3068","of the LORD",135,146],["H4838","of bright",147,156],["H5178","brass",157,162]]},"4:17":{"text":"In the plain of Jordan did the king cast them, in the clay ground between Succoth and Zeredathah.","words":[["H3603","In the plain",0,12],["H3383","of Jordan",13,22],["H4428","did the king",23,35],["H3332","cast",36,40],["H5645","them, in the clay",41,58],["H0127","ground",59,65],["H5523","between Succoth",66,81],["H6868","and Zeredathah",82,96]]},"4:18":{"text":"Thus Solomon made all these vessels in great abundance: for the weight of the brass could not be found out.","words":[["H8010","Thus Solomon",0,12],["H6213","made",13,17],["H3627","all these vessels",18,35],["H3966","in great",36,44],["H7230","abundance",45,54],["H4948","for the weight",56,70],["H5178","of the brass",71,83],["H2713","could not be found out",84,106]]},"4:19":{"text":"And Solomon made all the vessels that were for the house of God, the golden altar also, and the tables whereon the shewbread was set;","words":[["H8010","And Solomon",0,11],["H6213","made",12,16],["H3627","all the vessels",17,32],["H1004","that were for the house",33,56],["H0430","of God",57,63],["H2091","the golden",65,75],["H4196","altar",76,81],["H7979","also, and the tables",82,102],["H3899","whereon the shewbread",103,124],["H6440","whereon the shewbread",103,124]]},"4:20":{"text":"Moreover the candlesticks with their lamps, that they should burn after the manner before the oracle, of pure gold;","words":[["H4501","Moreover the candlesticks",0,25],["H5216","with their lamps",26,42],["H1197","that they should burn",44,65],["H4941","after the manner",66,82],["H6440","before",83,89],["H1687","the oracle",90,100],["H5462","of pure",102,109],["H2091","gold",110,114]]},"4:21":{"text":"And the flowers, and the lamps, and the tongs, made he of gold, and that perfect gold;","words":[["H6525","And the flowers",0,15],["H5216","and the lamps",17,30],["H4457","and the tongs",32,45],["H2091","made he of gold",47,62],["H4357","and that perfect",64,80],["H2091","gold",81,85]]},"4:22":{"text":"And the snuffers, and the basons, and the spoons, and the censers, of pure gold: and the entry of the house, the inner doors thereof for the most holy place, and the doors of the house of the temple, were of gold.","words":[["H4212","And the snuffers",0,16],["H4219","and the basons",18,32],["H3709","and the spoons",34,48],["H4289","and the censers",50,65],["H5462","of pure",67,74],["H2091","gold",75,79],["H6607","and the entry",81,94],["H1004","of the house",95,107],["H6442","the inner",109,118],["H1817","doors",119,124],["H6944","thereof for the most",125,145],["H6944","holy",146,150],["H1817","place, and the doors",151,171],["H1004","of the house",172,184],["H1964","of the temple",185,198],["H2091","were of gold",200,212]]},"5:1":{"text":"Thus all the work that Solomon made for the house of the LORD was finished: and Solomon brought in all the things that David his father had dedicated; and the silver, and the gold, and all the instruments, put he among the treasures of the house of God.","words":[["H4399","Thus all the work",0,17],["H8010","that Solomon",18,30],["H6213","made",31,35],["H1004","for the house",36,49],["H3068","of the LORD",50,61],["H7999","was finished",62,74],["H8010","and Solomon",76,87],["H0935","brought",88,95],["H6944","in all the things",96,113],["H1732","that David",114,124],["H0001","his father",125,135],["H6944","had dedicated",136,149],["H3701","and the silver",151,165],["H2091","and the gold",167,179],["H3627","and all the instruments",181,204],["H5414","put",206,209],["H0214","he among the treasures",210,232],["H1004","of the house",233,245],["H0430","of God",246,252]]},"5:2":{"text":"Then Solomon assembled the elders of Israel, and all the heads of the tribes, the chief of the fathers of the children of Israel, unto Jerusalem, to bring up the ark of the covenant of the LORD out of the city of David, which is Zion.","words":[["H8010","Then Solomon",0,12],["H6950","assembled",13,22],["H2205","the elders",23,33],["H3478","of Israel",34,43],["H7218","and all the heads",45,62],["H4294","of the tribes",63,76],["H5387","the chief",78,87],["H0001","of the fathers",88,102],["H1121","of the children",103,118],["H3478","of Israel",119,128],["H3389","unto Jerusalem",130,144],["H5927","to bring up",146,157],["H0727","the ark",158,165],["H1285","of the covenant",166,181],["H3068","of the LORD",182,193],["H5892","out of the city",194,209],["H1732","of David",210,218],["H6726","which is Zion",220,233]]},"5:3":{"text":"Wherefore all the men of Israel assembled themselves unto the king in the feast which was in the seventh month.","words":[["H0376","Wherefore all the men",0,21],["H3478","of Israel",22,31],["H6950","assembled",32,41],["H4428","themselves unto the king",42,66],["H2282","in the feast",67,79],["H7637","which was in the seventh",80,104],["H2320","month",105,110]]},"5:4":{"text":"And all the elders of Israel came; and the Levites took up the ark.","words":[["H2205","And all the elders",0,18],["H3478","of Israel",19,28],["H0935","came",29,33],["H3881","and the Levites",35,50],["H5375","took up",51,58],["H0727","the ark",59,66]]},"5:5":{"text":"And they brought up the ark, and the tabernacle of the congregation, and all the holy vessels that were in the tabernacle, these did the priests and the Levites bring up.","words":[["H5927","And they brought up",0,19],["H0727","the ark",20,27],["H0168","and the tabernacle",29,47],["H4150","of the congregation",48,67],["H6944","and all the holy",69,85],["H3627","vessels",86,93],["H0168","that were in the tabernacle",94,121],["H3548","these did the priests",123,144],["H3881","and the Levites",145,160],["H5927","bring up",161,169]]},"5:6":{"text":"Also king Solomon, and all the congregation of Israel that were assembled unto him before the ark, sacrificed sheep and oxen, which could not be told nor numbered for multitude.","words":[["H4428","Also king",0,9],["H8010","Solomon",10,17],["H5712","and all the congregation",19,43],["H3478","of Israel",44,53],["H3259","that were assembled",54,73],["H6440","unto him before",74,89],["H0727","the ark",90,97],["H2076","sacrificed",99,109],["H6629","sheep",110,115],["H1241","and oxen",116,124],["H5608","which could not be told",126,149],["H4487","nor numbered",150,162],["H7230","for multitude",163,176]]},"5:7":{"text":"And the priests brought in the ark of the covenant of the LORD unto his place, to the oracle of the house, into the most holy place, even under the wings of the cherubims:","words":[["H3548","And the priests",0,15],["H0935","brought in",16,26],["H0727","the ark",27,34],["H1285","of the covenant",35,50],["H3068","of the LORD",51,62],["H4725","unto his place",63,77],["H1687","to the oracle",79,92],["H1004","of the house",93,105],["H6944","into the most",107,120],["H6944","holy",121,125],["H3671","place, even under the wings",126,153],["H3742","of the cherubims",154,170]]},"5:8":{"text":"For the cherubims spread forth their wings over the place of the ark, and the cherubims covered the ark and the staves thereof above.","words":[["H3742","For the cherubims",0,17],["H6566","spread forth",18,30],["H3671","their wings",31,42],["H4725","over the place",43,57],["H0727","of the ark",58,68],["H3742","and the cherubims",70,87],["H3680","covered",88,95],["H0727","the ark",96,103],["H0905","and the staves",104,118],["H4605","thereof above",119,132]]},"5:9":{"text":"And they drew out the staves of the ark, that the ends of the staves were seen from the ark before the oracle; but they were not seen without. And there it is unto this day.","words":[["H0748","And they drew out",0,17],["H0905","the staves",18,28],["H7218","of the ark, that the ends",29,54],["H0905","of the staves",55,68],["H7200","were seen",69,78],["H0727","from the ark",79,91],["H6440","before",92,98],["H1687","the oracle",99,109],["H7200","but they were not seen",111,133],["H2351","without",134,141],["H3117","And there it is unto this day",143,172]]},"5:10":{"text":"There was nothing in the ark save the two tables which Moses put therein at Horeb, when the LORD made a covenant with the children of Israel, when they came out of Egypt.","words":[["H0727","There was nothing in the ark",0,28],["H8147","save the two",29,41],["H3871","tables",42,48],["H4872","which Moses",49,60],["H5414","put",61,64],["H2722","therein at Horeb",65,81],["H3068","when the LORD",83,96],["H3772","made",97,101],["H1121","a covenant with the children",102,130],["H3478","of Israel",131,140],["H3318","when they came out",142,160],["H4714","of Egypt",161,169]]},"5:11":{"text":"And it came to pass, when the priests were come out of the holy place: (for all the priests that were present were sanctified, and did not then wait by course:","words":[["H3548","And it came to pass, when the priests",0,37],["H3318","were come out",38,51],["H6944","of the holy",52,63],["H3548","place: (for all the priests",64,91],["H4672","that were present",92,109],["H6942","were sanctified",110,125],["H8104","and did not then wait",127,148],["H4256","by course",149,158]]},"5:12":{"text":"Also the Levites which were the singers, all of them of Asaph, of Heman, of Jeduthun, with their sons and their brethren, being arrayed in white linen, having cymbals and psalteries and harps, stood at the east end of the altar, and with them an hundred and twenty priests sounding with trumpets:)","words":[["H3881","Also the Levites",0,16],["H7891","which were the singers",17,39],["H0623","all of them of Asaph",41,61],["H1968","of Heman",63,71],["H3038","of Jeduthun",73,84],["H1121","with their sons",86,101],["H0251","and their brethren",102,120],["H3847","being arrayed",122,135],["H0948","in white linen",136,150],["H4700","having cymbals",152,166],["H5035","and psalteries",167,181],["H3658","and harps",182,191],["H5975","stood",193,198],["H4217","at the east end",199,214],["H4196","of the altar",215,227],["H3967","and with them an hundred",229,253],["H6242","and twenty",254,264],["H3548","priests",265,272],["H2690","sounding",273,281],["H2689","with trumpets",282,295]]},"5:13":{"text":"It came even to pass, as the trumpeters and singers were as one, to make one sound to be heard in praising and thanking the LORD; and when they lifted up their voice with the trumpets and cymbals and instruments of musick, and praised the LORD, saying, For he is good; for his mercy endureth for ever: that then the house was filled with a cloud, even the house of the LORD;","words":[["H2690","It came even to pass, as the trumpeters",0,39],["H2690","It came even to pass, as the trumpeters",0,39],["H7891","and singers",40,51],["H0259","were as one",52,63],["H0259","to make one",65,76],["H6963","sound",77,82],["H8085","to be heard",83,94],["H1984","in praising",95,106],["H3034","and thanking",107,119],["H3068","the LORD",120,128],["H7311","and when they lifted up",130,153],["H6963","their voice",154,165],["H2689","with the trumpets",166,183],["H4700","and cymbals",184,195],["H3627","and instruments",196,211],["H7892","of musick",212,221],["H1984","and praised",223,234],["H3068","the LORD",235,243],["H2896","saying, For he is good",245,267],["H2617","for his mercy",269,282],["H5769","endureth for ever",283,300],["H1004","that then the house",302,321],["H4390","was filled",322,332],["H6051","with a cloud",333,345],["H1004","even the house",347,361],["H3068","of the LORD",362,373]]},"5:14":{"text":"So that the priests could not stand to minister by reason of the cloud: for the glory of the LORD had filled the house of God.","words":[["H3548","So that the priests",0,19],["H3201","could",20,25],["H5975","not stand",26,35],["H8334","to minister",36,47],["H6440","by reason",48,57],["H6051","of the cloud",58,70],["H3519","for the glory",72,85],["H3068","of the LORD",86,97],["H4390","had filled",98,108],["H1004","the house",109,118],["H0430","of God",119,125]]},"6:1":{"text":"Then said Solomon, The LORD hath said that he would dwell in the thick darkness.","words":[["H0559","Then said",0,9],["H8010","Solomon",10,17],["H3068","The LORD",19,27],["H0559","hath said",28,37],["H7931","that he would dwell",38,57],["H6205","in the thick darkness",58,79]]},"6:2":{"text":"But I have built an house of habitation for thee, and a place for thy dwelling for ever.","words":[["H1129","But I have built",0,16],["H1004","an house",17,25],["H2073","of habitation",26,39],["H4349","for thee, and a place",40,61],["H3427","for thy dwelling",62,78],["H5769","for ever",79,87]]},"6:3":{"text":"And the king turned his face, and blessed the whole congregation of Israel: and all the congregation of Israel stood.","words":[["H4428","And the king",0,12],["H5437","turned",13,19],["H6440","his face",20,28],["H1288","and blessed",30,41],["H6951","the whole congregation",42,64],["H3478","of Israel",65,74],["H6951","and all the congregation",76,100],["H3478","of Israel",101,110],["H5975","stood",111,116]]},"6:4":{"text":"And he said, Blessed be the LORD God of Israel, who hath with his hands fulfilled that which he spake with his mouth to my father David, saying,","words":[["H0559","And he said",0,11],["H1288","Blessed",13,20],["H3068","be the LORD",21,32],["H0430","God",33,36],["H3478","of Israel",37,46],["H3027","who hath with his hands",48,71],["H4390","fulfilled",72,81],["H1696","that which he spake",82,101],["H6310","with his mouth",102,116],["H0001","to my father",117,129],["H1732","David",130,135],["H0559","saying",137,143]]},"6:5":{"text":"Since the day that I brought forth my people out of the land of Egypt I chose no city among all the tribes of Israel to build an house in, that my name might be there; neither chose I any man to be a ruler over my people Israel:","words":[["H3117","Since the day",0,13],["H3318","that I brought forth",14,34],["H5971","my people",35,44],["H0776","out of the land",45,60],["H4714","of Egypt",61,69],["H0977","I chose",70,77],["H5892","no city",78,85],["H7626","among all the tribes",86,106],["H3478","of Israel",107,116],["H1129","to build",117,125],["H1004","an house",126,134],["H8034","in, that my name",135,151],["H0977","might be there; neither chose",152,181],["H0376","I any man",182,191],["H5057","to be a ruler",192,205],["H5971","over my people",206,220],["H3478","Israel",221,227]]},"6:6":{"text":"But I have chosen Jerusalem, that my name might be there; and have chosen David to be over my people Israel.","words":[["H0977","But I have chosen",0,17],["H3389","Jerusalem",18,27],["H8034","that my name",29,41],["H0977","might be there; and have chosen",42,73],["H1732","David",74,79],["H5971","to be over my people",80,100],["H3478","Israel",101,107]]},"6:7":{"text":"Now it was in the heart of David my father to build an house for the name of the LORD God of Israel.","words":[["H3824","Now it was in the heart",0,23],["H1732","of David",24,32],["H0001","my father",33,42],["H1129","to build",43,51],["H1004","an house",52,60],["H8034","for the name",61,73],["H3068","of the LORD",74,85],["H0430","God",86,89],["H3478","of Israel",90,99]]},"6:8":{"text":"But the LORD said to David my father, Forasmuch as it was in thine heart to build an house for my name, thou didst well in that it was in thine heart:","words":[["H3068","But the LORD",0,12],["H0559","said",13,17],["H1732","to David",18,26],["H0001","my father",27,36],["H3824","Forasmuch as it was in thine heart",38,72],["H1129","to build",73,81],["H1004","an house",82,90],["H8034","for my name",91,102],["H2895","thou didst well",104,119],["H3824","in that it was in thine heart",120,149]]},"6:9":{"text":"Notwithstanding thou shalt not build the house; but thy son which shall come forth out of thy loins, he shall build the house for my name.","words":[["H7535","Notwithstanding",0,15],["H1129","thou shalt not build",16,36],["H1004","the house",37,46],["H1121","but thy son",48,59],["H3318","which shall come forth",60,82],["H2504","out of thy loins",83,99],["H1129","he shall build",101,115],["H1004","the house",116,125],["H8034","for my name",126,137]]},"6:10":{"text":"The LORD therefore hath performed his word that he hath spoken: for I am risen up in the room of David my father, and am set on the throne of Israel, as the LORD promised, and have built the house for the name of the LORD God of Israel.","words":[["H3068","The LORD",0,8],["H6965","therefore hath performed",9,33],["H1697","his word",34,42],["H1696","that he hath spoken",43,62],["H6965","for I am risen up",64,81],["H1732","in the room of David",82,102],["H0001","my father",103,112],["H3427","and am set",114,124],["H3678","on the throne",125,138],["H3478","of Israel",139,148],["H3068","as the LORD",150,161],["H1696","promised",162,170],["H1129","and have built",172,186],["H1004","the house",187,196],["H8034","for the name",197,209],["H3068","of the LORD",210,221],["H0430","God",222,225],["H3478","of Israel",226,235]]},"6:11":{"text":"And in it have I put the ark, wherein is the covenant of the LORD, that he made with the children of Israel.","words":[["H8033","And in it",0,9],["H7760","have I put",10,20],["H0727","the ark",21,28],["H1285","wherein is the covenant",30,53],["H3068","of the LORD",54,65],["H3772","that he made",67,79],["H1121","with the children",80,97],["H3478","of Israel",98,107]]},"6:12":{"text":"And he stood before the altar of the LORD in the presence of all the congregation of Israel, and spread forth his hands:","words":[["H5975","And he stood",0,12],["H6440","before",13,19],["H4196","the altar",20,29],["H3068","of the LORD",30,41],["H6951","in the presence of all the congregation",42,81],["H3478","of Israel",82,91],["H6566","and spread forth",93,109],["H3709","his hands",110,119]]},"6:13":{"text":"For Solomon had made a brasen scaffold, of five cubits long, and five cubits broad, and three cubits high, and had set it in the midst of the court: and upon it he stood, and kneeled down upon his knees before all the congregation of Israel, and spread forth his hands toward heaven,","words":[["H8010","For Solomon",0,11],["H6213","had made",12,20],["H5178","a brasen",21,29],["H3595","scaffold",30,38],["H2568","of five",40,47],["H0520","cubits",48,54],["H0753","long",55,59],["H2568","and five",61,69],["H0520","cubits",70,76],["H7341","broad",77,82],["H7969","and three",84,93],["H0520","cubits",94,100],["H6967","high",101,105],["H5414","and had set",107,118],["H8432","it in the midst",119,134],["H5835","of the court",135,147],["H5975","and upon it he stood",149,169],["H1288","and kneeled down",171,187],["H1290","upon his knees",188,202],["H6951","before all the congregation",203,230],["H3478","of Israel",231,240],["H6566","and spread forth",242,258],["H3709","his hands",259,268],["H8064","toward heaven",269,282]]},"6:14":{"text":"And said, O LORD God of Israel, there is no God like thee in the heaven, nor in the earth; which keepest covenant, and shewest mercy unto thy servants, that walk before thee with all their hearts:","words":[["H0559","And said",0,8],["H3068","O LORD",10,16],["H0430","God",17,20],["H3478","of Israel",21,30],["H0430","there is no God",32,47],["H8064","like thee in the heaven",48,71],["H0776","nor in the earth",73,89],["H8104","which keepest",91,104],["H1285","covenant",105,113],["H2617","and shewest mercy",115,132],["H5650","unto thy servants",133,150],["H1980","that walk",152,161],["H6440","before",162,168],["H3820","thee with all their hearts",169,195]]},"6:15":{"text":"Thou which hast kept with thy servant David my father that which thou hast promised him; and spakest with thy mouth, and hast fulfilled it with thine hand, as it is this day.","words":[["H8104","Thou which hast kept",0,20],["H5650","with thy servant",21,37],["H1732","David",38,43],["H0001","my father",44,53],["H1696","that which thou hast promised",54,83],["H1696","him; and spakest",84,100],["H6310","with thy mouth",101,115],["H4390","and hast fulfilled",117,135],["H3027","it with thine hand",136,154],["H3117","as it is this day",156,173]]},"6:16":{"text":"Now therefore, O LORD God of Israel, keep with thy servant David my father that which thou hast promised him, saying, There shall not fail thee a man in my sight to sit upon the throne of Israel; yet so that thy children take heed to their way to walk in my law, as thou hast walked before me.","words":[["H3068","Now therefore, O LORD",0,21],["H0430","God",22,25],["H3478","of Israel",26,35],["H8104","keep",37,41],["H5650","with thy servant",42,58],["H1732","David",59,64],["H0001","my father",65,74],["H1696","that which thou hast promised",75,104],["H0559","him, saying",105,116],["H3772","There shall not fail",118,138],["H0376","thee a man",139,149],["H6440","in my sight",150,161],["H3427","to sit",162,168],["H3678","upon the throne",169,184],["H3478","of Israel",185,194],["H7535","yet so",196,202],["H1121","that thy children",203,220],["H8104","take heed",221,230],["H1870","to their way",231,243],["H3212","to walk",244,251],["H8451","in my law",252,261],["H1980","as thou hast walked",263,282],["H6440","before",283,289]]},"6:17":{"text":"Now then, O LORD God of Israel, let thy word be verified, which thou hast spoken unto thy servant David.","words":[["H3068","Now then, O LORD",0,16],["H0430","God",17,20],["H3478","of Israel",21,30],["H1697","let thy word",32,44],["H0539","be verified",45,56],["H1696","which thou hast spoken",58,80],["H5650","unto thy servant",81,97],["H1732","David",98,103]]},"6:18":{"text":"But will God in very deed dwell with men on the earth? behold, heaven and the heaven of heavens cannot contain thee; how much less this house which I have built!","words":[["H0430","But will God",0,12],["H0552","in very deed",13,25],["H3427","dwell",26,31],["H0120","with men",32,40],["H0776","on the earth",41,53],["H8064","behold, heaven",55,69],["H8064","and the heaven",70,84],["H8064","of heavens",85,95],["H3557","cannot contain",96,110],["H1004","thee; how much less this house",111,141],["H1129","which I have built",142,160]]},"6:19":{"text":"Have respect therefore to the prayer of thy servant, and to his supplication, O LORD my God, to hearken unto the cry and the prayer which thy servant prayeth before thee:","words":[["H6437","Have respect",0,12],["H8605","therefore to the prayer",13,36],["H5650","of thy servant",37,51],["H8467","and to his supplication",53,76],["H3068","O LORD",78,84],["H0430","my God",85,91],["H8085","to hearken",93,103],["H7440","unto the cry",104,116],["H8605","and the prayer",117,131],["H5650","which thy servant",132,149],["H6419","prayeth",150,157],["H6440","before",158,164]]},"6:20":{"text":"That thine eyes may be open upon this house day and night, upon the place whereof thou hast said that thou wouldest put thy name there; to hearken unto the prayer which thy servant prayeth toward this place.","words":[["H5869","That thine eyes",0,15],["H6605","may be open",16,27],["H1004","upon this house",28,43],["H3119","day",44,47],["H3915","and night",48,57],["H4725","upon the place",59,73],["H0559","whereof thou hast said",74,96],["H7760","that thou wouldest put",97,119],["H8034","thy name",120,128],["H8085","there; to hearken",129,146],["H8605","unto the prayer",147,162],["H5650","which thy servant",163,180],["H6419","prayeth",181,188],["H4725","toward this place",189,206]]},"6:21":{"text":"Hearken therefore unto the supplications of thy servant, and of thy people Israel, which they shall make toward this place: hear thou from thy dwelling place, even from heaven; and when thou hearest, forgive.","words":[["H8085","Hearken",0,7],["H8469","therefore unto the supplications",8,40],["H5650","of thy servant",41,55],["H5971","and of thy people",57,74],["H3478","Israel",75,81],["H6419","which they shall make",83,104],["H4725","toward this place",105,122],["H8085","hear",124,128],["H3427","thou from thy dwelling",129,151],["H4725","place",152,157],["H8064","even from heaven",159,175],["H8085","and when thou hearest",177,198],["H5545","forgive",200,207]]},"6:22":{"text":"If a man sin against his neighbour, and an oath be laid upon him to make him swear, and the oath come before thine altar in this house;","words":[["H0376","If a man",0,8],["H2398","sin",9,12],["H7453","against his neighbour",13,34],["H0423","and an oath",36,47],["H5375","be laid",48,55],["H0422","upon him to make him swear",56,82],["H0423","and the oath",84,96],["H0935","come",97,101],["H6440","before",102,108],["H4196","thine altar",109,120],["H1004","in this house",121,134]]},"6:23":{"text":"Then hear thou from heaven, and do, and judge thy servants, by requiting the wicked, by recompensing his way upon his own head; and by justifying the righteous, by giving him according to his righteousness.","words":[["H8085","Then hear",0,9],["H8064","thou from heaven",10,26],["H6213","and do",28,34],["H8199","and judge",36,45],["H5650","thy servants",46,58],["H7725","by requiting",60,72],["H7563","the wicked",73,83],["H5414","by recompensing",85,100],["H1870","his way",101,108],["H7218","upon his own head",109,126],["H6663","and by justifying",128,145],["H6662","the righteous",146,159],["H5414","by giving",161,170],["H6666","him according to his righteousness",171,205]]},"6:24":{"text":"And if thy people Israel be put to the worse before the enemy, because they have sinned against thee; and shall return and confess thy name, and pray and make supplication before thee in this house;","words":[["H5971","And if thy people",0,17],["H3478","Israel",18,24],["H5062","be put to the worse",25,44],["H6440","before",45,51],["H0341","the enemy",52,61],["H2398","because they have sinned",63,87],["H7725","against thee; and shall return",88,118],["H3034","and confess",119,130],["H8034","thy name",131,139],["H6419","and pray",141,149],["H2603","and make supplication",150,171],["H6440","before",172,178],["H1004","thee in this house",179,197]]},"6:25":{"text":"Then hear thou from the heavens, and forgive the sin of thy people Israel, and bring them again unto the land which thou gavest to them and to their fathers.","words":[["H8085","Then hear",0,9],["H8064","thou from the heavens",10,31],["H5545","and forgive",33,44],["H2403","the sin",45,52],["H5971","of thy people",53,66],["H3478","Israel",67,73],["H7725","and bring them again",75,95],["H0127","unto the land",96,109],["H5414","which thou gavest",110,127],["H0001","to them and to their fathers",128,156]]},"6:26":{"text":"When the heaven is shut up, and there is no rain, because they have sinned against thee; yet if they pray toward this place, and confess thy name, and turn from their sin, when thou dost afflict them;","words":[["H8064","When the heaven",0,15],["H6113","is shut up",16,26],["H4306","and there is no rain",28,48],["H2398","because they have sinned",50,74],["H6419","against thee; yet if they pray",75,105],["H4725","toward this place",106,123],["H3034","and confess",125,136],["H8034","thy name",137,145],["H7725","and turn",147,155],["H2403","from their sin",156,170],["H6031","when thou dost afflict",172,194]]},"6:27":{"text":"Then hear thou from heaven, and forgive the sin of thy servants, and of thy people Israel, when thou hast taught them the good way, wherein they should walk; and send rain upon thy land, which thou hast given unto thy people for an inheritance.","words":[["H8085","Then hear",0,9],["H8064","thou from heaven",10,26],["H5545","and forgive",28,39],["H2403","the sin",40,47],["H5650","of thy servants",48,63],["H5971","and of thy people",65,82],["H3478","Israel",83,89],["H3384","when thou hast taught",91,112],["H2896","them the good",113,126],["H1870","way",127,130],["H3212","wherein they should walk",132,156],["H5414","and send",158,166],["H4306","rain",167,171],["H0776","upon thy land",172,185],["H5414","which thou hast given",187,208],["H5971","unto thy people",209,224],["H5159","for an inheritance",225,243]]},"6:28":{"text":"If there be dearth in the land, if there be pestilence, if there be blasting, or mildew, locusts, or caterpillers; if their enemies besiege them in the cities of their land; whatsoever sore or whatsoever sickness there be:","words":[["H7458","If there be dearth",0,18],["H0776","in the land",19,30],["H1698","if there be pestilence",32,54],["H7711","if there be blasting",56,76],["H3420","or mildew",78,87],["H0697","locusts",89,96],["H2625","or caterpillers",98,113],["H0341","if their enemies",115,131],["H6887","besiege",132,139],["H8179","them in the cities",140,158],["H0776","of their land",159,172],["H5061","whatsoever sore",174,189],["H4245","or whatsoever sickness",190,212]]},"6:29":{"text":"Then what prayer or what supplication soever shall be made of any man, or of all thy people Israel, when every one shall know his own sore and his own grief, and shall spread forth his hands in this house:","words":[["H8605","Then what prayer",0,16],["H8467","or what supplication",17,37],["H0120","soever shall be made of any man",38,69],["H5971","or of all thy people",71,91],["H3478","Israel",92,98],["H0376","when every one",100,114],["H3045","shall know",115,125],["H5061","his own sore",126,138],["H4341","and his own grief",139,156],["H6566","and shall spread forth",158,180],["H3709","his hands",181,190],["H1004","in this house",191,204]]},"6:30":{"text":"Then hear thou from heaven thy dwelling place, and forgive, and render unto every man according unto all his ways, whose heart thou knowest; (for thou only knowest the hearts of the children of men:)","words":[["H8085","Then hear",0,9],["H8064","thou from heaven",10,26],["H3427","thy dwelling",27,39],["H4349","place",40,45],["H5545","and forgive",47,58],["H5414","and render",60,70],["H0376","unto every man",71,85],["H1870","according unto all his ways",86,113],["H3824","whose heart",115,126],["H3045","thou knowest",127,139],["H3045","(for thou only knowest",141,163],["H3824","the hearts",164,174],["H1121","of the children",175,190],["H0120","of men",191,197]]},"6:31":{"text":"That they may fear thee, to walk in thy ways, so long as they live in the land which thou gavest unto our fathers.","words":[["H3372","That they may fear",0,18],["H3212","thee, to walk",19,32],["H1870","in thy ways",33,44],["H3117","so long as",46,56],["H2416","they live",57,66],["H6440","they live",57,66],["H0127","in the land",67,78],["H5414","which thou gavest",79,96],["H0001","unto our fathers",97,113]]},"6:32":{"text":"Moreover concerning the stranger, which is not of thy people Israel, but is come from a far country for thy great name's sake, and thy mighty hand, and thy stretched out arm; if they come and pray in this house;","words":[["H5237","Moreover concerning the stranger",0,32],["H5971","which is not of thy people",34,60],["H3478","Israel",61,67],["H0935","but is come",69,80],["H7350","from a far",81,91],["H0776","country",92,99],["H1419","for thy great",100,113],["H8034","name's",114,120],["H2389","sake, and thy mighty",121,141],["H3027","hand",142,146],["H5186","and thy stretched out",148,169],["H2220","arm",170,173],["H0935","if they come",175,187],["H6419","and pray",188,196],["H1004","in this house",197,210]]},"6:33":{"text":"Then hear thou from the heavens, even from thy dwelling place, and do according to all that the stranger calleth to thee for; that all people of the earth may know thy name, and fear thee, as doth thy people Israel, and may know that this house which I have built is called by thy name.","words":[["H8085","Then hear",0,9],["H8064","thou from the heavens",10,31],["H3427","even from thy dwelling",33,55],["H4349","place",56,61],["H6213","and do",63,69],["H5237","according to all that the stranger",70,104],["H7121","calleth",105,112],["H5971","to thee for; that all people",113,141],["H0776","of the earth",142,154],["H3045","may know",155,163],["H8034","thy name",164,172],["H3372","and fear",174,182],["H5971","thee, as doth thy people",183,207],["H3478","Israel",208,214],["H3045","and may know",216,228],["H1004","that this house",229,244],["H1129","which I have built",245,263],["H7121","is called",264,273],["H8034","by thy name",274,285]]},"6:34":{"text":"If thy people go out to war against their enemies by the way that thou shalt send them, and they pray unto thee toward this city which thou hast chosen, and the house which I have built for thy name;","words":[["H5971","If thy people",0,13],["H3318","go out",14,20],["H4421","to war",21,27],["H0341","against their enemies",28,49],["H1870","by the way",50,60],["H7971","that thou shalt send",61,81],["H6419","them, and they pray",82,101],["H1870","unto thee toward",102,118],["H5892","this city",119,128],["H0977","which thou hast chosen",129,151],["H1004","and the house",153,166],["H1129","which I have built",167,185],["H8034","for thy name",186,198]]},"6:35":{"text":"Then hear thou from the heavens their prayer and their supplication, and maintain their cause.","words":[["H8085","Then hear",0,9],["H8064","thou from the heavens",10,31],["H8605","their prayer",32,44],["H8467","and their supplication",45,67],["H6213","and maintain",69,81],["H4941","their cause",82,93]]},"6:36":{"text":"If they sin against thee, (for there is no man which sinneth not,) and thou be angry with them, and deliver them over before their enemies, and they carry them away captives unto a land far off or near;","words":[["H2398","If they sin",0,11],["H0120","against thee, (for there is no man",12,46],["H2398","which sinneth",47,60],["H0599","not,) and thou be angry",61,84],["H5414","with them, and deliver",85,107],["H6440","them over before",108,124],["H0341","their enemies",125,138],["H7617","and they carry them away",140,164],["H7617","captives",165,173],["H0776","unto a land",174,185],["H7350","far off",186,193],["H7138","or near",194,201]]},"6:37":{"text":"Yet if they bethink themselves in the land whither they are carried captive, and turn and pray unto thee in the land of their captivity, saying, We have sinned, we have done amiss, and have dealt wickedly;","words":[["H7725","Yet if they bethink",0,19],["H3824","Yet if they bethink",0,19],["H0776","themselves in the land",20,42],["H7617","whither they are carried captive",43,75],["H7725","and turn",77,85],["H2603","and pray",86,94],["H0776","unto thee in the land",95,116],["H7628","of their captivity",117,135],["H0559","saying",137,143],["H2398","We have sinned",145,159],["H5753","we have done amiss",161,179],["H7561","and have dealt wickedly",181,204]]},"6:38":{"text":"If they return to thee with all their heart and with all their soul in the land of their captivity, whither they have carried them captives, and pray toward their land, which thou gavest unto their fathers, and toward the city which thou hast chosen, and toward the house which I have built for thy name:","words":[["H7725","If they return",0,14],["H3820","to thee with all their heart",15,43],["H5315","and with all their soul",44,67],["H0776","in the land",68,79],["H7628","of their captivity",80,98],["H7617","whither they have carried them captives",100,139],["H6419","and pray",141,149],["H1870","toward",150,156],["H0776","their land",157,167],["H5414","which thou gavest",169,186],["H0001","unto their fathers",187,205],["H5892","and toward the city",207,226],["H0977","which thou hast chosen",227,249],["H1004","and toward the house",251,271],["H1129","which I have built",272,290],["H8034","for thy name",291,303]]},"6:39":{"text":"Then hear thou from the heavens, even from thy dwelling place, their prayer and their supplications, and maintain their cause, and forgive thy people which have sinned against thee.","words":[["H8085","Then hear",0,9],["H8064","thou from the heavens",10,31],["H3427","even from thy dwelling",33,55],["H4349","place",56,61],["H8605","their prayer",63,75],["H8467","and their supplications",76,99],["H6213","and maintain",101,113],["H4941","their cause",114,125],["H5545","and forgive",127,138],["H5971","thy people",139,149],["H2398","which have sinned",150,167]]},"6:40":{"text":"Now, my God, let, I beseech thee, thine eyes be open, and let thine ears be attent unto the prayer that is made in this place.","words":[["H0430","Now, my God",0,11],["H5869","let, I beseech thee, thine eyes",13,44],["H6605","be open",45,52],["H0241","and let thine ears",54,72],["H7183","be attent",73,82],["H8605","unto the prayer",83,98],["H4725","that is made in this place",99,125]]},"6:41":{"text":"Now therefore arise, O LORD God, into thy resting place, thou, and the ark of thy strength: let thy priests, O LORD God, be clothed with salvation, and let thy saints rejoice in goodness.","words":[["H6965","Now therefore arise",0,19],["H3068","O LORD",21,27],["H0430","God",28,31],["H5118","into thy resting",33,49],["H0727","place, thou, and the ark",50,74],["H5797","of thy strength",75,90],["H3548","let thy priests",92,107],["H3068","O LORD",109,115],["H0430","God",116,119],["H3847","be clothed",121,131],["H8668","with salvation",132,146],["H2623","and let thy saints",148,166],["H8055","rejoice",167,174],["H2896","in goodness",175,186]]},"6:42":{"text":"O LORD God, turn not away the face of thine anointed: remember the mercies of David thy servant.","words":[["H3068","O LORD",0,6],["H0430","God",7,10],["H7725","turn not away",12,25],["H6440","the face",26,34],["H4899","of thine anointed",35,52],["H2142","remember",54,62],["H2617","the mercies",63,74],["H1732","of David",75,83],["H5650","thy servant",84,95]]},"7:1":{"text":"Now when Solomon had made an end of praying, the fire came down from heaven, and consumed the burnt offering and the sacrifices; and the glory of the LORD filled the house.","words":[["H8010","Now when Solomon",0,16],["H3615","had made an end",17,32],["H6419","of praying",33,43],["H0784","the fire",45,53],["H3381","came down",54,63],["H8064","from heaven",64,75],["H0398","and consumed",77,89],["H5930","the burnt offering",90,108],["H2077","and the sacrifices",109,127],["H3519","and the glory",129,142],["H3068","of the LORD",143,154],["H4390","filled",155,161],["H1004","the house",162,171]]},"7:2":{"text":"And the priests could not enter into the house of the LORD, because the glory of the LORD had filled the LORD'S house.","words":[["H3548","And the priests",0,15],["H3201","could",16,21],["H0935","not enter",22,31],["H1004","into the house",32,46],["H3068","of the LORD",47,58],["H3519","because the glory",60,77],["H3068","of the LORD",78,89],["H4390","had filled",90,100],["H3068","the LORD'S",101,111],["H1004","house",112,117]]},"7:3":{"text":"And when all the children of Israel saw how the fire came down, and the glory of the LORD upon the house, they bowed themselves with their faces to the ground upon the pavement, and worshipped, and praised the LORD, saying, For he is good; for his mercy endureth for ever.","words":[["H1121","And when all the children",0,25],["H3478","of Israel",26,35],["H7200","saw",36,39],["H0784","how the fire",40,52],["H3381","came down",53,62],["H3519","and the glory",64,77],["H3068","of the LORD",78,89],["H1004","upon the house",90,104],["H3766","they bowed",106,116],["H0639","themselves with their faces",117,144],["H0776","to the ground",145,158],["H7531","upon the pavement",159,176],["H7812","and worshipped",178,192],["H3034","and praised",194,205],["H3068","the LORD",206,214],["H2896","saying, For he is good",216,238],["H2617","for his mercy",240,253],["H5769","endureth for ever",254,271]]},"7:4":{"text":"Then the king and all the people offered sacrifices before the LORD.","words":[["H4428","Then the king",0,13],["H5971","and all the people",14,32],["H2076","offered",33,40],["H2077","sacrifices",41,51],["H6440","before",52,58],["H3068","the LORD",59,67]]},"7:5":{"text":"And king Solomon offered a sacrifice of twenty and two thousand oxen, and an hundred and twenty thousand sheep: so the king and all the people dedicated the house of God.","words":[["H4428","And king",0,8],["H8010","Solomon",9,16],["H2076","offered",17,24],["H2077","a sacrifice",25,36],["H6242","of twenty",37,46],["H8147","and two",47,54],["H0505","thousand",55,63],["H1241","oxen",64,68],["H3967","and an hundred",70,84],["H6242","and twenty",85,95],["H0505","thousand",96,104],["H6629","sheep",105,110],["H4428","so the king",112,123],["H5971","and all the people",124,142],["H2596","dedicated",143,152],["H1004","the house",153,162],["H0430","of God",163,169]]},"7:6":{"text":"And the priests waited on their offices: the Levites also with instruments of musick of the LORD, which David the king had made to praise the LORD, because his mercy endureth for ever, when David praised by their ministry; and the priests sounded trumpets before them, and all Israel stood.","words":[["H3548","And the priests",0,15],["H5975","waited",16,22],["H4931","on their offices",23,39],["H3881","the Levites",41,52],["H3627","also with instruments",53,74],["H7892","of musick",75,84],["H3068","of the LORD",85,96],["H1732","which David",98,109],["H4428","the king",110,118],["H6213","had made",119,127],["H3034","to praise",128,137],["H3068","the LORD",138,146],["H2617","because his mercy",148,165],["H5769","endureth for ever",166,183],["H1732","when David",185,195],["H1984","praised",196,203],["H3027","by their ministry",204,221],["H3548","and the priests",223,238],["H2690","sounded trumpets",239,255],["H2690","sounded trumpets",239,255],["H3478","before them, and all Israel",256,283],["H5975","stood",284,289]]},"7:7":{"text":"Moreover Solomon hallowed the middle of the court that was before the house of the LORD: for there he offered burnt offerings, and the fat of the peace offerings, because the brasen altar which Solomon had made was not able to receive the burnt offerings, and the meat offerings, and the fat.","words":[["H8010","Moreover Solomon",0,16],["H6942","hallowed",17,25],["H8432","the middle",26,36],["H2691","of the court",37,49],["H6440","that was before",50,65],["H1004","the house",66,75],["H3068","of the LORD",76,87],["H6213","for there he offered",89,109],["H5930","burnt offerings",110,125],["H2459","and the fat",127,138],["H8002","of the peace offerings",139,161],["H5178","because the brasen",163,181],["H4196","altar",182,187],["H8010","which Solomon",188,201],["H6213","had made",202,210],["H3201","was not able",211,223],["H3557","to receive",224,234],["H5930","the burnt offerings",235,254],["H4503","and the meat offerings",256,278],["H2459","and the fat",280,291]]},"7:8":{"text":"Also at the same time Solomon kept the feast seven days, and all Israel with him, a very great congregation, from the entering in of Hamath unto the river of Egypt.","words":[["H6256","Also at the same time",0,21],["H8010","Solomon",22,29],["H6213","kept",30,34],["H2282","the feast",35,44],["H7651","seven",45,50],["H3117","days",51,55],["H3478","and all Israel",57,71],["H3966","with him, a very",72,88],["H1419","great",89,94],["H6951","congregation",95,107],["H0935","from the entering in",109,129],["H2574","of Hamath",130,139],["H5158","unto the river",140,154],["H4714","of Egypt",155,163]]},"7:9":{"text":"And in the eighth day they made a solemn assembly: for they kept the dedication of the altar seven days, and the feast seven days.","words":[["H8066","And in the eighth",0,17],["H3117","day",18,21],["H6213","they made",22,31],["H6116","a solemn assembly",32,49],["H6213","for they kept",51,64],["H2598","the dedication",65,79],["H4196","of the altar",80,92],["H7651","seven",93,98],["H3117","days",99,103],["H2282","and the feast",105,118],["H7651","seven",119,124],["H3117","days",125,129]]},"7:10":{"text":"And on the three and twentieth day of the seventh month he sent the people away into their tents, glad and merry in heart for the goodness that the LORD had shewed unto David, and to Solomon, and to Israel his people.","words":[["H7969","And on the three",0,16],["H6242","and twentieth",17,30],["H3117","day",31,34],["H7637","of the seventh",35,49],["H2320","month",50,55],["H7971","he sent",56,63],["H5971","the people",64,74],["H7971","away",75,79],["H0168","into their tents",80,96],["H8056","glad",98,102],["H2896","and merry",103,112],["H3820","in heart",113,121],["H2896","for the goodness",122,138],["H3068","that the LORD",139,152],["H6213","had shewed",153,163],["H1732","unto David",164,174],["H8010","and to Solomon",176,190],["H3478","and to Israel",192,205],["H5971","his people",206,216]]},"7:11":{"text":"Thus Solomon finished the house of the LORD, and the king's house: and all that came into Solomon's heart to make in the house of the LORD, and in his own house, he prosperously effected.","words":[["H8010","Thus Solomon",0,12],["H3615","finished",13,21],["H1004","the house",22,31],["H3068","of the LORD",32,43],["H4428","and the king's",45,59],["H1004","house",60,65],["H0935","and all that came",67,84],["H8010","into Solomon's",85,99],["H3820","heart",100,105],["H6213","to make",106,113],["H1004","in the house",114,126],["H3068","of the LORD",127,138],["H1004","and in his own house",140,160],["H6743","he prosperously effected",162,186]]},"7:12":{"text":"And the LORD appeared to Solomon by night, and said unto him, I have heard thy prayer, and have chosen this place to myself for an house of sacrifice.","words":[["H3068","And the LORD",0,12],["H7200","appeared",13,21],["H8010","to Solomon",22,32],["H3915","by night",33,41],["H0559","and said",43,51],["H8085","unto him, I have heard",52,74],["H8605","thy prayer",75,85],["H0977","and have chosen",87,102],["H4725","this place",103,113],["H1004","to myself for an house",114,136],["H2077","of sacrifice",137,149]]},"7:13":{"text":"If I shut up heaven that there be no rain, or if I command the locusts to devour the land, or if I send pestilence among my people;","words":[["H2005","If",0,2],["H6113","I shut up",3,12],["H8064","heaven",13,19],["H4306","that there be no rain",20,41],["H6680","or if I command",43,58],["H2284","the locusts",59,70],["H0398","to devour",71,80],["H0776","the land",81,89],["H7971","or if I send",91,103],["H1698","pestilence",104,114],["H5971","among my people",115,130]]},"7:14":{"text":"If my people, which are called by my name, shall humble themselves, and pray, and seek my face, and turn from their wicked ways; then will I hear from heaven, and will forgive their sin, and will heal their land.","words":[["H5971","If my people",0,12],["H7121","which are called",14,30],["H8034","by my name",31,41],["H3665","shall humble",43,55],["H6419","themselves, and pray",56,76],["H1245","and seek",78,86],["H6440","my face",87,94],["H7725","and turn",96,104],["H7451","from their wicked",105,122],["H1870","ways",123,127],["H8085","then will I hear",129,145],["H8064","from heaven",146,157],["H5545","and will forgive",159,175],["H2403","their sin",176,185],["H7495","and will heal",187,200],["H0776","their land",201,211]]},"7:15":{"text":"Now mine eyes shall be open, and mine ears attent unto the prayer that is made in this place.","words":[["H5869","Now mine eyes",0,13],["H6605","shall be open",14,27],["H0241","and mine ears",29,42],["H7183","attent",43,49],["H8605","unto the prayer",50,65],["H4725","that is made in this place",66,92]]},"7:16":{"text":"For now have I chosen and sanctified this house, that my name may be there for ever: and mine eyes and mine heart shall be there perpetually.","words":[["H0977","For now have I chosen",0,21],["H6942","and sanctified",22,36],["H1004","this house",37,47],["H8034","that my name",49,61],["H5704","may be there for",62,78],["H5769","ever",79,83],["H5869","and mine eyes",85,98],["H3820","and mine heart",99,113],["H3117","shall be there perpetually",114,140]]},"7:17":{"text":"And as for thee, if thou wilt walk before me, as David thy father walked, and do according to all that I have commanded thee, and shalt observe my statutes and my judgments;","words":[["H3212","And as for thee, if thou wilt walk",0,34],["H6440","before",35,41],["H1732","me, as David",42,54],["H0001","thy father",55,65],["H1980","walked",66,72],["H6213","and do",74,80],["H6680","according to all that I have commanded",81,119],["H8104","thee, and shalt observe",120,143],["H2706","my statutes",144,155],["H4941","and my judgments",156,172]]},"7:18":{"text":"Then will I stablish the throne of thy kingdom, according as I have covenanted with David thy father, saying, There shall not fail thee a man to be ruler in Israel.","words":[["H6965","Then will I stablish",0,20],["H3678","the throne",21,31],["H4438","of thy kingdom",32,46],["H3772","according as I have covenanted",48,78],["H1732","with David",79,89],["H0001","thy father",90,100],["H0559","saying",102,108],["H3772","There shall not fail",110,130],["H0376","thee a man",131,141],["H4910","to be ruler",142,153],["H3478","in Israel",154,163]]},"7:19":{"text":"But if ye turn away, and forsake my statutes and my commandments, which I have set before you, and shall go and serve other gods, and worship them;","words":[["H7725","But if ye turn away",0,19],["H5800","and forsake",21,32],["H2708","my statutes",33,44],["H4687","and my commandments",45,64],["H5414","which I have set",66,82],["H6440","before",83,89],["H1980","you, and shall go",90,107],["H5647","and serve",108,117],["H0312","other",118,123],["H0430","gods",124,128],["H7812","and worship",130,141]]},"7:20":{"text":"Then will I pluck them up by the roots out of my land which I have given them; and this house, which I have sanctified for my name, will I cast out of my sight, and will make it to be a proverb and a byword among all nations.","words":[["H5428","Then will I pluck them up by the roots",0,38],["H0127","out of my land",39,53],["H5414","which I have given",54,72],["H1004","them; and this house",73,93],["H6942","which I have sanctified",95,118],["H8034","for my name",119,130],["H7993","will I cast out",132,147],["H6440","of my sight",148,159],["H5414","and will make",161,174],["H4912","it to be a proverb",175,193],["H8148","and a byword",194,206],["H5971","among all nations",207,224]]},"7:21":{"text":"And this house, which is high, shall be an astonishment to every one that passeth by it; so that he shall say, Why hath the LORD done thus unto this land, and unto this house?","words":[["H1004","And this house",0,14],["H5945","which is high",16,29],["H8074","shall be an astonishment",31,55],["H5674","to every one that passeth",56,81],["H0559","by it; so that he shall say",82,109],["H3068","Why hath the LORD",111,128],["H6213","done",129,133],["H0776","thus unto this land",134,153],["H1004","and unto this house",155,174]]},"7:22":{"text":"And it shall be answered, Because they forsook the LORD God of their fathers, which brought them forth out of the land of Egypt, and laid hold on other gods, and worshipped them, and served them: therefore hath he brought all this evil upon them.","words":[["H0559","And it shall be answered",0,24],["H5800","Because they forsook",26,46],["H3068","the LORD",47,55],["H0430","God",56,59],["H0001","of their fathers",60,76],["H3318","which brought them forth",78,102],["H0776","out of the land",103,118],["H4714","of Egypt",119,127],["H2388","and laid hold",129,142],["H0312","on other",143,151],["H0430","gods",152,156],["H7812","and worshipped",158,172],["H5647","them, and served",173,189],["H0935","them: therefore hath he brought",190,221],["H7451","all this evil",222,235]]},"8:1":{"text":"And it came to pass at the end of twenty years, wherein Solomon had built the house of the LORD, and his own house,","words":[["H7093","And it came to pass at the end",0,30],["H6242","of twenty",31,40],["H8141","years",41,46],["H8010","wherein Solomon",48,63],["H1129","had built",64,73],["H1004","the house",74,83],["H3068","of the LORD",84,95],["H1004","and his own house",97,114]]},"8:2":{"text":"That the cities which Huram had restored to Solomon, Solomon built them, and caused the children of Israel to dwell there.","words":[["H5892","That the cities",0,15],["H2361","which Huram",16,27],["H5414","had restored",28,40],["H8010","to Solomon",41,51],["H8010","Solomon",53,60],["H1129","built",61,66],["H1121","them, and caused the children",67,96],["H3478","of Israel",97,106],["H3427","to dwell",107,115]]},"8:3":{"text":"And Solomon went to Hamathzobah, and prevailed against it.","words":[["H8010","And Solomon",0,11],["H3212","went",12,16],["H2578","to Hamathzobah",17,31],["H2388","and prevailed",33,46]]},"8:4":{"text":"And he built Tadmor in the wilderness, and all the store cities, which he built in Hamath.","words":[["H1129","And he built",0,12],["H8412","Tadmor",13,19],["H4057","in the wilderness",20,37],["H4543","and all the store",39,56],["H5892","cities",57,63],["H1129","which he built",65,79],["H2574","in Hamath",80,89]]},"8:5":{"text":"Also he built Bethhoron the upper, and Bethhoron the nether, fenced cities, with walls, gates, and bars;","words":[["H1129","Also he built",0,13],["H1032","Bethhoron",14,23],["H5945","the upper",24,33],["H1032","and Bethhoron",35,48],["H8481","the nether",49,59],["H4692","fenced",61,67],["H5892","cities",68,74],["H2346","with walls",76,86],["H1817","gates",88,93],["H1280","and bars",95,103]]},"8:6":{"text":"And Baalath, and all the store cities that Solomon had, and all the chariot cities, and the cities of the horsemen, and all that Solomon desired to build in Jerusalem, and in Lebanon, and throughout all the land of his dominion.","words":[["H1191","And Baalath",0,11],["H4543","and all the store",13,30],["H5892","cities",31,37],["H8010","that Solomon",38,50],["H7393","had, and all the chariot",51,75],["H5892","cities",76,82],["H5892","and the cities",84,98],["H6571","of the horsemen",99,114],["H8010","and all that Solomon",116,136],["H2836","desired",137,144],["H2837","desired",137,144],["H1129","to build",145,153],["H3389","in Jerusalem",154,166],["H3844","and in Lebanon",168,182],["H0776","and throughout all the land",184,211],["H4475","of his dominion",212,227]]},"8:7":{"text":"As for all the people that were left of the Hittites, and the Amorites, and the Perizzites, and the Hivites, and the Jebusites, which were not of Israel,","words":[["H5971","As for all the people",0,21],["H3498","that were left",22,36],["H2850","of the Hittites",37,52],["H0567","and the Amorites",54,70],["H6522","and the Perizzites",72,90],["H2340","and the Hivites",92,107],["H2983","and the Jebusites",109,126],["H3478","which were not of Israel",128,152]]},"8:8":{"text":"But of their children, who were left after them in the land, whom the children of Israel consumed not, them did Solomon make to pay tribute until this day.","words":[["H1121","But of their children",0,21],["H3498","who were left",23,36],["H0310","after",37,42],["H0776","them in the land",43,59],["H1121","whom the children",61,78],["H3478","of Israel",79,88],["H3615","consumed",89,97],["H8010","not, them did Solomon",98,119],["H5927","make to pay",120,131],["H4522","tribute",132,139],["H3117","until this day",140,154]]},"8:9":{"text":"But of the children of Israel did Solomon make no servants for his work; but they were men of war, and chief of his captains, and captains of his chariots and horsemen.","words":[["H1121","But of the children",0,19],["H3478","of Israel",20,29],["H8010","did Solomon",30,41],["H5414","make",42,46],["H5650","no servants",47,58],["H4399","for his work",59,71],["H0582","but they were men",73,90],["H4421","of war",91,97],["H8269","and chief",99,108],["H7991","of his captains",109,124],["H8269","and captains",126,138],["H7393","of his chariots",139,154],["H6571","and horsemen",155,167]]},"8:10":{"text":"And these were the chief of king Solomon's officers, even two hundred and fifty, that bare rule over the people.","words":[["H8269","And these were the chief",0,24],["H4428","of king",25,32],["H8010","Solomon's",33,42],["H5324","officers",43,51],["H5333","officers",43,51],["H3967","even two hundred",53,69],["H2572","and fifty",70,79],["H7287","that bare rule",81,95],["H5971","over the people",96,111]]},"8:11":{"text":"And Solomon brought up the daughter of Pharaoh out of the city of David unto the house that he had built for her: for he said, My wife shall not dwell in the house of David king of Israel, because the places are holy, whereunto the ark of the LORD hath come.","words":[["H8010","And Solomon",0,11],["H5927","brought up",12,22],["H1323","the daughter",23,35],["H6547","of Pharaoh",36,46],["H5892","out of the city",47,62],["H1732","of David",63,71],["H1004","unto the house",72,86],["H1129","that he had built",87,104],["H0559","for her: for he said",105,125],["H0802","My wife",127,134],["H3427","shall not dwell",135,150],["H1004","in the house",151,163],["H1732","of David",164,172],["H4428","king",173,177],["H3478","of Israel",178,187],["H6944","because the places are holy",189,216],["H0727","whereunto the ark",218,235],["H3068","of the LORD",236,247],["H0935","hath come",248,257]]},"8:12":{"text":"Then Solomon offered burnt offerings unto the LORD on the altar of the LORD, which he had built before the porch,","words":[["H8010","Then Solomon",0,12],["H5927","offered",13,20],["H5930","burnt offerings",21,36],["H3068","unto the LORD",37,50],["H4196","on the altar",51,63],["H3068","of the LORD",64,75],["H1129","which he had built",77,95],["H6440","before",96,102],["H0197","the porch",103,112]]},"8:13":{"text":"Even after a certain rate every day, offering according to the commandment of Moses, on the sabbaths, and on the new moons, and on the solemn feasts, three times in the year, even in the feast of unleavened bread, and in the feast of weeks, and in the feast of tabernacles.","words":[["H1697","Even after a certain rate",0,25],["H3117","every day",26,35],["H5927","offering",37,45],["H4687","according to the commandment",46,74],["H4872","of Moses",75,83],["H7676","on the sabbaths",85,100],["H2320","and on the new moons",102,122],["H4150","and on the solemn feasts",124,148],["H7969","three",150,155],["H6471","times",156,161],["H8141","in the year",162,173],["H2282","even in the feast",175,192],["H4682","of unleavened bread",193,212],["H2282","and in the feast",214,230],["H7620","of weeks",231,239],["H2282","and in the feast",241,257],["H5521","of tabernacles",258,272]]},"8:14":{"text":"And he appointed, according to the order of David his father, the courses of the priests to their service, and the Levites to their charges, to praise and minister before the priests, as the duty of every day required: the porters also by their courses at every gate: for so had David the man of God commanded.","words":[["H5975","And he appointed",0,16],["H4941","according to the order",18,40],["H1732","of David",41,49],["H0001","his father",50,60],["H4256","the courses",62,73],["H3548","of the priests",74,88],["H5656","to their service",89,105],["H3881","and the Levites",107,122],["H4931","to their charges",123,139],["H1984","to praise",141,150],["H8334","and minister",151,163],["H3548","before the priests",164,182],["H1697","as the duty",184,195],["H3117","of every day",196,208],["H3117","required",209,217],["H7778","the porters",219,230],["H4256","also by their courses",231,252],["H8179","at every gate",253,266],["H1732","for so had David",268,284],["H0376","the man",285,292],["H0430","of God",293,299],["H4687","commanded",300,309]]},"8:15":{"text":"And they departed not from the commandment of the king unto the priests and Levites concerning any matter, or concerning the treasures.","words":[["H5493","And they departed",0,17],["H4687","not from the commandment",18,42],["H4428","of the king",43,54],["H3548","unto the priests",55,71],["H3881","and Levites",72,83],["H1697","concerning any matter",84,105],["H0214","or concerning the treasures",107,134]]},"8:16":{"text":"Now all the work of Solomon was prepared unto the day of the foundation of the house of the LORD, and until it was finished. So the house of the LORD was perfected.","words":[["H4399","Now all the work",0,16],["H8010","of Solomon",17,27],["H3559","was prepared",28,40],["H3117","unto the day",41,53],["H4143","of the foundation",54,71],["H1004","of the house",72,84],["H3068","of the LORD",85,96],["H3615","and until it was finished",98,123],["H1004","So the house",125,137],["H3068","of the LORD",138,149],["H8003","was perfected",150,163]]},"8:17":{"text":"Then went Solomon to Eziongeber, and to Eloth, at the sea side in the land of Edom.","words":[["H1980","Then went",0,9],["H8010","Solomon",10,17],["H6100","to Eziongeber",18,31],["H0359","and to Eloth",33,45],["H3220","at the sea",47,57],["H8193","side",58,62],["H0776","in the land",63,74],["H0123","of Edom",75,82]]},"8:18":{"text":"And Huram sent him by the hands of his servants ships, and servants that had knowledge of the sea; and they went with the servants of Solomon to Ophir, and took thence four hundred and fifty talents of gold, and brought them to king Solomon.","words":[["H2361","And Huram",0,9],["H7971","sent",10,14],["H3027","him by the hands",15,31],["H5650","of his servants",32,47],["H0591","ships",48,53],["H0591","ships",48,53],["H5650","and servants",55,67],["H3045","that had knowledge",68,86],["H3220","of the sea",87,97],["H0935","and they went",99,112],["H5650","with the servants",113,130],["H8010","of Solomon",131,141],["H0211","to Ophir",142,150],["H3947","and took",152,160],["H0702","thence four",161,172],["H3967","hundred",173,180],["H2572","and fifty",181,190],["H3603","talents",191,198],["H2091","of gold",199,206],["H0935","and brought",208,219],["H4428","them to king",220,232],["H8010","Solomon",233,240]]},"9:1":{"text":"And when the queen of Sheba heard of the fame of Solomon, she came to prove Solomon with hard questions at Jerusalem, with a very great company, and camels that bare spices, and gold in abundance, and precious stones: and when she was come to Solomon, she communed with him of all that was in her heart.","words":[["H4436","And when the queen",0,18],["H7614","of Sheba",19,27],["H8085","heard",28,33],["H8088","of the fame",34,45],["H8010","of Solomon",46,56],["H0935","she came",58,66],["H5254","to prove",67,75],["H8010","Solomon",76,83],["H2420","with hard questions",84,103],["H3389","at Jerusalem",104,116],["H3966","with a very",118,129],["H3515","great",130,135],["H2428","company",136,143],["H1581","and camels",145,155],["H5375","that bare",156,165],["H1314","spices",166,172],["H2091","and gold",174,182],["H7230","in abundance",183,195],["H3368","and precious",197,209],["H0068","stones",210,216],["H0935","and when she was come",218,239],["H8010","to Solomon",240,250],["H1696","she communed",252,264],["H3824","with him of all that was in her heart",265,302]]},"9:2":{"text":"And Solomon told her all her questions: and there was nothing hid from Solomon which he told her not.","words":[["H8010","And Solomon",0,11],["H5046","told",12,16],["H1697","her all her questions",17,38],["H5956","and there was nothing hid",40,65],["H8010","from Solomon",66,78],["H5046","which he told",79,92]]},"9:3":{"text":"And when the queen of Sheba had seen the wisdom of Solomon, and the house that he had built,","words":[["H4436","And when the queen",0,18],["H7614","of Sheba",19,27],["H7200","had seen",28,36],["H2451","the wisdom",37,47],["H8010","of Solomon",48,58],["H1004","and the house",60,73],["H1129","that he had built",74,91]]},"9:4":{"text":"And the meat of his table, and the sitting of his servants, and the attendance of his ministers, and their apparel; his cupbearers also, and their apparel; and his ascent by which he went up into the house of the LORD; there was no more spirit in her.","words":[["H3978","And the meat",0,12],["H7979","of his table",13,25],["H4186","and the sitting",27,42],["H5650","of his servants",43,58],["H4612","and the attendance",60,78],["H8334","of his ministers",79,95],["H4403","and their apparel",97,114],["H8248","his cupbearers",116,130],["H4403","also, and their apparel",131,154],["H5944","and his ascent",156,170],["H5927","by which he went up",171,190],["H1004","into the house",191,205],["H3068","of the LORD",206,217],["H7307","there was no more spirit",219,243]]},"9:5":{"text":"And she said to the king, It was a true report which I heard in mine own land of thine acts, and of thy wisdom:","words":[["H0559","And she said",0,12],["H4428","to the king",13,24],["H0571","It was a true",26,39],["H1697","report",40,46],["H8085","which I heard",47,60],["H0776","in mine own land",61,77],["H1697","of thine acts",78,91],["H2451","and of thy wisdom",93,110]]},"9:6":{"text":"Howbeit I believed not their words, until I came, and mine eyes had seen it: and, behold, the one half of the greatness of thy wisdom was not told me: for thou exceedest the fame that I heard.","words":[["H0539","Howbeit I believed",0,18],["H1697","not their words",19,34],["H0935","until I came",36,48],["H5869","and mine eyes",50,63],["H7200","had seen",64,72],["H2677","it: and, behold, the one half",73,102],["H4768","of the greatness",103,119],["H2451","of thy wisdom",120,133],["H5046","was not told",134,146],["H3254","me: for thou exceedest",147,169],["H8052","the fame",170,178],["H8085","that I heard",179,191]]},"9:7":{"text":"Happy are thy men, and happy are these thy servants, which stand continually before thee, and hear thy wisdom.","words":[["H0835","Happy",0,5],["H0582","are thy men",6,17],["H0835","and happy",19,28],["H5650","are these thy servants",29,51],["H5975","which stand",53,64],["H8548","continually",65,76],["H6440","before",77,83],["H8085","thee, and hear",84,98],["H2451","thy wisdom",99,109]]},"9:8":{"text":"Blessed be the LORD thy God, which delighted in thee to set thee on his throne, to be king for the LORD thy God: because thy God loved Israel, to establish them for ever, therefore made he thee king over them, to do judgment and justice.","words":[["H1288","Blessed",0,7],["H3068","be the LORD",8,19],["H0430","thy God",20,27],["H2654","which delighted",29,44],["H5414","in thee to set",45,59],["H3678","thee on his throne",60,78],["H4428","to be king",80,90],["H3068","for the LORD",91,103],["H0430","thy God",104,111],["H0430","because thy God",113,128],["H0160","loved",129,134],["H3478","Israel",135,141],["H5975","to establish",143,155],["H5769","them for ever",156,169],["H5414","therefore made",171,185],["H4428","he thee king",186,198],["H6213","over them, to do",199,215],["H4941","judgment",216,224],["H6666","and justice",225,236]]},"9:9":{"text":"And she gave the king an hundred and twenty talents of gold, and of spices great abundance, and precious stones: neither was there any such spice as the queen of Sheba gave king Solomon.","words":[["H5414","And she gave",0,12],["H4428","the king",13,21],["H3967","an hundred",22,32],["H6242","and twenty",33,43],["H3603","talents",44,51],["H2091","of gold",52,59],["H1314","and of spices",61,74],["H3966","great",75,80],["H7230","abundance",81,90],["H3368","and precious",92,104],["H0068","stones",105,111],["H1314","neither was there any such spice",113,145],["H4436","as the queen",146,158],["H7614","of Sheba",159,167],["H5414","gave",168,172],["H4428","king",173,177],["H8010","Solomon",178,185]]},"9:10":{"text":"And the servants also of Huram, and the servants of Solomon, which brought gold from Ophir, brought algum trees and precious stones.","words":[["H5650","And the servants",0,16],["H2361","also of Huram",17,30],["H5650","and the servants",32,48],["H8010","of Solomon",49,59],["H0935","which brought",61,74],["H2091","gold",75,79],["H0211","from Ophir",80,90],["H0935","brought",92,99],["H0418","algum",100,105],["H6086","trees",106,111],["H3368","and precious",112,124],["H0068","stones",125,131]]},"9:11":{"text":"And the king made of the algum trees terraces to the house of the LORD, and to the king's palace, and harps and psalteries for singers: and there were none such seen before in the land of Judah.","words":[["H4428","And the king",0,12],["H6213","made",13,17],["H0418","of the algum",18,30],["H6086","trees",31,36],["H4546","terraces",37,45],["H1004","to the house",46,58],["H3068","of the LORD",59,70],["H4428","and to the king's",72,89],["H1004","palace",90,96],["H3658","and harps",98,107],["H5035","and psalteries",108,122],["H7891","for singers",123,134],["H1992","and there were none such",136,160],["H7200","seen",161,165],["H6440","before",166,172],["H0776","in the land",173,184],["H3063","of Judah",185,193]]},"9:12":{"text":"And king Solomon gave to the queen of Sheba all her desire, whatsoever she asked, beside that which she had brought unto the king. So she turned, and went away to her own land, she and her servants.","words":[["H4428","And king",0,8],["H8010","Solomon",9,16],["H5414","gave",17,21],["H4436","to the queen",22,34],["H7614","of Sheba",35,43],["H2656","all her desire",44,58],["H7592","whatsoever she asked",60,80],["H0935","beside that which she had brought",82,115],["H4428","unto the king",116,129],["H2015","So she turned",131,144],["H3212","and went away",146,159],["H0776","to her own land",160,175],["H5650","she and her servants",177,197]]},"9:13":{"text":"Now the weight of gold that came to Solomon in one year was six hundred and threescore and six talents of gold;","words":[["H4948","Now the weight",0,14],["H2091","of gold",15,22],["H0935","that came",23,32],["H8010","to Solomon",33,43],["H0259","in one",44,50],["H8141","year",51,55],["H8337","was six",56,63],["H3967","hundred",64,71],["H8346","and threescore",72,86],["H8337","and six",87,94],["H3603","talents",95,102],["H2091","of gold",103,110]]},"9:14":{"text":"Beside that which chapmen and merchants brought. And all the kings of Arabia and governors of the country brought gold and silver to Solomon.","words":[["H0582","Beside that which chapmen",0,25],["H8446","Beside that which chapmen",0,25],["H5503","and merchants",26,39],["H0935","brought",40,47],["H4428","And all the kings",49,66],["H6152","of Arabia",67,76],["H6346","and governors",77,90],["H0776","of the country",91,105],["H0935","brought",106,113],["H2091","gold",114,118],["H3701","and silver",119,129],["H8010","to Solomon",130,140]]},"9:15":{"text":"And king Solomon made two hundred targets of beaten gold: six hundred shekels of beaten gold went to one target.","words":[["H4428","And king",0,8],["H8010","Solomon",9,16],["H6213","made",17,21],["H3967","two hundred",22,33],["H6793","targets",34,41],["H7820","of beaten",42,51],["H2091","gold",52,56],["H8337","six",58,61],["H3967","hundred",62,69],["H7820","shekels of beaten",70,87],["H2091","gold",88,92],["H5927","went",93,97],["H0259","to one",98,104],["H6793","target",105,111]]},"9:16":{"text":"And three hundred shields made he of beaten gold: three hundred shekels of gold went to one shield. And the king put them in the house of the forest of Lebanon.","words":[["H7969","And three",0,9],["H3967","hundred",10,17],["H4043","shields",18,25],["H7820","made he of beaten",26,43],["H2091","gold",44,48],["H7969","three",50,55],["H3967","hundred",56,63],["H2091","shekels of gold",64,79],["H5927","went",80,84],["H0259","to one",85,91],["H4043","shield",92,98],["H4428","And the king",100,112],["H5414","put",113,116],["H1004","them in the house",117,134],["H3293","of the forest",135,148],["H3844","of Lebanon",149,159]]},"9:17":{"text":"Moreover the king made a great throne of ivory, and overlaid it with pure gold.","words":[["H4428","Moreover the king",0,17],["H6213","made",18,22],["H1419","a great",23,30],["H3678","throne",31,37],["H8127","of ivory",38,46],["H6823","and overlaid",48,60],["H2889","it with pure",61,73],["H2091","gold",74,78]]},"9:18":{"text":"And there were six steps to the throne, with a footstool of gold, which were fastened to the throne, and stays on each side of the sitting place, and two lions standing by the stays:","words":[["H8337","And there were six",0,18],["H4609","steps",19,24],["H3678","to the throne",25,38],["H3534","with a footstool",40,56],["H2091","of gold",57,64],["H0270","which were fastened",66,85],["H3678","to the throne",86,99],["H3027","and stays",101,110],["H3427","on each side of the sitting",111,138],["H4725","place",139,144],["H8147","and two",146,153],["H0738","lions",154,159],["H5975","standing",160,168],["H0681","by",169,171],["H3027","the stays",172,181]]},"9:19":{"text":"And twelve lions stood there on the one side and on the other upon the six steps. There was not the like made in any kingdom.","words":[["H8147","And twelve",0,10],["H6240","And twelve",0,10],["H0738","lions",11,16],["H5975","stood",17,22],["H8337","there on the one side and on the other upon the six",23,74],["H4609","steps",75,80],["H6213","There was not the like made",82,109],["H4467","in any kingdom",110,124]]},"9:20":{"text":"And all the drinking vessels of king Solomon were of gold, and all the vessels of the house of the forest of Lebanon were of pure gold: none were of silver; it was not any thing accounted of in the days of Solomon.","words":[["H4945","And all the drinking",0,20],["H3627","vessels",21,28],["H4428","of king",29,36],["H8010","Solomon",37,44],["H2091","were of gold",45,57],["H3627","and all the vessels",59,78],["H1004","of the house",79,91],["H3293","of the forest",92,105],["H3844","of Lebanon",106,116],["H5462","were of pure",117,129],["H2091","gold",130,134],["H3701","none were of silver",136,155],["H3972","it was not any",157,171],["H2803","thing accounted",172,187],["H3117","of in the days",188,202],["H8010","of Solomon",203,213]]},"9:21":{"text":"For the king's ships went to Tarshish with the servants of Huram: every three years once came the ships of Tarshish bringing gold, and silver, ivory, and apes, and peacocks.","words":[["H4428","For the king's",0,14],["H0591","ships",15,20],["H1980","went",21,25],["H8659","to Tarshish",26,37],["H5650","with the servants",38,55],["H2361","of Huram",56,64],["H7969","every three",66,77],["H8141","years",78,83],["H0259","once",84,88],["H0935","came",89,93],["H0591","the ships",94,103],["H8659","of Tarshish",104,115],["H5375","bringing",116,124],["H2091","gold",125,129],["H3701","and silver",131,141],["H8143","ivory",143,148],["H6971","and apes",150,158],["H8500","and peacocks",160,172]]},"9:22":{"text":"And king Solomon passed all the kings of the earth in riches and wisdom.","words":[["H4428","And king",0,8],["H8010","Solomon",9,16],["H1431","passed",17,23],["H4428","all the kings",24,37],["H0776","of the earth",38,50],["H6239","in riches",51,60],["H2451","and wisdom",61,71]]},"9:23":{"text":"And all the kings of the earth sought the presence of Solomon, to hear his wisdom, that God had put in his heart.","words":[["H4428","And all the kings",0,17],["H0776","of the earth",18,30],["H1245","sought",31,37],["H6440","the presence",38,50],["H8010","of Solomon",51,61],["H8085","to hear",63,70],["H2451","his wisdom",71,81],["H0430","that God",83,91],["H5414","had put",92,99],["H3820","in his heart",100,112]]},"9:24":{"text":"And they brought every man his present, vessels of silver, and vessels of gold, and raiment, harness, and spices, horses, and mules, a rate year by year.","words":[["H0935","And they brought",0,16],["H0376","every man",17,26],["H4503","his present",27,38],["H3627","vessels",40,47],["H3701","of silver",48,57],["H3627","and vessels",59,70],["H2091","of gold",71,78],["H8008","and raiment",80,91],["H5402","harness",93,100],["H1314","and spices",102,112],["H5483","horses",114,120],["H6505","and mules",122,131],["H1697","a rate",133,139],["H8141","year",140,144],["H8141","by year",145,152]]},"9:25":{"text":"And Solomon had four thousand stalls for horses and chariots, and twelve thousand horsemen; whom he bestowed in the chariot cities, and with the king at Jerusalem.","words":[["H8010","And Solomon",0,11],["H0702","had four",12,20],["H0505","thousand",21,29],["H0723","stalls",30,36],["H5483","for horses",37,47],["H4818","and chariots",48,60],["H8147","and twelve",62,72],["H6240","and twelve",62,72],["H0505","thousand",73,81],["H6571","horsemen",82,90],["H3240","whom he bestowed",92,108],["H7393","in the chariot",109,123],["H5892","cities",124,130],["H4428","and with the king",132,149],["H3389","at Jerusalem",150,162]]},"9:26":{"text":"And he reigned over all the kings from the river even unto the land of the Philistines, and to the border of Egypt.","words":[["H4910","And he reigned",0,14],["H4428","over all the kings",15,33],["H5104","from the river",34,48],["H0776","even unto the land",49,67],["H6430","of the Philistines",68,86],["H1366","and to the border",88,105],["H4714","of Egypt",106,114]]},"9:27":{"text":"And the king made silver in Jerusalem as stones, and cedar trees made he as the sycomore trees that are in the low plains in abundance.","words":[["H4428","And the king",0,12],["H5414","made",13,17],["H3701","silver",18,24],["H3389","in Jerusalem",25,37],["H0068","as stones",38,47],["H0730","and cedar trees",49,64],["H5414","made",65,69],["H8256","he as the sycomore trees",70,94],["H8219","that are in the low plains",95,121],["H7230","in abundance",122,134]]},"9:28":{"text":"And they brought unto Solomon horses out of Egypt, and out of all lands.","words":[["H3318","And they brought",0,16],["H8010","unto Solomon",17,29],["H5483","horses",30,36],["H4714","out of Egypt",37,49],["H0776","and out of all lands",51,71]]},"9:29":{"text":"Now the rest of the acts of Solomon, first and last, are they not written in the book of Nathan the prophet, and in the prophecy of Ahijah the Shilonite, and in the visions of Iddo the seer against Jeroboam the son of Nebat?","words":[["H7605","Now the rest",0,12],["H1697","of the acts",13,24],["H8010","of Solomon",25,35],["H7223","first",37,42],["H0314","and last",43,51],["H3789","are they not written",53,73],["H1697","in the book",74,85],["H5416","of Nathan",86,95],["H5030","the prophet",96,107],["H5016","and in the prophecy",109,128],["H0281","of Ahijah",129,138],["H7888","the Shilonite",139,152],["H2378","and in the visions",154,172],["H3260","of Iddo",173,180],["H2374","the seer",181,189],["H3379","against Jeroboam",190,206],["H1121","the son",207,214],["H5028","of Nebat",215,223]]},"9:30":{"text":"And Solomon reigned in Jerusalem over all Israel forty years.","words":[["H8010","And Solomon",0,11],["H4427","reigned",12,19],["H3389","in Jerusalem",20,32],["H3478","over all Israel",33,48],["H0705","forty",49,54],["H8141","years",55,60]]},"9:31":{"text":"And Solomon slept with his fathers, and he was buried in the city of David his father: and Rehoboam his son reigned in his stead.","words":[["H8010","And Solomon",0,11],["H7901","slept",12,17],["H0001","with his fathers",18,34],["H6912","and he was buried",36,53],["H5892","in the city",54,65],["H1732","of David",66,74],["H0001","his father",75,85],["H7346","and Rehoboam",87,99],["H1121","his son",100,107],["H4427","reigned",108,115]]},"10:1":{"text":"And Rehoboam went to Shechem: for to Shechem were all Israel come to make him king.","words":[["H7346","And Rehoboam",0,12],["H3212","went",13,17],["H7927","to Shechem",18,28],["H7927","for to Shechem",30,44],["H3478","were all Israel",45,60],["H0935","come",61,65],["H4427","to make him king",66,82]]},"10:2":{"text":"And it came to pass, when Jeroboam the son of Nebat, who was in Egypt, whither he had fled from the presence of Solomon the king, heard it, that Jeroboam returned out of Egypt.","words":[["H3379","And it came to pass, when Jeroboam",0,34],["H1121","the son",35,42],["H5028","of Nebat",43,51],["H4714","who was in Egypt",53,69],["H1272","whither he had fled",71,90],["H6440","from the presence",91,108],["H8010","of Solomon",109,119],["H4428","the king",120,128],["H8085","heard",130,135],["H3379","it, that Jeroboam",136,153],["H7725","returned",154,162],["H4714","out of Egypt",163,175]]},"10:3":{"text":"And they sent and called him. So Jeroboam and all Israel came and spake to Rehoboam, saying,","words":[["H7971","And they sent",0,13],["H7121","and called",14,24],["H3379","him. So Jeroboam",25,41],["H3478","and all Israel",42,56],["H0935","came",57,61],["H1696","and spake",62,71],["H7346","to Rehoboam",72,83],["H0559","saying",85,91]]},"10:4":{"text":"Thy father made our yoke grievous: now therefore ease thou somewhat the grievous servitude of thy father, and his heavy yoke that he put upon us, and we will serve thee.","words":[["H0001","Thy father",0,10],["H5923","made our yoke",11,24],["H7185","grievous",25,33],["H7043","now therefore ease",35,53],["H7186","thou somewhat the grievous",54,80],["H5656","servitude",81,90],["H0001","of thy father",91,104],["H3515","and his heavy",106,119],["H5923","yoke",120,124],["H5414","that he put",125,136],["H5647","upon us, and we will serve",137,163]]},"10:5":{"text":"And he said unto them, Come again unto me after three days. And the people departed.","words":[["H0559","And he said",0,11],["H7725","unto them, Come again",12,33],["H7969","unto me after three",34,53],["H3117","days",54,58],["H5971","And the people",60,74],["H3212","departed",75,83]]},"10:6":{"text":"And king Rehoboam took counsel with the old men that had stood before Solomon his father while he yet lived, saying, What counsel give ye me to return answer to this people?","words":[["H4428","And king",0,8],["H7346","Rehoboam",9,17],["H3289","took counsel",18,30],["H2205","with the old",31,43],["H5975","men that had stood",44,62],["H6440","before",63,69],["H8010","Solomon",70,77],["H0001","his father",78,88],["H2416","while he yet lived",89,107],["H0559","saying",109,115],["H0349","What",117,121],["H3289","counsel give",122,134],["H7725","ye me to return",135,150],["H1697","answer",151,157],["H5971","to this people",158,172]]},"10:7":{"text":"And they spake unto him, saying, If thou be kind to this people, and please them, and speak good words to them, they will be thy servants for ever.","words":[["H1696","And they spake",0,14],["H0559","unto him, saying",15,31],["H2896","If thou be kind",33,48],["H5971","to this people",49,63],["H7521","and please",65,75],["H1696","them, and speak",76,91],["H2896","good",92,96],["H1697","words",97,102],["H5650","to them, they will be thy servants",103,137],["H3117","for ever",138,146]]},"10:8":{"text":"But he forsook the counsel which the old men gave him, and took counsel with the young men that were brought up with him, that stood before him.","words":[["H5800","But he forsook",0,14],["H6098","the counsel",15,26],["H2205","which the old men",27,44],["H3289","gave",45,49],["H3289","him, and took counsel",50,71],["H3206","with the young men",72,90],["H1431","that were brought up",91,111],["H5975","with him, that stood",112,132],["H6440","before",133,139]]},"10:9":{"text":"And he said unto them, What advice give ye that we may return answer to this people, which have spoken to me, saying, Ease somewhat the yoke that thy father did put upon us?","words":[["H0559","And he said",0,11],["H3289","unto them, What advice",12,34],["H7725","give ye that we may return",35,61],["H1697","answer",62,68],["H5971","to this people",69,83],["H1696","which have spoken",85,102],["H0559","to me, saying",103,116],["H7043","Ease",118,122],["H5923","somewhat the yoke",123,140],["H0001","that thy father",141,156],["H5414","did put",157,164]]},"10:10":{"text":"And the young men that were brought up with him spake unto him, saying, Thus shalt thou answer the people that spake unto thee, saying, Thy father made our yoke heavy, but make thou it somewhat lighter for us; thus shalt thou say unto them, My little finger shall be thicker than my father's loins.","words":[["H3206","And the young men",0,17],["H1431","that were brought up",18,38],["H1696","with him spake",39,53],["H0559","unto him, saying",54,70],["H0559","Thus shalt thou answer",72,94],["H5971","the people",95,105],["H1696","that spake",106,116],["H0559","unto thee, saying",117,134],["H0001","Thy father",136,146],["H3513","made",147,151],["H5923","our yoke",152,160],["H3513","heavy",161,166],["H7043","but make thou it somewhat lighter",168,201],["H0559","for us; thus shalt thou say",202,229],["H6995","unto them, My little",230,250],["H5666","finger shall be thicker",251,274],["H0001","than my father's",275,291],["H4975","loins",292,297]]},"10:11":{"text":"For whereas my father put a heavy yoke upon you, I will put more to your yoke: my father chastised you with whips, but I will chastise you with scorpions.","words":[["H6258","For whereas",0,11],["H0001","my father",12,21],["H6006","put",22,25],["H3515","a heavy",26,33],["H5923","yoke",34,38],["H3254","upon you, I will put more",39,64],["H5923","to your yoke",65,77],["H0001","my father",79,88],["H3256","chastised",89,98],["H7752","you with whips",99,113],["H6137","but I will chastise you with scorpions",115,153]]},"10:12":{"text":"So Jeroboam and all the people came to Rehoboam on the third day, as the king bade, saying, Come again to me on the third day.","words":[["H3379","So Jeroboam",0,11],["H5971","and all the people",12,30],["H0935","came",31,35],["H7346","to Rehoboam",36,47],["H7992","on the third",48,60],["H3117","day",61,64],["H4428","as the king",66,77],["H1696","bade",78,82],["H0559","saying",84,90],["H7725","Come again",92,102],["H7992","to me on the third",103,121],["H3117","day",122,125]]},"10:13":{"text":"And the king answered them roughly; and king Rehoboam forsook the counsel of the old men,","words":[["H4428","And the king",0,12],["H6030","answered",13,21],["H7186","them roughly",22,34],["H4428","and king",36,44],["H7346","Rehoboam",45,53],["H5800","forsook",54,61],["H6098","the counsel",62,73],["H2205","of the old men",74,88]]},"10:14":{"text":"And answered them after the advice of the young men, saying, My father made your yoke heavy, but I will add thereto: my father chastised you with whips, but I will chastise you with scorpions.","words":[["H1696","And answered",0,12],["H6098","them after the advice",13,34],["H3206","of the young men",35,51],["H0559","saying",53,59],["H0001","My father",61,70],["H5923","made your yoke",71,85],["H3513","heavy",86,91],["H3254","but I will add",93,107],["H0001","thereto: my father",108,126],["H3256","chastised",127,136],["H7752","you with whips",137,151],["H6137","but I will chastise you with scorpions",153,191]]},"10:15":{"text":"So the king hearkened not unto the people: for the cause was of God, that the LORD might perform his word, which he spake by the hand of Ahijah the Shilonite to Jeroboam the son of Nebat.","words":[["H4428","So the king",0,11],["H8085","hearkened",12,21],["H5971","not unto the people",22,41],["H5252","for the cause",43,56],["H0430","was of God",57,67],["H3068","that the LORD",69,82],["H6965","might perform",83,96],["H1697","his word",97,105],["H1696","which he spake",107,121],["H3027","by the hand",122,133],["H0281","of Ahijah",134,143],["H7888","the Shilonite",144,157],["H3379","to Jeroboam",158,169],["H1121","the son",170,177],["H5028","of Nebat",178,186]]},"10:16":{"text":"And when all Israel saw that the king would not hearken unto them, the people answered the king, saying, What portion have we in David? and we have none inheritance in the son of Jesse: every man to your tents, O Israel: and now, David, see to thine own house. So all Israel went to their tents.","words":[["H3478","And when all Israel",0,19],["H7200","saw",20,23],["H4428","that the king",24,37],["H8085","would not hearken",38,55],["H5971","unto them, the people",56,77],["H7725","answered",78,86],["H4428","the king",87,95],["H0559","saying",97,103],["H2506","What portion",105,117],["H1732","have we in David",118,134],["H5159","and we have none inheritance",136,164],["H1121","in the son",165,175],["H3448","of Jesse",176,184],["H0376","every man",186,195],["H0168","to your tents",196,209],["H3478","O Israel",211,219],["H1732","and now, David",221,235],["H7200","see",237,240],["H1004","to thine own house",241,259],["H3478","So all Israel",261,274],["H3212","went",275,279],["H0168","to their tents",280,294]]},"10:17":{"text":"But as for the children of Israel that dwelt in the cities of Judah, Rehoboam reigned over them.","words":[["H1121","But as for the children",0,23],["H3478","of Israel",24,33],["H3427","that dwelt",34,44],["H5892","in the cities",45,58],["H3063","of Judah",59,67],["H7346","Rehoboam",69,77],["H4427","reigned",78,85]]},"10:18":{"text":"Then king Rehoboam sent Hadoram that was over the tribute; and the children of Israel stoned him with stones, that he died. But king Rehoboam made speed to get him up to his chariot, to flee to Jerusalem.","words":[["H4428","Then king",0,9],["H7346","Rehoboam",10,18],["H7971","sent",19,23],["H1913","Hadoram",24,31],["H4522","that was over the tribute",32,57],["H1121","and the children",59,75],["H3478","of Israel",76,85],["H7275","stoned",86,92],["H0068","him with stones",93,108],["H4191","that he died",110,122],["H4428","But king",124,132],["H7346","Rehoboam",133,141],["H0553","made speed",142,152],["H5927","to get him up",153,166],["H4818","to his chariot",167,181],["H5127","to flee",183,190],["H3389","to Jerusalem",191,203]]},"10:19":{"text":"And Israel rebelled against the house of David unto this day.","words":[["H3478","And Israel",0,10],["H6586","rebelled",11,19],["H1004","against the house",20,37],["H1732","of David",38,46],["H3117","unto this day",47,60]]},"11:1":{"text":"And when Rehoboam was come to Jerusalem, he gathered of the house of Judah and Benjamin an hundred and fourscore thousand chosen men, which were warriors, to fight against Israel, that he might bring the kingdom again to Rehoboam.","words":[["H7346","And when Rehoboam",0,17],["H0935","was come",18,26],["H3389","to Jerusalem",27,39],["H6950","he gathered",41,52],["H1004","of the house",53,65],["H3063","of Judah",66,74],["H1144","and Benjamin",75,87],["H3967","an hundred",88,98],["H8084","and fourscore",99,112],["H0505","thousand",113,121],["H0977","chosen",122,128],["H6213","men, which were warriors",129,153],["H4421","men, which were warriors",129,153],["H3898","to fight",155,163],["H3478","against Israel",164,178],["H7725","that he might bring",180,199],["H4467","the kingdom",200,211],["H7725","again",212,217],["H7346","to Rehoboam",218,229]]},"11:2":{"text":"But the word of the LORD came to Shemaiah the man of God, saying,","words":[["H1697","But the word",0,12],["H3068","of the LORD",13,24],["H8098","came to Shemaiah",25,41],["H0376","the man",42,49],["H0430","of God",50,56],["H0559","saying",58,64]]},"11:3":{"text":"Speak unto Rehoboam the son of Solomon, king of Judah, and to all Israel in Judah and Benjamin, saying,","words":[["H0559","Speak",0,5],["H7346","unto Rehoboam",6,19],["H1121","the son",20,27],["H8010","of Solomon",28,38],["H4428","king",40,44],["H3063","of Judah",45,53],["H3478","and to all Israel",55,72],["H3063","in Judah",73,81],["H1144","and Benjamin",82,94],["H0559","saying",96,102]]},"11:4":{"text":"Thus saith the LORD, Ye shall not go up, nor fight against your brethren: return every man to his house: for this thing is done of me. And they obeyed the words of the LORD, and returned from going against Jeroboam.","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H5927","Ye shall not go up",21,39],["H3898","nor fight",41,50],["H0251","against your brethren",51,72],["H7725","return",74,80],["H0376","every man",81,90],["H1004","to his house",91,103],["H1697","for this thing",105,119],["H1961","is done",120,127],["H8085","of me. And they obeyed",128,150],["H1697","the words",151,160],["H3068","of the LORD",161,172],["H7725","and returned",174,186],["H3212","from going",187,197],["H3379","against Jeroboam",198,214]]},"11:5":{"text":"And Rehoboam dwelt in Jerusalem, and built cities for defence in Judah.","words":[["H7346","And Rehoboam",0,12],["H3427","dwelt",13,18],["H3389","in Jerusalem",19,31],["H1129","and built",33,42],["H5892","cities",43,49],["H4692","for defence",50,61],["H3063","in Judah",62,70]]},"11:6":{"text":"He built even Bethlehem, and Etam, and Tekoa,","words":[["H1129","He built",0,8],["H1035","even Bethlehem",9,23],["H5862","and Etam",25,33],["H8620","and Tekoa",35,44]]},"11:7":{"text":"And Bethzur, and Shoco, and Adullam,","words":[["H1049","And Bethzur",0,11],["H7755","and Shoco",13,22],["H5725","and Adullam",24,35]]},"11:8":{"text":"And Gath, and Mareshah, and Ziph,","words":[["H1661","And Gath",0,8],["H4762","and Mareshah",10,22],["H2128","and Ziph",24,32]]},"11:9":{"text":"And Adoraim, and Lachish, and Azekah,","words":[["H0115","And Adoraim",0,11],["H3923","and Lachish",13,24],["H5825","and Azekah",26,36]]},"11:10":{"text":"And Zorah, and Aijalon, and Hebron, which are in Judah and in Benjamin fenced cities.","words":[["H6881","And Zorah",0,9],["H0357","and Aijalon",11,22],["H2275","and Hebron",24,34],["H3063","which are in Judah",36,54],["H1144","and in Benjamin",55,70],["H4694","fenced",71,77],["H5892","cities",78,84]]},"11:11":{"text":"And he fortified the strong holds, and put captains in them, and store of victual, and of oil and wine.","words":[["H2388","And he fortified",0,16],["H4694","the strong holds",17,33],["H5414","and put",35,42],["H5057","captains",43,51],["H0214","in them, and store",52,70],["H3978","of victual",71,81],["H8081","and of oil",83,93],["H3196","and wine",94,102]]},"11:12":{"text":"And in every several city he put shields and spears, and made them exceeding strong, having Judah and Benjamin on his side.","words":[["H5892","And in every several city",0,25],["H6793","he put shields",26,40],["H7420","and spears",41,51],["H7235","and made them exceeding",53,76],["H3966","and made them exceeding",53,76],["H2388","strong",77,83],["H3063","having Judah",85,97],["H1144","and Benjamin",98,110]]},"11:13":{"text":"And the priests and the Levites that were in all Israel resorted to him out of all their coasts.","words":[["H3548","And the priests",0,15],["H3881","and the Levites",16,31],["H3478","that were in all Israel",32,55],["H3320","resorted",56,64],["H1366","to him out of all their coasts",65,95]]},"11:14":{"text":"For the Levites left their suburbs and their possession, and came to Judah and Jerusalem: for Jeroboam and his sons had cast them off from executing the priest's office unto the LORD:","words":[["H3881","For the Levites",0,15],["H5800","left",16,20],["H4054","their suburbs",21,34],["H0272","and their possession",35,55],["H3212","and came",57,65],["H3063","to Judah",66,74],["H3389","and Jerusalem",75,88],["H3379","for Jeroboam",90,102],["H1121","and his sons",103,115],["H2186","had cast them off",116,133],["H3547","from executing the priest's office",134,168],["H3068","unto the LORD",169,182]]},"11:15":{"text":"And he ordained him priests for the high places, and for the devils, and for the calves which he had made.","words":[["H5975","And he ordained",0,15],["H3548","him priests",16,27],["H1116","for the high places",28,47],["H8163","and for the devils",49,67],["H5695","and for the calves",69,87],["H6213","which he had made",88,105]]},"11:16":{"text":"And after them out of all the tribes of Israel such as set their hearts to seek the LORD God of Israel came to Jerusalem, to sacrifice unto the LORD God of their fathers.","words":[["H0310","And after",0,9],["H7626","them out of all the tribes",10,36],["H3478","of Israel",37,46],["H5414","such as set",47,58],["H3824","their hearts",59,71],["H1245","to seek",72,79],["H3068","the LORD",80,88],["H0430","God",89,92],["H3478","of Israel",93,102],["H0935","came",103,107],["H3389","to Jerusalem",108,120],["H2076","to sacrifice",122,134],["H3068","unto the LORD",135,148],["H0430","God",149,152],["H0001","of their fathers",153,169]]},"11:17":{"text":"So they strengthened the kingdom of Judah, and made Rehoboam the son of Solomon strong, three years: for three years they walked in the way of David and Solomon.","words":[["H2388","So they strengthened",0,20],["H4438","the kingdom",21,32],["H3063","of Judah",33,41],["H7346","and made Rehoboam",43,60],["H1121","the son",61,68],["H8010","of Solomon",69,79],["H0553","strong",80,86],["H7969","three",88,93],["H8141","years",94,99],["H7969","for three",101,110],["H8141","years",111,116],["H1980","they walked",117,128],["H1870","in the way",129,139],["H1732","of David",140,148],["H8010","and Solomon",149,160]]},"11:18":{"text":"And Rehoboam took him Mahalath the daughter of Jerimoth the son of David to wife, and Abihail the daughter of Eliab the son of Jesse;","words":[["H7346","And Rehoboam",0,12],["H3947","took",13,17],["H4258","him Mahalath",18,30],["H1323","the daughter",31,43],["H1121","the daughter",31,43],["H3406","of Jerimoth",44,55],["H1121","the son",56,63],["H1732","of David",64,72],["H0802","to wife",73,80],["H0032","and Abihail",82,93],["H1323","the daughter",94,106],["H0446","of Eliab",107,115],["H1121","the son",116,123],["H3448","of Jesse",124,132]]},"11:19":{"text":"Which bare him children; Jeush, and Shamariah, and Zaham.","words":[["H3205","Which bare",0,10],["H1121","him children",11,23],["H3266","Jeush",25,30],["H8114","and Shamariah",32,45],["H2093","and Zaham",47,56]]},"11:20":{"text":"And after her he took Maachah the daughter of Absalom; which bare him Abijah, and Attai, and Ziza, and Shelomith.","words":[["H0310","And after",0,9],["H3947","her he took",10,21],["H4601","Maachah",22,29],["H1323","the daughter",30,42],["H0053","of Absalom",43,53],["H3205","which bare",55,65],["H0029","him Abijah",66,76],["H6262","and Attai",78,87],["H2124","and Ziza",89,97],["H8019","and Shelomith",99,112]]},"11:21":{"text":"And Rehoboam loved Maachah the daughter of Absalom above all his wives and his concubines: (for he took eighteen wives, and threescore concubines; and begat twenty and eight sons, and threescore daughters.)","words":[["H7346","And Rehoboam",0,12],["H0157","loved",13,18],["H4601","Maachah",19,26],["H1323","the daughter",27,39],["H0053","of Absalom",40,50],["H0802","above all his wives",51,70],["H6370","and his concubines",71,89],["H5375","(for he took",91,103],["H8083","eighteen",104,112],["H6240","eighteen",104,112],["H0802","wives",113,118],["H8346","and threescore",120,134],["H6370","concubines",135,145],["H3205","and begat",147,156],["H6242","twenty",157,163],["H8083","and eight",164,173],["H1121","sons",174,178],["H8346","and threescore",180,194],["H1323","daughters",195,204]]},"11:22":{"text":"And Rehoboam made Abijah the son of Maachah the chief, to be ruler among his brethren: for he thought to make him king.","words":[["H7346","And Rehoboam",0,12],["H5975","made",13,17],["H0029","Abijah",18,24],["H1121","the son",25,32],["H4601","of Maachah",33,43],["H7218","the chief",44,53],["H5057","to be ruler",55,66],["H0251","among his brethren",67,85],["H4427","for he thought to make him king",87,118]]},"11:23":{"text":"And he dealt wisely, and dispersed of all his children throughout all the countries of Judah and Benjamin, unto every fenced city: and he gave them victual in abundance. And he desired many wives.","words":[["H0995","And he dealt wisely",0,19],["H6555","and dispersed",21,34],["H1121","of all his children",35,54],["H0776","throughout all the countries",55,83],["H3063","of Judah",84,92],["H1144","and Benjamin",93,105],["H4694","unto every fenced",107,124],["H5892","city",125,129],["H5414","and he gave",131,142],["H4202","them victual",143,155],["H7230","in abundance",156,168],["H7592","And he desired",170,184],["H1995","many",185,189],["H0802","wives",190,195]]},"12:1":{"text":"And it came to pass, when Rehoboam had established the kingdom, and had strengthened himself, he forsook the law of the LORD, and all Israel with him.","words":[["H7346","And it came to pass, when Rehoboam",0,34],["H3559","had established",35,50],["H4438","the kingdom",51,62],["H2393","and had strengthened",64,84],["H5800","himself, he forsook",85,104],["H8451","the law",105,112],["H3068","of the LORD",113,124],["H3478","and all Israel",126,140]]},"12:2":{"text":"And it came to pass, that in the fifth year of king Rehoboam Shishak king of Egypt came up against Jerusalem, because they had transgressed against the LORD,","words":[["H2549","And it came to pass, that in the fifth",0,38],["H8141","year",39,43],["H4428","of king",44,51],["H7346","Rehoboam",52,60],["H7895","Shishak",61,68],["H4428","king",69,73],["H4714","of Egypt",74,82],["H5927","came up",83,90],["H3389","against Jerusalem",91,108],["H4603","because they had transgressed",110,139],["H3068","against the LORD",140,156]]},"12:3":{"text":"With twelve hundred chariots, and threescore thousand horsemen: and the people were without number that came with him out of Egypt; the Lubims, the Sukkiims, and the Ethiopians.","words":[["H3967","With twelve hundred",0,19],["H0505","With twelve hundred",0,19],["H7393","chariots",20,28],["H8346","and threescore",30,44],["H0505","thousand",45,53],["H6571","horsemen",54,62],["H5971","and the people",64,78],["H4557","were without number",79,98],["H0935","that came",99,108],["H4714","with him out of Egypt",109,130],["H3864","the Lubims",132,142],["H5525","the Sukkiims",144,156],["H3569","and the Ethiopians",158,176]]},"12:4":{"text":"And he took the fenced cities which pertained to Judah, and came to Jerusalem.","words":[["H3920","And he took",0,11],["H4694","the fenced",12,22],["H5892","cities",23,29],["H3063","which pertained to Judah",30,54],["H0935","and came",56,64],["H3389","to Jerusalem",65,77]]},"12:5":{"text":"Then came Shemaiah the prophet to Rehoboam, and to the princes of Judah, that were gathered together to Jerusalem because of Shishak, and said unto them, Thus saith the LORD, Ye have forsaken me, and therefore have I also left you in the hand of Shishak.","words":[["H0935","Then came",0,9],["H8098","Shemaiah",10,18],["H5030","the prophet",19,30],["H7346","to Rehoboam",31,42],["H8269","and to the princes",44,62],["H3063","of Judah",63,71],["H0622","that were gathered together",73,100],["H3389","to Jerusalem",101,113],["H6440","because",114,121],["H7895","of Shishak",122,132],["H0559","and said",134,142],["H0559","unto them, Thus saith",143,164],["H3068","the LORD",165,173],["H5800","Ye have forsaken",175,191],["H0637","me, and therefore have I also",192,221],["H5800","left",222,226],["H3027","you in the hand",227,242],["H7895","of Shishak",243,253]]},"12:6":{"text":"Whereupon the princes of Israel and the king humbled themselves; and they said, The LORD is righteous.","words":[["H8269","Whereupon the princes",0,21],["H3478","of Israel",22,31],["H4428","and the king",32,44],["H3665","humbled",45,52],["H0559","themselves; and they said",53,78],["H3068","The LORD",80,88],["H6662","is righteous",89,101]]},"12:7":{"text":"And when the LORD saw that they humbled themselves, the word of the LORD came to Shemaiah, saying, They have humbled themselves; therefore I will not destroy them, but I will grant them some deliverance; and my wrath shall not be poured out upon Jerusalem by the hand of Shishak.","words":[["H3068","And when the LORD",0,17],["H7200","saw",18,21],["H3665","that they humbled",22,39],["H1697","themselves, the word",40,60],["H3068","of the LORD",61,72],["H8098","came to Shemaiah",73,89],["H0559","saying",91,97],["H3665","They have humbled",99,116],["H7843","themselves; therefore I will not destroy",117,157],["H5414","them, but I will grant",158,180],["H4592","them some",181,190],["H6413","deliverance",191,202],["H2534","and my wrath",204,216],["H5413","shall not be poured out",217,240],["H3389","upon Jerusalem",241,255],["H3027","by the hand",256,267],["H7895","of Shishak",268,278]]},"12:8":{"text":"Nevertheless they shall be his servants; that they may know my service, and the service of the kingdoms of the countries.","words":[["H5650","Nevertheless they shall be his servants",0,39],["H3045","that they may know",41,59],["H5656","my service",60,70],["H5656","and the service",72,87],["H4467","of the kingdoms",88,103],["H0776","of the countries",104,120]]},"12:9":{"text":"So Shishak king of Egypt came up against Jerusalem, and took away the treasures of the house of the LORD, and the treasures of the king's house; he took all: he carried away also the shields of gold which Solomon had made.","words":[["H7895","So Shishak",0,10],["H4428","king",11,15],["H4714","of Egypt",16,24],["H5927","came up",25,32],["H3389","against Jerusalem",33,50],["H3947","and took away",52,65],["H0214","the treasures",66,79],["H1004","of the house",80,92],["H3068","of the LORD",93,104],["H0214","and the treasures",106,123],["H4428","of the king's",124,137],["H1004","house",138,143],["H3947","he took",145,152],["H3947","all: he carried away",153,173],["H4043","also the shields",174,190],["H2091","of gold",191,198],["H8010","which Solomon",199,212],["H6213","had made",213,221]]},"12:10":{"text":"Instead of which king Rehoboam made shields of brass, and committed them to the hands of the chief of the guard, that kept the entrance of the king's house.","words":[["H4428","Instead of which king",0,21],["H7346","Rehoboam",22,30],["H6213","made",31,35],["H4043","shields",36,43],["H5178","of brass",44,52],["H6485","and committed",54,67],["H3027","them to the hands",68,85],["H8269","of the chief",86,98],["H7323","of the guard",99,111],["H8104","that kept",113,122],["H6607","the entrance",123,135],["H4428","of the king's",136,149],["H1004","house",150,155]]},"12:11":{"text":"And when the king entered into the house of the LORD, the guard came and fetched them, and brought them again into the guard chamber.","words":[["H1767","And when",0,8],["H4428","the king",9,17],["H0935","entered",18,25],["H1004","into the house",26,40],["H3068","of the LORD",41,52],["H7323","the guard",54,63],["H0935","came",64,68],["H5375","and fetched",69,80],["H7725","them, and brought them again",81,109],["H7323","into the guard",110,124],["H8372","chamber",125,132]]},"12:12":{"text":"And when he humbled himself, the wrath of the LORD turned from him, that he would not destroy him altogether: and also in Judah things went well.","words":[["H3665","And when he humbled",0,19],["H0639","himself, the wrath",20,38],["H3068","of the LORD",39,50],["H7725","turned",51,57],["H7843","from him, that he would not destroy",58,93],["H3617","him altogether",94,108],["H3063","and also in Judah",110,127],["H1697","things",128,134],["H2896","went well",135,144]]},"12:13":{"text":"So king Rehoboam strengthened himself in Jerusalem, and reigned: for Rehoboam was one and forty years old when he began to reign, and he reigned seventeen years in Jerusalem, the city which the LORD had chosen out of all the tribes of Israel, to put his name there. And his mother's name was Naamah an Ammonitess.","words":[["H4428","So king",0,7],["H7346","Rehoboam",8,16],["H2388","strengthened",17,29],["H3389","himself in Jerusalem",30,50],["H4427","and reigned",52,63],["H7346","for Rehoboam",65,77],["H0259","was one",78,85],["H0705","and forty",86,95],["H8141","years",96,101],["H1121","old",102,105],["H4427","when he began to reign",106,128],["H4427","and he reigned",130,144],["H7651","seventeen",145,154],["H6240","seventeen",145,154],["H8141","years",155,160],["H3389","in Jerusalem",161,173],["H5892","the city",175,183],["H3068","which the LORD",184,198],["H0977","had chosen",199,209],["H7626","out of all the tribes",210,231],["H3478","of Israel",232,241],["H7760","to put",243,249],["H8034","his name",250,258],["H0517","there. And his mother's",259,282],["H8034","name",283,287],["H5279","was Naamah",288,298],["H5985","an Ammonitess",299,312]]},"12:14":{"text":"And he did evil, because he prepared not his heart to seek the LORD.","words":[["H6213","And he did",0,10],["H7451","evil",11,15],["H3559","because he prepared",17,36],["H3820","not his heart",37,50],["H1875","to seek",51,58],["H3068","the LORD",59,67]]},"12:15":{"text":"Now the acts of Rehoboam, first and last, are they not written in the book of Shemaiah the prophet, and of Iddo the seer concerning genealogies? And there were wars between Rehoboam and Jeroboam continually.","words":[["H1697","Now the acts",0,12],["H7346","of Rehoboam",13,24],["H7223","first",26,31],["H0314","and last",32,40],["H3789","are they not written",42,62],["H1697","in the book",63,74],["H8098","of Shemaiah",75,86],["H5030","the prophet",87,98],["H5714","and of Iddo",100,111],["H2374","the seer",112,120],["H3187","concerning genealogies",121,143],["H4421","And there were wars",145,164],["H7346","between Rehoboam",165,181],["H3379","and Jeroboam",182,194],["H3117","continually",195,206]]},"12:16":{"text":"And Rehoboam slept with his fathers, and was buried in the city of David: and Abijah his son reigned in his stead.","words":[["H7346","And Rehoboam",0,12],["H7901","slept",13,18],["H0001","with his fathers",19,35],["H6912","and was buried",37,51],["H5892","in the city",52,63],["H1732","of David",64,72],["H0029","and Abijah",74,84],["H1121","his son",85,92],["H4427","reigned",93,100]]},"13:1":{"text":"Now in the eighteenth year of king Jeroboam began Abijah to reign over Judah.","words":[["H8083","Now in the eighteenth",0,21],["H6240","Now in the eighteenth",0,21],["H8141","year",22,26],["H4428","of king",27,34],["H3379","Jeroboam",35,43],["H0029","began Abijah",44,56],["H4427","to reign",57,65],["H3063","over Judah",66,76]]},"13:2":{"text":"He reigned three years in Jerusalem. His mother's name also was Michaiah the daughter of Uriel of Gibeah. And there was war between Abijah and Jeroboam.","words":[["H4427","He reigned",0,10],["H7969","three",11,16],["H8141","years",17,22],["H3389","in Jerusalem",23,35],["H0517","His mother's",37,49],["H8034","name",50,54],["H4322","also was Michaiah",55,72],["H1323","the daughter",73,85],["H0222","of Uriel",86,94],["H1390","of Gibeah",95,104],["H4421","And there was war",106,123],["H0029","between Abijah",124,138],["H3379","and Jeroboam",139,151]]},"13:3":{"text":"And Abijah set the battle in array with an army of valiant men of war, even four hundred thousand chosen men: Jeroboam also set the battle in array against him with eight hundred thousand chosen men, being mighty men of valour.","words":[["H0029","And Abijah",0,10],["H0631","set",11,14],["H4421","the battle",15,25],["H0631","in array",26,34],["H2428","with an army",35,47],["H1368","of valiant men",48,62],["H4421","of war",63,69],["H0702","even four",71,80],["H3967","hundred",81,88],["H0505","thousand",89,97],["H0977","chosen",98,104],["H0376","men",105,108],["H3379","Jeroboam",110,118],["H4421","also set the battle",119,138],["H6186","in array",139,147],["H8083","against him with eight",148,170],["H3967","hundred",171,178],["H0505","thousand",179,187],["H0977","chosen",188,194],["H0376","men",195,198],["H1368","being mighty men",200,216],["H2428","of valour",217,226]]},"13:4":{"text":"And Abijah stood up upon mount Zemaraim, which is in mount Ephraim, and said, Hear me, thou Jeroboam, and all Israel;","words":[["H0029","And Abijah",0,10],["H6965","stood up",11,19],["H2022","upon mount",20,30],["H6787","Zemaraim",31,39],["H2022","which is in mount",41,58],["H0669","Ephraim",59,66],["H0559","and said",68,76],["H8085","Hear",78,82],["H3379","me, thou Jeroboam",83,100],["H3478","and all Israel",102,116]]},"13:5":{"text":"Ought ye not to know that the LORD God of Israel gave the kingdom over Israel to David for ever, even to him and to his sons by a covenant of salt?","words":[["H3045","Ought ye not to know",0,20],["H3068","that the LORD",21,34],["H0430","God",35,38],["H3478","of Israel",39,48],["H5414","gave",49,53],["H4467","the kingdom",54,65],["H3478","over Israel",66,77],["H1732","to David",78,86],["H5769","for ever",87,95],["H1121","even to him and to his sons",97,124],["H1285","by a covenant",125,138],["H4417","of salt",139,146]]},"13:6":{"text":"Yet Jeroboam the son of Nebat, the servant of Solomon the son of David, is risen up, and hath rebelled against his lord.","words":[["H3379","Yet Jeroboam",0,12],["H1121","the son",13,20],["H5028","of Nebat",21,29],["H5650","the servant",31,42],["H8010","of Solomon",43,53],["H1121","the son",54,61],["H1732","of David",62,70],["H6965","is risen up",72,83],["H4775","and hath rebelled",85,102],["H0113","against his lord",103,119]]},"13:7":{"text":"And there are gathered unto him vain men, the children of Belial, and have strengthened themselves against Rehoboam the son of Solomon, when Rehoboam was young and tenderhearted, and could not withstand them.","words":[["H6908","And there are gathered",0,22],["H7386","unto him vain",23,36],["H0582","men",37,40],["H1121","the children",42,54],["H1100","of Belial",55,64],["H0553","and have strengthened",66,87],["H7346","themselves against Rehoboam",88,115],["H1121","the son",116,123],["H8010","of Solomon",124,134],["H7346","when Rehoboam",136,149],["H5288","was young",150,159],["H7390","and tenderhearted",160,177],["H3824","and tenderhearted",160,177],["H2388","and could not withstand",179,202],["H6440","them",203,207]]},"13:8":{"text":"And now ye think to withstand the kingdom of the LORD in the hand of the sons of David; and ye be a great multitude, and there are with you golden calves, which Jeroboam made you for gods.","words":[["H0559","And now ye think",0,16],["H2388","to withstand",17,29],["H6440","the kingdom",30,41],["H4467","the kingdom",30,41],["H3068","of the LORD",42,53],["H3027","in the hand",54,65],["H1121","of the sons",66,77],["H1732","of David",78,86],["H7227","and ye be a great",88,105],["H1995","multitude",106,115],["H2091","and there are with you golden",117,146],["H5695","calves",147,153],["H3379","which Jeroboam",155,169],["H6213","made",170,174],["H0430","you for gods",175,187]]},"13:9":{"text":"Have ye not cast out the priests of the LORD, the sons of Aaron, and the Levites, and have made you priests after the manner of the nations of other lands? so that whosoever cometh to consecrate himself with a young bullock and seven rams, the same may be a priest of them that are no gods.","words":[["H5080","Have ye not cast out",0,20],["H3548","the priests",21,32],["H3068","of the LORD",33,44],["H1121","the sons",46,54],["H0175","of Aaron",55,63],["H3881","and the Levites",65,80],["H6213","and have made",82,95],["H3548","you priests",96,107],["H5971","after the manner of the nations",108,139],["H0776","of other lands",140,154],["H0935","so that whosoever cometh",156,180],["H4390","to consecrate",181,194],["H3027","to consecrate",181,194],["H1121","himself with a young",195,215],["H1241","himself with a young",195,215],["H6499","bullock",216,223],["H7651","and seven",224,233],["H0352","rams",234,238],["H3548","the same may be a priest",240,264],["H3808","of them that are no",265,284],["H0430","gods",285,289]]},"13:10":{"text":"But as for us, the LORD is our God, and we have not forsaken him; and the priests, which minister unto the LORD, are the sons of Aaron, and the Levites wait upon their business:","words":[["H3068","But as for us, the LORD",0,23],["H0430","is our God",24,34],["H5800","and we have not forsaken",36,60],["H3548","him; and the priests",61,81],["H8334","which minister",83,97],["H3068","unto the LORD",98,111],["H1121","are the sons",113,125],["H0175","of Aaron",126,134],["H3881","and the Levites",136,151],["H4399","wait upon their business",152,176]]},"13:11":{"text":"And they burn unto the LORD every morning and every evening burnt sacrifices and sweet incense: the shewbread also set they in order upon the pure table; and the candlestick of gold with the lamps thereof, to burn every evening: for we keep the charge of the LORD our God; but ye have forsaken him.","words":[["H6999","And they burn",0,13],["H3068","unto the LORD",14,27],["H1242","every morning",28,41],["H6153","and every evening",42,59],["H5930","burnt sacrifices",60,76],["H5561","and sweet",77,86],["H7004","incense",87,94],["H3899","the shewbread",96,109],["H4635","the shewbread",96,109],["H2889","also set they in order upon the pure",110,146],["H7979","table",147,152],["H4501","and the candlestick",154,173],["H2091","of gold",174,181],["H5216","with the lamps",182,196],["H1197","thereof, to burn",197,213],["H6153","every evening",214,227],["H8104","for we keep",229,240],["H4931","the charge",241,251],["H3068","of the LORD",252,263],["H0430","our God",264,271],["H5800","but ye have forsaken",273,293]]},"13:12":{"text":"And, behold, God himself is with us for our captain, and his priests with sounding trumpets to cry alarm against you. O children of Israel, fight ye not against the LORD God of your fathers; for ye shall not prosper.","words":[["H0430","And, behold, God",0,16],["H7218","himself is with us for our captain",17,51],["H3548","and his priests",53,68],["H8643","with sounding",69,82],["H2689","trumpets",83,91],["H7321","to cry alarm",92,104],["H1121","against you. O children",105,128],["H3478","of Israel",129,138],["H3898","fight",140,145],["H3068","ye not against the LORD",146,169],["H0430","God",170,173],["H0001","of your fathers",174,189],["H6743","for ye shall not prosper",191,215]]},"13:13":{"text":"But Jeroboam caused an ambushment to come about behind them: so they were before Judah, and the ambushment was behind them.","words":[["H3379","But Jeroboam",0,12],["H3993","caused an ambushment",13,33],["H0935","to come",34,41],["H5437","about",42,47],["H0310","behind",48,54],["H6440","them: so they were before",55,80],["H3063","Judah",81,86],["H3993","and the ambushment",88,106],["H0310","was behind",107,117]]},"13:14":{"text":"And when Judah looked back, behold, the battle was before and behind: and they cried unto the LORD, and the priests sounded with the trumpets.","words":[["H3063","And when Judah",0,14],["H6437","looked back",15,26],["H4421","behold, the battle",28,46],["H6440","was before",47,57],["H0268","and behind",58,68],["H6817","and they cried",70,84],["H3068","unto the LORD",85,98],["H3548","and the priests",100,115],["H2690","sounded",116,123],["H2690","sounded",116,123],["H2689","with the trumpets",124,141]]},"13:15":{"text":"Then the men of Judah gave a shout: and as the men of Judah shouted, it came to pass, that God smote Jeroboam and all Israel before Abijah and Judah.","words":[["H0376","Then the men",0,12],["H3063","of Judah",13,21],["H7321","gave a shout",22,34],["H0376","and as the men",36,50],["H3063","of Judah",51,59],["H7321","shouted",60,67],["H0430","it came to pass, that God",69,94],["H5062","smote",95,100],["H3379","Jeroboam",101,109],["H3478","and all Israel",110,124],["H6440","before",125,131],["H0029","Abijah",132,138],["H3063","and Judah",139,148]]},"13:16":{"text":"And the children of Israel fled before Judah: and God delivered them into their hand.","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H5127","fled",27,31],["H6440","before",32,38],["H3063","Judah",39,44],["H0430","and God",46,53],["H5414","delivered",54,63],["H3027","them into their hand",64,84]]},"13:17":{"text":"And Abijah and his people slew them with a great slaughter: so there fell down slain of Israel five hundred thousand chosen men.","words":[["H0029","And Abijah",0,10],["H5971","and his people",11,25],["H5221","slew",26,30],["H7227","them with a great",31,48],["H4347","slaughter",49,58],["H5307","so there fell down",60,78],["H2491","slain",79,84],["H3478","of Israel",85,94],["H2568","five",95,99],["H3967","hundred",100,107],["H0505","thousand",108,116],["H0977","chosen",117,123],["H0376","men",124,127]]},"13:18":{"text":"Thus the children of Israel were brought under at that time, and the children of Judah prevailed, because they relied upon the LORD God of their fathers.","words":[["H1121","Thus the children",0,17],["H3478","of Israel",18,27],["H3665","were brought",28,40],["H6256","under at that time",41,59],["H1121","and the children",61,77],["H3063","of Judah",78,86],["H0553","prevailed",87,96],["H8172","because they relied",98,117],["H3068","upon the LORD",118,131],["H0430","God",132,135],["H0001","of their fathers",136,152]]},"13:19":{"text":"And Abijah pursued after Jeroboam, and took cities from him, Bethel with the towns thereof, and Jeshanah with the towns thereof, and Ephrain with the towns thereof.","words":[["H0029","And Abijah",0,10],["H7291","pursued",11,18],["H0310","after",19,24],["H3379","Jeroboam",25,33],["H3920","and took",35,43],["H5892","cities",44,50],["H1008","from him, Bethel",51,67],["H1323","with the towns",68,82],["H3466","thereof, and Jeshanah",83,104],["H1323","with the towns",105,119],["H6085","thereof, and Ephrain",120,140],["H1323","with the towns",141,155]]},"13:20":{"text":"Neither did Jeroboam recover strength again in the days of Abijah: and the LORD struck him, and he died.","words":[["H3379","Neither did Jeroboam",0,20],["H6113","recover",21,28],["H3581","strength",29,37],["H3117","again in the days",38,55],["H0029","of Abijah",56,65],["H3068","and the LORD",67,79],["H5062","struck",80,86],["H4191","him, and he died",87,103]]},"13:21":{"text":"But Abijah waxed mighty, and married fourteen wives, and begat twenty and two sons, and sixteen daughters.","words":[["H0029","But Abijah",0,10],["H2388","waxed mighty",11,23],["H5375","and married",25,36],["H0702","fourteen",37,45],["H6240","fourteen",37,45],["H0802","wives",46,51],["H3205","and begat",53,62],["H6242","twenty",63,69],["H8147","and two",70,77],["H1121","sons",78,82],["H8337","and sixteen",84,95],["H6240","and sixteen",84,95],["H1323","daughters",96,105]]},"13:22":{"text":"And the rest of the acts of Abijah, and his ways, and his sayings, are written in the story of the prophet Iddo.","words":[["H3499","And the rest",0,12],["H1697","of the acts",13,24],["H0029","of Abijah",25,34],["H1870","and his ways",36,48],["H1697","and his sayings",50,65],["H3789","are written",67,78],["H4097","in the story",79,91],["H5030","of the prophet",92,106],["H5714","Iddo",107,111]]},"14:1":{"text":"So Abijah slept with his fathers, and they buried him in the city of David: and Asa his son reigned in his stead. In his days the land was quiet ten years.","words":[["H0029","So Abijah",0,9],["H7901","slept",10,15],["H0001","with his fathers",16,32],["H6912","and they buried",34,49],["H5892","him in the city",50,65],["H1732","of David",66,74],["H0609","and Asa",76,83],["H1121","his son",84,91],["H4427","reigned",92,99],["H3117","in his stead. In his days",100,125],["H0776","the land",126,134],["H8252","was quiet",135,144],["H6235","ten",145,148],["H8141","years",149,154]]},"14:2":{"text":"And Asa did that which was good and right in the eyes of the LORD his God:","words":[["H0609","And Asa",0,7],["H6213","did",8,11],["H2896","that which was good",12,31],["H3477","and right",32,41],["H5869","in the eyes",42,53],["H3068","of the LORD",54,65],["H0430","his God",66,73]]},"14:3":{"text":"For he took away the altars of the strange gods, and the high places, and brake down the images, and cut down the groves:","words":[["H5493","For he took away",0,16],["H4196","the altars",17,27],["H5236","of the strange",28,42],["H1116","gods, and the high places",43,68],["H7665","and brake down",70,84],["H4676","the images",85,95],["H1438","and cut down",97,109],["H0842","the groves",110,120]]},"14:4":{"text":"And commanded Judah to seek the LORD God of their fathers, and to do the law and the commandment.","words":[["H0559","And commanded",0,13],["H3063","Judah",14,19],["H1875","to seek",20,27],["H3068","the LORD",28,36],["H0430","God",37,40],["H0001","of their fathers",41,57],["H6213","and to do",59,68],["H8451","the law",69,76],["H4687","and the commandment",77,96]]},"14:5":{"text":"Also he took away out of all the cities of Judah the high places and the images: and the kingdom was quiet before him.","words":[["H5493","Also he took away",0,17],["H5892","out of all the cities",18,39],["H3063","of Judah",40,48],["H1116","the high places",49,64],["H2553","and the images",65,79],["H4467","and the kingdom",81,96],["H8252","was quiet",97,106],["H6440","before",107,113]]},"14:6":{"text":"And he built fenced cities in Judah: for the land had rest, and he had no war in those years; because the LORD had given him rest.","words":[["H1129","And he built",0,12],["H4694","fenced",13,19],["H5892","cities",20,26],["H3063","in Judah",27,35],["H0776","for the land",37,49],["H8252","had rest",50,58],["H4421","and he had no war",60,77],["H8141","in those years",78,92],["H3068","because the LORD",94,110],["H5117","had given him rest",111,129]]},"14:7":{"text":"Therefore he said unto Judah, Let us build these cities, and make about them walls, and towers, gates, and bars, while the land is yet before us; because we have sought the LORD our God, we have sought him, and he hath given us rest on every side. So they built and prospered.","words":[["H0559","Therefore he said",0,17],["H3063","unto Judah",18,28],["H1129","Let us build",30,42],["H5892","these cities",43,55],["H5437","and make about",57,71],["H2346","them walls",72,82],["H4026","and towers",84,94],["H1817","gates",96,101],["H1280","and bars",103,111],["H0776","while the land",113,127],["H6440","is yet before",128,141],["H1875","us; because we have sought",142,168],["H3068","the LORD",169,177],["H0430","our God",178,185],["H1875","we have sought",187,201],["H5117","him, and he hath given us rest",202,232],["H5439","on every side",233,246],["H1129","So they built",248,261],["H6743","and prospered",262,275]]},"14:8":{"text":"And Asa had an army of men that bare targets and spears, out of Judah three hundred thousand; and out of Benjamin, that bare shields and drew bows, two hundred and fourscore thousand: all these were mighty men of valour.","words":[["H0609","And Asa",0,7],["H2428","had an army",8,19],["H5375","of men that bare",20,36],["H6793","targets",37,44],["H7420","and spears",45,55],["H3063","out of Judah",57,69],["H7969","three",70,75],["H3967","hundred",76,83],["H0505","thousand",84,92],["H1144","and out of Benjamin",94,113],["H5375","that bare",115,124],["H4043","shields",125,132],["H1869","and drew",133,141],["H7198","bows",142,146],["H3967","two hundred",148,159],["H8084","and fourscore",160,173],["H0505","thousand",174,182],["H1368","all these were mighty men",184,209],["H2428","of valour",210,219]]},"14:9":{"text":"And there came out against them Zerah the Ethiopian with an host of a thousand thousand, and three hundred chariots; and came unto Mareshah.","words":[["H3318","And there came out",0,18],["H2226","against them Zerah",19,37],["H3569","the Ethiopian",38,51],["H2428","with an host",52,64],["H0505","of a thousand",65,78],["H0505","thousand",79,87],["H7969","and three",89,98],["H3967","hundred",99,106],["H4818","chariots",107,115],["H0935","and came",117,125],["H4762","unto Mareshah",126,139]]},"14:10":{"text":"Then Asa went out against him, and they set the battle in array in the valley of Zephathah at Mareshah.","words":[["H0609","Then Asa",0,8],["H3318","went out",9,17],["H6440","against",18,25],["H4421","him, and they set the battle",26,54],["H6186","in array",55,63],["H1516","in the valley",64,77],["H6859","of Zephathah",78,90],["H4762","at Mareshah",91,102]]},"14:11":{"text":"And Asa cried unto the LORD his God, and said, LORD, it is nothing with thee to help, whether with many, or with them that have no power: help us, O LORD our God; for we rest on thee, and in thy name we go against this multitude. O LORD, thou art our God; let not man prevail against thee.","words":[["H0609","And Asa",0,7],["H7121","cried",8,13],["H3068","unto the LORD",14,27],["H0430","his God",28,35],["H0559","and said",37,45],["H3068","LORD",47,51],["H5826","it is nothing with thee to help",53,84],["H0996","whether",86,93],["H7227","with many",94,103],["H3581","or with them that have no power",105,136],["H5826","help",138,142],["H3068","us, O LORD",143,153],["H0430","our God",154,161],["H8172","for we rest",163,174],["H8034","on thee, and in thy name",175,199],["H0935","we go",200,205],["H1995","against this multitude",206,228],["H3068","O LORD",230,236],["H0430","thou art our God",238,254],["H0582","let not man",256,267],["H6113","prevail",268,275]]},"14:12":{"text":"So the LORD smote the Ethiopians before Asa, and before Judah; and the Ethiopians fled.","words":[["H3068","So the LORD",0,11],["H5062","smote",12,17],["H3569","the Ethiopians",18,32],["H6440","before",33,39],["H0609","Asa",40,43],["H6440","and before",45,55],["H3063","Judah",56,61],["H3569","and the Ethiopians",63,81],["H5127","fled",82,86]]},"14:13":{"text":"And Asa and the people that were with him pursued them unto Gerar: and the Ethiopians were overthrown, that they could not recover themselves; for they were destroyed before the LORD, and before his host; and they carried away very much spoil.","words":[["H0609","And Asa",0,7],["H5971","and the people",8,22],["H7291","that were with him pursued",23,49],["H1642","them unto Gerar",50,65],["H3569","and the Ethiopians",67,85],["H5307","were overthrown",86,101],["H4241","that they could not recover",103,130],["H7665","themselves; for they were destroyed",131,166],["H6440","before",167,173],["H3068","the LORD",174,182],["H6440","and before",184,194],["H4264","his host",195,203],["H5375","and they carried away",205,226],["H3966","very",227,231],["H7235","much",232,236],["H7998","spoil",237,242]]},"14:14":{"text":"And they smote all the cities round about Gerar; for the fear of the LORD came upon them: and they spoiled all the cities; for there was exceeding much spoil in them.","words":[["H5221","And they smote",0,14],["H5892","all the cities",15,29],["H5439","round about",30,41],["H1642","Gerar",42,47],["H6343","for the fear",49,61],["H3068","of the LORD",62,73],["H0962","came upon them: and they spoiled",74,106],["H5892","all the cities",107,121],["H7227","for there was exceeding much",123,151],["H0961","spoil",152,157]]},"14:15":{"text":"They smote also the tents of cattle, and carried away sheep and camels in abundance, and returned to Jerusalem.","words":[["H5221","They smote",0,10],["H0168","also the tents",11,25],["H4735","of cattle",26,35],["H7617","and carried away",37,53],["H6629","sheep",54,59],["H1581","and camels",60,70],["H7230","in abundance",71,83],["H7725","and returned",85,97],["H3389","to Jerusalem",98,110]]},"15:1":{"text":"And the Spirit of God came upon Azariah the son of Oded:","words":[["H7307","And the Spirit",0,14],["H0430","of God",15,21],["H5838","came upon Azariah",22,39],["H1121","the son",40,47],["H5752","of Oded",48,55]]},"15:2":{"text":"And he went out to meet Asa, and said unto him, Hear ye me, Asa, and all Judah and Benjamin; The LORD is with you, while ye be with him; and if ye seek him, he will be found of you; but if ye forsake him, he will forsake you.","words":[["H3318","And he went out",0,15],["H6440","to meet",16,23],["H0609","Asa",24,27],["H0559","and said",29,37],["H8085","unto him, Hear",38,52],["H0609","ye me, Asa",53,63],["H3063","and all Judah",65,78],["H1144","and Benjamin",79,91],["H3068","The LORD",93,101],["H1875","is with you, while ye be with him; and if ye seek",102,151],["H4672","him, he will be found",152,173],["H5800","of you; but if ye forsake",174,199],["H5800","him, he will forsake",200,220]]},"15:3":{"text":"Now for a long season Israel hath been without the true God, and without a teaching priest, and without law.","words":[["H7227","Now for a long",0,14],["H3117","season",15,21],["H3478","Israel",22,28],["H3808","hath been without",29,46],["H0571","the true",47,55],["H0430","God",56,59],["H3384","and without a teaching",61,83],["H3548","priest",84,90],["H8451","and without law",92,107]]},"15:4":{"text":"But when they in their trouble did turn unto the LORD God of Israel, and sought him, he was found of them.","words":[["H6862","But when they in their trouble",0,30],["H7725","did turn",31,39],["H3068","unto the LORD",40,53],["H0430","God",54,57],["H3478","of Israel",58,67],["H1245","and sought",69,79],["H4672","him, he was found",80,97]]},"15:5":{"text":"And in those times there was no peace to him that went out, nor to him that came in, but great vexations were upon all the inhabitants of the countries.","words":[["H6256","And in those times",0,18],["H7965","there was no peace",19,37],["H3318","to him that went out",38,58],["H0935","nor to him that came in",60,83],["H7227","but great",85,94],["H4103","vexations",95,104],["H3427","were upon all the inhabitants",105,134],["H0776","of the countries",135,151]]},"15:6":{"text":"And nation was destroyed of nation, and city of city: for God did vex them with all adversity.","words":[["H1471","And nation",0,10],["H3807","was destroyed",11,24],["H1471","of nation",25,34],["H5892","and city",36,44],["H5892","of city",45,52],["H0430","for God",54,61],["H2000","did vex",62,69],["H6869","them with all adversity",70,93]]},"15:7":{"text":"Be ye strong therefore, and let not your hands be weak: for your work shall be rewarded.","words":[["H2388","Be ye strong",0,12],["H3027","therefore, and let not your hands",13,46],["H7503","be weak",47,54],["H6468","for your work",56,69],["H3426","shall be",70,78],["H7939","rewarded",79,87]]},"15:8":{"text":"And when Asa heard these words, and the prophecy of Oded the prophet, he took courage, and put away the abominable idols out of all the land of Judah and Benjamin, and out of the cities which he had taken from mount Ephraim, and renewed the altar of the LORD, that was before the porch of the LORD.","words":[["H0609","And when Asa",0,12],["H8085","heard",13,18],["H1697","these words",19,30],["H5016","and the prophecy",32,48],["H5752","of Oded",49,56],["H5030","the prophet",57,68],["H2388","he took courage",70,85],["H5674","and put away",87,99],["H8251","the abominable idols",100,120],["H0776","out of all the land",121,140],["H3063","of Judah",141,149],["H1144","and Benjamin",150,162],["H5892","and out of the cities",164,185],["H3920","which he had taken",186,204],["H2022","from mount",205,215],["H0669","Ephraim",216,223],["H2318","and renewed",225,236],["H4196","the altar",237,246],["H3068","of the LORD",247,258],["H6440","that was before",260,275],["H0197","the porch",276,285],["H3068","of the LORD",286,297]]},"15:9":{"text":"And he gathered all Judah and Benjamin, and the strangers with them out of Ephraim and Manasseh, and out of Simeon: for they fell to him out of Israel in abundance, when they saw that the LORD his God was with him.","words":[["H6908","And he gathered",0,15],["H3063","all Judah",16,25],["H1144","and Benjamin",26,38],["H1481","and the strangers",40,57],["H0669","with them out of Ephraim",58,82],["H4519","and Manasseh",83,95],["H8095","and out of Simeon",97,114],["H5307","for they fell",116,129],["H3478","to him out of Israel",130,150],["H7230","in abundance",151,163],["H7200","when they saw",165,178],["H3068","that the LORD",179,192],["H0430","his God",193,200]]},"15:10":{"text":"So they gathered themselves together at Jerusalem in the third month, in the fifteenth year of the reign of Asa.","words":[["H6908","So they gathered themselves together",0,36],["H3389","at Jerusalem",37,49],["H7992","in the third",50,62],["H2320","month",63,68],["H2568","in the fifteenth",70,86],["H6240","in the fifteenth",70,86],["H8141","year",87,91],["H4438","of the reign",92,104],["H0609","of Asa",105,111]]},"15:11":{"text":"And they offered unto the LORD the same time, of the spoil which they had brought, seven hundred oxen and seven thousand sheep.","words":[["H2076","And they offered",0,16],["H3068","unto the LORD",17,30],["H3117","the same time",31,44],["H7998","of the spoil",46,58],["H0935","which they had brought",59,81],["H7651","seven",83,88],["H3967","hundred",89,96],["H1241","oxen",97,101],["H7651","and seven",102,111],["H0505","thousand",112,120],["H6629","sheep",121,126]]},"15:12":{"text":"And they entered into a covenant to seek the LORD God of their fathers with all their heart and with all their soul;","words":[["H0935","And they entered",0,16],["H1285","into a covenant",17,32],["H1875","to seek",33,40],["H3068","the LORD",41,49],["H0430","God",50,53],["H0001","of their fathers",54,70],["H3824","with all their heart",71,91],["H5315","and with all their soul",92,115]]},"15:13":{"text":"That whosoever would not seek the LORD God of Israel should be put to death, whether small or great, whether man or woman.","words":[["H1875","That whosoever would not seek",0,29],["H3068","the LORD",30,38],["H0430","God",39,42],["H3478","of Israel",43,52],["H4191","should be put to death",53,75],["H4480","whether",77,84],["H6996","small",85,90],["H1419","or great",91,99],["H0376","whether man",101,112],["H0802","or woman",113,121]]},"15:14":{"text":"And they sware unto the LORD with a loud voice, and with shouting, and with trumpets, and with cornets.","words":[["H7650","And they sware",0,14],["H3068","unto the LORD",15,28],["H1419","with a loud",29,40],["H6963","voice",41,46],["H8643","and with shouting",48,65],["H2689","and with trumpets",67,84],["H7782","and with cornets",86,102]]},"15:15":{"text":"And all Judah rejoiced at the oath: for they had sworn with all their heart, and sought him with their whole desire; and he was found of them: and the LORD gave them rest round about.","words":[["H3063","And all Judah",0,13],["H8055","rejoiced",14,22],["H7621","at the oath",23,34],["H7650","for they had sworn",36,54],["H3824","with all their heart",55,75],["H1245","and sought",77,87],["H7522","him with their whole desire",88,115],["H4672","and he was found",117,133],["H3068","of them: and the LORD",134,155],["H5117","gave them rest",156,170],["H5439","round about",171,182]]},"15:16":{"text":"And also concerning Maachah the mother of Asa the king, he removed her from being queen, because she had made an idol in a grove: and Asa cut down her idol, and stamped it, and burnt it at the brook Kidron.","words":[["H4601","And also concerning Maachah",0,27],["H0517","the mother",28,38],["H0609","of Asa",39,45],["H4428","the king",46,54],["H5493","he removed",56,66],["H1377","her from being queen",67,87],["H6213","because she had made",89,109],["H4656","an idol",110,117],["H0842","in a grove",118,128],["H0609","and Asa",130,137],["H3772","cut down",138,146],["H4656","her idol",147,155],["H1854","and stamped",157,168],["H8313","it, and burnt",169,182],["H5158","it at the brook",183,198],["H6939","Kidron",199,205]]},"15:17":{"text":"But the high places were not taken away out of Israel: nevertheless the heart of Asa was perfect all his days.","words":[["H1116","But the high places",0,19],["H5493","were not taken away",20,39],["H3478","out of Israel",40,53],["H3824","nevertheless the heart",55,77],["H0609","of Asa",78,84],["H8003","was perfect",85,96],["H3117","all his days",97,109]]},"15:18":{"text":"And he brought into the house of God the things that his father had dedicated, and that he himself had dedicated, silver, and gold, and vessels.","words":[["H0935","And he brought",0,14],["H1004","into the house",15,29],["H0430","of God",30,36],["H0001","the things that his father",37,63],["H6944","had dedicated",64,77],["H6944","and that he himself had dedicated",79,112],["H3701","silver",114,120],["H2091","and gold",122,130],["H3627","and vessels",132,143]]},"15:19":{"text":"And there was no more war unto the five and thirtieth year of the reign of Asa.","words":[["H4421","And there was no more war",0,25],["H2568","unto the five",26,39],["H7970","and thirtieth",40,53],["H8141","year",54,58],["H4438","of the reign",59,71],["H0609","of Asa",72,78]]},"16:1":{"text":"In the six and thirtieth year of the reign of Asa Baasha king of Israel came up against Judah, and built Ramah, to the intent that he might let none go out or come in to Asa king of Judah.","words":[["H8337","In the six",0,10],["H7970","and thirtieth",11,24],["H8141","year",25,29],["H4438","of the reign",30,42],["H0609","of Asa",43,49],["H1201","Baasha",50,56],["H4428","king",57,61],["H3478","of Israel",62,71],["H5927","came up",72,79],["H3063","against Judah",80,93],["H1129","and built",95,104],["H7414","Ramah",105,110],["H1115","to the intent that",112,130],["H5414","he might let",131,143],["H3318","none go out",144,155],["H0935","or come in",156,166],["H0609","to Asa",167,173],["H4428","king",174,178],["H3063","of Judah",179,187]]},"16:2":{"text":"Then Asa brought out silver and gold out of the treasures of the house of the LORD and of the king's house, and sent to Benhadad king of Syria, that dwelt at Damascus, saying,","words":[["H0609","Then Asa",0,8],["H3318","brought out",9,20],["H3701","silver",21,27],["H2091","and gold",28,36],["H0214","out of the treasures",37,57],["H1004","of the house",58,70],["H3068","of the LORD",71,82],["H4428","and of the king's",83,100],["H1004","house",101,106],["H7971","and sent",108,116],["H1130","to Benhadad",117,128],["H4428","king",129,133],["H0758","of Syria",134,142],["H3427","that dwelt",144,154],["H1834","at Damascus",155,166],["H0559","saying",168,174]]},"16:3":{"text":"There is a league between me and thee, as there was between my father and thy father: behold, I have sent thee silver and gold; go, break thy league with Baasha king of Israel, that he may depart from me.","words":[["H1285","There is a league",0,17],["H0001","between me and thee, as there was between my father",18,69],["H0001","and thy father",70,84],["H7971","behold, I have sent",86,105],["H3701","thee silver",106,117],["H2091","and gold",118,126],["H3212","go",128,130],["H6565","break",132,137],["H1285","thy league",138,148],["H1201","with Baasha",149,160],["H4428","king",161,165],["H3478","of Israel",166,175],["H5927","that he may depart",177,195]]},"16:4":{"text":"And Benhadad hearkened unto king Asa, and sent the captains of his armies against the cities of Israel; and they smote Ijon, and Dan, and Abelmaim, and all the store cities of Naphtali.","words":[["H1130","And Benhadad",0,12],["H8085","hearkened",13,22],["H4428","unto king",23,32],["H0609","Asa",33,36],["H7971","and sent",38,46],["H8269","the captains",47,59],["H2428","of his armies",60,73],["H5892","against the cities",74,92],["H3478","of Israel",93,102],["H5221","and they smote",104,118],["H5859","Ijon",119,123],["H1835","and Dan",125,132],["H0066","and Abelmaim",134,146],["H4543","and all the store",148,165],["H5892","cities",166,172],["H5321","of Naphtali",173,184]]},"16:5":{"text":"And it came to pass, when Baasha heard it, that he left off building of Ramah, and let his work cease.","words":[["H1201","And it came to pass, when Baasha",0,32],["H8085","heard",33,38],["H2308","it, that he left off",39,59],["H1129","building",60,68],["H7414","of Ramah",69,77],["H4399","and let his work",79,95],["H7673","cease",96,101]]},"16:6":{"text":"Then Asa the king took all Judah; and they carried away the stones of Ramah, and the timber thereof, wherewith Baasha was building; and he built therewith Geba and Mizpah.","words":[["H0609","Then Asa",0,8],["H4428","the king",9,17],["H3947","took",18,22],["H3063","all Judah",23,32],["H5375","and they carried away",34,55],["H0068","the stones",56,66],["H7414","of Ramah",67,75],["H6086","and the timber",77,91],["H1201","thereof, wherewith Baasha",92,117],["H1129","was building",118,130],["H1129","and he built",132,144],["H1387","therewith Geba",145,159],["H4709","and Mizpah",160,170]]},"16:7":{"text":"And at that time Hanani the seer came to Asa king of Judah, and said unto him, Because thou hast relied on the king of Syria, and not relied on the LORD thy God, therefore is the host of the king of Syria escaped out of thine hand.","words":[["H6256","And at that time",0,16],["H2607","Hanani",17,23],["H7200","the seer",24,32],["H0935","came",33,37],["H0609","to Asa",38,44],["H4428","king",45,49],["H3063","of Judah",50,58],["H0559","and said",60,68],["H8172","unto him, Because thou hast relied",69,103],["H4428","on the king",104,115],["H0758","of Syria",116,124],["H8172","and not relied",126,140],["H3068","on the LORD",141,152],["H0430","thy God",153,160],["H2428","therefore is the host",162,183],["H4428","of the king",184,195],["H0758","of Syria",196,204],["H4422","escaped",205,212],["H3027","out of thine hand",213,230]]},"16:8":{"text":"Were not the Ethiopians and the Lubims a huge host, with very many chariots and horsemen? yet, because thou didst rely on the LORD, he delivered them into thine hand.","words":[["H3569","Were not the Ethiopians",0,23],["H3864","and the Lubims",24,38],["H7230","a huge",39,45],["H2428","host",46,50],["H3966","with very",52,61],["H7235","many",62,66],["H7393","chariots",67,75],["H6571","and horsemen",76,88],["H8172","yet, because thou didst rely",90,118],["H3068","on the LORD",119,130],["H5414","he delivered",132,144],["H3027","them into thine hand",145,165]]},"16:9":{"text":"For the eyes of the LORD run to and fro throughout the whole earth, to shew himself strong in the behalf of them whose heart is perfect toward him. Herein thou hast done foolishly: therefore from henceforth thou shalt have wars.","words":[["H5869","For the eyes",0,12],["H3068","of the LORD",13,24],["H7751","run to and fro",25,39],["H0776","throughout the whole earth",40,66],["H2388","to shew himself strong",68,90],["H3824","in the behalf of them whose heart",91,124],["H8003","is perfect",125,135],["H5528","toward him. Herein thou hast done foolishly",136,179],["H6258","therefore from henceforth",181,206],["H3426","thou shalt have",207,222],["H4421","wars",223,227]]},"16:10":{"text":"Then Asa was wroth with the seer, and put him in a prison house; for he was in a rage with him because of this thing. And Asa oppressed some of the people the same time.","words":[["H0609","Then Asa",0,8],["H3707","was wroth",9,18],["H7200","with the seer",19,32],["H5414","and put",34,41],["H4115","him in a prison",42,57],["H1004","house",58,63],["H2197","for he was in a rage",65,85],["H0609","with him because of this thing. And Asa",86,125],["H7533","oppressed",126,135],["H5971","some of the people",136,154],["H6256","the same time",155,168]]},"16:11":{"text":"And, behold, the acts of Asa, first and last, lo, they are written in the book of the kings of Judah and Israel.","words":[["H1697","And, behold, the acts",0,21],["H0609","of Asa",22,28],["H7223","first",30,35],["H0314","and last",36,44],["H3789","lo, they are written",46,66],["H5612","in the book",67,78],["H4428","of the kings",79,91],["H3063","of Judah",92,100],["H3478","and Israel",101,111]]},"16:12":{"text":"And Asa in the thirty and ninth year of his reign was diseased in his feet, until his disease was exceeding great: yet in his disease he sought not to the LORD, but to the physicians.","words":[["H0609","And Asa",0,7],["H7970","in the thirty",8,21],["H8672","and ninth",22,31],["H8141","year",32,36],["H4438","of his reign",37,49],["H2456","was diseased",50,62],["H7272","in his feet",63,74],["H2483","until his disease",76,93],["H4605","was exceeding",94,107],["H2483","great: yet in his disease",108,133],["H1875","he sought",134,143],["H3068","not to the LORD",144,159],["H7495","but to the physicians",161,182]]},"16:13":{"text":"And Asa slept with his fathers, and died in the one and fortieth year of his reign.","words":[["H0609","And Asa",0,7],["H7901","slept",8,13],["H0001","with his fathers",14,30],["H4191","and died",32,40],["H0259","in the one",41,51],["H0705","and fortieth",52,64],["H8141","year",65,69],["H4427","of his reign",70,82]]},"16:14":{"text":"And they buried him in his own sepulchres, which he had made for himself in the city of David, and laid him in the bed which was filled with sweet odours and divers kinds of spices prepared by the apothecaries' art: and they made a very great burning for him.","words":[["H6912","And they buried",0,15],["H6913","him in his own sepulchres",16,41],["H3738","which he had made",43,60],["H5892","for himself in the city",61,84],["H1732","of David",85,93],["H7901","and laid",95,103],["H4904","him in the bed",104,118],["H4390","which was filled",119,135],["H1314","with sweet odours",136,153],["H2177","and divers kinds",154,170],["H7543","of spices prepared",171,189],["H4842","by the apothecaries'",190,210],["H4639","art",211,214],["H8313","and they made",216,229],["H3966","a very",230,236],["H1419","great",237,242],["H8316","burning",243,250]]},"17:1":{"text":"And Jehoshaphat his son reigned in his stead, and strengthened himself against Israel.","words":[["H3092","And Jehoshaphat",0,15],["H1121","his son",16,23],["H4427","reigned",24,31],["H2388","in his stead, and strengthened",32,62],["H3478","himself against Israel",63,85]]},"17:2":{"text":"And he placed forces in all the fenced cities of Judah, and set garrisons in the land of Judah, and in the cities of Ephraim, which Asa his father had taken.","words":[["H5414","And he placed",0,13],["H2428","forces",14,20],["H1219","in all the fenced",21,38],["H5892","cities",39,45],["H3063","of Judah",46,54],["H5414","and set",56,63],["H5333","garrisons",64,73],["H0776","in the land",74,85],["H3063","of Judah",86,94],["H5892","and in the cities",96,113],["H0669","of Ephraim",114,124],["H0609","which Asa",126,135],["H0001","his father",136,146],["H3920","had taken",147,156]]},"17:3":{"text":"And the LORD was with Jehoshaphat, because he walked in the first ways of his father David, and sought not unto Baalim;","words":[["H3068","And the LORD",0,12],["H3092","was with Jehoshaphat",13,33],["H1980","because he walked",35,52],["H7223","in the first",53,65],["H1870","ways",66,70],["H0001","of his father",71,84],["H1732","David",85,90],["H1875","and sought",92,102],["H1168","not unto Baalim",103,118]]},"17:4":{"text":"But sought to the LORD God of his father, and walked in his commandments, and not after the doings of Israel.","words":[["H1875","But sought",0,10],["H0430","to the LORD God",11,26],["H0001","of his father",27,40],["H1980","and walked",42,52],["H4687","in his commandments",53,72],["H4639","and not after the doings",74,98],["H3478","of Israel",99,108]]},"17:5":{"text":"Therefore the LORD stablished the kingdom in his hand; and all Judah brought to Jehoshaphat presents; and he had riches and honour in abundance.","words":[["H3068","Therefore the LORD",0,18],["H3559","stablished",19,29],["H4467","the kingdom",30,41],["H3027","in his hand",42,53],["H3063","and all Judah",55,68],["H5414","brought",69,76],["H3092","to Jehoshaphat",77,91],["H4503","presents",92,100],["H6239","and he had riches",102,119],["H3519","and honour",120,130],["H7230","in abundance",131,143]]},"17:6":{"text":"And his heart was lifted up in the ways of the LORD: moreover he took away the high places and groves out of Judah.","words":[["H3820","And his heart",0,13],["H1361","was lifted up",14,27],["H1870","in the ways",28,39],["H3068","of the LORD",40,51],["H5493","moreover he took away",53,74],["H1116","the high places",75,90],["H0842","and groves",91,101],["H3063","out of Judah",102,114]]},"17:7":{"text":"Also in the third year of his reign he sent to his princes, even to Benhail, and to Obadiah, and to Zechariah, and to Nethaneel, and to Michaiah, to teach in the cities of Judah.","words":[["H7969","Also in the third",0,17],["H8141","year",18,22],["H4427","of his reign",23,35],["H7971","he sent",36,43],["H8269","to his princes",44,58],["H1134","even to Benhail",60,75],["H5662","and to Obadiah",77,91],["H2148","and to Zechariah",93,109],["H5417","and to Nethaneel",111,127],["H4322","and to Michaiah",129,144],["H3925","to teach",146,154],["H5892","in the cities",155,168],["H3063","of Judah",169,177]]},"17:8":{"text":"And with them he sent Levites, even Shemaiah, and Nethaniah, and Zebadiah, and Asahel, and Shemiramoth, and Jehonathan, and Adonijah, and Tobijah, and Tobadonijah, Levites; and with them Elishama and Jehoram, priests.","words":[["H3881","And with them he sent Levites",0,29],["H8098","even Shemaiah",31,44],["H5418","and Nethaniah",46,59],["H2069","and Zebadiah",61,73],["H6214","and Asahel",75,85],["H8070","and Shemiramoth",87,102],["H3083","and Jehonathan",104,118],["H0138","and Adonijah",120,132],["H2900","and Tobijah",134,145],["H2899","and Tobadonijah",147,162],["H3881","Levites",164,171],["H0476","and with them Elishama",173,195],["H3088","and Jehoram",196,207],["H3548","priests",209,216]]},"17:9":{"text":"And they taught in Judah, and had the book of the law of the LORD with them, and went about throughout all the cities of Judah, and taught the people.","words":[["H3925","And they taught",0,15],["H3063","in Judah",16,24],["H5612","and had the book",26,42],["H8451","of the law",43,53],["H3068","of the LORD",54,65],["H5437","with them, and went about",66,91],["H5892","throughout all the cities",92,117],["H3063","of Judah",118,126],["H3925","and taught",128,138],["H5971","the people",139,149]]},"17:10":{"text":"And the fear of the LORD fell upon all the kingdoms of the lands that were round about Judah, so that they made no war against Jehoshaphat.","words":[["H6343","And the fear",0,12],["H3068","of the LORD",13,24],["H4467","fell upon all the kingdoms",25,51],["H0776","of the lands",52,64],["H5439","that were round about",65,86],["H3063","Judah",87,92],["H3898","so that they made no war",94,118],["H3092","against Jehoshaphat",119,138]]},"17:11":{"text":"Also some of the Philistines brought Jehoshaphat presents, and tribute silver; and the Arabians brought him flocks, seven thousand and seven hundred rams, and seven thousand and seven hundred he goats.","words":[["H6430","Also some of the Philistines",0,28],["H0935","brought",29,36],["H3092","Jehoshaphat",37,48],["H4503","presents",49,57],["H4853","and tribute",59,70],["H3701","silver",71,77],["H6163","and the Arabians",79,95],["H0935","brought",96,103],["H6629","him flocks",104,114],["H7651","seven",116,121],["H0505","thousand",122,130],["H7651","and seven",131,140],["H3967","hundred",141,148],["H0352","rams",149,153],["H7651","and seven",155,164],["H0505","thousand",165,173],["H7651","and seven",174,183],["H3967","hundred",184,191],["H8495","he goats",192,200]]},"17:12":{"text":"And Jehoshaphat waxed great exceedingly; and he built in Judah castles, and cities of store.","words":[["H3092","And Jehoshaphat",0,15],["H1980","waxed",16,21],["H1432","great",22,27],["H4605","exceedingly",28,39],["H1129","and he built",41,53],["H3063","in Judah",54,62],["H1003","castles",63,70],["H5892","and cities",72,82],["H4543","of store",83,91]]},"17:13":{"text":"And he had much business in the cities of Judah: and the men of war, mighty men of valour, were in Jerusalem.","words":[["H7227","And he had much",0,15],["H4399","business",16,24],["H5892","in the cities",25,38],["H3063","of Judah",39,47],["H0582","and the men",49,60],["H4421","of war",61,67],["H1368","mighty men",69,79],["H2428","of valour",80,89],["H3389","were in Jerusalem",91,108]]},"17:14":{"text":"And these are the numbers of them according to the house of their fathers: Of Judah, the captains of thousands; Adnah the chief, and with him mighty men of valour three hundred thousand.","words":[["H6486","And these are the numbers",0,25],["H1004","of them according to the house",26,56],["H0001","of their fathers",57,73],["H3063","Of Judah",75,83],["H8269","the captains",85,97],["H0505","of thousands",98,110],["H5734","Adnah",112,117],["H8269","the chief",118,127],["H1368","and with him mighty men",129,152],["H2428","of valour",153,162],["H7969","three",163,168],["H3967","hundred",169,176],["H0505","thousand",177,185]]},"17:15":{"text":"And next to him was Jehohanan the captain, and with him two hundred and fourscore thousand.","words":[["H3027","And next",0,8],["H3076","to him was Jehohanan",9,29],["H8269","the captain",30,41],["H3967","and with him two hundred",43,67],["H8084","and fourscore",68,81],["H0505","thousand",82,90]]},"17:16":{"text":"And next him was Amasiah the son of Zichri, who willingly offered himself unto the LORD; and with him two hundred thousand mighty men of valour.","words":[["H3027","And next",0,8],["H6007","him was Amasiah",9,24],["H1121","the son",25,32],["H2147","of Zichri",33,42],["H5068","who willingly offered",44,65],["H3068","himself unto the LORD",66,87],["H3967","and with him two hundred",89,113],["H0505","thousand",114,122],["H1368","mighty men",123,133],["H2428","of valour",134,143]]},"17:17":{"text":"And of Benjamin; Eliada a mighty man of valour, and with him armed men with bow and shield two hundred thousand.","words":[["H1144","And of Benjamin",0,15],["H0450","Eliada",17,23],["H1368","a mighty man",24,36],["H2428","of valour",37,46],["H5401","and with him armed men",48,70],["H7198","with bow",71,79],["H4043","and shield",80,90],["H3967","two hundred",91,102],["H0505","thousand",103,111]]},"17:18":{"text":"And next him was Jehozabad, and with him an hundred and fourscore thousand ready prepared for the war.","words":[["H3027","And next",0,8],["H3075","him was Jehozabad",9,26],["H3967","and with him an hundred",28,51],["H8084","and fourscore",52,65],["H0505","thousand",66,74],["H2502","ready prepared",75,89],["H6635","for the war",90,101]]},"17:19":{"text":"These waited on the king, beside those whom the king put in the fenced cities throughout all Judah.","words":[["H8334","These waited",0,12],["H4428","on the king",13,24],["H4428","beside those whom the king",26,52],["H5414","put",53,56],["H4013","in the fenced",57,70],["H5892","cities",71,77],["H3063","throughout all Judah",78,98]]},"18:1":{"text":"Now Jehoshaphat had riches and honour in abundance, and joined affinity with Ahab.","words":[["H3092","Now Jehoshaphat",0,15],["H6239","had riches",16,26],["H3519","and honour",27,37],["H7230","in abundance",38,50],["H2859","and joined affinity",52,71],["H0256","with Ahab",72,81]]},"18:2":{"text":"And after certain years he went down to Ahab to Samaria. And Ahab killed sheep and oxen for him in abundance, and for the people that he had with him, and persuaded him to go up with him to Ramothgilead.","words":[["H7093","And after",0,9],["H8141","certain years",10,23],["H3381","he went down",24,36],["H0256","to Ahab",37,44],["H8111","to Samaria",45,55],["H0256","And Ahab",57,65],["H2076","killed",66,72],["H6629","sheep",73,78],["H1241","and oxen",79,87],["H7230","for him in abundance",88,108],["H5971","and for the people",110,128],["H5496","that he had with him, and persuaded",129,164],["H5927","him to go up",165,177],["H7433","with him to Ramothgilead",178,202],["H1568","with him to Ramothgilead",178,202]]},"18:3":{"text":"And Ahab king of Israel said unto Jehoshaphat king of Judah, Wilt thou go with me to Ramothgilead? And he answered him, I am as thou art, and my people as thy people; and we will be with thee in the war.","words":[["H0256","And Ahab",0,8],["H4428","king",9,13],["H3478","of Israel",14,23],["H0559","said",24,28],["H3092","unto Jehoshaphat",29,45],["H4428","king",46,50],["H3063","of Judah",51,59],["H3212","Wilt thou go",61,73],["H7433","with me to Ramothgilead",74,97],["H1568","with me to Ramothgilead",74,97],["H0559","And he answered",99,114],["H5971","him, I am as thou art, and my people",115,151],["H5971","as thy people",152,165],["H4421","and we will be with thee in the war",167,202]]},"18:4":{"text":"And Jehoshaphat said unto the king of Israel, Enquire, I pray thee, at the word of the LORD to day.","words":[["H3092","And Jehoshaphat",0,15],["H0559","said",16,20],["H4428","unto the king",21,34],["H3478","of Israel",35,44],["H1875","Enquire",46,53],["H1697","I pray thee, at the word",55,79],["H3068","of the LORD",80,91],["H3117","to day",92,98]]},"18:5":{"text":"Therefore the king of Israel gathered together of prophets four hundred men, and said unto them, Shall we go to Ramothgilead to battle, or shall I forbear? And they said, Go up; for God will deliver it into the king's hand.","words":[["H4428","Therefore the king",0,18],["H3478","of Israel",19,28],["H6908","gathered together",29,46],["H5030","of prophets",47,58],["H0702","four",59,63],["H3967","hundred",64,71],["H0376","men",72,75],["H0559","and said",77,85],["H3212","unto them, Shall we go",86,108],["H7433","to Ramothgilead",109,124],["H1568","to Ramothgilead",109,124],["H4421","to battle",125,134],["H2308","or shall I forbear",136,154],["H0559","And they said",156,169],["H5927","Go up",171,176],["H0430","for God",178,185],["H5414","will deliver",186,198],["H4428","it into the king's",199,217],["H3027","hand",218,222]]},"18:6":{"text":"But Jehoshaphat said, Is there not here a prophet of the LORD besides, that we might enquire of him?","words":[["H3092","But Jehoshaphat",0,15],["H0559","said",16,20],["H5030","Is there not here a prophet",22,49],["H3068","of the LORD",50,61],["H1875","besides, that we might enquire",62,92]]},"18:7":{"text":"And the king of Israel said unto Jehoshaphat, There is yet one man, by whom we may enquire of the LORD: but I hate him; for he never prophesied good unto me, but always evil: the same is Micaiah the son of Imla. And Jehoshaphat said, Let not the king say so.","words":[["H4428","And the king",0,12],["H3478","of Israel",13,22],["H0559","said",23,27],["H3092","unto Jehoshaphat",28,44],["H0259","There is yet one",46,62],["H0376","man",63,66],["H1875","by whom we may enquire",68,90],["H3068","of the LORD",91,102],["H8130","but I hate",104,114],["H5012","him; for he never prophesied",115,143],["H2896","good",144,148],["H3117","unto me, but always",149,168],["H7451","evil",169,173],["H4321","the same is Micaiah",175,194],["H1121","the son",195,202],["H3229","of Imla",203,210],["H3092","And Jehoshaphat",212,227],["H0559","said",228,232],["H4428","Let not the king",234,250],["H0559","say",251,254]]},"18:8":{"text":"And the king of Israel called for one of his officers, and said, Fetch quickly Micaiah the son of Imla.","words":[["H4428","And the king",0,12],["H3478","of Israel",13,22],["H7121","called",23,29],["H0259","for one",30,37],["H5631","of his officers",38,53],["H0559","and said",55,63],["H4116","Fetch quickly",65,78],["H4319","Micaiah",79,86],["H1121","the son",87,94],["H3229","of Imla",95,102]]},"18:9":{"text":"And the king of Israel and Jehoshaphat king of Judah sat either of them on his throne, clothed in their robes, and they sat in a void place at the entering in of the gate of Samaria; and all the prophets prophesied before them.","words":[["H4428","And the king",0,12],["H3478","of Israel",13,22],["H3092","and Jehoshaphat",23,38],["H4428","king",39,43],["H3063","of Judah",44,52],["H3427","sat",53,56],["H0376","either",57,63],["H3678","of them on his throne",64,85],["H3847","clothed",87,94],["H0899","in their robes",95,109],["H3427","and they sat",111,123],["H1637","in a void place",124,139],["H6607","at the entering in",140,158],["H8179","of the gate",159,170],["H8111","of Samaria",171,181],["H5030","and all the prophets",183,203],["H5012","prophesied",204,214],["H6440","before",215,221]]},"18:10":{"text":"And Zedekiah the son of Chenaanah had made him horns of iron, and said, Thus saith the LORD, With these thou shalt push Syria until they be consumed.","words":[["H6667","And Zedekiah",0,12],["H1121","the son",13,20],["H3668","of Chenaanah",21,33],["H6213","had made",34,42],["H7161","him horns",43,52],["H1270","of iron",53,60],["H0559","and said",62,70],["H0559","Thus saith",72,82],["H3068","the LORD",83,91],["H5055","With these thou shalt push",93,119],["H0758","Syria",120,125],["H3615","until they be consumed",126,148]]},"18:11":{"text":"And all the prophets prophesied so, saying, Go up to Ramothgilead, and prosper: for the LORD shall deliver it into the hand of the king.","words":[["H5030","And all the prophets",0,20],["H5012","prophesied",21,31],["H0559","so, saying",32,42],["H5927","Go up",44,49],["H7433","to Ramothgilead",50,65],["H1568","to Ramothgilead",50,65],["H6743","and prosper",67,78],["H3068","for the LORD",80,92],["H5414","shall deliver",93,106],["H3027","it into the hand",107,123],["H4428","of the king",124,135]]},"18:12":{"text":"And the messenger that went to call Micaiah spake to him, saying, Behold, the words of the prophets declare good to the king with one assent; let thy word therefore, I pray thee, be like one of theirs, and speak thou good.","words":[["H4397","And the messenger",0,17],["H1980","that went",18,27],["H7121","to call",28,35],["H4321","Micaiah",36,43],["H1696","spake",44,49],["H0559","to him, saying",50,64],["H1697","Behold, the words",66,83],["H5030","of the prophets",84,99],["H2896","declare good",100,112],["H4428","to the king",113,124],["H0259","with one",125,133],["H6310","assent",134,140],["H1697","let thy word",142,154],["H0259","therefore, I pray thee, be like one",155,190],["H1696","of theirs, and speak",191,211],["H2896","thou good",212,221]]},"18:13":{"text":"And Micaiah said, As the LORD liveth, even what my God saith, that will I speak.","words":[["H4321","And Micaiah",0,11],["H0559","said",12,16],["H3068","As the LORD",18,29],["H2416","liveth",30,36],["H0430","even what my God",38,54],["H0559","saith",55,60],["H1696","that will I speak",62,79]]},"18:14":{"text":"And when he was come to the king, the king said unto him, Micaiah, shall we go to Ramothgilead to battle, or shall I forbear? And he said, Go ye up, and prosper, and they shall be delivered into your hand.","words":[["H0935","And when he was come",0,20],["H4428","to the king",21,32],["H4428","the king",34,42],["H0559","said",43,47],["H4318","unto him, Micaiah",48,65],["H3212","shall we go",67,78],["H7433","to Ramothgilead",79,94],["H1568","to Ramothgilead",79,94],["H4421","to battle",95,104],["H2308","or shall I forbear",106,124],["H0559","And he said",126,137],["H5927","Go ye up",139,147],["H6743","and prosper",149,160],["H5414","and they shall be delivered",162,189],["H3027","into your hand",190,204]]},"18:15":{"text":"And the king said to him, How many times shall I adjure thee that thou say nothing but the truth to me in the name of the LORD?","words":[["H4428","And the king",0,12],["H0559","said",13,17],["H6471","to him, How many times",18,40],["H7650","shall I adjure",41,55],["H1696","thee that thou say",56,74],["H0571","nothing but the truth",75,96],["H8034","to me in the name",97,114],["H3068","of the LORD",115,126]]},"18:16":{"text":"Then he said, I did see all Israel scattered upon the mountains, as sheep that have no shepherd: and the LORD said, These have no master; let them return therefore every man to his house in peace.","words":[["H0559","Then he said",0,12],["H7200","I did see",14,23],["H3478","all Israel",24,34],["H6327","scattered",35,44],["H2022","upon the mountains",45,63],["H6629","as sheep",65,73],["H7462","that have no shepherd",74,95],["H3068","and the LORD",97,109],["H0559","said",110,114],["H0113","These have no master",116,136],["H7725","let them return",138,153],["H0376","therefore every man",154,173],["H1004","to his house",174,186],["H7965","in peace",187,195]]},"18:17":{"text":"And the king of Israel said to Jehoshaphat, Did I not tell thee that he would not prophesy good unto me, but evil?","words":[["H4428","And the king",0,12],["H3478","of Israel",13,22],["H0559","said",23,27],["H3092","to Jehoshaphat",28,42],["H0559","Did I not tell",44,58],["H5012","thee that he would not prophesy",59,90],["H2896","good",91,95],["H7451","unto me, but evil",96,113]]},"18:18":{"text":"Again he said, Therefore hear the word of the LORD; I saw the LORD sitting upon his throne, and all the host of heaven standing on his right hand and on his left.","words":[["H0559","Again he said",0,13],["H8085","Therefore hear",15,29],["H1697","the word",30,38],["H3068","of the LORD",39,50],["H7200","I saw",52,57],["H3068","the LORD",58,66],["H3427","sitting",67,74],["H3678","upon his throne",75,90],["H6635","and all the host",92,108],["H8064","of heaven",109,118],["H5975","standing",119,127],["H3225","on his right hand",128,145],["H8040","and on his left",146,161]]},"18:19":{"text":"And the LORD said, Who shall entice Ahab king of Israel, that he may go up and fall at Ramothgilead? And one spake saying after this manner, and another saying after that manner.","words":[["H3068","And the LORD",0,12],["H0559","said",13,17],["H6601","Who shall entice",19,35],["H0256","Ahab",36,40],["H4428","king",41,45],["H3478","of Israel",46,55],["H5927","that he may go up",57,74],["H5307","and fall",75,83],["H7433","at Ramothgilead",84,99],["H1568","at Ramothgilead",84,99],["H0559","And one spake",101,114],["H0559","saying",115,121],["H3602","after this manner",122,139],["H0559","and another saying",141,159],["H3602","after that manner",160,177]]},"18:20":{"text":"Then there came out a spirit, and stood before the LORD, and said, I will entice him. And the LORD said unto him, Wherewith?","words":[["H3318","Then there came out",0,19],["H7307","a spirit",20,28],["H5975","and stood",30,39],["H6440","before",40,46],["H3068","the LORD",47,55],["H0559","and said",57,65],["H6601","I will entice",67,80],["H3068","him. And the LORD",81,98],["H0559","said",99,103]]},"18:21":{"text":"And he said, I will go out, and be a lying spirit in the mouth of all his prophets. And the LORD said, Thou shalt entice him, and thou shalt also prevail: go out, and do even so.","words":[["H0559","And he said",0,11],["H3318","I will go out",13,26],["H8267","and be a lying",28,42],["H7307","spirit",43,49],["H6310","in the mouth",50,62],["H5030","of all his prophets",63,82],["H0559","And the LORD said",84,101],["H6601","Thou shalt entice",103,120],["H3201","him, and thou shalt also prevail",121,153],["H3318","go out",155,161],["H6213","and do",163,169]]},"18:22":{"text":"Now therefore, behold, the LORD hath put a lying spirit in the mouth of these thy prophets, and the LORD hath spoken evil against thee.","words":[["H3068","Now therefore, behold, the LORD",0,31],["H5414","hath put",32,40],["H8267","a lying",41,48],["H7307","spirit",49,55],["H6310","in the mouth",56,68],["H5030","of these thy prophets",69,90],["H3068","and the LORD",92,104],["H1696","hath spoken",105,116],["H7451","evil",117,121]]},"18:23":{"text":"Then Zedekiah the son of Chenaanah came near, and smote Micaiah upon the cheek, and said, Which way went the Spirit of the LORD from me to speak unto thee?","words":[["H6667","Then Zedekiah",0,13],["H1121","the son",14,21],["H3668","of Chenaanah",22,34],["H5066","came near",35,44],["H5221","and smote",46,55],["H4321","Micaiah",56,63],["H3895","upon the cheek",64,78],["H0559","and said",80,88],["H0335","Which",90,95],["H1870","way",96,99],["H5674","went",100,104],["H7307","the Spirit",105,115],["H3068","of the LORD",116,127],["H1696","from me to speak",128,144]]},"18:24":{"text":"And Micaiah said, Behold, thou shalt see on that day when thou shalt go into an inner chamber to hide thyself.","words":[["H4321","And Micaiah",0,11],["H0559","said",12,16],["H7200","Behold, thou shalt see",18,40],["H3117","on that day",41,52],["H0935","when thou shalt go",53,71],["H2315","into an inner",72,85],["H2315","chamber",86,93],["H2244","to hide",94,101]]},"18:25":{"text":"Then the king of Israel said, Take ye Micaiah, and carry him back to Amon the governor of the city, and to Joash the king's son;","words":[["H4428","Then the king",0,13],["H3478","of Israel",14,23],["H0559","said",24,28],["H3947","Take",30,34],["H4321","ye Micaiah",35,45],["H7725","and carry him back",47,65],["H0526","to Amon",66,73],["H8269","the governor",74,86],["H5892","of the city",87,98],["H3101","and to Joash",100,112],["H4428","the king's",113,123],["H1121","son",124,127]]},"18:26":{"text":"And say, Thus saith the king, Put this fellow in the prison, and feed him with bread of affliction and with water of affliction, until I return in peace.","words":[["H0559","And say",0,7],["H0559","Thus saith",9,19],["H4428","the king",20,28],["H7760","Put",30,33],["H1004","this fellow in the prison",34,59],["H3608","this fellow in the prison",34,59],["H0398","and feed",61,69],["H3899","him with bread",70,84],["H3906","of affliction",85,98],["H4325","and with water",99,113],["H3906","of affliction",114,127],["H7725","until I return",129,143],["H7965","in peace",144,152]]},"18:27":{"text":"And Micaiah said, If thou certainly return in peace, then hath not the LORD spoken by me. And he said, Hearken, all ye people.","words":[["H4321","And Micaiah",0,11],["H0559","said",12,16],["H7725","If thou certainly",18,35],["H7725","return",36,42],["H7965","in peace",43,51],["H3068","then hath not the LORD",53,75],["H1696","spoken",76,82],["H0559","by me. And he said",83,101],["H8085","Hearken",103,110],["H5971","all ye people",112,125]]},"18:28":{"text":"So the king of Israel and Jehoshaphat the king of Judah went up to Ramothgilead.","words":[["H4428","So the king",0,11],["H3478","of Israel",12,21],["H3092","and Jehoshaphat",22,37],["H4428","the king",38,46],["H3063","of Judah",47,55],["H5927","went up",56,63],["H7433","to Ramothgilead",64,79],["H1568","to Ramothgilead",64,79]]},"18:29":{"text":"And the king of Israel said unto Jehoshaphat, I will disguise myself, and will go to the battle; but put thou on thy robes. So the king of Israel disguised himself; and they went to the battle.","words":[["H4428","And the king",0,12],["H3478","of Israel",13,22],["H0559","said",23,27],["H3092","unto Jehoshaphat",28,44],["H2664","I will disguise",46,61],["H0935","myself, and will go",62,81],["H4421","to the battle",82,95],["H3847","but put",97,104],["H0899","thou on thy robes",105,122],["H4428","So the king",124,135],["H3478","of Israel",136,145],["H2664","disguised",146,155],["H0935","himself; and they went",156,178],["H4421","to the battle",179,192]]},"18:30":{"text":"Now the king of Syria had commanded the captains of the chariots that were with him, saying, Fight ye not with small or great, save only with the king of Israel.","words":[["H4428","Now the king",0,12],["H0758","of Syria",13,21],["H6680","had commanded",22,35],["H8269","the captains",36,48],["H7393","of the chariots",49,64],["H0559","that were with him, saying",65,91],["H3898","Fight",93,98],["H6996","ye not with small",99,116],["H1419","or great",117,125],["H4428","save only with the king",127,150],["H3478","of Israel",151,160]]},"18:31":{"text":"And it came to pass, when the captains of the chariots saw Jehoshaphat, that they said, It is the king of Israel. Therefore they compassed about him to fight: but Jehoshaphat cried out, and the LORD helped him; and God moved them to depart from him.","words":[["H8269","And it came to pass, when the captains",0,38],["H7393","of the chariots",39,54],["H7200","saw",55,58],["H3092","Jehoshaphat",59,70],["H0559","that they said",72,86],["H4428","It is the king",88,102],["H3478","of Israel",103,112],["H5437","Therefore they compassed about",114,144],["H3898","him to fight",145,157],["H3092","but Jehoshaphat",159,174],["H2199","cried out",175,184],["H3068","and the LORD",186,198],["H5826","helped",199,205],["H0430","him; and God",206,218],["H5496","moved",219,224]]},"18:32":{"text":"For it came to pass, that, when the captains of the chariots perceived that it was not the king of Israel, they turned back again from pursuing him.","words":[["H8269","For it came to pass, that, when the captains",0,44],["H7393","of the chariots",45,60],["H7200","perceived",61,70],["H4428","that it was not the king",71,95],["H3478","of Israel",96,105],["H7725","they turned back again",107,129],["H0310","from pursuing",130,143]]},"18:33":{"text":"And a certain man drew a bow at a venture, and smote the king of Israel between the joints of the harness: therefore he said to his chariot man, Turn thine hand, that thou mayest carry me out of the host; for I am wounded.","words":[["H4900","And a certain man drew",0,22],["H7198","a bow",23,28],["H8537","at a venture",29,41],["H5221","and smote",43,52],["H4428","the king",53,61],["H3478","of Israel",62,71],["H1694","between the joints",72,90],["H8302","of the harness",91,105],["H0559","therefore he said",107,124],["H7395","to his chariot",125,139],["H0376","man",140,143],["H2015","Turn",145,149],["H3027","thine hand",150,160],["H3318","that thou mayest carry me out",162,191],["H4264","of the host",192,203],["H2470","for I am wounded",205,221]]},"18:34":{"text":"And the battle increased that day: howbeit the king of Israel stayed himself up in his chariot against the Syrians until the even: and about the time of the sun going down he died.","words":[["H4421","And the battle",0,14],["H5927","increased",15,24],["H3117","that day",25,33],["H4428","howbeit the king",35,51],["H3478","of Israel",52,61],["H5975","stayed himself up",62,79],["H4818","in his chariot",80,94],["H5227","against",95,102],["H0758","the Syrians",103,114],["H6153","until the even",115,129],["H6256","and about the time",131,149],["H8121","of the sun",150,160],["H0935","going down",161,171],["H4191","he died",172,179]]},"19:1":{"text":"And Jehoshaphat the king of Judah returned to his house in peace to Jerusalem.","words":[["H3092","And Jehoshaphat",0,15],["H4428","the king",16,24],["H3063","of Judah",25,33],["H7725","returned",34,42],["H1004","to his house",43,55],["H7965","in peace",56,64],["H3389","to Jerusalem",65,77]]},"19:2":{"text":"And Jehu the son of Hanani the seer went out to meet him, and said to king Jehoshaphat, Shouldest thou help the ungodly, and love them that hate the LORD? therefore is wrath upon thee from before the LORD.","words":[["H3058","And Jehu",0,8],["H1121","the son",9,16],["H2607","of Hanani",17,26],["H2374","the seer",27,35],["H3318","went out",36,44],["H6440","to meet",45,52],["H0559","him, and said",53,66],["H4428","to king",67,74],["H3092","Jehoshaphat",75,86],["H5826","Shouldest thou help",88,107],["H7563","the ungodly",108,119],["H0157","and love",121,129],["H8130","them that hate",130,144],["H3068","the LORD",145,153],["H2063","therefore",155,164],["H7110","is wrath",165,173],["H6440","upon thee from before",174,195],["H3068","the LORD",196,204]]},"19:3":{"text":"Nevertheless there are good things found in thee, in that thou hast taken away the groves out of the land, and hast prepared thine heart to seek God.","words":[["H0061","Nevertheless",0,12],["H2896","there are good",13,27],["H1697","things",28,34],["H4672","found",35,40],["H1197","in thee, in that thou hast taken away",41,78],["H0842","the groves",79,89],["H0776","out of the land",90,105],["H3559","and hast prepared",107,124],["H3824","thine heart",125,136],["H1875","to seek",137,144],["H0430","God",145,148]]},"19:4":{"text":"And Jehoshaphat dwelt at Jerusalem: and he went out again through the people from Beersheba to mount Ephraim, and brought them back unto the LORD God of their fathers.","words":[["H3092","And Jehoshaphat",0,15],["H3427","dwelt",16,21],["H3389","at Jerusalem",22,34],["H3318","and he went out",36,51],["H7725","again",52,57],["H5971","through the people",58,76],["H0884","from Beersheba",77,91],["H2022","to mount",92,100],["H0669","Ephraim",101,108],["H7725","and brought them back",110,131],["H3068","unto the LORD",132,145],["H0430","God",146,149],["H0001","of their fathers",150,166]]},"19:5":{"text":"And he set judges in the land throughout all the fenced cities of Judah, city by city,","words":[["H5975","And he set",0,10],["H8199","judges",11,17],["H0776","in the land",18,29],["H1219","throughout all the fenced",30,55],["H5892","cities",56,62],["H3063","of Judah",63,71],["H5892","city",73,77],["H5892","by city",78,85]]},"19:6":{"text":"And said to the judges, Take heed what ye do: for ye judge not for man, but for the LORD, who is with you in the judgment.","words":[["H0559","And said",0,8],["H8199","to the judges",9,22],["H7200","Take heed",24,33],["H6213","what ye do",34,44],["H8199","for ye judge",46,58],["H0120","not for man",59,70],["H3068","but for the LORD",72,88],["H1697","who is with you in the judgment",90,121],["H4941","who is with you in the judgment",90,121]]},"19:7":{"text":"Wherefore now let the fear of the LORD be upon you; take heed and do it: for there is no iniquity with the LORD our God, nor respect of persons, nor taking of gifts.","words":[["H6343","Wherefore now let the fear",0,26],["H3068","of the LORD",27,38],["H8104","be upon you; take heed",39,61],["H6213","and do",62,68],["H5766","it: for there is no iniquity",69,97],["H3068","with the LORD",98,111],["H0430","our God",112,119],["H4856","nor respect",121,132],["H6440","of persons",133,143],["H4727","nor taking",145,155],["H7810","of gifts",156,164]]},"19:8":{"text":"Moreover in Jerusalem did Jehoshaphat set of the Levites, and of the priests, and of the chief of the fathers of Israel, for the judgment of the LORD, and for controversies, when they returned to Jerusalem.","words":[["H3389","Moreover in Jerusalem",0,21],["H3092","did Jehoshaphat",22,37],["H5975","set",38,41],["H3881","of the Levites",42,56],["H3548","and of the priests",58,76],["H7218","and of the chief",78,94],["H0001","of the fathers",95,109],["H3478","of Israel",110,119],["H4941","for the judgment",121,137],["H3068","of the LORD",138,149],["H7379","and for controversies",151,172],["H7725","when they returned",174,192],["H3389","to Jerusalem",193,205]]},"19:9":{"text":"And he charged them, saying, Thus shall ye do in the fear of the LORD, faithfully, and with a perfect heart.","words":[["H6680","And he charged",0,14],["H0559","them, saying",15,27],["H6213","Thus shall ye do",29,45],["H3374","in the fear",46,57],["H3068","of the LORD",58,69],["H0530","faithfully",71,81],["H8003","and with a perfect",83,101],["H3824","heart",102,107]]},"19:10":{"text":"And what cause soever shall come to you of your brethren that dwell in their cities, between blood and blood, between law and commandment, statutes and judgments, ye shall even warn them that they trespass not against the LORD, and so wrath come upon you, and upon your brethren: this do, and ye shall not trespass.","words":[["H7379","And what cause",0,14],["H0935","soever shall come",15,32],["H0251","to you of your brethren",33,56],["H3427","that dwell",57,67],["H5892","in their cities",68,83],["H1818","between blood",85,98],["H1818","and blood",99,108],["H8451","between law",110,121],["H4687","and commandment",122,137],["H2706","statutes",139,147],["H4941","and judgments",148,161],["H2094","ye shall even warn",163,181],["H0816","them that they trespass",182,205],["H3068","not against the LORD",206,226],["H7110","and so wrath",228,240],["H0251","come upon you, and upon your brethren",241,278],["H3541","this",280,284],["H6213","do",285,287],["H0816","and ye shall not trespass",289,314]]},"19:11":{"text":"And, behold, Amariah the chief priest is over you in all matters of the LORD; and Zebadiah the son of Ishmael, the ruler of the house of Judah, for all the king's matters: also the Levites shall be officers before you. Deal courageously, and the LORD shall be with the good.","words":[["H0568","And, behold, Amariah",0,20],["H7218","the chief",21,30],["H3548","priest",31,37],["H1697","is over you in all matters",38,64],["H3068","of the LORD",65,76],["H2069","and Zebadiah",78,90],["H1121","the son",91,98],["H3458","of Ishmael",99,109],["H5057","the ruler",111,120],["H1004","of the house",121,133],["H3063","of Judah",134,142],["H4428","for all the king's",144,162],["H1697","matters",163,170],["H3881","also the Levites",172,188],["H7860","shall be officers",189,206],["H6440","before",207,213],["H6213","you. Deal",214,223],["H2388","courageously",224,236],["H3068","and the LORD",238,250],["H2896","shall be with the good",251,273]]},"20:1":{"text":"It came to pass after this also, that the children of Moab, and the children of Ammon, and with them other beside the Ammonites, came against Jehoshaphat to battle.","words":[["H0310","It came to pass after this",0,26],["H1121","also, that the children",27,50],["H4124","of Moab",51,58],["H1121","and the children",60,76],["H5983","of Ammon",77,85],["H5984","and with them other beside the Ammonites",87,127],["H0935","came",129,133],["H3092","against Jehoshaphat",134,153],["H4421","to battle",154,163]]},"20:2":{"text":"Then there came some that told Jehoshaphat, saying, There cometh a great multitude against thee from beyond the sea on this side Syria; and, behold, they be in Hazazontamar, which is Engedi.","words":[["H0935","Then there came",0,15],["H5046","some that told",16,30],["H3092","Jehoshaphat",31,42],["H0559","saying",44,50],["H0935","There cometh",52,64],["H7227","a great",65,72],["H1995","multitude",73,82],["H5676","against thee from beyond",83,107],["H3220","the sea",108,115],["H0758","on this side Syria",116,134],["H2688","and, behold, they be in Hazazontamar",136,172],["H5872","which is Engedi",174,189]]},"20:3":{"text":"And Jehoshaphat feared, and set himself to seek the LORD, and proclaimed a fast throughout all Judah.","words":[["H3092","And Jehoshaphat",0,15],["H3372","feared",16,22],["H5414","and set",24,31],["H6440","himself",32,39],["H1875","to seek",40,47],["H3068","the LORD",48,56],["H7121","and proclaimed",58,72],["H6685","a fast",73,79],["H5921","throughout",80,90],["H3063","all Judah",91,100]]},"20:4":{"text":"And Judah gathered themselves together, to ask help of the LORD: even out of all the cities of Judah they came to seek the LORD.","words":[["H3063","And Judah",0,9],["H6908","gathered themselves together",10,38],["H1245","to ask",40,46],["H3068","help of the LORD",47,63],["H5892","even out of all the cities",65,91],["H3063","of Judah",92,100],["H0935","they came",101,110],["H1245","to seek",111,118],["H3068","the LORD",119,127]]},"20:5":{"text":"And Jehoshaphat stood in the congregation of Judah and Jerusalem, in the house of the LORD, before the new court,","words":[["H3092","And Jehoshaphat",0,15],["H5975","stood",16,21],["H6951","in the congregation",22,41],["H3063","of Judah",42,50],["H3389","and Jerusalem",51,64],["H1004","in the house",66,78],["H3068","of the LORD",79,90],["H6440","before",92,98],["H2319","the new",99,106],["H2691","court",107,112]]},"20:6":{"text":"And said, O LORD God of our fathers, art not thou God in heaven? and rulest not thou over all the kingdoms of the heathen? and in thine hand is there not power and might, so that none is able to withstand thee?","words":[["H0559","And said",0,8],["H3068","O LORD",10,16],["H0430","God",17,20],["H0001","of our fathers",21,35],["H0430","art not thou God",37,53],["H8064","in heaven",54,63],["H4910","and rulest",65,75],["H4467","not thou over all the kingdoms",76,106],["H1471","of the heathen",107,121],["H3027","and in thine hand",123,140],["H3581","is there not power",141,159],["H1369","and might",160,169],["H3320","so that none is able to withstand",171,204]]},"20:7":{"text":"Art not thou our God, who didst drive out the inhabitants of this land before thy people Israel, and gavest it to the seed of Abraham thy friend for ever?","words":[["H0430","Art not thou our God",0,20],["H3423","who didst drive out",22,41],["H3427","the inhabitants",42,57],["H0776","of this land",58,70],["H6440","before",71,77],["H5971","thy people",78,88],["H3478","Israel",89,95],["H5414","and gavest",97,107],["H2233","it to the seed",108,122],["H0085","of Abraham",123,133],["H0157","thy friend",134,144],["H5769","for ever",145,153]]},"20:8":{"text":"And they dwelt therein, and have built thee a sanctuary therein for thy name, saying,","words":[["H3427","And they dwelt",0,14],["H1129","therein, and have built",15,38],["H4720","thee a sanctuary",39,55],["H8034","therein for thy name",56,76],["H0559","saying",78,84]]},"20:9":{"text":"If, when evil cometh upon us, as the sword, judgment, or pestilence, or famine, we stand before this house, and in thy presence, (for thy name is in this house,) and cry unto thee in our affliction, then thou wilt hear and help.","words":[["H7451","If, when evil",0,13],["H0935","cometh",14,20],["H2719","upon us, as the sword",21,42],["H8196","judgment",44,52],["H1698","or pestilence",54,67],["H7458","or famine",69,78],["H5975","we stand",80,88],["H6440","before",89,95],["H1004","this house",96,106],["H6440","and in thy presence",108,127],["H8034","(for thy name",129,142],["H1004","is in this house",143,159],["H2199",") and cry",160,169],["H6869","unto thee in our affliction",170,197],["H8085","then thou wilt hear",199,218],["H3467","and help",219,227]]},"20:10":{"text":"And now, behold, the children of Ammon and Moab and mount Seir, whom thou wouldest not let Israel invade, when they came out of the land of Egypt, but they turned from them, and destroyed them not;","words":[["H1121","And now, behold, the children",0,29],["H5983","of Ammon",30,38],["H4124","and Moab",39,47],["H2022","and mount",48,57],["H8165","Seir",58,62],["H5414","whom thou wouldest not let",64,90],["H3478","Israel",91,97],["H0935","invade",98,104],["H0935","when they came out",106,124],["H0776","of the land",125,136],["H4714","of Egypt",137,145],["H5493","but they turned",147,162],["H8045","from them, and destroyed",163,187]]},"20:11":{"text":"Behold, I say, how they reward us, to come to cast us out of thy possession, which thou hast given us to inherit.","words":[["H1580","Behold, I say, how they reward",0,30],["H0935","us, to come",31,42],["H1644","to cast us out",43,57],["H3425","of thy possession",58,75],["H3423","which thou hast given us to inherit",77,112]]},"20:12":{"text":"O our God, wilt thou not judge them? for we have no might against this great company that cometh against us; neither know we what to do: but our eyes are upon thee.","words":[["H0430","O our God",0,9],["H8199","wilt thou not judge",11,30],["H3581","them? for we have no might",31,57],["H6440","against",58,65],["H7227","this great",66,76],["H1995","company",77,84],["H0935","that cometh",85,96],["H3045","against us; neither know",97,121],["H0587","we",122,124],["H6213","what to do",125,135],["H5869","but our eyes",137,149]]},"20:13":{"text":"And all Judah stood before the LORD, with their little ones, their wives, and their children.","words":[["H3063","And all Judah",0,13],["H5975","stood",14,19],["H6440","before",20,26],["H3068","the LORD",27,35],["H1571","with",37,41],["H2945","their little ones",42,59],["H0802","their wives",61,72],["H1121","and their children",74,92]]},"20:14":{"text":"Then upon Jahaziel the son of Zechariah, the son of Benaiah, the son of Jeiel, the son of Mattaniah, a Levite of the sons of Asaph, came the Spirit of the LORD in the midst of the congregation;","words":[["H3166","Then upon Jahaziel",0,18],["H1121","the son",19,26],["H2148","of Zechariah",27,39],["H1121","the son",41,48],["H1141","of Benaiah",49,59],["H1121","the son",61,68],["H3273","of Jeiel",69,77],["H1121","the son",79,86],["H4983","of Mattaniah",87,99],["H3881","a Levite",101,109],["H1121","of the sons",110,121],["H0623","of Asaph",122,130],["H7307","came the Spirit",132,147],["H3068","of the LORD",148,159],["H8432","in the midst",160,172],["H6951","of the congregation",173,192]]},"20:15":{"text":"And he said, Hearken ye, all Judah, and ye inhabitants of Jerusalem, and thou king Jehoshaphat, Thus saith the LORD unto you, Be not afraid nor dismayed by reason of this great multitude; for the battle is not yours, but God's.","words":[["H0559","And he said",0,11],["H7181","Hearken",13,20],["H3063","ye, all Judah",21,34],["H3427","and ye inhabitants",36,54],["H3389","of Jerusalem",55,67],["H4428","and thou king",69,82],["H3092","Jehoshaphat",83,94],["H0559","Thus saith",96,106],["H3068","the LORD",107,115],["H3372","unto you, Be not afraid",116,139],["H2865","nor dismayed",140,152],["H6440","by reason",153,162],["H7227","of this great",163,176],["H1995","multitude",177,186],["H4421","for the battle",188,202],["H0430","is not yours, but God's",203,226]]},"20:16":{"text":"To morrow go ye down against them: behold, they come up by the cliff of Ziz; and ye shall find them at the end of the brook, before the wilderness of Jeruel.","words":[["H4279","To morrow",0,9],["H3381","go ye down",10,20],["H5927","against them: behold, they come up",21,55],["H4608","by the cliff",56,68],["H6732","of Ziz",69,75],["H4672","and ye shall find",77,94],["H5490","them at the end",95,110],["H5158","of the brook",111,123],["H6440","before",125,131],["H4057","the wilderness",132,146],["H3385","of Jeruel",147,156]]},"20:17":{"text":"Ye shall not need to fight in this battle: set yourselves, stand ye still, and see the salvation of the LORD with you, O Judah and Jerusalem: fear not, nor be dismayed; to morrow go out against them: for the LORD will be with you.","words":[["H3898","Ye shall not need to fight",0,26],["H2063","in this",27,34],["H3320","battle: set",35,46],["H5975","yourselves, stand",47,64],["H7200","ye still, and see",65,82],["H3444","the salvation",83,96],["H3068","of the LORD",97,108],["H3063","with you, O Judah",109,126],["H3389","and Jerusalem",127,140],["H3372","fear",142,146],["H2865","not, nor be dismayed",147,167],["H4279","to morrow",169,178],["H3318","go out",179,185],["H6440","against",186,193],["H3068","them: for the LORD",194,212]]},"20:18":{"text":"And Jehoshaphat bowed his head with his face to the ground: and all Judah and the inhabitants of Jerusalem fell before the LORD, worshipping the LORD.","words":[["H3092","And Jehoshaphat",0,15],["H6915","bowed",16,21],["H0639","his head with his face",22,44],["H0776","to the ground",45,58],["H3063","and all Judah",60,73],["H3427","and the inhabitants",74,93],["H3389","of Jerusalem",94,106],["H5307","fell",107,111],["H6440","before",112,118],["H3068","the LORD",119,127],["H7812","worshipping",129,140],["H3068","the LORD",141,149]]},"20:19":{"text":"And the Levites, of the children of the Kohathites, and of the children of the Korhites, stood up to praise the LORD God of Israel with a loud voice on high.","words":[["H3881","And the Levites",0,15],["H1121","of the children",17,32],["H6956","of the Kohathites",33,50],["H1121","and of the children",52,71],["H7145","of the Korhites",72,87],["H6965","stood up",89,97],["H1984","to praise",98,107],["H3068","the LORD",108,116],["H0430","God",117,120],["H3478","of Israel",121,130],["H1419","with a loud",131,142],["H6963","voice",143,148],["H4605","on high",149,156]]},"20:20":{"text":"And they rose early in the morning, and went forth into the wilderness of Tekoa: and as they went forth, Jehoshaphat stood and said, Hear me, O Judah, and ye inhabitants of Jerusalem; Believe in the LORD your God, so shall ye be established; believe his prophets, so shall ye prosper.","words":[["H7925","And they rose early",0,19],["H1242","in the morning",20,34],["H3318","and went forth",36,50],["H4057","into the wilderness",51,70],["H8620","of Tekoa",71,79],["H3318","and as they went forth",81,103],["H3092","Jehoshaphat",105,116],["H5975","stood",117,122],["H0559","and said",123,131],["H8085","Hear",133,137],["H3063","me, O Judah",138,149],["H3427","and ye inhabitants",151,169],["H3389","of Jerusalem",170,182],["H0539","Believe",184,191],["H3068","in the LORD",192,203],["H0430","your God",204,212],["H0539","so shall ye be established",214,240],["H0539","believe",242,249],["H5030","his prophets",250,262],["H6743","so shall ye prosper",264,283]]},"20:21":{"text":"And when he had consulted with the people, he appointed singers unto the LORD, and that should praise the beauty of holiness, as they went out before the army, and to say, Praise the LORD; for his mercy endureth for ever.","words":[["H3289","And when he had consulted",0,25],["H5971","with the people",26,41],["H5975","he appointed",43,55],["H7891","singers",56,63],["H3068","unto the LORD",64,77],["H1984","and that should praise",79,101],["H1927","the beauty",102,112],["H6944","of holiness",113,124],["H3318","as they went out",126,142],["H6440","before",143,149],["H2502","the army",150,158],["H0559","and to say",160,170],["H3034","Praise",172,178],["H3068","the LORD",179,187],["H2617","for his mercy",189,202],["H5769","endureth for ever",203,220]]},"20:22":{"text":"And when they began to sing and to praise, the LORD set ambushments against the children of Ammon, Moab, and mount Seir, which were come against Judah; and they were smitten.","words":[["H6256","And when",0,8],["H2490","they began",9,19],["H7440","to sing",20,27],["H8416","and to praise",28,41],["H3068","the LORD",43,51],["H5414","set",52,55],["H0693","ambushments",56,67],["H1121","against the children",68,88],["H5983","of Ammon",89,97],["H4124","Moab",99,103],["H2022","and mount",105,114],["H8165","Seir",115,119],["H0935","which were come",121,136],["H3063","against Judah",137,150],["H5062","and they were smitten",152,173]]},"20:23":{"text":"For the children of Ammon and Moab stood up against the inhabitants of mount Seir, utterly to slay and destroy them: and when they had made an end of the inhabitants of Seir, every one helped to destroy another.","words":[["H1121","For the children",0,16],["H5983","of Ammon",17,25],["H4124","and Moab",26,34],["H5975","stood up",35,43],["H3427","against the inhabitants",44,67],["H2022","of mount",68,76],["H8165","Seir",77,81],["H2763","utterly to slay",83,98],["H8045","and destroy",99,110],["H3615","them: and when they had made an end",111,146],["H3427","of the inhabitants",147,165],["H8165","of Seir",166,173],["H0376","every one",175,184],["H5826","helped",185,191],["H4889","to destroy",192,202],["H7453","another",203,210]]},"20:24":{"text":"And when Judah came toward the watch tower in the wilderness, they looked unto the multitude, and, behold, they were dead bodies fallen to the earth, and none escaped.","words":[["H3063","And when Judah",0,14],["H0935","came",15,19],["H4707","toward the watch tower",20,42],["H4708","toward the watch tower",20,42],["H4057","in the wilderness",43,60],["H6437","they looked",62,73],["H1995","unto the multitude",74,92],["H6297","and, behold, they were dead bodies",94,128],["H5307","fallen",129,135],["H0776","to the earth",136,148],["H6413","and none escaped",150,166]]},"20:25":{"text":"And when Jehoshaphat and his people came to take away the spoil of them, they found among them in abundance both riches with the dead bodies, and precious jewels, which they stripped off for themselves, more than they could carry away: and they were three days in gathering of the spoil, it was so much.","words":[["H3092","And when Jehoshaphat",0,20],["H5971","and his people",21,35],["H0935","came",36,40],["H0962","to take away",41,53],["H7998","the spoil",54,63],["H4672","of them, they found",64,83],["H7230","among them in abundance",84,107],["H7399","both riches",108,119],["H6297","with the dead bodies",120,140],["H2532","and precious",142,154],["H3627","jewels",155,161],["H5337","which they stripped off",163,186],["H0369","for themselves, more than",187,212],["H4853","they could carry away",213,234],["H7969","and they were three",236,255],["H3117","days",256,260],["H0962","in gathering",261,273],["H7998","of the spoil",274,286],["H7227","it was so much",288,302]]},"20:26":{"text":"And on the fourth day they assembled themselves in the valley of Berachah; for there they blessed the LORD: therefore the name of the same place was called, The valley of Berachah, unto this day.","words":[["H7243","And on the fourth",0,17],["H3117","day",18,21],["H6950","they assembled",22,36],["H6010","themselves in the valley",37,61],["H1294","of Berachah",62,73],["H1288","for there they blessed",75,97],["H3068","the LORD",98,106],["H8034","therefore the name",108,126],["H4725","of the same place",127,144],["H7121","was called",145,155],["H6010","The valley",157,167],["H1294","of Berachah",168,179],["H3117","unto this day",181,194]]},"20:27":{"text":"Then they returned, every man of Judah and Jerusalem, and Jehoshaphat in the forefront of them, to go again to Jerusalem with joy; for the LORD had made them to rejoice over their enemies.","words":[["H7725","Then they returned",0,18],["H0376","every man",20,29],["H3063","of Judah",30,38],["H3389","and Jerusalem",39,52],["H3092","and Jehoshaphat",54,69],["H7218","in the forefront",70,86],["H7725","of them, to go again",87,107],["H3389","to Jerusalem",108,120],["H8057","with joy",121,129],["H3068","for the LORD",131,143],["H8055","had made them to rejoice",144,168],["H0341","over their enemies",169,187]]},"20:28":{"text":"And they came to Jerusalem with psalteries and harps and trumpets unto the house of the LORD.","words":[["H0935","And they came",0,13],["H3389","to Jerusalem",14,26],["H5035","with psalteries",27,42],["H3658","and harps",43,52],["H2689","and trumpets",53,65],["H1004","unto the house",66,80],["H3068","of the LORD",81,92]]},"20:29":{"text":"And the fear of God was on all the kingdoms of those countries, when they had heard that the LORD fought against the enemies of Israel.","words":[["H6343","And the fear",0,12],["H0430","of God",13,19],["H4467","was on all the kingdoms",20,43],["H0776","of those countries",44,62],["H8085","when they had heard",64,83],["H3068","that the LORD",84,97],["H3898","fought",98,104],["H0341","against the enemies",105,124],["H3478","of Israel",125,134]]},"20:30":{"text":"So the realm of Jehoshaphat was quiet: for his God gave him rest round about.","words":[["H4438","So the realm",0,12],["H3092","of Jehoshaphat",13,27],["H8252","was quiet",28,37],["H0430","for his God",39,50],["H5117","gave him rest",51,64],["H5439","round about",65,76]]},"20:31":{"text":"And Jehoshaphat reigned over Judah: he was thirty and five years old when he began to reign, and he reigned twenty and five years in Jerusalem. And his mother's name was Azubah the daughter of Shilhi.","words":[["H3092","And Jehoshaphat",0,15],["H4427","reigned",16,23],["H3063","over Judah",24,34],["H7970","he was thirty",36,49],["H2568","and five",50,58],["H8141","years",59,64],["H1121","old",65,68],["H4427","when he began to reign",69,91],["H4427","and he reigned",93,107],["H6242","twenty",108,114],["H2568","and five",115,123],["H8141","years",124,129],["H3389","in Jerusalem",130,142],["H0517","And his mother's",144,160],["H8034","name",161,165],["H5806","was Azubah",166,176],["H1323","the daughter",177,189],["H7977","of Shilhi",190,199]]},"20:32":{"text":"And he walked in the way of Asa his father, and departed not from it, doing that which was right in the sight of the LORD.","words":[["H3212","And he walked",0,13],["H1870","in the way",14,24],["H0609","of Asa",25,31],["H0001","his father",32,42],["H5493","and departed",44,56],["H6213","not from it, doing",57,75],["H3477","that which was right",76,96],["H5869","in the sight",97,109],["H3068","of the LORD",110,121]]},"20:33":{"text":"Howbeit the high places were not taken away: for as yet the people had not prepared their hearts unto the God of their fathers.","words":[["H1116","Howbeit the high places",0,23],["H5493","were not taken away",24,43],["H5971","for as yet the people",45,66],["H3559","had not prepared",67,83],["H3824","their hearts",84,96],["H0430","unto the God",97,109],["H0001","of their fathers",110,126]]},"20:34":{"text":"Now the rest of the acts of Jehoshaphat, first and last, behold, they are written in the book of Jehu the son of Hanani, who is mentioned in the book of the kings of Israel.","words":[["H3499","Now the rest",0,12],["H1697","of the acts",13,24],["H3092","of Jehoshaphat",25,39],["H7223","first",41,46],["H0314","and last",47,55],["H3789","behold, they are written",57,81],["H1697","in the book",82,93],["H3058","of Jehu",94,101],["H1121","the son",102,109],["H2607","of Hanani",110,119],["H5927","who is mentioned",121,137],["H5612","in the book",138,149],["H4428","of the kings",150,162],["H3478","of Israel",163,172]]},"20:35":{"text":"And after this did Jehoshaphat king of Judah join himself with Ahaziah king of Israel, who did very wickedly:","words":[["H0310","And after",0,9],["H3092","this did Jehoshaphat",10,30],["H4428","king",31,35],["H3063","of Judah",36,44],["H2266","join",45,49],["H0274","himself with Ahaziah",50,70],["H4428","king",71,75],["H3478","of Israel",76,85],["H6213","who did",87,94],["H7561","very wickedly",95,108]]},"20:36":{"text":"And he joined himself with him to make ships to go to Tarshish: and they made the ships in Eziongeber.","words":[["H2266","And he joined",0,13],["H6213","himself with him to make",14,38],["H0591","ships",39,44],["H3212","to go",45,50],["H8659","to Tarshish",51,62],["H6213","and they made",64,77],["H0591","the ships",78,87],["H6100","in Eziongeber",88,101]]},"20:37":{"text":"Then Eliezer the son of Dodavah of Mareshah prophesied against Jehoshaphat, saying, Because thou hast joined thyself with Ahaziah, the LORD hath broken thy works. And the ships were broken, that they were not able to go to Tarshish.","words":[["H0461","Then Eliezer",0,12],["H1121","the son",13,20],["H1735","of Dodavah",21,31],["H4762","of Mareshah",32,43],["H5012","prophesied",44,54],["H3092","against Jehoshaphat",55,74],["H0559","saying",76,82],["H2266","Because thou hast joined",84,108],["H0274","thyself with Ahaziah",109,129],["H3068","the LORD",131,139],["H6555","hath broken",140,151],["H4639","thy works",152,161],["H0591","And the ships",163,176],["H7665","were broken",177,188],["H6113","that they were not able",190,213],["H3212","to go",214,219],["H8659","to Tarshish",220,231]]},"21:1":{"text":"Now Jehoshaphat slept with his fathers, and was buried with his fathers in the city of David. And Jehoram his son reigned in his stead.","words":[["H3092","Now Jehoshaphat",0,15],["H7901","slept",16,21],["H0001","with his fathers",22,38],["H6912","and was buried",40,54],["H0001","with his fathers",55,71],["H5892","in the city",72,83],["H1732","of David",84,92],["H3088","And Jehoram",94,105],["H1121","his son",106,113],["H4427","reigned",114,121]]},"21:2":{"text":"And he had brethren the sons of Jehoshaphat, Azariah, and Jehiel, and Zechariah, and Azariah, and Michael, and Shephatiah: all these were the sons of Jehoshaphat king of Israel.","words":[["H0251","And he had brethren",0,19],["H1121","the sons",20,28],["H3092","of Jehoshaphat",29,43],["H5838","Azariah",45,52],["H3171","and Jehiel",54,64],["H2148","and Zechariah",66,79],["H5838","and Azariah",81,92],["H4317","and Michael",94,105],["H8203","and Shephatiah",107,121],["H1121","all these were the sons",123,146],["H3092","of Jehoshaphat",147,161],["H4428","king",162,166],["H3478","of Israel",167,176]]},"21:3":{"text":"And their father gave them great gifts of silver, and of gold, and of precious things, with fenced cities in Judah: but the kingdom gave he to Jehoram; because he was the firstborn.","words":[["H0001","And their father",0,16],["H5414","gave",17,21],["H7227","them great",22,32],["H4979","gifts",33,38],["H3701","of silver",39,48],["H2091","and of gold",50,61],["H4030","and of precious things",63,85],["H4694","with fenced",87,98],["H5892","cities",99,105],["H3063","in Judah",106,114],["H4467","but the kingdom",116,131],["H5414","gave",132,136],["H3088","he to Jehoram",137,150],["H1060","because he was the firstborn",152,180]]},"21:4":{"text":"Now when Jehoram was risen up to the kingdom of his father, he strengthened himself, and slew all his brethren with the sword, and divers also of the princes of Israel.","words":[["H3088","Now when Jehoram",0,16],["H6965","was risen up",17,29],["H4467","to the kingdom",30,44],["H0001","of his father",45,58],["H2388","he strengthened",60,75],["H2026","himself, and slew",76,93],["H0251","all his brethren",94,110],["H2719","with the sword",111,125],["H8269","and divers also of the princes",127,157],["H3478","of Israel",158,167]]},"21:5":{"text":"Jehoram was thirty and two years old when he began to reign, and he reigned eight years in Jerusalem.","words":[["H3088","Jehoram",0,7],["H7970","was thirty",8,18],["H8147","and two",19,26],["H8141","years",27,32],["H1121","old",33,36],["H4427","when he began to reign",37,59],["H4427","and he reigned",61,75],["H8083","eight",76,81],["H8141","years",82,87],["H3389","in Jerusalem",88,100]]},"21:6":{"text":"And he walked in the way of the kings of Israel, like as did the house of Ahab: for he had the daughter of Ahab to wife: and he wrought that which was evil in the eyes of the LORD.","words":[["H3212","And he walked",0,13],["H1870","in the way",14,24],["H4428","of the kings",25,37],["H3478","of Israel",38,47],["H6213","like as did",49,60],["H1004","the house",61,70],["H0256","of Ahab",71,78],["H1323","for he had the daughter",80,103],["H0256","of Ahab",104,111],["H0802","to wife",112,119],["H6213","and he wrought",121,135],["H7451","that which was evil",136,155],["H5869","in the eyes",156,167],["H3068","of the LORD",168,179]]},"21:7":{"text":"Howbeit the LORD would not destroy the house of David, because of the covenant that he had made with David, and as he promised to give a light to him and to his sons for ever.","words":[["H3068","Howbeit the LORD",0,16],["H0014","would",17,22],["H7843","not destroy",23,34],["H1004","the house",35,44],["H1732","of David",45,53],["H1285","because of the covenant",55,78],["H3772","that he had made",79,95],["H1732","with David",96,106],["H0559","and as he promised",108,126],["H5414","to give",127,134],["H5216","a light",135,142],["H1121","to him and to his sons",143,165],["H3117","for ever",166,174]]},"21:8":{"text":"In his days the Edomites revolted from under the dominion of Judah, and made themselves a king.","words":[["H3117","In his days",0,11],["H0123","the Edomites",12,24],["H6586","revolted",25,33],["H3027","from under the dominion",34,57],["H3063","of Judah",58,66],["H4427","and made",68,76],["H4428","themselves a king",77,94]]},"21:9":{"text":"Then Jehoram went forth with his princes, and all his chariots with him: and he rose up by night, and smote the Edomites which compassed him in, and the captains of the chariots.","words":[["H3088","Then Jehoram",0,12],["H5674","went forth",13,23],["H8269","with his princes",24,40],["H7393","and all his chariots",42,62],["H6965","with him: and he rose up",63,87],["H3915","by night",88,96],["H5221","and smote",98,107],["H0123","the Edomites",108,120],["H5437","which compassed him in",121,143],["H8269","and the captains",145,161],["H7393","of the chariots",162,177]]},"21:10":{"text":"So the Edomites revolted from under the hand of Judah unto this day. The same time also did Libnah revolt from under his hand; because he had forsaken the LORD God of his fathers.","words":[["H0123","So the Edomites",0,15],["H6586","revolted",16,24],["H3027","from under the hand",25,44],["H3063","of Judah",45,53],["H3117","unto this day",54,67],["H6256","The same time",69,82],["H3841","also did Libnah",83,98],["H6586","revolt",99,105],["H3027","from under his hand",106,125],["H5800","because he had forsaken",127,150],["H3068","the LORD",151,159],["H0430","God",160,163],["H0001","of his fathers",164,178]]},"21:11":{"text":"Moreover he made high places in the mountains of Judah, and caused the inhabitants of Jerusalem to commit fornication, and compelled Judah thereto.","words":[["H6213","Moreover he made",0,16],["H1116","high places",17,28],["H2022","in the mountains",29,45],["H3063","of Judah",46,54],["H3427","and caused the inhabitants",56,82],["H3389","of Jerusalem",83,95],["H2181","to commit fornication",96,117],["H5080","and compelled",119,132],["H3063","Judah",133,138]]},"21:12":{"text":"And there came a writing to him from Elijah the prophet, saying, Thus saith the LORD God of David thy father, Because thou hast not walked in the ways of Jehoshaphat thy father, nor in the ways of Asa king of Judah,","words":[["H0935","And there came",0,14],["H4385","a writing",15,24],["H0452","to him from Elijah",25,43],["H5030","the prophet",44,55],["H0559","saying",57,63],["H0559","Thus saith",65,75],["H3068","the LORD",76,84],["H0430","God",85,88],["H1732","of David",89,97],["H0001","thy father",98,108],["H1980","Because thou hast not walked",110,138],["H1870","in the ways",139,150],["H3092","of Jehoshaphat",151,165],["H0001","thy father",166,176],["H1870","nor in the ways",178,193],["H0609","of Asa",194,200],["H4428","king",201,205],["H3063","of Judah",206,214]]},"21:13":{"text":"But hast walked in the way of the kings of Israel, and hast made Judah and the inhabitants of Jerusalem to go a whoring, like to the whoredoms of the house of Ahab, and also hast slain thy brethren of thy father's house, which were better than thyself:","words":[["H3212","But hast walked",0,15],["H1870","in the way",16,26],["H4428","of the kings",27,39],["H3478","of Israel",40,49],["H3063","and hast made Judah",51,70],["H3427","and the inhabitants",71,90],["H3389","of Jerusalem",91,103],["H2181","to go a whoring",104,119],["H2181","like to the whoredoms",121,142],["H1004","of the house",143,155],["H0256","of Ahab",156,163],["H2026","and also hast slain",165,184],["H0251","thy brethren",185,197],["H0001","of thy father's",198,213],["H1004","house",214,219],["H2896","which were better",221,238]]},"21:14":{"text":"Behold, with a great plague will the LORD smite thy people, and thy children, and thy wives, and all thy goods:","words":[["H1419","Behold, with a great",0,20],["H4046","plague",21,27],["H3068","will the LORD",28,41],["H5062","smite",42,47],["H5971","thy people",48,58],["H1121","and thy children",60,76],["H0802","and thy wives",78,91],["H7399","and all thy goods",93,110]]},"21:15":{"text":"And thou shalt have great sickness by disease of thy bowels, until thy bowels fall out by reason of the sickness day by day.","words":[["H7227","And thou shalt have great",0,25],["H2483","sickness",26,34],["H4245","by disease",35,45],["H4578","of thy bowels",46,59],["H4578","until thy bowels",61,77],["H3318","fall out",78,86],["H2483","by reason of the sickness",87,112],["H3117","day",113,116],["H3117","by day",117,123]]},"21:16":{"text":"Moreover the LORD stirred up against Jehoram the spirit of the Philistines, and of the Arabians, that were near the Ethiopians:","words":[["H3068","Moreover the LORD",0,17],["H5782","stirred up",18,28],["H3088","against Jehoram",29,44],["H7307","the spirit",45,55],["H6430","of the Philistines",56,74],["H6163","and of the Arabians",76,95],["H5921","that were near",97,111],["H3027","that were near",97,111],["H3569","the Ethiopians",112,126]]},"21:17":{"text":"And they came up into Judah, and brake into it, and carried away all the substance that was found in the king's house, and his sons also, and his wives; so that there was never a son left him, save Jehoahaz, the youngest of his sons.","words":[["H5927","And they came up",0,16],["H3063","into Judah",17,27],["H1234","and brake",29,38],["H7617","into it, and carried away",39,64],["H7399","all the substance",65,82],["H4672","that was found",83,97],["H4428","in the king's",98,111],["H1004","house",112,117],["H1121","and his sons",119,131],["H0802","also, and his wives",132,151],["H1121","so that there was never a son",153,182],["H7604","left",183,187],["H3059","him, save Jehoahaz",188,206],["H6996","the youngest",208,220],["H1121","of his sons",221,232]]},"21:18":{"text":"And after all this the LORD smote him in his bowels with an incurable disease.","words":[["H0310","And after",0,9],["H3068","all this the LORD",10,27],["H5062","smote",28,33],["H4578","him in his bowels",34,51],["H0369","with an incurable",52,69],["H4832","with an incurable",52,69],["H2483","disease",70,77]]},"21:19":{"text":"And it came to pass, that in process of time, after the end of two years, his bowels fell out by reason of his sickness: so he died of sore diseases. And his people made no burning for him, like the burning of his fathers.","words":[["H3117","And it came to pass, that in process of time",0,44],["H3318","after",46,51],["H6256","after",46,51],["H7093","the end",52,59],["H8147","of two",60,66],["H3117","years",67,72],["H4578","his bowels",74,84],["H3318","fell out",85,93],["H5973","by reason",94,103],["H2483","of his sickness",104,119],["H4191","so he died",121,131],["H7451","of sore",132,139],["H8463","diseases",140,148],["H5971","And his people",150,164],["H6213","made",165,169],["H8316","no burning",170,180],["H8316","for him, like the burning",181,206],["H0001","of his fathers",207,221]]},"21:20":{"text":"Thirty and two years old was he when he began to reign, and he reigned in Jerusalem eight years, and departed without being desired. Howbeit they buried him in the city of David, but not in the sepulchres of the kings.","words":[["H7970","Thirty",0,6],["H8147","and two",7,14],["H1121","years old",15,24],["H4427","was he when he began to reign",25,54],["H4427","and he reigned",56,70],["H3389","in Jerusalem",71,83],["H8083","eight",84,89],["H8141","years",90,95],["H3212","and departed",97,109],["H2532","without being desired",110,131],["H6912","Howbeit they buried",133,152],["H5892","him in the city",153,168],["H1732","of David",169,177],["H6913","but not in the sepulchres",179,204],["H4428","of the kings",205,217]]},"22:1":{"text":"And the inhabitants of Jerusalem made Ahaziah his youngest son king in his stead: for the band of men that came with the Arabians to the camp had slain all the eldest. So Ahaziah the son of Jehoram king of Judah reigned.","words":[["H3427","And the inhabitants",0,19],["H3389","of Jerusalem",20,32],["H4427","made",33,37],["H0274","Ahaziah",38,45],["H6996","his youngest",46,58],["H1121","son",59,62],["H4427","king",63,67],["H1416","in his stead: for the band of men",68,101],["H0935","that came",102,111],["H6163","with the Arabians",112,129],["H4264","to the camp",130,141],["H2026","had slain",142,151],["H7223","all the eldest",152,166],["H0274","So Ahaziah",168,178],["H1121","the son",179,186],["H3088","of Jehoram",187,197],["H4428","king",198,202],["H3063","of Judah",203,211],["H4427","reigned",212,219]]},"22:2":{"text":"Forty and two years old was Ahaziah when he began to reign, and he reigned one year in Jerusalem. His mother's name also was Athaliah the daughter of Omri.","words":[["H0705","Forty",0,5],["H8147","and two",6,13],["H8141","years",14,19],["H1121","old",20,23],["H0274","was Ahaziah",24,35],["H4427","when he began to reign",36,58],["H4427","and he reigned",60,74],["H0259","one",75,78],["H8141","year",79,83],["H3389","in Jerusalem",84,96],["H0517","His mother's",98,110],["H8034","name",111,115],["H6271","also was Athaliah",116,133],["H1323","the daughter",134,146],["H6018","of Omri",147,154]]},"22:3":{"text":"He also walked in the ways of the house of Ahab: for his mother was his counsellor to do wickedly.","words":[["H1980","He also walked",0,14],["H1870","in the ways",15,26],["H1004","of the house",27,39],["H0256","of Ahab",40,47],["H0517","for his mother",49,63],["H3289","was his counsellor",64,82],["H7561","to do wickedly",83,97]]},"22:4":{"text":"Wherefore he did evil in the sight of the LORD like the house of Ahab: for they were his counsellors after the death of his father to his destruction.","words":[["H6213","Wherefore he did",0,16],["H7451","evil",17,21],["H5869","in the sight",22,34],["H3068","of the LORD",35,46],["H1004","like the house",47,61],["H0256","of Ahab",62,69],["H3289","for they were his counsellors",71,100],["H0310","after",101,106],["H4194","the death",107,116],["H0001","of his father",117,130],["H4889","to his destruction",131,149]]},"22:5":{"text":"He walked also after their counsel, and went with Jehoram the son of Ahab king of Israel to war against Hazael king of Syria at Ramothgilead: and the Syrians smote Joram.","words":[["H1980","He walked",0,9],["H6098","also after their counsel",10,34],["H3212","and went",36,44],["H3088","with Jehoram",45,57],["H1121","the son",58,65],["H0256","of Ahab",66,73],["H4428","king",74,78],["H3478","of Israel",79,88],["H4421","to war",89,95],["H2371","against Hazael",96,110],["H4428","king",111,115],["H0758","of Syria",116,124],["H7433","at Ramothgilead",125,140],["H1568","at Ramothgilead",125,140],["H7421","and the Syrians",142,157],["H5221","smote",158,163],["H3141","Joram",164,169]]},"22:6":{"text":"And he returned to be healed in Jezreel because of the wounds which were given him at Ramah, when he fought with Hazael king of Syria. And Azariah the son of Jehoram king of Judah went down to see Jehoram the son of Ahab at Jezreel, because he was sick.","words":[["H7725","And he returned",0,15],["H7495","to be healed",16,28],["H3157","in Jezreel",29,39],["H4347","because of the wounds",40,61],["H5221","which were given",62,78],["H7414","him at Ramah",79,91],["H3898","when he fought",93,107],["H2371","with Hazael",108,119],["H4428","king",120,124],["H0758","of Syria",125,133],["H5838","And Azariah",135,146],["H1121","the son",147,154],["H3088","of Jehoram",155,165],["H4428","king",166,170],["H3063","of Judah",171,179],["H3381","went down",180,189],["H7200","to see",190,196],["H3088","Jehoram",197,204],["H1121","the son",205,212],["H0256","of Ahab",213,220],["H3157","at Jezreel",221,231],["H2470","because he was sick",233,252]]},"22:7":{"text":"And the destruction of Ahaziah was of God by coming to Joram: for when he was come, he went out with Jehoram against Jehu the son of Nimshi, whom the LORD had anointed to cut off the house of Ahab.","words":[["H8395","And the destruction",0,19],["H0274","of Ahaziah",20,30],["H0430","was of God",31,41],["H0935","by coming",42,51],["H3141","to Joram",52,60],["H0935","for when he was come",62,82],["H3318","he went out",84,95],["H3088","with Jehoram",96,108],["H3058","against Jehu",109,121],["H1121","the son",122,129],["H5250","of Nimshi",130,139],["H3068","whom the LORD",141,154],["H4886","had anointed",155,167],["H3772","to cut off",168,178],["H1004","the house",179,188],["H0256","of Ahab",189,196]]},"22:8":{"text":"And it came to pass, that, when Jehu was executing judgment upon the house of Ahab, and found the princes of Judah, and the sons of the brethren of Ahaziah, that ministered to Ahaziah, he slew them.","words":[["H3058","And it came to pass, that, when Jehu",0,36],["H8199","was executing judgment",37,59],["H1004","upon the house",60,74],["H0256","of Ahab",75,82],["H4672","and found",84,93],["H8269","the princes",94,105],["H3063","of Judah",106,114],["H1121","and the sons",116,128],["H0251","of the brethren",129,144],["H0274","of Ahaziah",145,155],["H8334","that ministered",157,172],["H0274","to Ahaziah",173,183],["H2026","he slew",185,192]]},"22:9":{"text":"And he sought Ahaziah: and they caught him, (for he was hid in Samaria,) and brought him to Jehu: and when they had slain him, they buried him: Because, said they, he is the son of Jehoshaphat, who sought the LORD with all his heart. So the house of Ahaziah had no power to keep still the kingdom.","words":[["H1245","And he sought",0,13],["H0274","Ahaziah",14,21],["H3920","and they caught",23,38],["H2244","him, (for he was hid",39,59],["H8111","in Samaria",60,70],["H0935",") and brought",71,84],["H3058","him to Jehu",85,96],["H4191","and when they had slain",98,121],["H6912","him, they buried",122,138],["H0559","him: Because, said",139,157],["H1121","they, he is the son",158,177],["H3092","of Jehoshaphat",178,192],["H1875","who sought",194,204],["H3068","the LORD",205,213],["H3824","with all his heart",214,232],["H1004","So the house",234,246],["H0274","of Ahaziah",247,257],["H3581","had no power",258,270],["H6113","to keep",271,278],["H4467","still the kingdom",279,296]]},"22:10":{"text":"But when Athaliah the mother of Ahaziah saw that her son was dead, she arose and destroyed all the seed royal of the house of Judah.","words":[["H6271","But when Athaliah",0,17],["H0517","the mother",18,28],["H0274","of Ahaziah",29,39],["H7200","saw",40,43],["H1121","that her son",44,56],["H4191","was dead",57,65],["H6965","she arose",67,76],["H1696","and destroyed",77,90],["H2233","all the seed",91,103],["H4467","royal",104,109],["H1004","of the house",110,122],["H3063","of Judah",123,131]]},"22:11":{"text":"But Jehoshabeath, the daughter of the king, took Joash the son of Ahaziah, and stole him from among the king's sons that were slain, and put him and his nurse in a bedchamber. So Jehoshabeath, the daughter of king Jehoram, the wife of Jehoiada the priest, (for she was the sister of Ahaziah,) hid him from Athaliah, so that she slew him not.","words":[["H3090","But Jehoshabeath",0,16],["H1323","the daughter",18,30],["H4428","of the king",31,42],["H3947","took",44,48],["H3101","Joash",49,54],["H1121","the son",55,62],["H0274","of Ahaziah",63,73],["H1589","and stole",75,84],["H8432","him from among",85,99],["H4428","the king's",100,110],["H1121","sons",111,115],["H4191","that were slain",116,131],["H5414","and put",133,140],["H3243","him and his nurse",141,158],["H2315","in a bedchamber",159,174],["H4296","in a bedchamber",159,174],["H3090","So Jehoshabeath",176,191],["H1323","the daughter",193,205],["H4428","of king",206,213],["H3088","Jehoram",214,221],["H0802","the wife",223,231],["H3077","of Jehoiada",232,243],["H3548","the priest",244,254],["H0269","(for she was the sister",256,279],["H0274","of Ahaziah",280,290],["H5641",") hid",291,296],["H6440","him from",297,305],["H6271","Athaliah",306,314],["H4191","so that she slew",316,332]]},"22:12":{"text":"And he was with them hid in the house of God six years: and Athaliah reigned over the land.","words":[["H2244","And he was with them hid",0,24],["H1004","in the house",25,37],["H0430","of God",38,44],["H8337","six",45,48],["H8141","years",49,54],["H6271","and Athaliah",56,68],["H4427","reigned",69,76],["H0776","over the land",77,90]]},"23:1":{"text":"And in the seventh year Jehoiada strengthened himself, and took the captains of hundreds, Azariah the son of Jeroham, and Ishmael the son of Jehohanan, and Azariah the son of Obed, and Maaseiah the son of Adaiah, and Elishaphat the son of Zichri, into covenant with him.","words":[["H7637","And in the seventh",0,18],["H8141","year",19,23],["H3077","Jehoiada",24,32],["H2388","strengthened",33,45],["H3947","himself, and took",46,63],["H8269","the captains",64,76],["H3967","of hundreds",77,88],["H5838","Azariah",90,97],["H1121","the son",98,105],["H3395","of Jeroham",106,116],["H3458","and Ishmael",118,129],["H1121","the son",130,137],["H3076","of Jehohanan",138,150],["H5838","and Azariah",152,163],["H1121","the son",164,171],["H5744","of Obed",172,179],["H4641","and Maaseiah",181,193],["H1121","the son",194,201],["H5718","of Adaiah",202,211],["H0478","and Elishaphat",213,227],["H1121","the son",228,235],["H2147","of Zichri",236,245],["H1285","into covenant",247,260]]},"23:2":{"text":"And they went about in Judah, and gathered the Levites out of all the cities of Judah, and the chief of the fathers of Israel, and they came to Jerusalem.","words":[["H5437","And they went about",0,19],["H3063","in Judah",20,28],["H6908","and gathered",30,42],["H3881","the Levites",43,54],["H5892","out of all the cities",55,76],["H3063","of Judah",77,85],["H7218","and the chief",87,100],["H0001","of the fathers",101,115],["H3478","of Israel",116,125],["H0935","and they came",127,140],["H3389","to Jerusalem",141,153]]},"23:3":{"text":"And all the congregation made a covenant with the king in the house of God. And he said unto them, Behold, the king's son shall reign, as the LORD hath said of the sons of David.","words":[["H6951","And all the congregation",0,24],["H3772","made",25,29],["H1285","a covenant",30,40],["H4428","with the king",41,54],["H1004","in the house",55,67],["H0430","of God",68,74],["H0559","And he said",76,87],["H4428","unto them, Behold, the king's",88,117],["H1121","son",118,121],["H4427","shall reign",122,133],["H3068","as the LORD",135,146],["H1696","hath said",147,156],["H1121","of the sons",157,168],["H1732","of David",169,177]]},"23:4":{"text":"This is the thing that ye shall do; A third part of you entering on the sabbath, of the priests and of the Levites, shall be porters of the doors;","words":[["H1697","This is the thing",0,17],["H6213","that ye shall do",18,34],["H7992","A third part",36,48],["H0935","of you entering",49,64],["H7676","on the sabbath",65,79],["H3548","of the priests",81,95],["H3881","and of the Levites",96,114],["H7778","shall be porters",116,132],["H5592","of the doors",133,145]]},"23:5":{"text":"And a third part shall be at the king's house; and a third part at the gate of the foundation: and all the people shall be in the courts of the house of the LORD.","words":[["H7992","And a third part",0,16],["H4428","shall be at the king's",17,39],["H1004","house",40,45],["H7992","and a third part",47,63],["H8179","at the gate",64,75],["H3247","of the foundation",76,93],["H5971","and all the people",95,113],["H2691","shall be in the courts",114,136],["H1004","of the house",137,149],["H3068","of the LORD",150,161]]},"23:6":{"text":"But let none come into the house of the LORD, save the priests, and they that minister of the Levites; they shall go in, for they are holy: but all the people shall keep the watch of the LORD.","words":[["H0935","But let none come",0,17],["H1004","into the house",18,32],["H3068","of the LORD",33,44],["H3548","save the priests",46,62],["H8334","and they that minister",64,86],["H3881","of the Levites",87,101],["H0935","they shall go in",103,119],["H6944","for they are holy",121,138],["H5971","but all the people",140,158],["H8104","shall keep",159,169],["H4931","the watch",170,179],["H3068","of the LORD",180,191]]},"23:7":{"text":"And the Levites shall compass the king round about, every man with his weapons in his hand; and whosoever else cometh into the house, he shall be put to death: but be ye with the king when he cometh in, and when he goeth out.","words":[["H3881","And the Levites",0,15],["H5362","shall compass",16,29],["H4428","the king",30,38],["H5439","round about",39,50],["H0376","every man",52,61],["H3627","with his weapons",62,78],["H3027","in his hand",79,90],["H0935","and whosoever else cometh",92,117],["H1004","into the house",118,132],["H4191","he shall be put to death",134,158],["H4428","but be ye with the king",160,183],["H0935","when he cometh in",184,201],["H3318","and when he goeth out",203,224]]},"23:8":{"text":"So the Levites and all Judah did according to all things that Jehoiada the priest had commanded, and took every man his men that were to come in on the sabbath, with them that were to go out on the sabbath: for Jehoiada the priest dismissed not the courses.","words":[["H3881","So the Levites",0,14],["H3063","and all Judah",15,28],["H6213","did",29,32],["H3077","according to all things that Jehoiada",33,70],["H3548","the priest",71,81],["H6680","had commanded",82,95],["H3947","and took",97,105],["H0376","every man",106,115],["H0582","his men",116,123],["H0935","that were to come in",124,144],["H7676","on the sabbath",145,159],["H3318","with them that were to go",161,186],["H7676","out on the sabbath",187,205],["H3077","for Jehoiada",207,219],["H3548","the priest",220,230],["H6358","dismissed",231,240],["H4256","not the courses",241,256]]},"23:9":{"text":"Moreover Jehoiada the priest delivered to the captains of hundreds spears, and bucklers, and shields, that had been king David's, which were in the house of God.","words":[["H3077","Moreover Jehoiada",0,17],["H3548","the priest",18,28],["H5414","delivered",29,38],["H8269","to the captains",39,54],["H3967","of hundreds",55,66],["H2595","spears",67,73],["H4043","and bucklers",75,87],["H7982","and shields",89,100],["H4428","that had been king",102,120],["H1732","David's",121,128],["H1004","which were in the house",130,153],["H0430","of God",154,160]]},"23:10":{"text":"And he set all the people, every man having his weapon in his hand, from the right side of the temple to the left side of the temple, along by the altar and the temple, by the king round about.","words":[["H5975","And he set",0,10],["H5971","all the people",11,25],["H0376","every man",27,36],["H7973","having his weapon",37,54],["H3027","in his hand",55,66],["H3233","from the right",68,82],["H3802","side",83,87],["H1004","of the temple",88,101],["H8042","to the left",102,113],["H3802","side",114,118],["H1004","of the temple",119,132],["H4196","along by the altar",134,152],["H1004","and the temple",153,167],["H4428","by the king",169,180],["H5439","round about",181,192]]},"23:11":{"text":"Then they brought out the king's son, and put upon him the crown, and gave him the testimony, and made him king. And Jehoiada and his sons anointed him, and said, God save the king.","words":[["H3318","Then they brought out",0,21],["H4428","the king's",22,32],["H1121","son",33,36],["H5414","and put",38,45],["H5145","upon him the crown",46,64],["H5715","and gave him the testimony",66,92],["H4427","and made him king",94,111],["H3077","And Jehoiada",113,125],["H1121","and his sons",126,138],["H4886","anointed",139,147],["H0559","him, and said",148,161],["H2421","God save",163,171],["H4428","the king",172,180]]},"23:12":{"text":"Now when Athaliah heard the noise of the people running and praising the king, she came to the people into the house of the LORD:","words":[["H6271","Now when Athaliah",0,17],["H8085","heard",18,23],["H6963","the noise",24,33],["H5971","of the people",34,47],["H7323","running",48,55],["H1984","and praising",56,68],["H4428","the king",69,77],["H0935","she came",79,87],["H5971","to the people",88,101],["H1004","into the house",102,116],["H3068","of the LORD",117,128]]},"23:13":{"text":"And she looked, and, behold, the king stood at his pillar at the entering in, and the princes and the trumpets by the king: and all the people of the land rejoiced, and sounded with trumpets, also the singers with instruments of musick, and such as taught to sing praise. Then Athaliah rent her clothes, and said, Treason, Treason.","words":[["H7200","And she looked",0,14],["H4428","and, behold, the king",16,37],["H5975","stood",38,43],["H5982","at his pillar",44,57],["H3996","at the entering in",58,76],["H8269","and the princes",78,93],["H2689","and the trumpets",94,110],["H4428","by the king",111,122],["H5971","and all the people",124,142],["H0776","of the land",143,154],["H8056","rejoiced",155,163],["H8628","and sounded",165,176],["H2689","with trumpets",177,190],["H7891","also the singers",192,208],["H3627","with instruments",209,225],["H7892","of musick",226,235],["H3045","and such as taught",237,255],["H1984","to sing praise",256,270],["H6271","Then Athaliah",272,285],["H7167","rent",286,290],["H0899","her clothes",291,302],["H0559","and said",304,312],["H7195","Treason",314,321],["H7195","Treason",323,330]]},"23:14":{"text":"Then Jehoiada the priest brought out the captains of hundreds that were set over the host, and said unto them, Have her forth of the ranges: and whoso followeth her, let him be slain with the sword. For the priest said, Slay her not in the house of the LORD.","words":[["H3077","Then Jehoiada",0,13],["H3548","the priest",14,24],["H3318","brought out",25,36],["H8269","the captains",37,49],["H3967","of hundreds",50,61],["H6485","that were set over",62,80],["H2428","the host",81,89],["H0559","and said",91,99],["H3318","unto them, Have her forth",100,125],["H1004","of the ranges",126,139],["H7713","of the ranges",126,139],["H0935","and whoso followeth",141,160],["H0310","and whoso followeth",141,160],["H4191","her, let him be slain",161,182],["H2719","with the sword",183,197],["H3548","For the priest",199,213],["H0559","said",214,218],["H4191","Slay",220,224],["H1004","her not in the house",225,245],["H3068","of the LORD",246,257]]},"23:15":{"text":"So they laid hands on her; and when she was come to the entering of the horse gate by the king's house, they slew her there.","words":[["H7760","So they laid",0,12],["H3027","hands",13,18],["H0935","on her; and when she was come",19,48],["H3996","to the entering",49,64],["H5483","of the horse",65,77],["H8179","gate",78,82],["H4428","by the king's",83,96],["H1004","house",97,102],["H4191","they slew",104,113]]},"23:16":{"text":"And Jehoiada made a covenant between him, and between all the people, and between the king, that they should be the LORD'S people.","words":[["H3077","And Jehoiada",0,12],["H3772","made",13,17],["H1285","a covenant",18,28],["H5971","between him, and between all the people",29,68],["H4428","and between the king",70,90],["H3068","that they should be the LORD'S",92,122],["H5971","people",123,129]]},"23:17":{"text":"Then all the people went to the house of Baal, and brake it down, and brake his altars and his images in pieces, and slew Mattan the priest of Baal before the altars.","words":[["H5971","Then all the people",0,19],["H0935","went",20,24],["H1004","to the house",25,37],["H1168","of Baal",38,45],["H5422","and brake it down",47,64],["H7665","and brake",66,75],["H4196","his altars",76,86],["H6754","and his images",87,101],["H7665","in pieces",102,111],["H2026","and slew",113,121],["H4977","Mattan",122,128],["H3548","the priest",129,139],["H1168","of Baal",140,147],["H6440","before",148,154],["H4196","the altars",155,165]]},"23:18":{"text":"Also Jehoiada appointed the offices of the house of the LORD by the hand of the priests the Levites, whom David had distributed in the house of the LORD, to offer the burnt offerings of the LORD, as it is written in the law of Moses, with rejoicing and with singing, as it was ordained by David.","words":[["H3077","Also Jehoiada",0,13],["H7760","appointed",14,23],["H6486","the offices",24,35],["H1004","of the house",36,48],["H3068","of the LORD",49,60],["H3027","by the hand",61,72],["H3548","of the priests",73,87],["H3881","the Levites",88,99],["H1732","whom David",101,111],["H2505","had distributed",112,127],["H1004","in the house",128,140],["H3068","of the LORD",141,152],["H5927","to offer",154,162],["H5930","the burnt offerings",163,182],["H3068","of the LORD",183,194],["H3789","as it is written",196,212],["H8451","in the law",213,223],["H4872","of Moses",224,232],["H8057","with rejoicing",234,248],["H7892","and with singing",249,265],["H3027","as it was ordained by",267,288],["H1732","David",289,294]]},"23:19":{"text":"And he set the porters at the gates of the house of the LORD, that none which was unclean in any thing should enter in.","words":[["H5975","And he set",0,10],["H7778","the porters",11,22],["H8179","at the gates",23,35],["H1004","of the house",36,48],["H3068","of the LORD",49,60],["H2931","that none which was unclean",62,89],["H1697","in any thing",90,102],["H0935","should enter in",103,118]]},"23:20":{"text":"And he took the captains of hundreds, and the nobles, and the governors of the people, and all the people of the land, and brought down the king from the house of the LORD: and they came through the high gate into the king's house, and set the king upon the throne of the kingdom.","words":[["H3947","And he took",0,11],["H8269","the captains",12,24],["H3967","of hundreds",25,36],["H0117","and the nobles",38,52],["H4910","and the governors",54,71],["H5971","of the people",72,85],["H5971","and all the people",87,105],["H0776","of the land",106,117],["H3381","and brought down",119,135],["H4428","the king",136,144],["H1004","from the house",145,159],["H3068","of the LORD",160,171],["H0935","and they came",173,186],["H8432","through",187,194],["H5945","the high",195,203],["H8179","gate",204,208],["H4428","into the king's",209,224],["H1004","house",225,230],["H3427","and set",232,239],["H4428","the king",240,248],["H3678","upon the throne",249,264],["H4467","of the kingdom",265,279]]},"23:21":{"text":"And all the people of the land rejoiced: and the city was quiet, after that they had slain Athaliah with the sword.","words":[["H5971","And all the people",0,18],["H0776","of the land",19,30],["H8055","rejoiced",31,39],["H5892","and the city",41,53],["H8252","was quiet",54,63],["H4191","after that they had slain",65,90],["H6271","Athaliah",91,99],["H2719","with the sword",100,114]]},"24:1":{"text":"Joash was seven years old when he began to reign, and he reigned forty years in Jerusalem. His mother's name also was Zibiah of Beersheba.","words":[["H3101","Joash",0,5],["H7651","was seven",6,15],["H8141","years",16,21],["H1121","old",22,25],["H4427","when he began to reign",26,48],["H4427","and he reigned",50,64],["H0705","forty",65,70],["H8141","years",71,76],["H3389","in Jerusalem",77,89],["H0517","His mother's",91,103],["H8034","name",104,108],["H6645","also was Zibiah",109,124],["H0884","of Beersheba",125,137]]},"24:2":{"text":"And Joash did that which was right in the sight of the LORD all the days of Jehoiada the priest.","words":[["H3101","And Joash",0,9],["H6213","did",10,13],["H3477","that which was right",14,34],["H5869","in the sight",35,47],["H3068","of the LORD",48,59],["H3117","all the days",60,72],["H3077","of Jehoiada",73,84],["H3548","the priest",85,95]]},"24:3":{"text":"And Jehoiada took for him two wives; and he begat sons and daughters.","words":[["H3077","And Jehoiada",0,12],["H5375","took",13,17],["H8147","for him two",18,29],["H0802","wives",30,35],["H3205","and he begat",37,49],["H1121","sons",50,54],["H1323","and daughters",55,68]]},"24:4":{"text":"And it came to pass after this, that Joash was minded to repair the house of the LORD.","words":[["H0310","And it came to pass after",0,25],["H3101","this, that Joash",26,42],["H3820","was minded",43,53],["H2318","to repair",54,63],["H1004","the house",64,73],["H3068","of the LORD",74,85]]},"24:5":{"text":"And he gathered together the priests and the Levites, and said to them, Go out unto the cities of Judah, and gather of all Israel money to repair the house of your God from year to year, and see that ye hasten the matter. Howbeit the Levites hastened it not.","words":[["H6908","And he gathered together",0,24],["H3548","the priests",25,36],["H3881","and the Levites",37,52],["H0559","and said",54,62],["H3318","to them, Go out",63,78],["H5892","unto the cities",79,94],["H3063","of Judah",95,103],["H6908","and gather",105,115],["H3478","of all Israel",116,129],["H3701","money",130,135],["H2388","to repair",136,145],["H1004","the house",146,155],["H0430","of your God",156,167],["H1767","from",168,172],["H8141","year",173,177],["H8141","to year",178,185],["H4116","and see that ye hasten",187,209],["H1697","the matter",210,220],["H3881","Howbeit the Levites",222,241],["H4116","hastened",242,250]]},"24:6":{"text":"And the king called for Jehoiada the chief, and said unto him, Why hast thou not required of the Levites to bring in out of Judah and out of Jerusalem the collection, according to the commandment of Moses the servant of the LORD, and of the congregation of Israel, for the tabernacle of witness?","words":[["H4428","And the king",0,12],["H7121","called",13,19],["H3077","for Jehoiada",20,32],["H7218","the chief",33,42],["H0559","and said",44,52],["H1875","unto him, Why hast thou not required",53,89],["H3881","of the Levites",90,104],["H0935","to bring in",105,116],["H3063","out of Judah",117,129],["H3389","and out of Jerusalem",130,150],["H4864","the collection",151,165],["H4872","according to the commandment of Moses",167,204],["H5650","the servant",205,216],["H3068","of the LORD",217,228],["H6951","and of the congregation",230,253],["H3478","of Israel",254,263],["H0168","for the tabernacle",265,283],["H5715","of witness",284,294]]},"24:7":{"text":"For the sons of Athaliah, that wicked woman, had broken up the house of God; and also all the dedicated things of the house of the LORD did they bestow upon Baalim.","words":[["H1121","For the sons",0,12],["H6271","of Athaliah",13,24],["H4849","that wicked",26,37],["H6555","woman, had broken up",38,58],["H1004","the house",59,68],["H0430","of God",69,75],["H6944","and also all the dedicated things",77,110],["H1004","of the house",111,123],["H3068","of the LORD",124,135],["H6213","did they bestow",136,151],["H1168","upon Baalim",152,163]]},"24:8":{"text":"And at the king's commandment they made a chest, and set it without at the gate of the house of the LORD.","words":[["H4428","And at the king's",0,17],["H0559","commandment",18,29],["H6213","they made",30,39],["H0259","a",40,41],["H0727","chest",42,47],["H5414","and set",49,56],["H2351","it without",57,67],["H8179","at the gate",68,79],["H1004","of the house",80,92],["H3068","of the LORD",93,104]]},"24:9":{"text":"And they made a proclamation through Judah and Jerusalem, to bring in to the LORD the collection that Moses the servant of God laid upon Israel in the wilderness.","words":[["H5414","And they made",0,13],["H6963","a proclamation",14,28],["H3063","through Judah",29,42],["H3389","and Jerusalem",43,56],["H0935","to bring in",58,69],["H3068","to the LORD",70,81],["H4864","the collection",82,96],["H4872","that Moses",97,107],["H5650","the servant",108,119],["H0430","of God",120,126],["H3478","laid upon Israel",127,143],["H4057","in the wilderness",144,161]]},"24:10":{"text":"And all the princes and all the people rejoiced, and brought in, and cast into the chest, until they had made an end.","words":[["H8269","And all the princes",0,19],["H5971","and all the people",20,38],["H8055","rejoiced",39,47],["H0935","and brought in",49,63],["H7993","and cast",65,73],["H0727","into the chest",74,88],["H3615","until they had made an end",90,116]]},"24:11":{"text":"Now it came to pass, that at what time the chest was brought unto the king's office by the hand of the Levites, and when they saw that there was much money, the king's scribe and the high priest's officer came and emptied the chest, and took it, and carried it to his place again. Thus they did day by day, and gathered money in abundance.","words":[["H6256","Now it came to pass, that at what time",0,38],["H0727","the chest",39,48],["H0935","was brought",49,60],["H4428","unto the king's",61,76],["H6486","office",77,83],["H3027","by the hand",84,95],["H3881","of the Levites",96,110],["H7200","and when they saw",112,129],["H7227","that there was much",130,149],["H3701","money",150,155],["H4428","the king's",157,167],["H5608","scribe",168,174],["H7218","and the high",175,187],["H3548","priest's",188,196],["H6496","officer",197,204],["H0935","came",205,209],["H6168","and emptied",210,221],["H0727","the chest",222,231],["H5375","and took",233,241],["H7725","it, and carried",242,257],["H4725","it to his place",258,273],["H7725","again",274,279],["H6213","Thus they did",281,294],["H3117","day",295,298],["H3117","by day",299,305],["H0622","and gathered",307,319],["H3701","money",320,325],["H7230","in abundance",326,338]]},"24:12":{"text":"And the king and Jehoiada gave it to such as did the work of the service of the house of the LORD, and hired masons and carpenters to repair the house of the LORD, and also such as wrought iron and brass to mend the house of the LORD.","words":[["H4428","And the king",0,12],["H3077","and Jehoiada",13,25],["H5414","gave",26,30],["H6213","it to such as did",31,48],["H4399","the work",49,57],["H5656","of the service",58,72],["H1004","of the house",73,85],["H3068","of the LORD",86,97],["H7936","and hired",99,108],["H2672","masons",109,115],["H2796","and carpenters",116,130],["H2318","to repair",131,140],["H1004","the house",141,150],["H3068","of the LORD",151,162],["H2796","and also such as wrought",164,188],["H1270","iron",189,193],["H5178","and brass",194,203],["H2388","to mend",204,211],["H1004","the house",212,221],["H3068","of the LORD",222,233]]},"24:13":{"text":"So the workmen wrought, and the work was perfected by them, and they set the house of God in his state, and strengthened it.","words":[["H4399","So the workmen",0,14],["H6213","So the workmen",0,14],["H6213","wrought",15,22],["H4399","and the work",24,36],["H5927","was",37,40],["H0724","perfected",41,50],["H3027","by them",51,58],["H5975","and they set",60,72],["H1004","the house",73,82],["H0430","of God",83,89],["H4971","in his state",90,102],["H0553","and strengthened",104,120]]},"24:14":{"text":"And when they had finished it, they brought the rest of the money before the king and Jehoiada, whereof were made vessels for the house of the LORD, even vessels to minister, and to offer withal, and spoons, and vessels of gold and silver. And they offered burnt offerings in the house of the LORD continually all the days of Jehoiada.","words":[["H3615","And when they had finished",0,26],["H0935","it, they brought",27,43],["H7605","the rest",44,52],["H3701","of the money",53,65],["H6440","before",66,72],["H4428","the king",73,81],["H3077","and Jehoiada",82,94],["H6213","whereof were made",96,113],["H3627","vessels",114,121],["H1004","for the house",122,135],["H3068","of the LORD",136,147],["H3627","even vessels",149,161],["H8335","to minister",162,173],["H5927","and to offer",175,187],["H3709","withal, and spoons",188,206],["H3627","and vessels",208,219],["H2091","of gold",220,227],["H3701","and silver",228,238],["H5927","And they offered",240,256],["H5930","burnt offerings",257,272],["H1004","in the house",273,285],["H3068","of the LORD",286,297],["H8548","continually",298,309],["H3117","all the days",310,322],["H3077","of Jehoiada",323,334]]},"24:15":{"text":"But Jehoiada waxed old, and was full of days when he died; an hundred and thirty years old was he when he died.","words":[["H3077","But Jehoiada",0,12],["H2204","waxed old",13,22],["H7646","and was full",24,36],["H3117","of days",37,44],["H4191","when he died",45,57],["H3967","an hundred",59,69],["H7970","and thirty",70,80],["H8141","years",81,86],["H1121","old",87,90],["H4194","was he when he died",91,110]]},"24:16":{"text":"And they buried him in the city of David among the kings, because he had done good in Israel, both toward God, and toward his house.","words":[["H6912","And they buried",0,15],["H5892","him in the city",16,31],["H1732","of David",32,40],["H4428","among the kings",41,56],["H6213","because he had done",58,77],["H2896","good",78,82],["H3478","in Israel",83,92],["H0430","both toward God",94,109],["H1004","and toward his house",111,131]]},"24:17":{"text":"Now after the death of Jehoiada came the princes of Judah, and made obeisance to the king. Then the king hearkened unto them.","words":[["H0310","Now after",0,9],["H4194","the death",10,19],["H3077","of Jehoiada",20,31],["H0935","came",32,36],["H8269","the princes",37,48],["H3063","of Judah",49,57],["H7812","and made obeisance",59,77],["H4428","to the king",78,89],["H4428","Then the king",91,104],["H8085","hearkened",105,114]]},"24:18":{"text":"And they left the house of the LORD God of their fathers, and served groves and idols: and wrath came upon Judah and Jerusalem for this their trespass.","words":[["H5800","And they left",0,13],["H1004","the house",14,23],["H3068","of the LORD",24,35],["H0430","God",36,39],["H0001","of their fathers",40,56],["H5647","and served",58,68],["H0842","groves",69,75],["H6091","and idols",76,85],["H7110","and wrath",87,96],["H3063","came upon Judah",97,112],["H3389","and Jerusalem",113,126],["H0819","for this their trespass",127,150]]},"24:19":{"text":"Yet he sent prophets to them, to bring them again unto the LORD; and they testified against them: but they would not give ear.","words":[["H7971","Yet he sent",0,11],["H5030","prophets",12,20],["H7725","to them, to bring them again",21,49],["H3068","unto the LORD",50,63],["H5749","and they testified",65,83],["H0238","against them: but they would not give ear",84,125]]},"24:20":{"text":"And the Spirit of God came upon Zechariah the son of Jehoiada the priest, which stood above the people, and said unto them, Thus saith God, Why transgress ye the commandments of the LORD, that ye cannot prosper? because ye have forsaken the LORD, he hath also forsaken you.","words":[["H7307","And the Spirit",0,14],["H0430","of God",15,21],["H3847","came",22,26],["H2148","upon Zechariah",27,41],["H1121","the son",42,49],["H3077","of Jehoiada",50,61],["H3548","the priest",62,72],["H5975","which stood",74,85],["H5971","above the people",86,102],["H0559","and said",104,112],["H0559","unto them, Thus saith",113,134],["H0430","God",135,138],["H5674","Why transgress",140,154],["H4687","ye the commandments",155,174],["H3068","of the LORD",175,186],["H6743","that ye cannot prosper",188,210],["H5800","because ye have forsaken",212,236],["H3068","the LORD",237,245],["H5800","he hath also forsaken",247,268]]},"24:21":{"text":"And they conspired against him, and stoned him with stones at the commandment of the king in the court of the house of the LORD.","words":[["H7194","And they conspired",0,18],["H7275","against him, and stoned",19,42],["H0068","him with stones",43,58],["H4687","at the commandment",59,77],["H4428","of the king",78,89],["H2691","in the court",90,102],["H1004","of the house",103,115],["H3068","of the LORD",116,127]]},"24:22":{"text":"Thus Joash the king remembered not the kindness which Jehoiada his father had done to him, but slew his son. And when he died, he said, The LORD look upon it, and require it.","words":[["H3101","Thus Joash",0,10],["H4428","the king",11,19],["H2142","remembered",20,30],["H2617","not the kindness",31,47],["H3077","which Jehoiada",48,62],["H0001","his father",63,73],["H6213","had done",74,82],["H2026","to him, but slew",83,99],["H1121","his son",100,107],["H4194","And when he died",109,125],["H0559","he said",127,134],["H3068","The LORD",136,144],["H7200","look",145,149],["H1875","upon it, and require",150,170]]},"24:23":{"text":"And it came to pass at the end of the year, that the host of Syria came up against him: and they came to Judah and Jerusalem, and destroyed all the princes of the people from among the people, and sent all the spoil of them unto the king of Damascus.","words":[["H8622","And it came to pass at the end",0,30],["H8141","of the year",31,42],["H2428","that the host",44,57],["H0758","of Syria",58,66],["H5927","came up",67,74],["H0935","against him: and they came",75,101],["H3063","to Judah",102,110],["H3389","and Jerusalem",111,124],["H7843","and destroyed",126,139],["H8269","all the princes",140,155],["H5971","of the people",156,169],["H5971","from among the people",170,191],["H7971","and sent",193,201],["H7998","all the spoil",202,215],["H4428","of them unto the king",216,237],["H1834","of Damascus",238,249]]},"24:24":{"text":"For the army of the Syrians came with a small company of men, and the LORD delivered a very great host into their hand, because they had forsaken the LORD God of their fathers. So they executed judgment against Joash.","words":[["H2428","For the army",0,12],["H0758","of the Syrians",13,27],["H0935","came",28,32],["H4705","with a small",33,45],["H0582","company of men",46,60],["H3068","and the LORD",62,74],["H5414","delivered",75,84],["H3966","a very",85,91],["H7230","great",92,97],["H2428","host",98,102],["H3027","into their hand",103,118],["H5800","because they had forsaken",120,145],["H3068","the LORD",146,154],["H0430","God",155,158],["H0001","of their fathers",159,175],["H6213","So they executed",177,193],["H8201","judgment",194,202],["H3101","against Joash",203,216]]},"24:25":{"text":"And when they were departed from him, (for they left him in great diseases,) his own servants conspired against him for the blood of the sons of Jehoiada the priest, and slew him on his bed, and he died: and they buried him in the city of David, but they buried him not in the sepulchres of the kings.","words":[["H3212","And when they were departed",0,27],["H5800","from him, (for they left",28,52],["H7227","him in great",53,65],["H4251","diseases",66,74],["H5650",") his own servants",75,93],["H7194","conspired",94,103],["H1818","against him for the blood",104,129],["H1121","of the sons",130,141],["H3077","of Jehoiada",142,153],["H3548","the priest",154,164],["H2026","and slew",166,174],["H4296","him on his bed",175,189],["H4191","and he died",191,202],["H6912","and they buried",204,219],["H5892","him in the city",220,235],["H1732","of David",236,244],["H6912","but they buried",246,261],["H6913","him not in the sepulchres",262,287],["H4428","of the kings",288,300]]},"24:26":{"text":"And these are they that conspired against him; Zabad the son of Shimeath an Ammonitess, and Jehozabad the son of Shimrith a Moabitess.","words":[["H7194","And these are they that conspired",0,33],["H2066","against him; Zabad",34,52],["H1121","the son",53,60],["H8100","of Shimeath",61,72],["H5985","an Ammonitess",73,86],["H3075","and Jehozabad",88,101],["H1121","the son",102,109],["H8116","of Shimrith",110,121],["H4125","a Moabitess",122,133]]},"24:27":{"text":"Now concerning his sons, and the greatness of the burdens laid upon him, and the repairing of the house of God, behold, they are written in the story of the book of the kings. And Amaziah his son reigned in his stead.","words":[["H1121","Now concerning his sons",0,23],["H7235","and the greatness",25,42],["H7230","and the greatness",25,42],["H4853","of the burdens",43,57],["H3247","laid upon him, and the repairing",58,90],["H1004","of the house",91,103],["H0430","of God",104,110],["H3789","behold, they are written",112,136],["H4097","in the story",137,149],["H5612","of the book",150,161],["H4428","of the kings",162,174],["H0558","And Amaziah",176,187],["H1121","his son",188,195],["H4427","reigned",196,203]]},"25:1":{"text":"Amaziah was twenty and five years old when he began to reign, and he reigned twenty and nine years in Jerusalem. And his mother's name was Jehoaddan of Jerusalem.","words":[["H0558","Amaziah",0,7],["H6242","was twenty",8,18],["H2568","and five",19,27],["H8141","years",28,33],["H1121","old",34,37],["H4427","when he began to reign",38,60],["H4427","and he reigned",62,76],["H6242","twenty",77,83],["H8672","and nine",84,92],["H8141","years",93,98],["H3389","in Jerusalem",99,111],["H0517","And his mother's",113,129],["H8034","name",130,134],["H3086","was Jehoaddan",135,148],["H3389","of Jerusalem",149,161]]},"25:2":{"text":"And he did that which was right in the sight of the LORD, but not with a perfect heart.","words":[["H6213","And he did",0,10],["H3477","that which was right",11,31],["H5869","in the sight",32,44],["H3068","of the LORD",45,56],["H8003","but not with a perfect",58,80],["H3824","heart",81,86]]},"25:3":{"text":"Now it came to pass, when the kingdom was established to him, that he slew his servants that had killed the king his father.","words":[["H4467","Now it came to pass, when the kingdom",0,37],["H2388","was established",38,53],["H2026","to him, that he slew",54,74],["H5650","his servants",75,87],["H5221","that had killed",88,103],["H4428","the king",104,112],["H0001","his father",113,123]]},"25:4":{"text":"But he slew not their children, but did as it is written in the law in the book of Moses, where the LORD commanded, saying, The fathers shall not die for the children, neither shall the children die for the fathers, but every man shall die for his own sin.","words":[["H4191","But he slew",0,11],["H1121","not their children",12,30],["H3789","but did as it is written",32,56],["H8451","in the law",57,67],["H5612","in the book",68,79],["H4872","of Moses",80,88],["H3068","where the LORD",90,104],["H6680","commanded",105,114],["H0559","saying",116,122],["H0001","The fathers",124,135],["H4191","shall not die",136,149],["H1121","for the children",150,166],["H1121","neither shall the children",168,194],["H4191","die",195,198],["H0001","for the fathers",199,214],["H0376","but every man",216,229],["H4191","shall die",230,239],["H2399","for his own sin",240,255]]},"25:5":{"text":"Moreover Amaziah gathered Judah together, and made them captains over thousands, and captains over hundreds, according to the houses of their fathers, throughout all Judah and Benjamin: and he numbered them from twenty years old and above, and found them three hundred thousand choice men, able to go forth to war, that could handle spear and shield.","words":[["H0558","Moreover Amaziah",0,16],["H6908","gathered",17,25],["H3063","Judah",26,31],["H6908","together",32,40],["H5975","and made",42,50],["H8269","them captains",51,64],["H0505","over thousands",65,79],["H8269","and captains",81,93],["H3967","over hundreds",94,107],["H1004","according to the houses",109,132],["H0001","of their fathers",133,149],["H3063","throughout all Judah",151,171],["H1144","and Benjamin",172,184],["H6485","and he numbered",186,201],["H6242","them from twenty",202,218],["H8141","years",219,224],["H1121","old",225,228],["H4605","and above",229,238],["H4672","and found",240,249],["H7969","them three",250,260],["H3967","hundred",261,268],["H0505","thousand",269,277],["H0977","choice",278,284],["H3318","men, able to go forth",285,306],["H6635","to war",307,313],["H0270","that could handle",315,332],["H7420","spear",333,338],["H6793","and shield",339,349]]},"25:6":{"text":"He hired also an hundred thousand mighty men of valour out of Israel for an hundred talents of silver.","words":[["H7936","He hired",0,8],["H3967","also an hundred",9,24],["H0505","thousand",25,33],["H1368","mighty",34,40],["H2428","men of valour",41,54],["H3478","out of Israel",55,68],["H3967","for an hundred",69,83],["H3603","talents",84,91],["H3701","of silver",92,101]]},"25:7":{"text":"But there came a man of God to him, saying, O king, let not the army of Israel go with thee; for the LORD is not with Israel, to wit, with all the children of Ephraim.","words":[["H0935","But there came",0,14],["H0376","a man",15,20],["H0430","of God",21,27],["H0559","to him, saying",28,42],["H4428","O king",44,50],["H6635","let not the army",52,68],["H3478","of Israel",69,78],["H0935","go",79,81],["H3068","with thee; for the LORD",82,105],["H3478","is not with Israel",106,124],["H1121","to wit, with all the children",126,155],["H0669","of Ephraim",156,166]]},"25:8":{"text":"But if thou wilt go, do it, be strong for the battle: God shall make thee fall before the enemy: for God hath power to help, and to cast down.","words":[["H0935","But if thou wilt go",0,19],["H6213","do",21,23],["H2388","it, be strong",24,37],["H4421","for the battle",38,52],["H0430","God",54,57],["H3782","shall make thee fall",58,78],["H6440","before",79,85],["H0341","the enemy",86,95],["H0430","for God",97,104],["H3426","hath",105,109],["H3581","power",110,115],["H5826","to help",116,123],["H3782","and to cast down",125,141]]},"25:9":{"text":"And Amaziah said to the man of God, But what shall we do for the hundred talents which I have given to the army of Israel? And the man of God answered, The LORD is able to give thee much more than this.","words":[["H0558","And Amaziah",0,11],["H0559","said",12,16],["H0376","to the man",17,27],["H0430","of God",28,34],["H6213","But what shall we do",36,56],["H3967","for the hundred",57,72],["H3603","talents",73,80],["H5414","which I have given",81,99],["H1416","to the army",100,111],["H3478","of Israel",112,121],["H0376","And the man",123,134],["H0430","of God",135,141],["H0559","answered",142,150],["H3068","The LORD",152,160],["H3426","is",161,163],["H5414","able to give",164,176],["H7235","thee much more",177,191]]},"25:10":{"text":"Then Amaziah separated them, to wit, the army that was come to him out of Ephraim, to go home again: wherefore their anger was greatly kindled against Judah, and they returned home in great anger.","words":[["H0558","Then Amaziah",0,12],["H0914","separated",13,22],["H1416","them, to wit, the army",23,45],["H0935","that was come",46,59],["H0669","to him out of Ephraim",60,81],["H3212","to go",83,88],["H4725","home",89,93],["H3212","again",94,99],["H0639","wherefore their anger",101,122],["H3966","was greatly",123,134],["H2734","kindled",135,142],["H3063","against Judah",143,156],["H7725","and they returned",158,175],["H4725","home",176,180],["H2750","in great",181,189],["H0639","anger",190,195]]},"25:11":{"text":"And Amaziah strengthened himself, and led forth his people, and went to the valley of salt, and smote of the children of Seir ten thousand.","words":[["H0558","And Amaziah",0,11],["H2388","strengthened",12,24],["H5090","himself, and led forth",25,47],["H5971","his people",48,58],["H3212","and went",60,68],["H1516","to the valley",69,82],["H4417","of salt",83,90],["H5221","and smote",92,101],["H1121","of the children",102,117],["H8165","of Seir",118,125],["H6235","ten",126,129],["H0505","thousand",130,138]]},"25:12":{"text":"And other ten thousand left alive did the children of Judah carry away captive, and brought them unto the top of the rock, and cast them down from the top of the rock, that they all were broken in pieces.","words":[["H6235","And other ten",0,13],["H0505","thousand",14,22],["H2416","left alive",23,33],["H1121","did the children",34,50],["H3063","of Judah",51,59],["H7617","carry away captive",60,78],["H0935","and brought",80,91],["H7218","them unto the top",92,109],["H5553","of the rock",110,121],["H7993","and cast them down",123,141],["H7218","from the top",142,154],["H5553","of the rock",155,166],["H1234","that they all were broken in pieces",168,203]]},"25:13":{"text":"But the soldiers of the army which Amaziah sent back, that they should not go with him to battle, fell upon the cities of Judah, from Samaria even unto Bethhoron, and smote three thousand of them, and took much spoil.","words":[["H1121","But the soldiers",0,16],["H1416","of the army",17,28],["H0558","which Amaziah",29,42],["H7725","sent back",43,52],["H3212","that they should not go",54,77],["H4421","with him to battle",78,96],["H6584","fell",98,102],["H5892","upon the cities",103,118],["H3063","of Judah",119,127],["H8111","from Samaria",129,141],["H1032","even unto Bethhoron",142,161],["H5221","and smote",163,172],["H7969","three",173,178],["H0505","thousand",179,187],["H0962","of them, and took",188,205],["H7227","much",206,210],["H0961","spoil",211,216]]},"25:14":{"text":"Now it came to pass, after that Amaziah was come from the slaughter of the Edomites, that he brought the gods of the children of Seir, and set them up to be his gods, and bowed down himself before them, and burned incense unto them.","words":[["H0310","Now it came to pass, after",0,26],["H0558","that Amaziah",27,39],["H0935","was come",40,48],["H5221","from the slaughter",49,67],["H0130","of the Edomites",68,83],["H0935","that he brought",85,100],["H0430","the gods",101,109],["H1121","of the children",110,125],["H8165","of Seir",126,133],["H5975","and set them up",135,150],["H0430","to be his gods",151,165],["H7812","and bowed down",167,181],["H6440","himself before",182,196],["H6999","them, and burned incense",197,221]]},"25:15":{"text":"Wherefore the anger of the LORD was kindled against Amaziah, and he sent unto him a prophet, which said unto him, Why hast thou sought after the gods of the people, which could not deliver their own people out of thine hand?","words":[["H0639","Wherefore the anger",0,19],["H3068","of the LORD",20,31],["H2734","was kindled",32,43],["H0558","against Amaziah",44,59],["H7971","and he sent",61,72],["H5030","unto him a prophet",73,91],["H0559","which said",93,103],["H1875","unto him, Why hast thou sought",104,134],["H0430","after the gods",135,149],["H5971","of the people",150,163],["H5337","which could not deliver",165,188],["H5971","their own people",189,205],["H3027","out of thine hand",206,223]]},"25:16":{"text":"And it came to pass, as he talked with him, that the king said unto him, Art thou made of the king's counsel? forbear; why shouldest thou be smitten? Then the prophet forbare, and said, I know that God hath determined to destroy thee, because thou hast done this, and hast not hearkened unto my counsel.","words":[["H1696","And it came to pass, as he talked",0,33],["H0559","with him, that the king said",34,62],["H5414","unto him, Art thou made",63,86],["H4428","of the king's",87,100],["H3289","counsel",101,108],["H2308","forbear",110,117],["H5221","why shouldest thou be smitten",119,148],["H5030","Then the prophet",150,166],["H2308","forbare",167,174],["H0559","and said",176,184],["H3045","I know",186,192],["H0430","that God",193,201],["H3289","hath determined",202,217],["H7843","to destroy",218,228],["H6213","thee, because thou hast done",229,257],["H8085","this, and hast not hearkened",258,286],["H6098","unto my counsel",287,302]]},"25:17":{"text":"Then Amaziah king of Judah took advice, and sent to Joash, the son of Jehoahaz, the son of Jehu, king of Israel, saying, Come, let us see one another in the face.","words":[["H0558","Then Amaziah",0,12],["H4428","king",13,17],["H3063","of Judah",18,26],["H3289","took advice",27,38],["H7971","and sent",40,48],["H3101","to Joash",49,57],["H1121","the son",59,66],["H3059","of Jehoahaz",67,78],["H1121","the son",80,87],["H3058","of Jehu",88,95],["H4428","king",97,101],["H3478","of Israel",102,111],["H0559","saying",113,119],["H3212","Come",121,125],["H7200","let us see one another",127,149],["H6440","in the face",150,161]]},"25:18":{"text":"And Joash king of Israel sent to Amaziah king of Judah, saying, The thistle that was in Lebanon sent to the cedar that was in Lebanon, saying, Give thy daughter to my son to wife: and there passed by a wild beast that was in Lebanon, and trode down the thistle.","words":[["H3101","And Joash",0,9],["H4428","king",10,14],["H3478","of Israel",15,24],["H7971","sent",25,29],["H0558","to Amaziah",30,40],["H4428","king",41,45],["H3063","of Judah",46,54],["H0559","saying",56,62],["H2336","The thistle",64,75],["H3844","that was in Lebanon",76,95],["H7971","sent",96,100],["H0730","to the cedar",101,113],["H3844","that was in Lebanon",114,133],["H0559","saying",135,141],["H5414","Give",143,147],["H1323","thy daughter",148,160],["H1121","to my son",161,170],["H0802","to wife",171,178],["H5674","and there passed by",180,199],["H7704","a wild",200,206],["H2416","beast",207,212],["H3844","that was in Lebanon",213,232],["H7429","and trode down",234,248],["H2336","the thistle",249,260]]},"25:19":{"text":"Thou sayest, Lo, thou hast smitten the Edomites; and thine heart lifteth thee up to boast: abide now at home; why shouldest thou meddle to thine hurt, that thou shouldest fall, even thou, and Judah with thee?","words":[["H0559","Thou sayest",0,11],["H5221","Lo, thou hast smitten",13,34],["H0123","the Edomites",35,47],["H3820","and thine heart",49,64],["H5375","lifteth thee up",65,80],["H3513","to boast",81,89],["H3427","abide",91,96],["H1004","now at home",97,108],["H1624","why shouldest thou meddle",110,135],["H7451","to thine hurt",136,149],["H5307","that thou shouldest fall",151,175],["H3063","even thou, and Judah",177,197]]},"25:20":{"text":"But Amaziah would not hear; for it came of God, that he might deliver them into the hand of their enemies, because they sought after the gods of Edom.","words":[["H0558","But Amaziah",0,11],["H8085","would not hear",12,26],["H0430","for it came of God",28,46],["H5414","that he might deliver",48,69],["H3027","them into the hand",70,88],["H1875","of their enemies, because they sought",89,126],["H0430","after the gods",127,141],["H0123","of Edom",142,149]]},"25:21":{"text":"So Joash the king of Israel went up; and they saw one another in the face, both he and Amaziah king of Judah, at Bethshemesh, which belongeth to Judah.","words":[["H3101","So Joash",0,8],["H4428","the king",9,17],["H3478","of Israel",18,27],["H5927","went up",28,35],["H7200","and they saw one another",37,61],["H6440","in the face",62,73],["H0558","both he and Amaziah",75,94],["H4428","king",95,99],["H3063","of Judah",100,108],["H1053","at Bethshemesh",110,124],["H3063","which belongeth to Judah",126,150]]},"25:22":{"text":"And Judah was put to the worse before Israel, and they fled every man to his tent.","words":[["H3063","And Judah",0,9],["H5062","was put to the worse",10,30],["H6440","before",31,37],["H3478","Israel",38,44],["H5127","and they fled",46,59],["H0376","every man",60,69],["H0168","to his tent",70,81]]},"25:23":{"text":"And Joash the king of Israel took Amaziah king of Judah, the son of Joash, the son of Jehoahaz, at Bethshemesh, and brought him to Jerusalem, and brake down the wall of Jerusalem from the gate of Ephraim to the corner gate, four hundred cubits.","words":[["H3101","And Joash",0,9],["H4428","the king",10,18],["H3478","of Israel",19,28],["H8610","took",29,33],["H0558","Amaziah",34,41],["H4428","king",42,46],["H3063","of Judah",47,55],["H1121","the son",57,64],["H3101","of Joash",65,73],["H1121","the son",75,82],["H3059","of Jehoahaz",83,94],["H1053","at Bethshemesh",96,110],["H0935","and brought",112,123],["H3389","him to Jerusalem",124,140],["H6555","and brake down",142,156],["H2346","the wall",157,165],["H3389","of Jerusalem",166,178],["H8179","from the gate",179,192],["H0669","of Ephraim",193,203],["H6437","to the corner",204,217],["H8179","gate",218,222],["H0702","four",224,228],["H3967","hundred",229,236],["H0520","cubits",237,243]]},"25:24":{"text":"And he took all the gold and the silver, and all the vessels that were found in the house of God with Obededom, and the treasures of the king's house, the hostages also, and returned to Samaria.","words":[["H2091","And he took all the gold",0,24],["H3701","and the silver",25,39],["H3627","and all the vessels",41,60],["H4672","that were found",61,76],["H1004","in the house",77,89],["H0430","of God",90,96],["H5654","with Obededom",97,110],["H0214","and the treasures",112,129],["H4428","of the king's",130,143],["H1004","house",144,149],["H1121","the hostages",151,163],["H8594","the hostages",151,163],["H7725","also, and returned",164,182],["H8111","to Samaria",183,193]]},"25:25":{"text":"And Amaziah the son of Joash king of Judah lived after the death of Joash son of Jehoahaz king of Israel fifteen years.","words":[["H0558","And Amaziah",0,11],["H1121","the son",12,19],["H3101","of Joash",20,28],["H4428","king",29,33],["H3063","of Judah",34,42],["H2421","lived",43,48],["H0310","after",49,54],["H4194","the death",55,64],["H3101","of Joash",65,73],["H1121","son",74,77],["H3059","of Jehoahaz",78,89],["H4428","king",90,94],["H3478","of Israel",95,104],["H2568","fifteen",105,112],["H6240","fifteen",105,112],["H8141","years",113,118]]},"25:26":{"text":"Now the rest of the acts of Amaziah, first and last, behold, are they not written in the book of the kings of Judah and Israel?","words":[["H3499","Now the rest",0,12],["H1697","of the acts",13,24],["H0558","of Amaziah",25,35],["H7223","first",37,42],["H0314","and last",43,51],["H3789","behold, are they not written",53,81],["H5612","in the book",82,93],["H4428","of the kings",94,106],["H3063","of Judah",107,115],["H3478","and Israel",116,126]]},"25:27":{"text":"Now after the time that Amaziah did turn away from following the LORD they made a conspiracy against him in Jerusalem; and he fled to Lachish: but they sent to Lachish after him, and slew him there.","words":[["H6256","Now after the time",0,18],["H0558","that Amaziah",19,31],["H5493","did turn away",32,45],["H0310","from following",46,60],["H3068","the LORD",61,69],["H7194","they made",70,79],["H7195","a conspiracy",80,92],["H3389","against him in Jerusalem",93,117],["H5127","and he fled",119,130],["H3923","to Lachish",131,141],["H7971","but they sent",143,156],["H3923","to Lachish",157,167],["H0310","after",168,173],["H4191","him, and slew",174,187]]},"25:28":{"text":"And they brought him upon horses, and buried him with his fathers in the city of Judah.","words":[["H5375","And they brought",0,16],["H5483","him upon horses",17,32],["H6912","and buried",34,44],["H0001","him with his fathers",45,65],["H5892","in the city",66,77],["H3063","of Judah",78,86]]},"26:1":{"text":"Then all the people of Judah took Uzziah, who was sixteen years old, and made him king in the room of his father Amaziah.","words":[["H5971","Then all the people",0,19],["H3063","of Judah",20,28],["H3947","took",29,33],["H5818","Uzziah",34,40],["H8337","who was sixteen",42,57],["H6240","who was sixteen",42,57],["H8141","years",58,63],["H1121","old",64,67],["H4427","and made him king",69,86],["H0001","in the room of his father",87,112],["H0558","Amaziah",113,120]]},"26:2":{"text":"He built Eloth, and restored it to Judah, after that the king slept with his fathers.","words":[["H1129","He built",0,8],["H0359","Eloth",9,14],["H7725","and restored",16,28],["H3063","it to Judah",29,40],["H0310","after",42,47],["H4428","that the king",48,61],["H7901","slept",62,67],["H0001","with his fathers",68,84]]},"26:3":{"text":"Sixteen years old was Uzziah when he began to reign, and he reigned fifty and two years in Jerusalem. His mother's name also was Jecoliah of Jerusalem.","words":[["H8337","Sixteen",0,7],["H6240","Sixteen",0,7],["H8141","years",8,13],["H1121","old",14,17],["H5818","was Uzziah",18,28],["H4427","when he began to reign",29,51],["H4427","and he reigned",53,67],["H2572","fifty",68,73],["H8147","and two",74,81],["H8141","years",82,87],["H3389","in Jerusalem",88,100],["H0517","His mother's",102,114],["H8034","name",115,119],["H3203","also was Jecoliah",120,137],["H3389","of Jerusalem",138,150]]},"26:4":{"text":"And he did that which was right in the sight of the LORD, according to all that his father Amaziah did.","words":[["H6213","And he did",0,10],["H3477","that which was right",11,31],["H5869","in the sight",32,44],["H3068","of the LORD",45,56],["H0001","according to all that his father",58,90],["H0558","Amaziah",91,98],["H6213","did",99,102]]},"26:5":{"text":"And he sought God in the days of Zechariah, who had understanding in the visions of God: and as long as he sought the LORD, God made him to prosper.","words":[["H1875","And he sought",0,13],["H0430","God",14,17],["H3117","in the days",18,29],["H2148","of Zechariah",30,42],["H0995","who had understanding",44,65],["H7200","in the visions",66,80],["H0430","of God",81,87],["H3117","and as long as",89,103],["H1875","he sought",104,113],["H3068","the LORD",114,122],["H0430","God",124,127],["H6743","made him to prosper",128,147]]},"26:6":{"text":"And he went forth and warred against the Philistines, and brake down the wall of Gath, and the wall of Jabneh, and the wall of Ashdod, and built cities about Ashdod, and among the Philistines.","words":[["H3318","And he went forth",0,17],["H3898","and warred",18,28],["H6430","against the Philistines",29,52],["H6555","and brake down",54,68],["H2346","the wall",69,77],["H1661","of Gath",78,85],["H2346","and the wall",87,99],["H2996","of Jabneh",100,109],["H2346","and the wall",111,123],["H0795","of Ashdod",124,133],["H1129","and built",135,144],["H5892","cities",145,151],["H0795","about Ashdod",152,164],["H6430","and among the Philistines",166,191]]},"26:7":{"text":"And God helped him against the Philistines, and against the Arabians that dwelt in Gurbaal, and the Mehunims.","words":[["H0430","And God",0,7],["H5826","helped",8,14],["H6430","him against the Philistines",15,42],["H6163","and against the Arabians",44,68],["H3427","that dwelt",69,79],["H1485","in Gurbaal",80,90],["H4586","and the Mehunims",92,108]]},"26:8":{"text":"And the Ammonites gave gifts to Uzziah: and his name spread abroad even to the entering in of Egypt; for he strengthened himself exceedingly.","words":[["H5984","And the Ammonites",0,17],["H5414","gave",18,22],["H4503","gifts",23,28],["H5818","to Uzziah",29,38],["H8034","and his name",40,52],["H3212","spread abroad",53,66],["H0935","even to the entering",67,87],["H4714","in of Egypt",88,99],["H2388","for he strengthened",101,120],["H4605","himself exceedingly",121,140]]},"26:9":{"text":"Moreover Uzziah built towers in Jerusalem at the corner gate, and at the valley gate, and at the turning of the wall, and fortified them.","words":[["H5818","Moreover Uzziah",0,15],["H1129","built",16,21],["H4026","towers",22,28],["H3389","in Jerusalem",29,41],["H6438","at the corner",42,55],["H8179","gate",56,60],["H1516","and at the valley",62,79],["H8179","gate",80,84],["H4740","and at the turning",86,104],["H2388","of the wall, and fortified",105,131]]},"26:10":{"text":"Also he built towers in the desert, and digged many wells: for he had much cattle, both in the low country, and in the plains: husbandmen also, and vine dressers in the mountains, and in Carmel: for he loved husbandry.","words":[["H1129","Also he built",0,13],["H4026","towers",14,20],["H4057","in the desert",21,34],["H2672","and digged",36,46],["H7227","many",47,51],["H0953","wells",52,57],["H7227","for he had much",59,74],["H4735","cattle",75,81],["H8219","both in the low country",83,106],["H4334","and in the plains",108,125],["H0406","husbandmen",127,137],["H3755","also, and vine dressers",138,161],["H2022","in the mountains",162,178],["H3760","and in Carmel",180,193],["H0157","for he loved",195,207],["H0127","husbandry",208,217]]},"26:11":{"text":"Moreover Uzziah had an host of fighting men, that went out to war by bands, according to the number of their account by the hand of Jeiel the scribe and Maaseiah the ruler, under the hand of Hananiah, one of the king's captains.","words":[["H5818","Moreover Uzziah",0,15],["H2428","had an host",16,27],["H4421","of fighting",28,39],["H6213","men",40,43],["H3318","that went out",45,58],["H6635","to war",59,65],["H1416","by bands",66,74],["H4557","according to the number",76,99],["H6486","of their account",100,116],["H3027","by the hand",117,128],["H3273","of Jeiel",129,137],["H5608","the scribe",138,148],["H4641","and Maaseiah",149,161],["H7860","the ruler",162,171],["H3027","under the hand",173,187],["H2608","of Hananiah",188,199],["H4428","one of the king's",201,218],["H8269","captains",219,227]]},"26:12":{"text":"The whole number of the chief of the fathers of the mighty men of valour were two thousand and six hundred.","words":[["H4557","The whole number",0,16],["H7218","of the chief",17,29],["H0001","of the fathers",30,44],["H1368","of the mighty men",45,62],["H2428","of valour",63,72],["H0505","were two thousand",73,90],["H8337","and six",91,98],["H3967","hundred",99,106]]},"26:13":{"text":"And under their hand was an army, three hundred thousand and seven thousand and five hundred, that made war with mighty power, to help the king against the enemy.","words":[["H3027","And under their hand",0,20],["H2428","was an army",21,32],["H6635","was an army",21,32],["H7969","three",34,39],["H3967","hundred",40,47],["H0505","thousand",48,56],["H7651","and seven",57,66],["H0505","thousand",67,75],["H2568","and five",76,84],["H3967","hundred",85,92],["H6213","that made",94,103],["H4421","war",104,107],["H2428","with mighty",108,119],["H3581","power",120,125],["H5826","to help",127,134],["H4428","the king",135,143],["H0341","against the enemy",144,161]]},"26:14":{"text":"And Uzziah prepared for them throughout all the host shields, and spears, and helmets, and habergeons, and bows, and slings to cast stones.","words":[["H5818","And Uzziah",0,10],["H3559","prepared",11,19],["H6635","for them throughout all the host",20,52],["H4043","shields",53,60],["H7420","and spears",62,72],["H3553","and helmets",74,85],["H8302","and habergeons",87,101],["H7198","and bows",103,111],["H7050","and slings",113,123],["H0068","to cast stones",124,138]]},"26:15":{"text":"And he made in Jerusalem engines, invented by cunning men, to be on the towers and upon the bulwarks, to shoot arrows and great stones withal. And his name spread far abroad; for he was marvellously helped, till he was strong.","words":[["H6213","And he made",0,11],["H3389","in Jerusalem",12,24],["H2810","engines",25,32],["H4284","invented",34,42],["H2803","by cunning men",43,57],["H4026","to be on the towers",59,78],["H6438","and upon the bulwarks",79,100],["H3384","to shoot",102,110],["H2671","arrows",111,117],["H1419","and great",118,127],["H0068","stones",128,134],["H8034","withal. And his name",135,155],["H3318","spread",156,162],["H7350","far abroad",163,173],["H6381","for he was marvellously",175,198],["H5826","helped",199,205],["H3588","till",207,211],["H2388","he was strong",212,225]]},"26:16":{"text":"But when he was strong, his heart was lifted up to his destruction: for he transgressed against the LORD his God, and went into the temple of the LORD to burn incense upon the altar of incense.","words":[["H2393","But when he was strong",0,22],["H3820","his heart",24,33],["H1361","was lifted up",34,47],["H7843","to his destruction",48,66],["H4603","for he transgressed",68,87],["H3068","against the LORD",88,104],["H0430","his God",105,112],["H0935","and went",114,122],["H1964","into the temple",123,138],["H3068","of the LORD",139,150],["H6999","to burn incense",151,166],["H4196","upon the altar",167,181],["H7004","of incense",182,192]]},"26:17":{"text":"And Azariah the priest went in after him, and with him fourscore priests of the LORD, that were valiant men:","words":[["H5838","And Azariah",0,11],["H3548","the priest",12,22],["H0935","went in",23,30],["H0310","after",31,36],["H8084","him, and with him fourscore",37,64],["H3548","priests",65,72],["H3068","of the LORD",73,84],["H2428","that were valiant",86,103],["H1121","men",104,107]]},"26:18":{"text":"And they withstood Uzziah the king, and said unto him, It appertaineth not unto thee, Uzziah, to burn incense unto the LORD, but to the priests the sons of Aaron, that are consecrated to burn incense: go out of the sanctuary; for thou hast trespassed; neither shall it be for thine honour from the LORD God.","words":[["H5975","And they withstood",0,18],["H5818","Uzziah",19,25],["H4428","the king",26,34],["H0559","and said",36,44],["H5818","unto him, It appertaineth not unto thee, Uzziah",45,92],["H6999","to burn incense",94,109],["H3068","unto the LORD",110,123],["H3548","but to the priests",125,143],["H1121","the sons",144,152],["H0175","of Aaron",153,161],["H6942","that are consecrated",163,183],["H6999","to burn incense",184,199],["H3318","go out",201,207],["H4720","of the sanctuary",208,224],["H4603","for thou hast trespassed",226,250],["H3519","neither shall it be for thine honour",252,288],["H3068","from the LORD",289,302],["H0430","God",303,306]]},"26:19":{"text":"Then Uzziah was wroth, and had a censer in his hand to burn incense: and while he was wroth with the priests, the leprosy even rose up in his forehead before the priests in the house of the LORD, from beside the incense altar.","words":[["H5818","Then Uzziah",0,11],["H2196","was wroth",12,21],["H4730","and had a censer",23,39],["H3027","in his hand",40,51],["H6999","to burn incense",52,67],["H2196","and while he was wroth",69,91],["H3548","with the priests",92,108],["H6883","the leprosy",110,121],["H2224","even rose up",122,134],["H4696","in his forehead",135,150],["H6440","before",151,157],["H3548","the priests",158,169],["H1004","in the house",170,182],["H3068","of the LORD",183,194],["H7004","from beside the incense",196,219],["H4196","altar",220,225]]},"26:20":{"text":"And Azariah the chief priest, and all the priests, looked upon him, and, behold, he was leprous in his forehead, and they thrust him out from thence; yea, himself hasted also to go out, because the LORD had smitten him.","words":[["H5838","And Azariah",0,11],["H7218","the chief",12,21],["H3548","priest",22,28],["H3548","and all the priests",30,49],["H6437","looked",51,57],["H6879","upon him, and, behold, he was leprous",58,95],["H4696","in his forehead",96,111],["H0926","and they thrust him out",113,136],["H1765","from thence; yea, himself hasted",137,169],["H3318","also to go out",170,184],["H3068","because the LORD",186,202],["H5060","had smitten",203,214]]},"26:21":{"text":"And Uzziah the king was a leper unto the day of his death, and dwelt in a several house, being a leper; for he was cut off from the house of the LORD: and Jotham his son was over the king's house, judging the people of the land.","words":[["H5818","And Uzziah",0,10],["H4428","the king",11,19],["H6879","was a leper",20,31],["H3117","unto the day",32,44],["H4194","of his death",45,57],["H3427","and dwelt in",59,71],["H2669","a several",72,81],["H2669","a several",72,81],["H1004","house",82,87],["H6879","being a leper",89,102],["H1504","for he was cut off",104,122],["H1004","from the house",123,137],["H3068","of the LORD",138,149],["H3147","and Jotham",151,161],["H1121","his son",162,169],["H4428","was over the king's",170,189],["H1004","house",190,195],["H8199","judging",197,204],["H5971","the people",205,215],["H0776","of the land",216,227]]},"26:22":{"text":"Now the rest of the acts of Uzziah, first and last, did Isaiah the prophet, the son of Amoz, write.","words":[["H3499","Now the rest",0,12],["H1697","of the acts",13,24],["H5818","of Uzziah",25,34],["H7223","first",36,41],["H0314","and last",42,50],["H3470","did Isaiah",52,62],["H5030","the prophet",63,74],["H1121","the son",76,83],["H0531","of Amoz",84,91],["H3789","write",93,98]]},"26:23":{"text":"So Uzziah slept with his fathers, and they buried him with his fathers in the field of the burial which belonged to the kings; for they said, He is a leper: and Jotham his son reigned in his stead.","words":[["H5818","So Uzziah",0,9],["H7901","slept",10,15],["H0001","with his fathers",16,32],["H6912","and they buried",34,49],["H0001","him with his fathers",50,70],["H7704","in the field",71,83],["H6900","of the burial",84,97],["H4428","which belonged to the kings",98,125],["H0559","for they said",127,140],["H6879","He is a leper",142,155],["H3147","and Jotham",157,167],["H1121","his son",168,175],["H4427","reigned",176,183]]},"27:1":{"text":"Jotham was twenty and five years old when he began to reign, and he reigned sixteen years in Jerusalem. His mother's name also was Jerushah, the daughter of Zadok.","words":[["H3147","Jotham",0,6],["H6242","was twenty",7,17],["H2568","and five",18,26],["H8141","years",27,32],["H1121","old",33,36],["H4427","when he began to reign",37,59],["H4427","and he reigned",61,75],["H8337","sixteen",76,83],["H6240","sixteen",76,83],["H8141","years",84,89],["H3389","in Jerusalem",90,102],["H0517","His mother's",104,116],["H8034","name",117,121],["H3388","also was Jerushah",122,139],["H1323","the daughter",141,153],["H6659","of Zadok",154,162]]},"27:2":{"text":"And he did that which was right in the sight of the LORD, according to all that his father Uzziah did: howbeit he entered not into the temple of the LORD. And the people did yet corruptly.","words":[["H6213","And he did",0,10],["H3477","that which was right",11,31],["H5869","in the sight",32,44],["H3068","of the LORD",45,56],["H0001","according to all that his father",58,90],["H5818","Uzziah",91,97],["H6213","did",98,101],["H0935","howbeit he entered",103,121],["H1964","not into the temple",122,141],["H3068","of the LORD",142,153],["H5971","And the people",155,169],["H7843","did yet corruptly",170,187]]},"27:3":{"text":"He built the high gate of the house of the LORD, and on the wall of Ophel he built much.","words":[["H1129","He built",0,8],["H5945","the high",9,17],["H8179","gate",18,22],["H1004","of the house",23,35],["H3068","of the LORD",36,47],["H2346","and on the wall",49,64],["H6077","of Ophel",65,73],["H1129","he built",74,82],["H7230","much",83,87]]},"27:4":{"text":"Moreover he built cities in the mountains of Judah, and in the forests he built castles and towers.","words":[["H1129","Moreover he built",0,17],["H5892","cities",18,24],["H2022","in the mountains",25,41],["H3063","of Judah",42,50],["H2793","and in the forests",52,70],["H1129","he built",71,79],["H1003","castles",80,87],["H4026","and towers",88,98]]},"27:5":{"text":"He fought also with the king of the Ammonites, and prevailed against them. And the children of Ammon gave him the same year an hundred talents of silver, and ten thousand measures of wheat, and ten thousand of barley. So much did the children of Ammon pay unto him, both the second year, and the third.","words":[["H3898","He fought",0,9],["H4428","also with the king",10,28],["H5984","of the Ammonites",29,45],["H2388","and prevailed",47,60],["H1121","against them. And the children",61,91],["H5983","of Ammon",92,100],["H5414","gave",101,105],["H8141","him the same year",106,123],["H3967","an hundred",124,134],["H3603","talents",135,142],["H3701","of silver",143,152],["H6235","and ten",154,161],["H0505","thousand",162,170],["H3734","measures",171,179],["H2406","of wheat",180,188],["H6235","and ten",190,197],["H0505","thousand",198,206],["H8184","of barley",207,216],["H1121","So much did the children",218,242],["H5983","of Ammon",243,251],["H7725","pay",252,255],["H2063","unto",256,260],["H8145","him, both the second",261,281],["H8141","year",282,286],["H7992","and the third",288,301]]},"27:6":{"text":"So Jotham became mighty, because he prepared his ways before the LORD his God.","words":[["H3147","So Jotham",0,9],["H2388","became mighty",10,23],["H3559","because he prepared",25,44],["H1870","his ways",45,53],["H6440","before",54,60],["H3068","the LORD",61,69],["H0430","his God",70,77]]},"27:7":{"text":"Now the rest of the acts of Jotham, and all his wars, and his ways, lo, they are written in the book of the kings of Israel and Judah.","words":[["H3499","Now the rest",0,12],["H1697","of the acts",13,24],["H3147","of Jotham",25,34],["H4421","and all his wars",36,52],["H1870","and his ways",54,66],["H3789","lo, they are written",68,88],["H5612","in the book",89,100],["H4428","of the kings",101,113],["H3478","of Israel",114,123],["H3063","and Judah",124,133]]},"27:8":{"text":"He was five and twenty years old when he began to reign, and reigned sixteen years in Jerusalem.","words":[["H2568","He was five",0,11],["H6242","and twenty",12,22],["H8141","years",23,28],["H1121","old",29,32],["H4427","when he began to reign",33,55],["H4427","and reigned",57,68],["H8337","sixteen",69,76],["H6240","sixteen",69,76],["H8141","years",77,82],["H3389","in Jerusalem",83,95]]},"27:9":{"text":"And Jotham slept with his fathers, and they buried him in the city of David: and Ahaz his son reigned in his stead.","words":[["H3147","And Jotham",0,10],["H7901","slept",11,16],["H0001","with his fathers",17,33],["H6912","and they buried",35,50],["H5892","him in the city",51,66],["H1732","of David",67,75],["H0271","and Ahaz",77,85],["H1121","his son",86,93],["H4427","reigned",94,101]]},"28:1":{"text":"Ahaz was twenty years old when he began to reign, and he reigned sixteen years in Jerusalem: but he did not that which was right in the sight of the LORD, like David his father:","words":[["H0271","Ahaz",0,4],["H6242","was twenty",5,15],["H8141","years",16,21],["H1121","old",22,25],["H4427","when he began to reign",26,48],["H4427","and he reigned",50,64],["H8337","sixteen",65,72],["H6240","sixteen",65,72],["H8141","years",73,78],["H3389","in Jerusalem",79,91],["H6213","but he did",93,103],["H3477","not that which was right",104,128],["H5869","in the sight",129,141],["H3068","of the LORD",142,153],["H1732","like David",155,165],["H0001","his father",166,176]]},"28:2":{"text":"For he walked in the ways of the kings of Israel, and made also molten images for Baalim.","words":[["H3212","For he walked in",0,16],["H1870","the ways",17,25],["H4428","of the kings",26,38],["H3478","of Israel",39,48],["H6213","and made",50,58],["H4541","also molten images",59,77],["H1168","for Baalim",78,88]]},"28:3":{"text":"Moreover he burnt incense in the valley of the son of Hinnom, and burnt his children in the fire, after the abominations of the heathen whom the LORD had cast out before the children of Israel.","words":[["H6999","Moreover he burnt incense",0,25],["H1516","in the valley",26,39],["H1121","of the son",40,50],["H2011","of Hinnom",51,60],["H1197","and burnt",62,71],["H1121","his children",72,84],["H0784","in the fire",85,96],["H8441","after the abominations",98,120],["H1471","of the heathen",121,135],["H3068","whom the LORD",136,149],["H3423","had cast out",150,162],["H6440","before",163,169],["H1121","the children",170,182],["H3478","of Israel",183,192]]},"28:4":{"text":"He sacrificed also and burnt incense in the high places, and on the hills, and under every green tree.","words":[["H2076","He sacrificed",0,13],["H6999","also and burnt incense",14,36],["H1116","in the high places",37,55],["H1389","and on the hills",57,73],["H7488","and under every green",75,96],["H6086","tree",97,101]]},"28:5":{"text":"Wherefore the LORD his God delivered him into the hand of the king of Syria; and they smote him, and carried away a great multitude of them captives, and brought them to Damascus. And he was also delivered into the hand of the king of Israel, who smote him with a great slaughter.","words":[["H3068","Wherefore the LORD",0,18],["H0430","his God",19,26],["H5414","delivered",27,36],["H3027","him into the hand",37,54],["H4428","of the king",55,66],["H0758","of Syria",67,75],["H5221","and they smote",77,91],["H7617","him, and carried away",92,113],["H1419","a great multitude",114,131],["H7633","of them captives",132,148],["H0935","and brought",150,161],["H1834","them to Damascus",162,178],["H5414","And he was also delivered",180,205],["H3027","into the hand",206,219],["H4428","of the king",220,231],["H3478","of Israel",232,241],["H5221","who smote",243,252],["H1419","him with a great",253,269],["H4347","slaughter",270,279]]},"28:6":{"text":"For Pekah the son of Remaliah slew in Judah an hundred and twenty thousand in one day, which were all valiant men; because they had forsaken the LORD God of their fathers.","words":[["H6492","For Pekah",0,9],["H1121","the son",10,17],["H7425","of Remaliah",18,29],["H2026","slew",30,34],["H3063","in Judah",35,43],["H3967","an hundred",44,54],["H6242","and twenty",55,65],["H0505","thousand",66,74],["H0259","in one",75,81],["H3117","day",82,85],["H2428","which were all valiant",87,109],["H1121","men",110,113],["H5800","because they had forsaken",115,140],["H3068","the LORD",141,149],["H0430","God",150,153],["H0001","of their fathers",154,170]]},"28:7":{"text":"And Zichri, a mighty man of Ephraim, slew Maaseiah the king's son, and Azrikam the governor of the house, and Elkanah that was next to the king.","words":[["H2147","And Zichri",0,10],["H1368","a mighty man",12,24],["H0669","of Ephraim",25,35],["H2026","slew",37,41],["H4641","Maaseiah",42,50],["H4428","the king's",51,61],["H1121","son",62,65],["H5840","and Azrikam",67,78],["H5057","the governor",79,91],["H1004","of the house",92,104],["H0511","and Elkanah",106,117],["H4932","that was next",118,131],["H4428","to the king",132,143]]},"28:8":{"text":"And the children of Israel carried away captive of their brethren two hundred thousand, women, sons, and daughters, and took also away much spoil from them, and brought the spoil to Samaria.","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H7617","carried away captive",27,47],["H0251","of their brethren",48,65],["H3967","two hundred",66,77],["H0505","thousand",78,86],["H0802","women",88,93],["H1121","sons",95,99],["H1323","and daughters",101,114],["H0962","and took also away",116,134],["H7227","much",135,139],["H7998","spoil",140,145],["H0935","from them, and brought",146,168],["H7998","the spoil",169,178],["H8111","to Samaria",179,189]]},"28:9":{"text":"But a prophet of the LORD was there, whose name was Oded: and he went out before the host that came to Samaria, and said unto them, Behold, because the LORD God of your fathers was wroth with Judah, he hath delivered them into your hand, and ye have slain them in a rage that reacheth up unto heaven.","words":[["H5030","But a prophet",0,13],["H3068","of the LORD",14,25],["H8034","was there, whose name",26,47],["H5752","was Oded",48,56],["H3318","and he went out",58,73],["H6440","before",74,80],["H6635","the host",81,89],["H0935","that came",90,99],["H8111","to Samaria",100,110],["H0559","and said",112,120],["H3068","unto them, Behold, because the LORD",121,156],["H0430","God",157,160],["H0001","of your fathers",161,176],["H2534","was wroth",177,186],["H3063","with Judah",187,197],["H5414","he hath delivered",199,216],["H3027","them into your hand",217,236],["H2026","and ye have slain",238,255],["H2197","them in a rage",256,270],["H5060","that reacheth up",271,287],["H8064","unto heaven",288,299]]},"28:10":{"text":"And now ye purpose to keep under the children of Judah and Jerusalem for bondmen and bondwomen unto you: but are there not with you, even with you, sins against the LORD your God?","words":[["H0559","And now ye purpose",0,18],["H3533","to keep under",19,32],["H1121","the children",33,45],["H3063","of Judah",46,54],["H3389","and Jerusalem",55,68],["H5650","for bondmen",69,80],["H8198","and bondwomen",81,94],["H7535","unto you: but are there not with you, even",95,137],["H0819","with you, sins",138,152],["H3068","against the LORD",153,169],["H0430","your God",170,178]]},"28:11":{"text":"Now hear me therefore, and deliver the captives again, which ye have taken captive of your brethren: for the fierce wrath of the LORD is upon you.","words":[["H8085","Now hear",0,8],["H7725","me therefore, and deliver",9,34],["H7633","the captives",35,47],["H7617","again, which ye have taken captive",48,82],["H0251","of your brethren",83,99],["H2740","for the fierce",101,115],["H0639","wrath",116,121],["H3068","of the LORD",122,133]]},"28:12":{"text":"Then certain of the heads of the children of Ephraim, Azariah the son of Johanan, Berechiah the son of Meshillemoth, and Jehizkiah the son of Shallum, and Amasa the son of Hadlai, stood up against them that came from the war,","words":[["H0582","Then certain",0,12],["H7218","of the heads",13,25],["H1121","of the children",26,41],["H0669","of Ephraim",42,52],["H5838","Azariah",54,61],["H1121","the son",62,69],["H3076","of Johanan",70,80],["H1296","Berechiah",82,91],["H1121","the son",92,99],["H4919","of Meshillemoth",100,115],["H3169","and Jehizkiah",117,130],["H1121","the son",131,138],["H7967","of Shallum",139,149],["H6021","and Amasa",151,160],["H1121","the son",161,168],["H2311","of Hadlai",169,178],["H6965","stood up",180,188],["H0935","against them that came",189,211],["H6635","from the war",212,224]]},"28:13":{"text":"And said unto them, Ye shall not bring in the captives hither: for whereas we have offended against the LORD already, ye intend to add more to our sins and to our trespass: for our trespass is great, and there is fierce wrath against Israel.","words":[["H0559","And said",0,8],["H0935","unto them, Ye shall not bring in",9,41],["H7633","the captives",42,54],["H0819","hither: for whereas we have offended",55,91],["H3068","against the LORD",92,108],["H0559","already, ye intend",109,127],["H3254","to add",128,134],["H2403","more to our sins",135,151],["H0819","and to our trespass",152,171],["H0819","for our trespass",173,189],["H7227","is great",190,198],["H2740","and there is fierce",200,219],["H0639","wrath",220,225],["H3478","against Israel",226,240]]},"28:14":{"text":"So the armed men left the captives and the spoil before the princes and all the congregation.","words":[["H2502","So the armed men",0,16],["H5800","left",17,21],["H7633","the captives",22,34],["H0961","and the spoil",35,48],["H6440","before",49,55],["H8269","the princes",56,67],["H6951","and all the congregation",68,92]]},"28:15":{"text":"And the men which were expressed by name rose up, and took the captives, and with the spoil clothed all that were naked among them, and arrayed them, and shod them, and gave them to eat and to drink, and anointed them, and carried all the feeble of them upon asses, and brought them to Jericho, the city of palm trees, to their brethren: then they returned to Samaria.","words":[["H0582","And the men",0,11],["H5344","which were expressed",12,32],["H8034","by name",33,40],["H6965","rose up",41,48],["H2388","and took",50,58],["H7633","the captives",59,71],["H7998","and with the spoil",73,91],["H3847","clothed",92,99],["H4636","all that were naked",100,119],["H3847","among them, and arrayed",120,143],["H5274","them, and shod",144,158],["H0398","them, and gave them to eat",159,185],["H8248","and to drink",186,198],["H5480","and anointed",200,212],["H5095","them, and carried",213,230],["H3782","all the feeble",231,245],["H2543","of them upon asses",246,264],["H0935","and brought",266,277],["H3405","them to Jericho",278,293],["H5892","the city",295,303],["H8558","of palm trees",304,317],["H5899","of palm trees",304,317],["H0681","to",319,321],["H0251","their brethren",322,336],["H7725","then they returned",338,356],["H8111","to Samaria",357,367]]},"28:16":{"text":"At that time did king Ahaz send unto the kings of Assyria to help him.","words":[["H6256","At that time",0,12],["H4428","did king",13,21],["H0271","Ahaz",22,26],["H7971","send",27,31],["H4428","unto the kings",32,46],["H0804","of Assyria",47,57],["H5826","to help",58,65]]},"28:17":{"text":"For again the Edomites had come and smitten Judah, and carried away captives.","words":[["H0130","For again the Edomites",0,22],["H0935","had come",23,31],["H5221","and smitten",32,43],["H3063","Judah",44,49],["H7617","and carried away",51,67],["H7628","captives",68,76]]},"28:18":{"text":"The Philistines also had invaded the cities of the low country, and of the south of Judah, and had taken Bethshemesh, and Ajalon, and Gederoth, and Shocho with the villages thereof, and Timnah with the villages thereof, Gimzo also and the villages thereof: and they dwelt there.","words":[["H6430","The Philistines",0,15],["H6584","also had invaded",16,32],["H5892","the cities",33,43],["H8219","of the low country",44,62],["H5045","and of the south",64,80],["H3063","of Judah",81,89],["H3920","and had taken",91,104],["H1053","Bethshemesh",105,116],["H0357","and Ajalon",118,128],["H1450","and Gederoth",130,142],["H7755","and Shocho",144,154],["H1323","with the villages",155,172],["H8553","thereof, and Timnah",173,192],["H1323","with the villages",193,210],["H1579","thereof, Gimzo",211,225],["H1323","also and the villages",226,247],["H3427","thereof: and they dwelt",248,271]]},"28:19":{"text":"For the LORD brought Judah low because of Ahaz king of Israel; for he made Judah naked, and transgressed sore against the LORD.","words":[["H3068","For the LORD",0,12],["H3665","brought",13,20],["H3063","Judah",21,26],["H3665","low",27,30],["H0271","because of Ahaz",31,46],["H4428","king",47,51],["H3478","of Israel",52,61],["H6544","for he made",63,74],["H3063","Judah",75,80],["H6544","naked",81,86],["H4603","and transgressed",88,104],["H4604","sore",105,109],["H3068","against the LORD",110,126]]},"28:20":{"text":"And Tilgathpilneser king of Assyria came unto him, and distressed him, but strengthened him not.","words":[["H8407","And Tilgathpilneser",0,19],["H4428","king",20,24],["H0804","of Assyria",25,35],["H0935","came",36,40],["H6696","unto him, and distressed",41,65],["H2388","him, but strengthened",66,87]]},"28:21":{"text":"For Ahaz took away a portion out of the house of the LORD, and out of the house of the king, and of the princes, and gave it unto the king of Assyria: but he helped him not.","words":[["H0271","For Ahaz",0,8],["H2505","took away a portion",9,28],["H1004","out of the house",29,45],["H3068","of the LORD",46,57],["H1004","and out of the house",59,79],["H4428","of the king",80,91],["H8269","and of the princes",93,111],["H5414","and gave",113,121],["H4428","it unto the king",122,138],["H0804","of Assyria",139,149],["H5833","but he helped",151,164]]},"28:22":{"text":"And in the time of his distress did he trespass yet more against the LORD: this is that king Ahaz.","words":[["H6256","And in the time",0,15],["H6887","of his distress",16,31],["H4603","did he trespass",32,47],["H3254","yet more",48,56],["H3068","against the LORD",57,73],["H4428","this is that king",75,92],["H0271","Ahaz",93,97]]},"28:23":{"text":"For he sacrificed unto the gods of Damascus, which smote him: and he said, Because the gods of the kings of Syria help them, therefore will I sacrifice to them, that they may help me. But they were the ruin of him, and of all Israel.","words":[["H2076","For he sacrificed",0,17],["H0430","unto the gods",18,31],["H1834","of Damascus",32,43],["H5221","which smote",45,56],["H0559","him: and he said",57,73],["H0430","Because the gods",75,91],["H4428","of the kings",92,104],["H0758","of Syria",105,113],["H5826","help",114,118],["H2076","them, therefore will I sacrifice",119,151],["H5826","to them, that they may help",152,179],["H3782","me. But they were the ruin",180,206],["H3478","of him, and of all Israel",207,232]]},"28:24":{"text":"And Ahaz gathered together the vessels of the house of God, and cut in pieces the vessels of the house of God, and shut up the doors of the house of the LORD, and he made him altars in every corner of Jerusalem.","words":[["H0271","And Ahaz",0,8],["H0622","gathered together",9,26],["H3627","the vessels",27,38],["H1004","of the house",39,51],["H0430","of God",52,58],["H7112","and cut in pieces",60,77],["H3627","the vessels",78,89],["H1004","of the house",90,102],["H0430","of God",103,109],["H5462","and shut up",111,122],["H1817","the doors",123,132],["H1004","of the house",133,145],["H3068","of the LORD",146,157],["H6213","and he made",159,170],["H4196","him altars",171,181],["H6438","in every corner",182,197],["H3389","of Jerusalem",198,210]]},"28:25":{"text":"And in every several city of Judah he made high places to burn incense unto other gods, and provoked to anger the LORD God of his fathers.","words":[["H5892","And in every several city",0,25],["H3063","of Judah",26,34],["H6213","he made",35,42],["H1116","high places",43,54],["H6999","to burn incense",55,70],["H0312","unto other",71,81],["H0430","gods",82,86],["H3707","and provoked to anger",88,109],["H3068","the LORD",110,118],["H0430","God",119,122],["H0001","of his fathers",123,137]]},"28:26":{"text":"Now the rest of his acts and of all his ways, first and last, behold, they are written in the book of the kings of Judah and Israel.","words":[["H3499","Now the rest",0,12],["H1697","of his acts",13,24],["H1870","and of all his ways",25,44],["H7223","first",46,51],["H0314","and last",52,60],["H3789","behold, they are written",62,86],["H5612","in the book",87,98],["H4428","of the kings",99,111],["H3063","of Judah",112,120],["H3478","and Israel",121,131]]},"28:27":{"text":"And Ahaz slept with his fathers, and they buried him in the city, even in Jerusalem: but they brought him not into the sepulchres of the kings of Israel: and Hezekiah his son reigned in his stead.","words":[["H0271","And Ahaz",0,8],["H7901","slept",9,14],["H0001","with his fathers",15,31],["H6912","and they buried",33,48],["H5892","him in the city",49,64],["H3389","even in Jerusalem",66,83],["H0935","but they brought",85,101],["H6913","him not into the sepulchres",102,129],["H4428","of the kings",130,142],["H3478","of Israel",143,152],["H3169","and Hezekiah",154,166],["H1121","his son",167,174],["H4427","reigned",175,182]]},"29:1":{"text":"Hezekiah began to reign when he was five and twenty years old, and he reigned nine and twenty years in Jerusalem. And his mother's name was Abijah, the daughter of Zechariah.","words":[["H3169","Hezekiah",0,8],["H4427","began to reign",9,23],["H2568","when he was five",24,40],["H6242","and twenty",41,51],["H8141","years",52,57],["H1121","old",58,61],["H4427","and he reigned",63,77],["H8672","nine",78,82],["H6242","and twenty",83,93],["H8141","years",94,99],["H3389","in Jerusalem",100,112],["H0517","And his mother's",114,130],["H8034","name",131,135],["H0029","was Abijah",136,146],["H1323","the daughter",148,160],["H2148","of Zechariah",161,173]]},"29:2":{"text":"And he did that which was right in the sight of the LORD, according to all that David his father had done.","words":[["H6213","And he did",0,10],["H3477","that which was right",11,31],["H5869","in the sight",32,44],["H3068","of the LORD",45,56],["H1732","according to all that David",58,85],["H0001","his father",86,96],["H6213","had done",97,105]]},"29:3":{"text":"He in the first year of his reign, in the first month, opened the doors of the house of the LORD, and repaired them.","words":[["H7223","He in the first",0,15],["H8141","year",16,20],["H4427","of his reign",21,33],["H7223","in the first",35,47],["H2320","month",48,53],["H6605","opened",55,61],["H1817","the doors",62,71],["H1004","of the house",72,84],["H3068","of the LORD",85,96],["H2388","and repaired",98,110]]},"29:4":{"text":"And he brought in the priests and the Levites, and gathered them together into the east street,","words":[["H0935","And he brought in",0,17],["H3548","the priests",18,29],["H3881","and the Levites",30,45],["H0622","and gathered them together",47,73],["H4217","into the east",74,87],["H7339","street",88,94]]},"29:5":{"text":"And said unto them, Hear me, ye Levites, sanctify now yourselves, and sanctify the house of the LORD God of your fathers, and carry forth the filthiness out of the holy place.","words":[["H0559","And said",0,8],["H8085","unto them, Hear",9,24],["H3881","me, ye Levites",25,39],["H6942","sanctify",41,49],["H6942","now yourselves, and sanctify",50,78],["H1004","the house",79,88],["H3068","of the LORD",89,100],["H0430","God",101,104],["H0001","of your fathers",105,120],["H3318","and carry forth",122,137],["H5079","the filthiness",138,152],["H6944","out of the holy",153,168]]},"29:6":{"text":"For our fathers have trespassed, and done that which was evil in the eyes of the LORD our God, and have forsaken him, and have turned away their faces from the habitation of the LORD, and turned their backs.","words":[["H0001","For our fathers",0,15],["H4603","have trespassed",16,31],["H6213","and done",33,41],["H7451","that which was evil",42,61],["H5869","in the eyes",62,73],["H3068","of the LORD",74,85],["H0430","our God",86,93],["H5800","and have forsaken",95,112],["H5437","him, and have turned away",113,138],["H6440","their faces",139,150],["H4908","from the habitation",151,170],["H3068","of the LORD",171,182],["H5414","and turned",184,194],["H6203","their backs",195,206]]},"29:7":{"text":"Also they have shut up the doors of the porch, and put out the lamps, and have not burned incense nor offered burnt offerings in the holy place unto the God of Israel.","words":[["H5462","Also they have shut up",0,22],["H1817","the doors",23,32],["H0197","of the porch",33,45],["H3518","and put out",47,58],["H5216","the lamps",59,68],["H6999","and have not burned",70,89],["H7004","incense",90,97],["H5927","nor offered",98,109],["H5930","burnt offerings",110,125],["H6944","in the holy",126,137],["H0430","place unto the God",138,156],["H3478","of Israel",157,166]]},"29:8":{"text":"Wherefore the wrath of the LORD was upon Judah and Jerusalem, and he hath delivered them to trouble, to astonishment, and to hissing, as ye see with your eyes.","words":[["H7110","Wherefore the wrath",0,19],["H3068","of the LORD",20,31],["H3063","was upon Judah",32,46],["H3389","and Jerusalem",47,60],["H5414","and he hath delivered",62,83],["H2189","them to trouble",84,99],["H2113","them to trouble",84,99],["H8047","to astonishment",101,116],["H8322","and to hissing",118,132],["H7200","as ye see",134,143],["H5869","with your eyes",144,158]]},"29:9":{"text":"For, lo, our fathers have fallen by the sword, and our sons and our daughters and our wives are in captivity for this.","words":[["H0001","For, lo, our fathers",0,20],["H5307","have fallen",21,32],["H2719","by the sword",33,45],["H1121","and our sons",47,59],["H1323","and our daughters",60,77],["H0802","and our wives",78,91],["H7628","are in captivity",92,108]]},"29:10":{"text":"Now it is in mine heart to make a covenant with the LORD God of Israel, that his fierce wrath may turn away from us.","words":[["H3824","Now it is in mine heart",0,23],["H3772","to make",24,31],["H1285","a covenant",32,42],["H3068","with the LORD",43,56],["H0430","God",57,60],["H3478","of Israel",61,70],["H2740","that his fierce",72,87],["H0639","wrath",88,93],["H7725","may turn away",94,107]]},"29:11":{"text":"My sons, be not now negligent: for the LORD hath chosen you to stand before him, to serve him, and that ye should minister unto him, and burn incense.","words":[["H1121","My sons",0,7],["H7952","be not now negligent",9,29],["H3068","for the LORD",31,43],["H0977","hath chosen",44,55],["H5975","you to stand",56,68],["H6440","before",69,75],["H8334","him, to serve",76,89],["H8334","him, and that ye should minister",90,122],["H6999","unto him, and burn incense",123,149]]},"29:12":{"text":"Then the Levites arose, Mahath the son of Amasai, and Joel the son of Azariah, of the sons of the Kohathites: and of the sons of Merari, Kish the son of Abdi, and Azariah the son of Jehalelel: and of the Gershonites; Joah the son of Zimmah, and Eden the son of Joah:","words":[["H3881","Then the Levites",0,16],["H6965","arose",17,22],["H4287","Mahath",24,30],["H1121","the son",31,38],["H6022","of Amasai",39,48],["H3100","and Joel",50,58],["H1121","the son",59,66],["H5838","of Azariah",67,77],["H1121","of the sons",79,90],["H6956","of the Kohathites",91,108],["H1121","and of the sons",110,125],["H4847","of Merari",126,135],["H7027","Kish",137,141],["H1121","the son",142,149],["H5660","of Abdi",150,157],["H5838","and Azariah",159,170],["H1121","the son",171,178],["H3094","of Jehalelel",179,191],["H1649","and of the Gershonites",193,215],["H3098","Joah",217,221],["H1121","the son",222,229],["H2155","of Zimmah",230,239],["H5731","and Eden",241,249],["H1121","the son",250,257],["H3098","of Joah",258,265]]},"29:13":{"text":"And of the sons of Elizaphan; Shimri, and Jeiel: and of the sons of Asaph; Zechariah, and Mattaniah:","words":[["H1121","And of the sons",0,15],["H0469","of Elizaphan",16,28],["H8113","Shimri",30,36],["H3273","and Jeiel",38,47],["H1121","and of the sons",49,64],["H0623","of Asaph",65,73],["H2148","Zechariah",75,84],["H4983","and Mattaniah",86,99]]},"29:14":{"text":"And of the sons of Heman; Jehiel, and Shimei: and of the sons of Jeduthun; Shemaiah, and Uzziel.","words":[["H1121","And of the sons",0,15],["H1968","of Heman",16,24],["H3171","Jehiel",26,32],["H8096","and Shimei",34,44],["H1121","and of the sons",46,61],["H3038","of Jeduthun",62,73],["H8098","Shemaiah",75,83],["H5816","and Uzziel",85,95]]},"29:15":{"text":"And they gathered their brethren, and sanctified themselves, and came, according to the commandment of the king, by the words of the LORD, to cleanse the house of the LORD.","words":[["H0622","And they gathered",0,17],["H0251","their brethren",18,32],["H6942","and sanctified",34,48],["H0935","themselves, and came",49,69],["H4687","according to the commandment",71,99],["H4428","of the king",100,111],["H1697","by the words",113,125],["H3068","of the LORD",126,137],["H2891","to cleanse",139,149],["H1004","the house",150,159],["H3068","of the LORD",160,171]]},"29:16":{"text":"And the priests went into the inner part of the house of the LORD, to cleanse it, and brought out all the uncleanness that they found in the temple of the LORD into the court of the house of the LORD. And the Levites took it, to carry it out abroad into the brook Kidron.","words":[["H3548","And the priests",0,15],["H0935","went",16,20],["H6441","into the inner part",21,40],["H1004","of the house",41,53],["H3068","of the LORD",54,65],["H2891","to cleanse",67,77],["H3318","it, and brought out",78,97],["H2932","all the uncleanness",98,117],["H4672","that they found",118,133],["H1964","in the temple",134,147],["H3068","of the LORD",148,159],["H2691","into the court",160,174],["H1004","of the house",175,187],["H3068","of the LORD",188,199],["H3881","And the Levites",201,216],["H6901","took",217,221],["H3318","it, to carry it out",222,241],["H2351","abroad",242,248],["H5158","into the brook",249,263],["H6939","Kidron",264,270]]},"29:17":{"text":"Now they began on the first day of the first month to sanctify, and on the eighth day of the month came they to the porch of the LORD: so they sanctified the house of the LORD in eight days; and in the sixteenth day of the first month they made an end.","words":[["H2490","Now they began",0,14],["H0259","on the first",15,27],["H7223","day of the first",28,44],["H2320","month",45,50],["H6942","to sanctify",51,62],["H8083","and on the eighth",64,81],["H3117","day",82,85],["H2320","of the month",86,98],["H0935","came",99,103],["H0197","they to the porch",104,121],["H3068","of the LORD",122,133],["H6942","so they sanctified",135,153],["H1004","the house",154,163],["H3068","of the LORD",164,175],["H8083","in eight",176,184],["H3117","days",185,189],["H8337","and in the sixteenth",191,211],["H6240","and in the sixteenth",191,211],["H7223","day of the first",212,228],["H2320","month",229,234],["H3615","they made an end",235,251]]},"29:18":{"text":"Then they went in to Hezekiah the king, and said, We have cleansed all the house of the LORD, and the altar of burnt offering, with all the vessels thereof, and the shewbread table, with all the vessels thereof.","words":[["H0935","Then they went",0,14],["H6441","in",15,17],["H2396","to Hezekiah",18,29],["H4428","the king",30,38],["H0559","and said",40,48],["H2891","We have cleansed",50,66],["H1004","all the house",67,80],["H3068","of the LORD",81,92],["H4196","and the altar",94,107],["H5930","of burnt offering",108,125],["H3627","with all the vessels",127,147],["H4635","thereof, and the shewbread",148,174],["H7979","table",175,180],["H3627","with all the vessels",182,202]]},"29:19":{"text":"Moreover all the vessels, which king Ahaz in his reign did cast away in his transgression, have we prepared and sanctified, and, behold, they are before the altar of the LORD.","words":[["H3627","Moreover all the vessels",0,24],["H4428","which king",26,36],["H0271","Ahaz",37,41],["H4438","in his reign",42,54],["H2186","did cast away",55,68],["H4604","in his transgression",69,89],["H3559","have we prepared",91,107],["H6942","and sanctified",108,122],["H6440","and, behold, they are before",124,152],["H4196","the altar",153,162],["H3068","of the LORD",163,174]]},"29:20":{"text":"Then Hezekiah the king rose early, and gathered the rulers of the city, and went up to the house of the LORD.","words":[["H3169","Then Hezekiah",0,13],["H4428","the king",14,22],["H7925","rose early",23,33],["H0622","and gathered",35,47],["H8269","the rulers",48,58],["H5892","of the city",59,70],["H5927","and went up",72,83],["H1004","to the house",84,96],["H3068","of the LORD",97,108]]},"29:21":{"text":"And they brought seven bullocks, and seven rams, and seven lambs, and seven he goats, for a sin offering for the kingdom, and for the sanctuary, and for Judah. And he commanded the priests the sons of Aaron to offer them on the altar of the LORD.","words":[["H0935","And they brought",0,16],["H7651","seven",17,22],["H6499","bullocks",23,31],["H7651","and seven",33,42],["H0352","rams",43,47],["H7651","and seven",49,58],["H3532","lambs",59,64],["H7651","and seven",66,75],["H6842","he",76,78],["H5795","goats",79,84],["H2403","for a sin offering",86,104],["H4467","for the kingdom",105,120],["H4720","and for the sanctuary",122,143],["H3063","and for Judah",145,158],["H0559","And he commanded",160,176],["H3548","the priests",177,188],["H1121","the sons",189,197],["H0175","of Aaron",198,206],["H5927","to offer",207,215],["H4196","them on the altar",216,233],["H3068","of the LORD",234,245]]},"29:22":{"text":"So they killed the bullocks, and the priests received the blood, and sprinkled it on the altar: likewise, when they had killed the rams, they sprinkled the blood upon the altar: they killed also the lambs, and they sprinkled the blood upon the altar.","words":[["H7819","So they killed",0,14],["H1241","the bullocks",15,27],["H3548","and the priests",29,44],["H6901","received",45,53],["H1818","the blood",54,63],["H2236","and sprinkled",65,78],["H4196","it on the altar",79,94],["H7819","likewise, when they had killed",96,126],["H0352","the rams",127,135],["H2236","they sprinkled",137,151],["H1818","the blood",152,161],["H4196","upon the altar",162,176],["H7819","they killed",178,189],["H3532","also the lambs",190,204],["H2236","and they sprinkled",206,224],["H1818","the blood",225,234],["H4196","upon the altar",235,249]]},"29:23":{"text":"And they brought forth the he goats for the sin offering before the king and the congregation; and they laid their hands upon them:","words":[["H5066","And they brought forth",0,22],["H8163","the he goats",23,35],["H2403","for the sin offering",36,56],["H6440","before",57,63],["H4428","the king",64,72],["H6951","and the congregation",73,93],["H5564","and they laid",95,108],["H3027","their hands",109,120]]},"29:24":{"text":"And the priests killed them, and they made reconciliation with their blood upon the altar, to make an atonement for all Israel: for the king commanded that the burnt offering and the sin offering should be made for all Israel.","words":[["H3548","And the priests",0,15],["H7819","killed",16,22],["H2398","them, and they made reconciliation",23,57],["H1818","with their blood",58,74],["H4196","upon the altar",75,89],["H3722","to make an atonement",91,111],["H3478","for all Israel",112,126],["H4428","for the king",128,140],["H0559","commanded",141,150],["H5930","that the burnt offering",151,174],["H2403","and the sin offering",175,195],["H3478","should be made for all Israel",196,225]]},"29:25":{"text":"And he set the Levites in the house of the LORD with cymbals, with psalteries, and with harps, according to the commandment of David, and of Gad the king's seer, and Nathan the prophet: for so was the commandment of the LORD by his prophets.","words":[["H5975","And he set",0,10],["H3881","the Levites",11,22],["H1004","in the house",23,35],["H3068","of the LORD",36,47],["H4700","with cymbals",48,60],["H5035","with psalteries",62,77],["H3658","and with harps",79,93],["H4687","according to the commandment",95,123],["H1732","of David",124,132],["H1410","and of Gad",134,144],["H4428","the king's",145,155],["H2374","seer",156,160],["H5416","and Nathan",162,172],["H5030","the prophet",173,184],["H4687","for so was the commandment",186,212],["H3027","of",213,215],["H3068","the LORD",216,224],["H3027","by",225,227],["H5030","his prophets",228,240]]},"29:26":{"text":"And the Levites stood with the instruments of David, and the priests with the trumpets.","words":[["H3881","And the Levites",0,15],["H5975","stood",16,21],["H3627","with the instruments",22,42],["H1732","of David",43,51],["H3548","and the priests",53,68],["H2689","with the trumpets",69,86]]},"29:27":{"text":"And Hezekiah commanded to offer the burnt offering upon the altar. And when the burnt offering began, the song of the LORD began also with the trumpets, and with the instruments ordained by David king of Israel.","words":[["H2396","And Hezekiah",0,12],["H0559","commanded",13,22],["H5927","to offer",23,31],["H5930","the burnt offering",32,50],["H4196","upon the altar",51,65],["H6256","And when",67,75],["H5930","the burnt offering",76,94],["H2490","began",95,100],["H7892","the song",102,110],["H3068","of the LORD",111,122],["H2490","began",123,128],["H2689","also with the trumpets",129,151],["H3627","and with the instruments",153,177],["H3027","ordained by",178,189],["H1732","David",190,195],["H4428","king",196,200],["H3478","of Israel",201,210]]},"29:28":{"text":"And all the congregation worshipped, and the singers sang, and the trumpeters sounded: and all this continued until the burnt offering was finished.","words":[["H6951","And all the congregation",0,24],["H7812","worshipped",25,35],["H7892","and the singers",37,52],["H7891","sang",53,57],["H2689","and the trumpeters",59,77],["H2690","sounded",78,85],["H2690","sounded",78,85],["H5930","and all this continued until the burnt offering",87,134],["H3615","was finished",135,147]]},"29:29":{"text":"And when they had made an end of offering, the king and all that were present with him bowed themselves, and worshipped.","words":[["H3615","And when they had made an end",0,29],["H5927","of offering",30,41],["H4428","the king",43,51],["H4672","and all that were present",52,77],["H3766","with him bowed",78,92],["H7812","themselves, and worshipped",93,119]]},"29:30":{"text":"Moreover Hezekiah the king and the princes commanded the Levites to sing praise unto the LORD with the words of David, and of Asaph the seer. And they sang praises with gladness, and they bowed their heads and worshipped.","words":[["H3169","Moreover Hezekiah",0,17],["H4428","the king",18,26],["H8269","and the princes",27,42],["H0559","commanded",43,52],["H3881","the Levites",53,64],["H1984","to sing praise",65,79],["H3068","unto the LORD",80,93],["H1697","with the words",94,108],["H1732","of David",109,117],["H0623","and of Asaph",119,131],["H2374","the seer",132,140],["H1984","And they sang praises",142,163],["H8057","with gladness",164,177],["H6915","and they bowed their heads",179,205],["H7812","and worshipped",206,220]]},"29:31":{"text":"Then Hezekiah answered and said, Now ye have consecrated yourselves unto the LORD, come near and bring sacrifices and thank offerings into the house of the LORD. And the congregation brought in sacrifices and thank offerings; and as many as were of a free heart burnt offerings.","words":[["H3169","Then Hezekiah",0,13],["H6030","answered",14,22],["H0559","and said",23,31],["H4390","Now ye have consecrated",33,56],["H3027","Now ye have consecrated",33,56],["H3068","yourselves unto the LORD",57,81],["H5066","come near",83,92],["H0935","and bring",93,102],["H2077","sacrifices",103,113],["H8426","and thank offerings",114,133],["H1004","into the house",134,148],["H3068","of the LORD",149,160],["H6951","And the congregation",162,182],["H0935","brought in",183,193],["H2077","sacrifices",194,204],["H8426","and thank offerings",205,224],["H5081","and as many as were of a free",226,255],["H3820","heart",256,261],["H5930","burnt offerings",262,277]]},"29:32":{"text":"And the number of the burnt offerings, which the congregation brought, was threescore and ten bullocks, an hundred rams, and two hundred lambs: all these were for a burnt offering to the LORD.","words":[["H4557","And the number",0,14],["H5930","of the burnt offerings",15,37],["H6951","which the congregation",39,61],["H0935","brought",62,69],["H7657","was threescore and ten",71,93],["H1241","bullocks",94,102],["H3967","an hundred",104,114],["H0352","rams",115,119],["H3967","and two hundred",121,136],["H3532","lambs",137,142],["H5930","all these were for a burnt offering",144,179],["H3068","to the LORD",180,191]]},"29:33":{"text":"And the consecrated things were six hundred oxen and three thousand sheep.","words":[["H6944","And the consecrated things",0,26],["H8337","were six",27,35],["H3967","hundred",36,43],["H1241","oxen",44,48],["H7969","and three",49,58],["H0505","thousand",59,67],["H6629","sheep",68,73]]},"29:34":{"text":"But the priests were too few, so that they could not flay all the burnt offerings: wherefore their brethren the Levites did help them, till the work was ended, and until the other priests had sanctified themselves: for the Levites were more upright in heart to sanctify themselves than the priests.","words":[["H3548","But the priests",0,15],["H4592","were too few",16,28],["H3201","so that they could",30,48],["H6584","not flay",49,57],["H5930","all the burnt offerings",58,81],["H0251","wherefore their brethren",83,107],["H3881","the Levites",108,119],["H2388","did help",120,128],["H4399","them, till the work",129,148],["H3615","was ended",149,158],["H3548","and until the other priests",160,187],["H6942","had sanctified",188,202],["H3881","themselves: for the Levites",203,230],["H3477","were more upright",231,248],["H3824","in heart",249,257],["H6942","to sanctify",258,269],["H3548","themselves than the priests",270,297]]},"29:35":{"text":"And also the burnt offerings were in abundance, with the fat of the peace offerings, and the drink offerings for every burnt offering. So the service of the house of the LORD was set in order.","words":[["H5930","And also the burnt offerings",0,28],["H7230","were in abundance",29,46],["H2459","with the fat",48,60],["H8002","of the peace offerings",61,83],["H5262","and the drink offerings",85,108],["H5930","for every burnt offering",109,133],["H5656","So the service",135,149],["H1004","of the house",150,162],["H3068","of the LORD",163,174],["H3559","was set in order",175,191]]},"29:36":{"text":"And Hezekiah rejoiced, and all the people, that God had prepared the people: for the thing was done suddenly.","words":[["H3169","And Hezekiah",0,12],["H8055","rejoiced",13,21],["H5971","and all the people",23,41],["H0430","that God",43,51],["H3559","had prepared",52,64],["H5971","the people",65,75],["H1697","for the thing",77,90],["H6597","was done suddenly",91,108]]},"30:1":{"text":"And Hezekiah sent to all Israel and Judah, and wrote letters also to Ephraim and Manasseh, that they should come to the house of the LORD at Jerusalem, to keep the passover unto the LORD God of Israel.","words":[["H3169","And Hezekiah",0,12],["H7971","sent",13,17],["H3478","to all Israel",18,31],["H3063","and Judah",32,41],["H3789","and wrote",43,52],["H0107","letters",53,60],["H0669","also to Ephraim",61,76],["H4519","and Manasseh",77,89],["H0935","that they should come",91,112],["H1004","to the house",113,125],["H3068","of the LORD",126,137],["H3389","at Jerusalem",138,150],["H6213","to keep",152,159],["H6453","the passover",160,172],["H3068","unto the LORD",173,186],["H0430","God",187,190],["H3478","of Israel",191,200]]},"30:2":{"text":"For the king had taken counsel, and his princes, and all the congregation in Jerusalem, to keep the passover in the second month.","words":[["H4428","For the king",0,12],["H3289","had taken counsel",13,30],["H8269","and his princes",32,47],["H6951","and all the congregation",49,73],["H3389","in Jerusalem",74,86],["H6213","to keep",88,95],["H6453","the passover",96,108],["H8145","in the second",109,122],["H2320","month",123,128]]},"30:3":{"text":"For they could not keep it at that time, because the priests had not sanctified themselves sufficiently, neither had the people gathered themselves together to Jerusalem.","words":[["H3201","For they could",0,14],["H6213","not keep",15,23],["H6256","it at that time",24,39],["H3548","because the priests",41,60],["H6942","had not sanctified",61,79],["H4078","themselves sufficiently",80,103],["H1767","themselves sufficiently",80,103],["H5971","neither had the people",105,127],["H0622","gathered themselves together",128,156],["H3389","to Jerusalem",157,169]]},"30:4":{"text":"And the thing pleased the king and all the congregation.","words":[["H1697","And the thing",0,13],["H3474","pleased",14,21],["H5869","pleased",14,21],["H4428","the king",22,30],["H6951","and all the congregation",31,55]]},"30:5":{"text":"So they established a decree to make proclamation throughout all Israel, from Beersheba even to Dan, that they should come to keep the passover unto the LORD God of Israel at Jerusalem: for they had not done it of a long time in such sort as it was written.","words":[["H5975","So they established",0,19],["H1697","a decree",20,28],["H5674","to make proclamation",29,49],["H6963","to make proclamation",29,49],["H3478","throughout all Israel",50,71],["H0884","from Beersheba",73,87],["H1835","even to Dan",88,99],["H0935","that they should come",101,122],["H6213","to keep",123,130],["H6453","the passover",131,143],["H3068","unto the LORD",144,157],["H0430","God",158,161],["H3478","of Israel",162,171],["H3389","at Jerusalem",172,184],["H6213","for they had not done",186,207],["H7230","it of a long",208,220],["H3789","time in such sort as it was written",221,256]]},"30:6":{"text":"So the posts went with the letters from the king and his princes throughout all Israel and Judah, and according to the commandment of the king, saying, Ye children of Israel, turn again unto the LORD God of Abraham, Isaac, and Israel, and he will return to the remnant of you, that are escaped out of the hand of the kings of Assyria.","words":[["H7323","So the posts",0,12],["H3212","went",13,17],["H0107","with the letters",18,34],["H3027","from",35,39],["H4428","the king",40,48],["H8269","and his princes",49,64],["H3478","throughout all Israel",65,86],["H3063","and Judah",87,96],["H4687","and according to the commandment",98,130],["H4428","of the king",131,142],["H0559","saying",144,150],["H1121","Ye children",152,163],["H3478","of Israel",164,173],["H7725","turn again",175,185],["H3068","unto the LORD",186,199],["H0430","God",200,203],["H0085","of Abraham",204,214],["H3327","Isaac",216,221],["H3478","and Israel",223,233],["H7725","and he will return",235,253],["H7604","to the remnant",254,268],["H6413","of you, that are escaped",269,293],["H3709","out of the hand",294,309],["H4428","of the kings",310,322],["H0804","of Assyria",323,333]]},"30:7":{"text":"And be not ye like your fathers, and like your brethren, which trespassed against the LORD God of their fathers, who therefore gave them up to desolation, as ye see.","words":[["H0001","And be not ye like your fathers",0,31],["H0251","and like your brethren",33,55],["H4603","which trespassed",57,73],["H3068","against the LORD",74,90],["H0430","God",91,94],["H0001","of their fathers",95,111],["H5414","who therefore gave them up",113,139],["H8047","to desolation",140,153],["H7200","as ye see",155,164]]},"30:8":{"text":"Now be ye not stiffnecked, as your fathers were, but yield yourselves unto the LORD, and enter into his sanctuary, which he hath sanctified for ever: and serve the LORD your God, that the fierceness of his wrath may turn away from you.","words":[["H7185","Now be ye not stiffnecked",0,25],["H6203","Now be ye not stiffnecked",0,25],["H0001","as your fathers",27,42],["H5414","were, but yield",43,58],["H3027","yourselves",59,69],["H3068","unto the LORD",70,83],["H0935","and enter",85,94],["H4720","into his sanctuary",95,113],["H6942","which he hath sanctified",115,139],["H5769","for ever",140,148],["H5647","and serve",150,159],["H3068","the LORD",160,168],["H0430","your God",169,177],["H2740","that the fierceness",179,198],["H0639","of his wrath",199,211],["H7725","may turn away",212,225]]},"30:9":{"text":"For if ye turn again unto the LORD, your brethren and your children shall find compassion before them that lead them captive, so that they shall come again into this land: for the LORD your God is gracious and merciful, and will not turn away his face from you, if ye return unto him.","words":[["H7725","For if ye turn again",0,20],["H3068","unto the LORD",21,34],["H0251","your brethren",36,49],["H1121","and your children",50,67],["H7356","shall find compassion",68,89],["H6440","before",90,96],["H7617","them that lead them captive",97,124],["H7725","so that they shall come again",126,155],["H0776","into this land",156,170],["H3068","for the LORD",172,184],["H0430","your God",185,193],["H2587","is gracious",194,205],["H7349","and merciful",206,218],["H5493","and will not turn away",220,242],["H6440","his face",243,251],["H7725","from you, if ye return",252,274]]},"30:10":{"text":"So the posts passed from city to city through the country of Ephraim and Manasseh even unto Zebulun: but they laughed them to scorn, and mocked them.","words":[["H7323","So the posts",0,12],["H5674","passed",13,19],["H5892","from city",20,29],["H5892","to city",30,37],["H0776","through the country",38,57],["H0669","of Ephraim",58,68],["H4519","and Manasseh",69,81],["H2074","even unto Zebulun",82,99],["H7832","but they laughed them to scorn",101,131],["H3932","and mocked",133,143]]},"30:11":{"text":"Nevertheless divers of Asher and Manasseh and of Zebulun humbled themselves, and came to Jerusalem.","words":[["H0582","Nevertheless divers",0,19],["H0836","of Asher",20,28],["H4519","and Manasseh",29,41],["H2074","and of Zebulun",42,56],["H3665","humbled",57,64],["H0935","themselves, and came",65,85],["H3389","to Jerusalem",86,98]]},"30:12":{"text":"Also in Judah the hand of God was to give them one heart to do the commandment of the king and of the princes, by the word of the LORD.","words":[["H3063","Also in Judah",0,13],["H3027","the hand",14,22],["H0430","of God",23,29],["H5414","was to give",30,41],["H0259","them one",42,50],["H3820","heart",51,56],["H6213","to do",57,62],["H4687","the commandment",63,78],["H4428","of the king",79,90],["H8269","and of the princes",91,109],["H1697","by the word",111,122],["H3068","of the LORD",123,134]]},"30:13":{"text":"And there assembled at Jerusalem much people to keep the feast of unleavened bread in the second month, a very great congregation.","words":[["H0622","And there assembled",0,19],["H3389","at Jerusalem",20,32],["H7227","much",33,37],["H5971","people",38,44],["H6213","to keep",45,52],["H2282","the feast",53,62],["H4682","of unleavened bread",63,82],["H8145","in the second",83,96],["H2320","month",97,102],["H3966","a very",104,110],["H7230","great",111,116],["H6951","congregation",117,129]]},"30:14":{"text":"And they arose and took away the altars that were in Jerusalem, and all the altars for incense took they away, and cast them into the brook Kidron.","words":[["H6965","And they arose",0,14],["H5493","and took away",15,28],["H4196","the altars",29,39],["H3389","that were in Jerusalem",40,62],["H6999","and all the altars for incense",64,94],["H5493","took they away",95,109],["H7993","and cast",111,119],["H5158","them into the brook",120,139],["H6939","Kidron",140,146]]},"30:15":{"text":"Then they killed the passover on the fourteenth day of the second month: and the priests and the Levites were ashamed, and sanctified themselves, and brought in the burnt offerings into the house of the LORD.","words":[["H7819","Then they killed",0,16],["H6453","the passover",17,29],["H0702","on the fourteenth",30,47],["H6240","on the fourteenth",30,47],["H8145","day of the second",48,65],["H2320","month",66,71],["H3548","and the priests",73,88],["H3881","and the Levites",89,104],["H3637","were ashamed",105,117],["H6942","and sanctified",119,133],["H0935","themselves, and brought in",134,160],["H5930","the burnt offerings",161,180],["H1004","into the house",181,195],["H3068","of the LORD",196,207]]},"30:16":{"text":"And they stood in their place after their manner, according to the law of Moses the man of God: the priests sprinkled the blood, which they received of the hand of the Levites.","words":[["H5975","And they stood",0,14],["H5977","in their place",15,29],["H4941","after their manner",30,48],["H8451","according to the law",50,70],["H4872","of Moses",71,79],["H0376","the man",80,87],["H0430","of God",88,94],["H3548","the priests",96,107],["H2236","sprinkled",108,117],["H1818","the blood",118,127],["H3027","which they received of the hand",129,160],["H3881","of the Levites",161,175]]},"30:17":{"text":"For there were many in the congregation that were not sanctified: therefore the Levites had the charge of the killing of the passovers for every one that was not clean, to sanctify them unto the LORD.","words":[["H7227","For there were many",0,19],["H6951","in the congregation",20,39],["H6942","that were not sanctified",40,64],["H3881","therefore the Levites",66,87],["H7821","had the charge of the killing",88,117],["H6453","of the passovers",118,134],["H2889","for every one that was not clean",135,167],["H6942","to sanctify",169,180],["H3068","them unto the LORD",181,199]]},"30:18":{"text":"For a multitude of the people, even many of Ephraim, and Manasseh, Issachar, and Zebulun, had not cleansed themselves, yet did they eat the passover otherwise than it was written. But Hezekiah prayed for them, saying, The good LORD pardon every one","words":[["H4768","For a multitude",0,15],["H5971","of the people",16,29],["H7227","even many",31,40],["H0669","of Ephraim",41,51],["H4519","and Manasseh",53,65],["H3485","Issachar",67,75],["H2074","and Zebulun",77,88],["H3808","had not",90,97],["H2891","cleansed",98,106],["H0398","themselves, yet did they eat",107,135],["H6453","the passover",136,148],["H3789","otherwise than it was written",149,178],["H3169","But Hezekiah",180,192],["H6419","prayed",193,199],["H0559","for them, saying",200,216],["H2896","The good",218,226],["H3068","LORD",227,231],["H3722","pardon",232,238]]},"30:19":{"text":"That prepareth his heart to seek God, the LORD God of his fathers, though he be not cleansed according to the purification of the sanctuary.","words":[["H3559","That prepareth",0,14],["H3824","his heart",15,24],["H1875","to seek",25,32],["H0430","God",33,36],["H3068","the LORD",38,46],["H0430","God",47,50],["H0001","of his fathers",51,65],["H2893","though he be not cleansed according to the purification",67,122],["H6944","of the sanctuary",123,139]]},"30:20":{"text":"And the LORD hearkened to Hezekiah, and healed the people.","words":[["H3068","And the LORD",0,12],["H8085","hearkened",13,22],["H3169","to Hezekiah",23,34],["H7495","and healed",36,46],["H5971","the people",47,57]]},"30:21":{"text":"And the children of Israel that were present at Jerusalem kept the feast of unleavened bread seven days with great gladness: and the Levites and the priests praised the LORD day by day, singing with loud instruments unto the LORD.","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H4672","that were present",27,44],["H3389","at Jerusalem",45,57],["H6213","kept",58,62],["H2282","the feast",63,72],["H4682","of unleavened bread",73,92],["H7651","seven",93,98],["H3117","days",99,103],["H1419","with great",104,114],["H8057","gladness",115,123],["H3881","and the Levites",125,140],["H3548","and the priests",141,156],["H1984","praised",157,164],["H3068","the LORD",165,173],["H3117","day",174,177],["H3117","by day",178,184],["H5797","singing with loud",186,203],["H3627","instruments",204,215],["H3068","unto the LORD",216,229]]},"30:22":{"text":"And Hezekiah spake comfortably unto all the Levites that taught the good knowledge of the LORD: and they did eat throughout the feast seven days, offering peace offerings, and making confession to the LORD God of their fathers.","words":[["H3169","And Hezekiah",0,12],["H1696","spake",13,18],["H3820","comfortably",19,30],["H3881","unto all the Levites",31,51],["H7919","that taught",52,63],["H2896","the good",64,72],["H7922","knowledge",73,82],["H3068","of the LORD",83,94],["H0398","and they did eat",96,112],["H4150","throughout the feast",113,133],["H7651","seven",134,139],["H3117","days",140,144],["H2076","offering",146,154],["H8002","peace",155,160],["H2077","offerings",161,170],["H3034","and making confession",172,193],["H3068","to the LORD",194,205],["H0430","God",206,209],["H0001","of their fathers",210,226]]},"30:23":{"text":"And the whole assembly took counsel to keep other seven days: and they kept other seven days with gladness.","words":[["H6951","And the whole assembly",0,22],["H3289","took counsel",23,35],["H6213","to keep",36,43],["H0312","other",44,49],["H7651","seven",50,55],["H3117","days",56,60],["H6213","and they kept",62,75],["H7651","other seven",76,87],["H3117","days",88,92],["H8057","with gladness",93,106]]},"30:24":{"text":"For Hezekiah king of Judah did give to the congregation a thousand bullocks and seven thousand sheep; and the princes gave to the congregation a thousand bullocks and ten thousand sheep: and a great number of priests sanctified themselves.","words":[["H2396","For Hezekiah",0,12],["H4428","king",13,17],["H3063","of Judah",18,26],["H7311","did give",27,35],["H6951","to the congregation",36,55],["H0505","a thousand",56,66],["H6499","bullocks",67,75],["H7651","and seven",76,85],["H0505","thousand",86,94],["H6629","sheep",95,100],["H8269","and the princes",102,117],["H7311","gave",118,122],["H6951","to the congregation",123,142],["H0505","a thousand",143,153],["H6499","bullocks",154,162],["H6235","and ten",163,170],["H0505","thousand",171,179],["H6629","sheep",180,185],["H7230","and a great number",187,205],["H3548","of priests",206,216],["H6942","sanctified",217,227]]},"30:25":{"text":"And all the congregation of Judah, with the priests and the Levites, and all the congregation that came out of Israel, and the strangers that came out of the land of Israel, and that dwelt in Judah, rejoiced.","words":[["H6951","And all the congregation",0,24],["H3063","of Judah",25,33],["H3548","with the priests",35,51],["H3881","and the Levites",52,67],["H6951","and all the congregation",69,93],["H0935","that came out",94,107],["H3478","of Israel",108,117],["H1616","and the strangers",119,136],["H0935","that came out",137,150],["H0776","of the land",151,162],["H3478","of Israel",163,172],["H3427","and that dwelt",174,188],["H3063","in Judah",189,197],["H8055","rejoiced",199,207]]},"30:26":{"text":"So there was great joy in Jerusalem: for since the time of Solomon the son of David king of Israel there was not the like in Jerusalem.","words":[["H1419","So there was great",0,18],["H8057","joy",19,22],["H3389","in Jerusalem",23,35],["H3117","for since the time",37,55],["H8010","of Solomon",56,66],["H1121","the son",67,74],["H1732","of David",75,83],["H4428","king",84,88],["H3478","of Israel",89,98],["H3389","there was not the like in Jerusalem",99,134]]},"30:27":{"text":"Then the priests the Levites arose and blessed the people: and their voice was heard, and their prayer came up to his holy dwelling place, even unto heaven.","words":[["H3548","Then the priests",0,16],["H3881","the Levites",17,28],["H6965","arose",29,34],["H1288","and blessed",35,46],["H5971","the people",47,57],["H6963","and their voice",59,74],["H8085","was heard",75,84],["H8605","and their prayer",86,102],["H0935","came",103,107],["H6944","up to his holy",108,122],["H4583","dwelling place",123,137],["H8064","even unto heaven",139,155]]},"31:1":{"text":"Now when all this was finished, all Israel that were present went out to the cities of Judah, and brake the images in pieces, and cut down the groves, and threw down the high places and the altars out of all Judah and Benjamin, in Ephraim also and Manasseh, until they had utterly destroyed them all. Then all the children of Israel returned, every man to his possession, into their own cities.","words":[["H3615","Now when all this was finished",0,30],["H3478","all Israel",32,42],["H4672","that were present",43,60],["H3318","went out",61,69],["H5892","to the cities",70,83],["H3063","of Judah",84,92],["H7665","and brake",94,103],["H4676","the images",104,114],["H7665","in pieces",115,124],["H1438","and cut down",126,138],["H0842","the groves",139,149],["H5422","and threw down",151,165],["H1116","the high places",166,181],["H4196","and the altars",182,196],["H3063","out of all Judah",197,213],["H1144","and Benjamin",214,226],["H0669","in Ephraim",228,238],["H4519","also and Manasseh",239,256],["H3615","until they had utterly destroyed",258,290],["H1121","them all. Then all the children",291,322],["H3478","of Israel",323,332],["H7725","returned",333,341],["H0376","every man",343,352],["H0272","to his possession",353,370],["H5892","into their own cities",372,393]]},"31:2":{"text":"And Hezekiah appointed the courses of the priests and the Levites after their courses, every man according to his service, the priests and Levites for burnt offerings and for peace offerings, to minister, and to give thanks, and to praise in the gates of the tents of the LORD.","words":[["H3169","And Hezekiah",0,12],["H5975","appointed",13,22],["H4256","the courses",23,34],["H3548","of the priests",35,49],["H3881","and the Levites",50,65],["H4256","after their courses",66,85],["H0376","every man",87,96],["H6310","according",97,106],["H5656","to his service",107,121],["H3548","the priests",123,134],["H3881","and Levites",135,146],["H5930","for burnt offerings",147,166],["H8002","and for peace offerings",167,190],["H8334","to minister",192,203],["H3034","and to give thanks",205,223],["H1984","and to praise",225,238],["H8179","in the gates",239,251],["H4264","of the tents",252,264],["H3068","of the LORD",265,276]]},"31:3":{"text":"He appointed also the king's portion of his substance for the burnt offerings, to wit, for the morning and evening burnt offerings, and the burnt offerings for the sabbaths, and for the new moons, and for the set feasts, as it is written in the law of the LORD.","words":[["H4428","He appointed also the king's",0,28],["H4521","portion",29,36],["H7399","of his substance",37,53],["H5930","for the burnt offerings",54,77],["H1242","to wit, for the morning",79,102],["H6153","and evening",103,114],["H5930","burnt offerings",115,130],["H5930","and the burnt offerings",132,155],["H7676","for the sabbaths",156,172],["H2320","and for the new moons",174,195],["H4150","and for the set feasts",197,219],["H3789","as it is written",221,237],["H8451","in the law",238,248],["H3068","of the LORD",249,260]]},"31:4":{"text":"Moreover he commanded the people that dwelt in Jerusalem to give the portion of the priests and the Levites, that they might be encouraged in the law of the LORD.","words":[["H0559","Moreover he commanded",0,21],["H5971","the people",22,32],["H3427","that dwelt",33,43],["H3389","in Jerusalem",44,56],["H5414","to give",57,64],["H4521","the portion",65,76],["H3548","of the priests",77,91],["H3881","and the Levites",92,107],["H2388","that they might be encouraged",109,138],["H8451","in the law",139,149],["H3068","of the LORD",150,161]]},"31:5":{"text":"And as soon as the commandment came abroad, the children of Israel brought in abundance the firstfruits of corn, wine, and oil, and honey, and of all the increase of the field; and the tithe of all things brought they in abundantly.","words":[["H1697","And as soon as the commandment",0,30],["H6555","came abroad",31,42],["H1121","the children",44,56],["H3478","of Israel",57,66],["H0935","brought",67,74],["H7235","in abundance",75,87],["H7225","the firstfruits",88,103],["H1715","of corn",104,111],["H8492","wine",113,117],["H3323","and oil",119,126],["H1706","and honey",128,137],["H8393","and of all the increase",139,162],["H7704","of the field",163,175],["H4643","and the tithe",177,190],["H0935","of all things brought",191,212],["H7230","they in abundantly",213,231]]},"31:6":{"text":"And concerning the children of Israel and Judah, that dwelt in the cities of Judah, they also brought in the tithe of oxen and sheep, and the tithe of holy things which were consecrated unto the LORD their God, and laid them by heaps.","words":[["H1121","And concerning the children",0,27],["H3478","of Israel",28,37],["H3063","and Judah",38,47],["H3427","that dwelt",49,59],["H5892","in the cities",60,73],["H3063","of Judah",74,82],["H0935","they also brought in",84,104],["H4643","the tithe",105,114],["H1241","of oxen",115,122],["H6629","and sheep",123,132],["H4643","and the tithe",134,147],["H6944","of holy things",148,162],["H6942","which were consecrated",163,185],["H3068","unto the LORD",186,199],["H0430","their God",200,209],["H5414","and laid",211,219],["H6194","them by heaps",220,233],["H6194","them by heaps",220,233]]},"31:7":{"text":"In the third month they began to lay the foundation of the heaps, and finished them in the seventh month.","words":[["H7992","In the third",0,12],["H2320","month",13,18],["H2490","they began",19,29],["H3245","to lay the foundation",30,51],["H6194","of the heaps",52,64],["H3615","and finished",66,78],["H7637","them in the seventh",79,98],["H2320","month",99,104]]},"31:8":{"text":"And when Hezekiah and the princes came and saw the heaps, they blessed the LORD, and his people Israel.","words":[["H3169","And when Hezekiah",0,17],["H8269","and the princes",18,33],["H0935","came",34,38],["H7200","and saw",39,46],["H6194","the heaps",47,56],["H1288","they blessed",58,70],["H3068","the LORD",71,79],["H5971","and his people",81,95],["H3478","Israel",96,102]]},"31:9":{"text":"Then Hezekiah questioned with the priests and the Levites concerning the heaps.","words":[["H3169","Then Hezekiah",0,13],["H1875","questioned",14,24],["H3548","with the priests",25,41],["H3881","and the Levites",42,57],["H6194","concerning the heaps",58,78]]},"31:10":{"text":"And Azariah the chief priest of the house of Zadok answered him, and said, Since the people began to bring the offerings into the house of the LORD, we have had enough to eat, and have left plenty: for the LORD hath blessed his people; and that which is left is this great store.","words":[["H5838","And Azariah",0,11],["H7218","the chief",12,21],["H3548","priest",22,28],["H1004","of the house",29,41],["H6659","of Zadok",42,50],["H0559","answered",51,59],["H0559","him, and said",60,73],["H2490","Since the people began",75,97],["H0935","to bring",98,106],["H8641","the offerings",107,120],["H1004","into the house",121,135],["H3068","of the LORD",136,147],["H7646","we have had enough",149,167],["H0398","to eat",168,174],["H3498","and have left",176,189],["H7230","plenty",190,196],["H3068","for the LORD",198,210],["H1288","hath blessed",211,223],["H5971","his people",224,234],["H3498","and that which is left",236,258],["H1995","is this great store",259,278]]},"31:11":{"text":"Then Hezekiah commanded to prepare chambers in the house of the LORD; and they prepared them,","words":[["H3169","Then Hezekiah",0,13],["H0559","commanded",14,23],["H3559","to prepare",24,34],["H3957","chambers",35,43],["H1004","in the house",44,56],["H3068","of the LORD",57,68],["H3559","and they prepared",70,87]]},"31:12":{"text":"And brought in the offerings and the tithes and the dedicated things faithfully: over which Cononiah the Levite was ruler, and Shimei his brother was the next.","words":[["H0935","And brought in",0,14],["H8641","the offerings",15,28],["H4643","and the tithes",29,43],["H6944","and the dedicated",44,61],["H0530","things faithfully",62,79],["H3562","over which Cononiah",81,100],["H3881","the Levite",101,111],["H5057","was ruler",112,121],["H8096","and Shimei",123,133],["H0251","his brother",134,145],["H4932","was the next",146,158]]},"31:13":{"text":"And Jehiel, and Azaziah, and Nahath, and Asahel, and Jerimoth, and Jozabad, and Eliel, and Ismachiah, and Mahath, and Benaiah, were overseers under the hand of Cononiah and Shimei his brother, at the commandment of Hezekiah the king, and Azariah the ruler of the house of God.","words":[["H3171","And Jehiel",0,10],["H5812","and Azaziah",12,23],["H5184","and Nahath",25,35],["H6214","and Asahel",37,47],["H3406","and Jerimoth",49,61],["H3107","and Jozabad",63,74],["H0447","and Eliel",76,85],["H3253","and Ismachiah",87,100],["H4287","and Mahath",102,112],["H1141","and Benaiah",114,125],["H6496","were overseers",127,141],["H3027","under the hand",142,156],["H3562","of Cononiah",157,168],["H8096","and Shimei",169,179],["H0251","his brother",180,191],["H4662","at the commandment",193,211],["H3169","of Hezekiah",212,223],["H4428","the king",224,232],["H5838","and Azariah",234,245],["H5057","the ruler",246,255],["H1004","of the house",256,268],["H0430","of God",269,275]]},"31:14":{"text":"And Kore the son of Imnah the Levite, the porter toward the east, was over the freewill offerings of God, to distribute the oblations of the LORD, and the most holy things.","words":[["H6981","And Kore",0,8],["H1121","the son",9,16],["H3232","of Imnah",17,25],["H3881","the Levite",26,36],["H7778","the porter",38,48],["H4217","toward the east",49,64],["H5071","was over the freewill offerings",66,97],["H0430","of God",98,104],["H5414","to distribute",106,119],["H8641","the oblations",120,133],["H3068","of the LORD",134,145],["H6944","and the most",147,159],["H6944","holy things",160,171]]},"31:15":{"text":"And next him were Eden, and Miniamin, and Jeshua, and Shemaiah, Amariah, and Shecaniah, in the cities of the priests, in their set office, to give to their brethren by courses, as well to the great as to the small:","words":[["H5731","And next him were Eden",0,22],["H4509","and Miniamin",24,36],["H3442","and Jeshua",38,48],["H8098","and Shemaiah",50,62],["H0568","Amariah",64,71],["H7935","and Shecaniah",73,86],["H5892","in the cities",88,101],["H3548","of the priests",102,116],["H0530","in their set office",118,137],["H5414","to give",139,146],["H0251","to their brethren",147,164],["H3027","by",165,167],["H4256","courses",168,175],["H1419","as well to the great",177,197],["H6996","as to the small",198,213]]},"31:16":{"text":"Beside their genealogy of males, from three years old and upward, even unto every one that entereth into the house of the LORD, his daily portion for their service in their charges according to their courses;","words":[["H3187","Beside their genealogy",0,22],["H2145","of males",23,31],["H7969","from three",33,43],["H8141","years",44,49],["H1121","old",50,53],["H4605","and upward",54,64],["H0935","even unto every one that entereth",66,99],["H1004","into the house",100,114],["H3068","of the LORD",115,126],["H3117","his daily",128,137],["H3117","his daily",128,137],["H1697","portion",138,145],["H5656","for their service",146,163],["H4931","in their charges",164,180],["H4256","according to their courses",181,207]]},"31:17":{"text":"Both to the genealogy of the priests by the house of their fathers, and the Levites from twenty years old and upward, in their charges by their courses;","words":[["H3187","Both to the genealogy",0,21],["H3548","of the priests",22,36],["H1004","by the house",37,49],["H0001","of their fathers",50,66],["H3881","and the Levites",68,83],["H6242","from twenty",84,95],["H8141","years",96,101],["H1121","old",102,105],["H4605","and upward",106,116],["H4931","in their charges",118,134],["H4256","by their courses",135,151]]},"31:18":{"text":"And to the genealogy of all their little ones, their wives, and their sons, and their daughters, through all the congregation: for in their set office they sanctified themselves in holiness:","words":[["H3187","And to the genealogy",0,20],["H2945","of all their little ones",21,45],["H0802","their wives",47,58],["H1121","and their sons",60,74],["H1323","and their daughters",76,95],["H6951","through all the congregation",97,125],["H0530","for in their set office",127,150],["H6942","they sanctified",151,166],["H6944","themselves in holiness",167,189]]},"31:19":{"text":"Also of the sons of Aaron the priests, which were in the fields of the suburbs of their cities, in every several city, the men that were expressed by name, to give portions to all the males among the priests, and to all that were reckoned by genealogies among the Levites.","words":[["H1121","Also of the sons",0,16],["H0175","of Aaron",17,25],["H3548","the priests",26,37],["H7704","which were in the fields",39,63],["H4054","of the suburbs",64,78],["H5892","of their cities",79,94],["H5892","in every several city",96,117],["H0582","the men",119,126],["H5344","that were expressed",127,146],["H8034","by name",147,154],["H5414","to give",156,163],["H4490","portions",164,172],["H2145","to all the males",173,189],["H3548","among the priests",190,207],["H3187","and to all that were reckoned by genealogies",209,253],["H3881","among the Levites",254,271]]},"31:20":{"text":"And thus did Hezekiah throughout all Judah, and wrought that which was good and right and truth before the LORD his God.","words":[["H6213","And thus did",0,12],["H3169","Hezekiah",13,21],["H3063","throughout all Judah",22,42],["H6213","and wrought",44,55],["H2896","that which was good",56,75],["H3477","and right",76,85],["H0571","and truth",86,95],["H6440","before",96,102],["H3068","the LORD",103,111],["H0430","his God",112,119]]},"31:21":{"text":"And in every work that he began in the service of the house of God, and in the law, and in the commandments, to seek his God, he did it with all his heart, and prospered.","words":[["H4639","And in every work",0,17],["H2490","that he began",18,31],["H5656","in the service",32,46],["H1004","of the house",47,59],["H0430","of God",60,66],["H8451","and in the law",68,82],["H4687","and in the commandments",84,107],["H1875","to seek",109,116],["H0430","his God",117,124],["H6213","he did",126,132],["H3824","it with all his heart",133,154],["H6743","and prospered",156,169]]},"32:1":{"text":"After these things, and the establishment thereof, Sennacherib king of Assyria came, and entered into Judah, and encamped against the fenced cities, and thought to win them for himself.","words":[["H0310","After",0,5],["H1697","these things",6,18],["H0571","and the establishment",20,41],["H5576","thereof, Sennacherib",42,62],["H4428","king",63,67],["H0804","of Assyria",68,78],["H0935","came",79,83],["H0935","and entered",85,96],["H3063","into Judah",97,107],["H2583","and encamped",109,121],["H1219","against the fenced",122,140],["H5892","cities",141,147],["H0559","and thought",149,160],["H1234","to win",161,167]]},"32:2":{"text":"And when Hezekiah saw that Sennacherib was come, and that he was purposed to fight against Jerusalem,","words":[["H3169","And when Hezekiah",0,17],["H7200","saw",18,21],["H5576","that Sennacherib",22,38],["H0935","was come",39,47],["H6440","and that he was purposed",49,73],["H4421","to fight",74,82],["H3389","against Jerusalem",83,100]]},"32:3":{"text":"He took counsel with his princes and his mighty men to stop the waters of the fountains which were without the city: and they did help him.","words":[["H3289","He took counsel",0,15],["H8269","with his princes",16,32],["H1368","and his mighty men",33,51],["H5640","to stop",52,59],["H4325","the waters",60,70],["H5869","of the fountains",71,87],["H2351","which were without",88,106],["H5892","the city",107,115],["H5826","and they did help",117,134]]},"32:4":{"text":"So there was gathered much people together, who stopped all the fountains, and the brook that ran through the midst of the land, saying, Why should the kings of Assyria come, and find much water?","words":[["H6908","So there was gathered",0,21],["H7227","much",22,26],["H5971","people",27,33],["H6908","together",34,42],["H5640","who stopped",44,55],["H4599","all the fountains",56,73],["H5158","and the brook",75,88],["H7857","that ran",89,97],["H8432","through the midst",98,115],["H0776","of the land",116,127],["H0559","saying",129,135],["H4428","Why should the kings",137,157],["H0804","of Assyria",158,168],["H0935","come",169,173],["H4672","and find",175,183],["H7227","much",184,188],["H4325","water",189,194]]},"32:5":{"text":"Also he strengthened himself, and built up all the wall that was broken, and raised it up to the towers, and another wall without, and repaired Millo in the city of David, and made darts and shields in abundance.","words":[["H2388","Also he strengthened",0,20],["H1129","himself, and built up",21,42],["H2346","all the wall",43,55],["H6555","that was broken",56,71],["H5927","and raised it up",73,89],["H4026","to the towers",90,103],["H0312","and another",105,116],["H2346","wall",117,121],["H2351","without",122,129],["H2388","and repaired",131,143],["H4407","Millo",144,149],["H5892","in the city",150,161],["H1732","of David",162,170],["H6213","and made",172,180],["H7973","darts",181,186],["H4043","and shields",187,198],["H7230","in abundance",199,211]]},"32:6":{"text":"And he set captains of war over the people, and gathered them together to him in the street of the gate of the city, and spake comfortably to them, saying,","words":[["H5414","And he set",0,10],["H8269","captains",11,19],["H4421","of war",20,26],["H5971","over the people",27,42],["H6908","and gathered them together",44,70],["H7339","to him in the street",71,91],["H8179","of the gate",92,103],["H5892","of the city",104,115],["H1696","and spake",117,126],["H3824","comfortably",127,138],["H0559","to them, saying",139,154]]},"32:7":{"text":"Be strong and courageous, be not afraid nor dismayed for the king of Assyria, nor for all the multitude that is with him: for there be more with us than with him:","words":[["H2388","Be strong",0,9],["H0553","and courageous",10,24],["H3372","be not afraid",26,39],["H2865","nor dismayed",40,52],["H6440","for",53,56],["H4428","the king",57,65],["H0804","of Assyria",66,76],["H1995","nor for all the multitude",78,103],["H7227","that is with him: for there be more",104,139]]},"32:8":{"text":"With him is an arm of flesh; but with us is the LORD our God to help us, and to fight our battles. And the people rested themselves upon the words of Hezekiah king of Judah.","words":[["H2220","With him is an arm",0,18],["H1320","of flesh",19,27],["H3068","but with us is the LORD",29,52],["H0430","our God",53,60],["H5826","to help",61,68],["H3898","us, and to fight",69,85],["H4421","our battles",86,97],["H5971","And the people",99,113],["H5564","rested",114,120],["H1697","themselves upon the words",121,146],["H3169","of Hezekiah",147,158],["H4428","king",159,163],["H3063","of Judah",164,172]]},"32:9":{"text":"After this did Sennacherib king of Assyria send his servants to Jerusalem, (but he himself laid siege against Lachish, and all his power with him,) unto Hezekiah king of Judah, and unto all Judah that were at Jerusalem, saying,","words":[["H0310","After",0,5],["H5576","this did Sennacherib",6,26],["H4428","king",27,31],["H0804","of Assyria",32,42],["H7971","send",43,47],["H5650","his servants",48,60],["H3389","to Jerusalem",61,73],["H3923","(but he himself laid siege against Lachish",75,117],["H4475","and all his power",119,136],["H3169","with him,) unto Hezekiah",137,161],["H4428","king",162,166],["H3063","of Judah",167,175],["H3063","and unto all Judah",177,195],["H3389","that were at Jerusalem",196,218],["H0559","saying",220,226]]},"32:10":{"text":"Thus saith Sennacherib king of Assyria, Whereon do ye trust, that ye abide in the siege in Jerusalem?","words":[["H0559","Thus saith",0,10],["H5576","Sennacherib",11,22],["H4428","king",23,27],["H0804","of Assyria",28,38],["H0982","Whereon do ye trust",40,59],["H3427","that ye abide",61,74],["H4692","in the siege",75,87],["H3389","in Jerusalem",88,100]]},"32:11":{"text":"Doth not Hezekiah persuade you to give over yourselves to die by famine and by thirst, saying, The LORD our God shall deliver us out of the hand of the king of Assyria?","words":[["H3169","Doth not Hezekiah",0,17],["H5496","persuade",18,26],["H5414","you to give",27,38],["H4191","over yourselves to die",39,61],["H7458","by famine",62,71],["H6772","and by thirst",72,85],["H0559","saying",87,93],["H3068","The LORD",95,103],["H0430","our God",104,111],["H5337","shall deliver",112,125],["H3709","us out of the hand",126,144],["H4428","of the king",145,156],["H0804","of Assyria",157,167]]},"32:12":{"text":"Hath not the same Hezekiah taken away his high places and his altars, and commanded Judah and Jerusalem, saying, Ye shall worship before one altar, and burn incense upon it?","words":[["H3169","Hath not the same Hezekiah",0,26],["H5493","taken away",27,37],["H1116","his high places",38,53],["H4196","and his altars",54,68],["H0559","and commanded",70,83],["H3063","Judah",84,89],["H3389","and Jerusalem",90,103],["H0559","saying",105,111],["H7812","Ye shall worship",113,129],["H6440","before",130,136],["H0259","one",137,140],["H4196","altar",141,146],["H6999","and burn incense",148,164]]},"32:13":{"text":"Know ye not what I and my fathers have done unto all the people of other lands? were the gods of the nations of those lands any ways able to deliver their lands out of mine hand?","words":[["H3045","Know",0,4],["H0001","ye not what I and my fathers",5,33],["H6213","have done",34,43],["H5971","unto all the people",44,63],["H0776","of other lands",64,78],["H0430","were the gods",80,93],["H1471","of the nations",94,108],["H0776","of those lands",109,123],["H3201","any ways",124,132],["H3201","able",133,137],["H5337","to deliver",138,148],["H0776","their lands",149,160],["H3027","out of mine hand",161,177]]},"32:14":{"text":"Who was there among all the gods of those nations that my fathers utterly destroyed, that could deliver his people out of mine hand, that your God should be able to deliver you out of mine hand?","words":[["H0430","Who was there among all the gods",0,32],["H1471","of those nations",33,49],["H0001","that my fathers",50,65],["H2763","utterly destroyed",66,83],["H3201","that could",85,95],["H5337","deliver",96,103],["H5971","his people",104,114],["H3027","out of mine hand",115,131],["H0430","that your God",133,146],["H3201","should be able",147,161],["H5337","to deliver",162,172],["H3027","you out of mine hand",173,193]]},"32:15":{"text":"Now therefore let not Hezekiah deceive you, nor persuade you on this manner, neither yet believe him: for no god of any nation or kingdom was able to deliver his people out of mine hand, and out of the hand of my fathers: how much less shall your God deliver you out of mine hand?","words":[["H3808","Now therefore let not",0,21],["H2396","Hezekiah",22,30],["H5377","deceive",31,38],["H5496","you, nor persuade",39,56],["H0539","you on this manner, neither yet believe",57,96],["H0433","him: for no god",97,112],["H1471","of any nation",113,126],["H4467","or kingdom",127,137],["H3201","was able",138,146],["H5337","to deliver",147,157],["H5971","his people",158,168],["H3027","out of mine hand",169,185],["H3027","and out of the hand",187,206],["H0001","of my fathers",207,220],["H0430","how much less shall your God",222,250],["H5337","deliver",251,258],["H3027","you out of mine hand",259,279]]},"32:16":{"text":"And his servants spake yet more against the LORD God, and against his servant Hezekiah.","words":[["H5650","And his servants",0,16],["H1696","spake",17,22],["H3068","yet more against the LORD",23,48],["H0430","God",49,52],["H5650","and against his servant",54,77],["H3169","Hezekiah",78,86]]},"32:17":{"text":"He wrote also letters to rail on the LORD God of Israel, and to speak against him, saying, As the gods of the nations of other lands have not delivered their people out of mine hand, so shall not the God of Hezekiah deliver his people out of mine hand.","words":[["H3789","He wrote",0,8],["H5612","also letters",9,21],["H2778","to rail",22,29],["H3068","on the LORD",30,41],["H0430","God",42,45],["H3478","of Israel",46,55],["H0559","and to speak",57,69],["H0559","against him, saying",70,89],["H0430","As the gods",91,102],["H1471","of the nations",103,117],["H0776","of other lands",118,132],["H5337","have not delivered",133,151],["H5971","their people",152,164],["H3027","out of mine hand",165,181],["H0430","so shall not the God",183,203],["H3169","of Hezekiah",204,215],["H5337","deliver",216,223],["H5971","his people",224,234],["H3027","out of mine hand",235,251]]},"32:18":{"text":"Then they cried with a loud voice in the Jews' speech unto the people of Jerusalem that were on the wall, to affright them, and to trouble them; that they might take the city.","words":[["H7121","Then they cried",0,15],["H1419","with a loud",16,27],["H6963","voice",28,33],["H3066","in the Jews' speech",34,53],["H5971","unto the people",54,69],["H3389","of Jerusalem",70,82],["H2346","that were on the wall",83,104],["H3372","to affright",106,117],["H0926","them, and to trouble",118,138],["H3920","them; that they might take",139,165],["H5892","the city",166,174]]},"32:19":{"text":"And they spake against the God of Jerusalem, as against the gods of the people of the earth, which were the work of the hands of man.","words":[["H1696","And they spake",0,14],["H5921","against",15,22],["H0430","the God",23,30],["H3389","of Jerusalem",31,43],["H0430","as against the gods",45,64],["H5971","of the people",65,78],["H0776","of the earth",79,91],["H4639","which were the work",93,112],["H3027","of the hands",113,125],["H0120","of man",126,132]]},"32:20":{"text":"And for this cause Hezekiah the king, and the prophet Isaiah the son of Amoz, prayed and cried to heaven.","words":[["H3169","And for this cause Hezekiah",0,27],["H4428","the king",28,36],["H5030","and the prophet",38,53],["H3470","Isaiah",54,60],["H1121","the son",61,68],["H0531","of Amoz",69,76],["H6419","prayed",78,84],["H2199","and cried",85,94],["H8064","to heaven",95,104]]},"32:21":{"text":"And the LORD sent an angel, which cut off all the mighty men of valour, and the leaders and captains in the camp of the king of Assyria. So he returned with shame of face to his own land. And when he was come into the house of his god, they that came forth of his own bowels slew him there with the sword.","words":[["H3068","And the LORD",0,12],["H7971","sent",13,17],["H4397","an angel",18,26],["H3582","which cut off",28,41],["H1368","all the mighty men",42,60],["H2428","of valour",61,70],["H5057","and the leaders",72,87],["H8269","and captains",88,100],["H4264","in the camp",101,112],["H4428","of the king",113,124],["H0804","of Assyria",125,135],["H7725","So he returned",137,151],["H1322","with shame",152,162],["H6440","of face",163,170],["H0776","to his own land",171,186],["H0935","And when he was come",188,208],["H1004","into the house",209,223],["H0430","of his god",224,234],["H3329","they that came forth",236,256],["H4578","of his own bowels",257,274],["H5307","slew",275,279],["H2719","him there with the sword",280,304]]},"32:22":{"text":"Thus the LORD saved Hezekiah and the inhabitants of Jerusalem from the hand of Sennacherib the king of Assyria, and from the hand of all other, and guided them on every side.","words":[["H3068","Thus the LORD",0,13],["H3467","saved",14,19],["H3169","Hezekiah",20,28],["H3427","and the inhabitants",29,48],["H3389","of Jerusalem",49,61],["H3027","from the hand",62,75],["H5576","of Sennacherib",76,90],["H4428","the king",91,99],["H0804","of Assyria",100,110],["H3027","and from the hand",112,129],["H5095","of all other, and guided",130,154],["H5439","them on every side",155,173]]},"32:23":{"text":"And many brought gifts unto the LORD to Jerusalem, and presents to Hezekiah king of Judah: so that he was magnified in the sight of all nations from thenceforth.","words":[["H7227","And many",0,8],["H0935","brought",9,16],["H4503","gifts",17,22],["H3068","unto the LORD",23,36],["H3389","to Jerusalem",37,49],["H4030","and presents",51,63],["H3169","to Hezekiah",64,75],["H4428","king",76,80],["H3063","of Judah",81,89],["H5375","so that he was magnified",91,115],["H5869","in the sight",116,128],["H1471","of all nations",129,143],["H0310","from thenceforth",144,160]]},"32:24":{"text":"In those days Hezekiah was sick to the death, and prayed unto the LORD: and he spake unto him, and he gave him a sign.","words":[["H3117","In those days",0,13],["H3169","Hezekiah",14,22],["H2470","was sick",23,31],["H4191","to the death",32,44],["H6419","and prayed",46,56],["H3068","unto the LORD",57,70],["H0559","and he spake",72,84],["H5414","unto him, and he gave",85,106],["H4159","him a sign",107,117]]},"32:25":{"text":"But Hezekiah rendered not again according to the benefit done unto him; for his heart was lifted up: therefore there was wrath upon him, and upon Judah and Jerusalem.","words":[["H3169","But Hezekiah",0,12],["H7725","rendered not again",13,31],["H1576","according to the benefit",32,56],["H3820","done unto him; for his heart",57,85],["H1361","was lifted up",86,99],["H7110","therefore there was wrath",101,126],["H3063","upon him, and upon Judah",127,151],["H3389","and Jerusalem",152,165]]},"32:26":{"text":"Notwithstanding Hezekiah humbled himself for the pride of his heart, both he and the inhabitants of Jerusalem, so that the wrath of the LORD came not upon them in the days of Hezekiah.","words":[["H3169","Notwithstanding Hezekiah",0,24],["H3665","humbled",25,32],["H1363","himself for the pride",33,54],["H3820","of his heart",55,67],["H3427","both he and the inhabitants",69,96],["H3389","of Jerusalem",97,109],["H7110","so that the wrath",111,128],["H3068","of the LORD",129,140],["H0935","came",141,145],["H3117","not upon them in the days",146,171],["H3169","of Hezekiah",172,183]]},"32:27":{"text":"And Hezekiah had exceeding much riches and honour: and he made himself treasuries for silver, and for gold, and for precious stones, and for spices, and for shields, and for all manner of pleasant jewels;","words":[["H3169","And Hezekiah",0,12],["H3966","had exceeding",13,26],["H7235","much",27,31],["H6239","riches",32,38],["H3519","and honour",39,49],["H6213","and he made",51,62],["H0214","himself treasuries",63,81],["H3701","for silver",82,92],["H2091","and for gold",94,106],["H3368","and for precious",108,124],["H0068","stones",125,131],["H1314","and for spices",133,147],["H4043","and for shields",149,164],["H2532","and for all manner of pleasant",166,196],["H3627","jewels",197,203]]},"32:28":{"text":"Storehouses also for the increase of corn, and wine, and oil; and stalls for all manner of beasts, and cotes for flocks.","words":[["H4543","Storehouses",0,11],["H8393","also for the increase",12,33],["H1715","of corn",34,41],["H8492","and wine",43,51],["H3323","and oil",53,60],["H0723","and stalls",62,72],["H0929","for all manner of beasts",73,97],["H0220","and cotes",99,108],["H5739","for flocks",109,119]]},"32:29":{"text":"Moreover he provided him cities, and possessions of flocks and herds in abundance: for God had given him substance very much.","words":[["H6213","Moreover he provided",0,20],["H5892","him cities",21,31],["H4735","and possessions",33,48],["H6629","of flocks",49,58],["H1241","and herds",59,68],["H7230","in abundance",69,81],["H0430","for God",83,90],["H5414","had given",91,100],["H7399","him substance",101,114],["H3966","very",115,119],["H7227","much",120,124]]},"32:30":{"text":"This same Hezekiah also stopped the upper watercourse of Gihon, and brought it straight down to the west side of the city of David. And Hezekiah prospered in all his works.","words":[["H3169","This same Hezekiah",0,18],["H5640","also stopped",19,31],["H5945","the upper",32,41],["H4161","watercourse",42,53],["H4325","watercourse",42,53],["H1521","of Gihon",54,62],["H3474","and brought it straight",64,87],["H4295","down",88,92],["H4628","to the west side",93,109],["H5892","of the city",110,121],["H1732","of David",122,130],["H3169","And Hezekiah",132,144],["H6743","prospered",145,154],["H4639","in all his works",155,171]]},"32:31":{"text":"Howbeit in the business of the ambassadors of the princes of Babylon, who sent unto him to enquire of the wonder that was done in the land, God left him, to try him, that he might know all that was in his heart.","words":[["H3651","Howbeit",0,7],["H3887","in the business of the ambassadors",8,42],["H8269","of the princes",43,57],["H0894","of Babylon",58,68],["H7971","who sent",70,78],["H1875","unto him to enquire",79,98],["H4159","of the wonder",99,112],["H0776","that was done in the land",113,138],["H0430","God",140,143],["H5800","left",144,148],["H5254","him, to try",149,160],["H3045","him, that he might know",161,184],["H3824","all that was in his heart",185,210]]},"32:32":{"text":"Now the rest of the acts of Hezekiah, and his goodness, behold, they are written in the vision of Isaiah the prophet, the son of Amoz, and in the book of the kings of Judah and Israel.","words":[["H3499","Now the rest",0,12],["H1697","of the acts",13,24],["H3169","of Hezekiah",25,36],["H2617","and his goodness",38,54],["H3789","behold, they are written",56,80],["H2377","in the vision",81,94],["H3470","of Isaiah",95,104],["H5030","the prophet",105,116],["H1121","the son",118,125],["H0531","of Amoz",126,133],["H5612","and in the book",135,150],["H4428","of the kings",151,163],["H3063","of Judah",164,172],["H3478","and Israel",173,183]]},"32:33":{"text":"And Hezekiah slept with his fathers, and they buried him in the chiefest of the sepulchres of the sons of David: and all Judah and the inhabitants of Jerusalem did him honour at his death. And Manasseh his son reigned in his stead.","words":[["H3169","And Hezekiah",0,12],["H7901","slept",13,18],["H0001","with his fathers",19,35],["H6912","and they buried",37,52],["H4608","him in the chiefest",53,72],["H6913","of the sepulchres",73,90],["H1121","of the sons",91,102],["H1732","of David",103,111],["H3063","and all Judah",113,126],["H3427","and the inhabitants",127,146],["H3389","of Jerusalem",147,159],["H6213","did him",160,167],["H3519","honour",168,174],["H4194","at his death",175,187],["H4519","And Manasseh",189,201],["H1121","his son",202,209],["H4427","reigned",210,217]]},"33:1":{"text":"Manasseh was twelve years old when he began to reign, and he reigned fifty and five years in Jerusalem:","words":[["H4519","Manasseh",0,8],["H8147","was twelve",9,19],["H6240","was twelve",9,19],["H8141","years",20,25],["H1121","old",26,29],["H4427","when he began to reign",30,52],["H4427","and he reigned",54,68],["H2572","fifty",69,74],["H2568","and five",75,83],["H8141","years",84,89],["H3389","in Jerusalem",90,102]]},"33:2":{"text":"But did that which was evil in the sight of the LORD, like unto the abominations of the heathen, whom the LORD had cast out before the children of Israel.","words":[["H6213","But did",0,7],["H7451","that which was evil",8,27],["H5869","in the sight",28,40],["H3068","of the LORD",41,52],["H8441","like unto the abominations",54,80],["H1471","of the heathen",81,95],["H3068","whom the LORD",97,110],["H3423","had cast out",111,123],["H6440","before",124,130],["H1121","the children",131,143],["H3478","of Israel",144,153]]},"33:3":{"text":"For he built again the high places which Hezekiah his father had broken down, and he reared up altars for Baalim, and made groves, and worshipped all the host of heaven, and served them.","words":[["H1129","For he built",0,12],["H7725","again",13,18],["H1116","the high places",19,34],["H3169","which Hezekiah",35,49],["H0001","his father",50,60],["H5422","had broken down",61,76],["H6965","and he reared up",78,94],["H4196","altars",95,101],["H1168","for Baalim",102,112],["H6213","and made",114,122],["H0842","groves",123,129],["H7812","and worshipped",131,145],["H6635","all the host",146,158],["H8064","of heaven",159,168],["H5647","and served",170,180]]},"33:4":{"text":"Also he built altars in the house of the LORD, whereof the LORD had said, In Jerusalem shall my name be for ever.","words":[["H1129","Also he built",0,13],["H4196","altars",14,20],["H1004","in the house",21,33],["H3068","of the LORD",34,45],["H3068","whereof the LORD",47,63],["H0559","had said",64,72],["H3389","In Jerusalem",74,86],["H8034","shall my name",87,100],["H5769","be for ever",101,112]]},"33:5":{"text":"And he built altars for all the host of heaven in the two courts of the house of the LORD.","words":[["H1129","And he built",0,12],["H4196","altars",13,19],["H6635","for all the host",20,36],["H8064","of heaven",37,46],["H8147","in the two",47,57],["H2691","courts",58,64],["H1004","of the house",65,77],["H3068","of the LORD",78,89]]},"33:6":{"text":"And he caused his children to pass through the fire in the valley of the son of Hinnom: also he observed times, and used enchantments, and used witchcraft, and dealt with a familiar spirit, and with wizards: he wrought much evil in the sight of the LORD, to provoke him to anger.","words":[["H5674","And he caused",0,13],["H1121","his children",14,26],["H5674","to pass through",27,42],["H0784","the fire",43,51],["H1516","in the valley",52,65],["H1121","of the son",66,76],["H2011","of Hinnom",77,86],["H6049","also he observed times",88,110],["H5172","and used enchantments",112,133],["H3784","and used witchcraft",135,154],["H6213","and dealt",156,165],["H0178","with a familiar spirit",166,188],["H3049","and with wizards",190,206],["H6213","he wrought",208,218],["H7235","much",219,223],["H7451","evil",224,228],["H5869","in the sight",229,241],["H3068","of the LORD",242,253],["H3707","to provoke him to anger",255,278]]},"33:7":{"text":"And he set a carved image, the idol which he had made, in the house of God, of which God had said to David and to Solomon his son, In this house, and in Jerusalem, which I have chosen before all the tribes of Israel, will I put my name for ever:","words":[["H7760","And he set",0,10],["H6459","a carved image",11,25],["H5566","the idol",27,35],["H6213","which he had made",36,53],["H1004","in the house",55,67],["H0430","of God",68,74],["H0430","of which God",76,88],["H0559","had said",89,97],["H1732","to David",98,106],["H8010","and to Solomon",107,121],["H1121","his son",122,129],["H1004","In this house",131,144],["H3389","and in Jerusalem",146,162],["H0977","which I have chosen",164,183],["H7626","before all the tribes",184,205],["H3478","of Israel",206,215],["H7760","will I put",217,227],["H8034","my name",228,235],["H5865","for ever",236,244]]},"33:8":{"text":"Neither will I any more remove the foot of Israel from out of the land which I have appointed for your fathers; so that they will take heed to do all that I have commanded them, according to the whole law and the statutes and the ordinances by the hand of Moses.","words":[["H3254","Neither will I any more",0,23],["H5493","remove",24,30],["H7272","the foot",31,39],["H3478","of Israel",40,49],["H5921","from out",50,58],["H0127","of the land",59,70],["H5975","which I have appointed",71,93],["H0001","for your fathers",94,110],["H0518","so that",112,119],["H8104","they will take heed",120,139],["H6213","to do",140,145],["H6680","all that I have commanded",146,171],["H8451","them, according to the whole law",172,204],["H2706","and the statutes",205,221],["H4941","and the ordinances",222,240],["H3027","by the hand",241,252],["H4872","of Moses",253,261]]},"33:9":{"text":"So Manasseh made Judah and the inhabitants of Jerusalem to err, and to do worse than the heathen, whom the LORD had destroyed before the children of Israel.","words":[["H4519","So Manasseh",0,11],["H8582","made",12,16],["H3063","Judah",17,22],["H3427","and the inhabitants",23,42],["H3389","of Jerusalem",43,55],["H8582","to err",56,62],["H6213","and to do",64,73],["H7451","worse",74,79],["H1471","than the heathen",80,96],["H3068","whom the LORD",98,111],["H8045","had destroyed",112,125],["H6440","before",126,132],["H1121","the children",133,145],["H3478","of Israel",146,155]]},"33:10":{"text":"And the LORD spake to Manasseh, and to his people: but they would not hearken.","words":[["H3068","And the LORD",0,12],["H1696","spake",13,18],["H4519","to Manasseh",19,30],["H5971","and to his people",32,49],["H7181","but they would not hearken",51,77]]},"33:11":{"text":"Wherefore the LORD brought upon them the captains of the host of the king of Assyria, which took Manasseh among the thorns, and bound him with fetters, and carried him to Babylon.","words":[["H3068","Wherefore the LORD",0,18],["H0935","brought",19,26],["H8269","upon them the captains of",27,52],["H6635","the host of",53,64],["H4428","the king",65,73],["H0804","of Assyria",74,84],["H3920","which took",86,96],["H4519","Manasseh",97,105],["H2336","among the thorns",106,122],["H0631","and bound him",124,137],["H5178","with fetters",138,150],["H3212","and carried",152,163],["H0894","him to Babylon",164,178]]},"33:12":{"text":"And when he was in affliction, he besought the LORD his God, and humbled himself greatly before the God of his fathers,","words":[["H6887","And when he was in affliction",0,29],["H2470","he besought",31,42],["H3068","the LORD",43,51],["H0430","his God",52,59],["H3665","and humbled",61,72],["H3966","himself greatly",73,88],["H6440","before",89,95],["H0430","the God",96,103],["H0001","of his fathers",104,118]]},"33:13":{"text":"And prayed unto him: and he was intreated of him, and heard his supplication, and brought him again to Jerusalem into his kingdom. Then Manasseh knew that the LORD he was God.","words":[["H6419","And prayed",0,10],["H6279","unto him: and he was intreated",11,41],["H8085","of him, and heard",42,59],["H8467","his supplication",60,76],["H7725","and brought him again",78,99],["H3389","to Jerusalem",100,112],["H4438","into his kingdom",113,129],["H4519","Then Manasseh",131,144],["H3045","knew",145,149],["H3068","that the LORD",150,163],["H0430","he was God",164,174]]},"33:14":{"text":"Now after this he built a wall without the city of David, on the west side of Gihon, in the valley, even to the entering in at the fish gate, and compassed about Ophel, and raised it up a very great height, and put captains of war in all the fenced cities of Judah.","words":[["H0310","Now after this",0,14],["H1129","he built",15,23],["H2346","a wall",24,30],["H2435","without",31,38],["H5892","the city",39,47],["H1732","of David",48,56],["H4628","on the west side",58,74],["H1521","of Gihon",75,83],["H5158","in the valley",85,98],["H0935","even to the entering in",100,123],["H1709","at the fish",124,135],["H8179","gate",136,140],["H5437","and compassed",142,155],["H6077","about Ophel",156,167],["H1361","and raised it up",169,185],["H3966","a very great height",186,205],["H7760","and put",207,214],["H8269","captains",215,223],["H2428","of war",224,230],["H1219","in all the fenced",231,248],["H5892","cities",249,255],["H3063","of Judah",256,264]]},"33:15":{"text":"And he took away the strange gods, and the idol out of the house of the LORD, and all the altars that he had built in the mount of the house of the LORD, and in Jerusalem, and cast them out of the city.","words":[["H5493","And he took away",0,16],["H5236","the strange",17,28],["H0430","gods",29,33],["H5566","and the idol",35,47],["H1004","out of the house",48,64],["H3068","of the LORD",65,76],["H4196","and all the altars",78,96],["H1129","that he had built",97,114],["H2022","in the mount",115,127],["H1004","of the house",128,140],["H3068","of the LORD",141,152],["H3389","and in Jerusalem",154,170],["H7993","and cast",172,180],["H2351","them out",181,189],["H5892","of the city",190,201]]},"33:16":{"text":"And he repaired the altar of the LORD, and sacrificed thereon peace offerings and thank offerings, and commanded Judah to serve the LORD God of Israel.","words":[["H1129","And he repaired",0,15],["H4196","the altar",16,25],["H3068","of the LORD",26,37],["H2076","and sacrificed",39,53],["H8002","thereon peace",54,67],["H2077","offerings",68,77],["H8426","and thank offerings",78,97],["H0559","and commanded",99,112],["H3063","Judah",113,118],["H5647","to serve",119,127],["H3068","the LORD",128,136],["H0430","God",137,140],["H3478","of Israel",141,150]]},"33:17":{"text":"Nevertheless the people did sacrifice still in the high places, yet unto the LORD their God only.","words":[["H0061","Nevertheless",0,12],["H5971","the people",13,23],["H2076","did sacrifice",24,37],["H1116","still in the high places",38,62],["H3068","yet unto the LORD",64,81],["H0430","their God",82,91]]},"33:18":{"text":"Now the rest of the acts of Manasseh, and his prayer unto his God, and the words of the seers that spake to him in the name of the LORD God of Israel, behold, they are written in the book of the kings of Israel.","words":[["H3499","Now the rest",0,12],["H1697","of the acts",13,24],["H4519","of Manasseh",25,36],["H8605","and his prayer",38,52],["H0430","unto his God",53,65],["H1697","and the words",67,80],["H2374","of the seers",81,93],["H1696","that spake",94,104],["H8034","to him in the name",105,123],["H3068","of the LORD",124,135],["H0430","God",136,139],["H3478","of Israel",140,149],["H1697","behold, they are written in the book",151,187],["H4428","of the kings",188,200],["H3478","of Israel",201,210]]},"33:19":{"text":"His prayer also, and how God was intreated of him, and all his sin, and his trespass, and the places wherein he built high places, and set up groves and graven images, before he was humbled: behold, they are written among the sayings of the seers.","words":[["H8605","His prayer",0,10],["H6279","also, and how God was intreated",11,42],["H2403","of him, and all his sin",43,66],["H4604","and his trespass",68,84],["H4725","and the places",86,100],["H1129","wherein he built",101,117],["H1116","high places",118,129],["H5975","and set up",131,141],["H0842","groves",142,148],["H6456","and graven images",149,166],["H6440","before",168,174],["H3665","he was humbled",175,189],["H3789","behold, they are written",191,215],["H1697","among the sayings",216,233],["H2374","of the seers",234,246],["H2335","of the seers",234,246]]},"33:20":{"text":"So Manasseh slept with his fathers, and they buried him in his own house: and Amon his son reigned in his stead.","words":[["H4519","So Manasseh",0,11],["H7901","slept",12,17],["H0001","with his fathers",18,34],["H6912","and they buried",36,51],["H1004","him in his own house",52,72],["H0526","and Amon",74,82],["H1121","his son",83,90],["H4427","reigned",91,98]]},"33:21":{"text":"Amon was two and twenty years old when he began to reign, and reigned two years in Jerusalem.","words":[["H0526","Amon",0,4],["H8147","was two",5,12],["H6242","and twenty",13,23],["H8141","years",24,29],["H1121","old",30,33],["H4427","when he began to reign",34,56],["H4427","and reigned",58,69],["H8147","two",70,73],["H8141","years",74,79],["H3389","in Jerusalem",80,92]]},"33:22":{"text":"But he did that which was evil in the sight of the LORD, as did Manasseh his father: for Amon sacrificed unto all the carved images which Manasseh his father had made, and served them;","words":[["H6213","But he did",0,10],["H7451","that which was evil",11,30],["H5869","in the sight",31,43],["H3068","of the LORD",44,55],["H6213","as did",57,63],["H4519","Manasseh",64,72],["H0001","his father",73,83],["H0526","for Amon",85,93],["H2076","sacrificed",94,104],["H6456","unto all the carved images",105,131],["H4519","which Manasseh",132,146],["H0001","his father",147,157],["H6213","had made",158,166],["H5647","and served",168,178]]},"33:23":{"text":"And humbled not himself before the LORD, as Manasseh his father had humbled himself; but Amon trespassed more and more.","words":[["H3665","And humbled",0,11],["H6440","not himself before",12,30],["H3068","the LORD",31,39],["H4519","as Manasseh",41,52],["H0001","his father",53,63],["H3665","had humbled",64,75],["H0526","himself; but Amon",76,93],["H0819","trespassed",94,104],["H7235","more and more",105,118]]},"33:24":{"text":"And his servants conspired against him, and slew him in his own house.","words":[["H5650","And his servants",0,16],["H7194","conspired",17,26],["H4191","against him, and slew",27,48],["H1004","him in his own house",49,69]]},"33:25":{"text":"But the people of the land slew all them that had conspired against king Amon; and the people of the land made Josiah his son king in his stead.","words":[["H5971","But the people",0,14],["H0776","of the land",15,26],["H5221","slew",27,31],["H7194","all them that had conspired",32,59],["H4428","against king",60,72],["H0526","Amon",73,77],["H5971","and the people",79,93],["H0776","of the land",94,105],["H4427","made",106,110],["H2977","Josiah",111,117],["H1121","his son",118,125],["H4427","king",126,130]]},"34:1":{"text":"Josiah was eight years old when he began to reign, and he reigned in Jerusalem one and thirty years.","words":[["H2977","Josiah",0,6],["H8083","was eight",7,16],["H8141","years",17,22],["H1121","old",23,26],["H4427","when he began to reign",27,49],["H4427","and he reigned",51,65],["H3389","in Jerusalem",66,78],["H0259","one",79,82],["H7970","and thirty",83,93],["H8141","years",94,99]]},"34:2":{"text":"And he did that which was right in the sight of the LORD, and walked in the ways of David his father, and declined neither to the right hand, nor to the left.","words":[["H6213","And he did",0,10],["H3477","that which was right",11,31],["H5869","in the sight",32,44],["H3068","of the LORD",45,56],["H3212","and walked",58,68],["H1870","in the ways",69,80],["H1732","of David",81,89],["H0001","his father",90,100],["H5493","and declined",102,114],["H3225","neither to the right hand",115,140],["H8040","nor to the left",142,157]]},"34:3":{"text":"For in the eighth year of his reign, while he was yet young, he began to seek after the God of David his father: and in the twelfth year he began to purge Judah and Jerusalem from the high places, and the groves, and the carved images, and the molten images.","words":[["H8083","For in the eighth",0,17],["H8141","year",18,22],["H4427","of his reign",23,35],["H5288","while he was yet young",37,59],["H2490","he began",61,69],["H1875","to seek",70,77],["H0430","after the God",78,91],["H1732","of David",92,100],["H0001","his father",101,111],["H8147","and in the twelfth",113,131],["H6240","and in the twelfth",113,131],["H8141","year",132,136],["H2490","he began",137,145],["H2891","to purge",146,154],["H3063","Judah",155,160],["H3389","and Jerusalem",161,174],["H1116","from the high places",175,195],["H0842","and the groves",197,211],["H6456","and the carved images",213,234],["H4541","and the molten images",236,257]]},"34:4":{"text":"And they brake down the altars of Baalim in his presence; and the images, that were on high above them, he cut down; and the groves, and the carved images, and the molten images, he brake in pieces, and made dust of them, and strowed it upon the graves of them that had sacrificed unto them.","words":[["H5422","And they brake down",0,19],["H4196","the altars",20,30],["H1168","of Baalim",31,40],["H6440","in his presence",41,56],["H2553","and the images",58,72],["H4605","that were on high above them",74,102],["H1438","he cut down",104,115],["H0842","and the groves",117,131],["H6456","and the carved images",133,154],["H4541","and the molten images",156,177],["H7665","he brake in pieces",179,197],["H1854","and made dust",199,212],["H2236","of them, and strowed",213,233],["H6440","it upon",234,241],["H6913","the graves",242,252],["H2076","of them that had sacrificed",253,280]]},"34:5":{"text":"And he burnt the bones of the priests upon their altars, and cleansed Judah and Jerusalem.","words":[["H8313","And he burnt",0,12],["H6106","the bones",13,22],["H3548","of the priests",23,37],["H4196","upon their altars",38,55],["H2891","and cleansed",57,69],["H3063","Judah",70,75],["H3389","and Jerusalem",76,89]]},"34:6":{"text":"And so did he in the cities of Manasseh, and Ephraim, and Simeon, even unto Naphtali, with their mattocks round about.","words":[["H5892","And so did he in the cities",0,27],["H4519","of Manasseh",28,39],["H0669","and Ephraim",41,52],["H8095","and Simeon",54,64],["H5321","even unto Naphtali",66,84],["H2719","with their mattocks",86,105],["H5439","round about",106,117]]},"34:7":{"text":"And when he had broken down the altars and the groves, and had beaten the graven images into powder, and cut down all the idols throughout all the land of Israel, he returned to Jerusalem.","words":[["H5422","And when he had broken down",0,27],["H4196","the altars",28,38],["H0842","and the groves",39,53],["H3807","and had beaten",55,69],["H6456","the graven images",70,87],["H1854","into powder",88,99],["H1438","and cut down",101,113],["H2553","all the idols",114,127],["H0776","throughout all the land",128,151],["H3478","of Israel",152,161],["H7725","he returned",163,174],["H3389","to Jerusalem",175,187]]},"34:8":{"text":"Now in the eighteenth year of his reign, when he had purged the land, and the house, he sent Shaphan the son of Azaliah, and Maaseiah the governor of the city, and Joah the son of Joahaz the recorder, to repair the house of the LORD his God.","words":[["H8083","Now in the eighteenth",0,21],["H6240","Now in the eighteenth",0,21],["H8141","year",22,26],["H4427","of his reign",27,39],["H2891","when he had purged",41,59],["H0776","the land",60,68],["H1004","and the house",70,83],["H7971","he sent",85,92],["H8227","Shaphan",93,100],["H1121","the son",101,108],["H0683","of Azaliah",109,119],["H4641","and Maaseiah",121,133],["H8269","the governor",134,146],["H5892","of the city",147,158],["H3098","and Joah",160,168],["H1121","the son",169,176],["H3099","of Joahaz",177,186],["H2142","the recorder",187,199],["H2388","to repair",201,210],["H1004","the house",211,220],["H3068","of the LORD",221,232],["H0430","his God",233,240]]},"34:9":{"text":"And when they came to Hilkiah the high priest, they delivered the money that was brought into the house of God, which the Levites that kept the doors had gathered of the hand of Manasseh and Ephraim, and of all the remnant of Israel, and of all Judah and Benjamin; and they returned to Jerusalem.","words":[["H0935","And when they came",0,18],["H2518","to Hilkiah",19,29],["H1419","the high",30,38],["H3548","priest",39,45],["H5414","they delivered",47,61],["H3701","the money",62,71],["H0935","that was brought",72,88],["H1004","into the house",89,103],["H0430","of God",104,110],["H3881","which the Levites",112,129],["H8104","that kept",130,139],["H5592","the doors",140,149],["H0622","had gathered",150,162],["H3027","of the hand",163,174],["H4519","of Manasseh",175,186],["H0669","and Ephraim",187,198],["H7611","and of all the remnant",200,222],["H3478","of Israel",223,232],["H3063","and of all Judah",234,250],["H1144","and Benjamin",251,263],["H7725","and they returned",265,282],["H3427","and they returned",265,282],["H3389","to Jerusalem",283,295]]},"34:10":{"text":"And they put it in the hand of the workmen that had the oversight of the house of the LORD, and they gave it to the workmen that wrought in the house of the LORD, to repair and amend the house:","words":[["H5414","And they put",0,12],["H3027","it in the hand",13,27],["H6213","of the workmen",28,42],["H4399","of the workmen",28,42],["H6485","that had the oversight",43,65],["H1004","of the house",66,78],["H3068","of the LORD",79,90],["H5414","and they gave",92,105],["H6213","it to the workmen",106,123],["H4399","it to the workmen",106,123],["H6213","that wrought",124,136],["H1004","in the house",137,149],["H3068","of the LORD",150,161],["H0918","to repair",163,172],["H2388","and amend",173,182],["H1004","the house",183,192]]},"34:11":{"text":"Even to the artificers and builders gave they it, to buy hewn stone, and timber for couplings, and to floor the houses which the kings of Judah had destroyed.","words":[["H2796","Even to the artificers",0,22],["H1129","and builders",23,35],["H5414","gave",36,40],["H7069","they it, to buy",41,56],["H4274","hewn",57,61],["H0068","stone",62,67],["H6086","and timber",69,79],["H4226","for couplings",80,93],["H7136","and to floor",95,107],["H1004","the houses",108,118],["H4428","which the kings",119,134],["H3063","of Judah",135,143],["H7843","had destroyed",144,157]]},"34:12":{"text":"And the men did the work faithfully: and the overseers of them were Jahath and Obadiah, the Levites, of the sons of Merari; and Zechariah and Meshullam, of the sons of the Kohathites, to set it forward; and other of the Levites, all that could skill of instruments of musick.","words":[["H0582","And the men",0,11],["H6213","did",12,15],["H4399","the work",16,24],["H0530","faithfully",25,35],["H5329","and the overseers",37,54],["H3189","of them were Jahath",55,74],["H5662","and Obadiah",75,86],["H3881","the Levites",88,99],["H1121","of the sons",101,112],["H4847","of Merari",113,122],["H2148","and Zechariah",124,137],["H4918","and Meshullam",138,151],["H6956","of the sons of the Kohathites",153,182],["H6485","to set it forward",184,201],["H3881","and other of the Levites",203,227],["H0995","all that could skill",229,249],["H3627","of instruments",250,264],["H7892","of musick",265,274]]},"34:13":{"text":"Also they were over the bearers of burdens, and were overseers of all that wrought the work in any manner of service: and of the Levites there were scribes, and officers, and porters.","words":[["H5449","Also they were over the bearers of burdens",0,42],["H5329","and were overseers",44,62],["H6213","of all that wrought",63,82],["H4399","the work",83,91],["H5656","in any manner of service",92,116],["H3881","and of the Levites",118,136],["H5608","there were scribes",137,155],["H7860","and officers",157,169],["H7778","and porters",171,182]]},"34:14":{"text":"And when they brought out the money that was brought into the house of the LORD, Hilkiah the priest found a book of the law of the LORD given by Moses.","words":[["H3318","And when they brought out",0,25],["H3701","the money",26,35],["H0935","that was brought into",36,57],["H1004","the house",58,67],["H3068","of the LORD",68,79],["H2518","Hilkiah",81,88],["H3548","the priest",89,99],["H4672","found",100,105],["H5612","a book",106,112],["H8451","of the law",113,123],["H3068","of the LORD",124,135],["H3027","given by",136,144],["H4872","Moses",145,150]]},"34:15":{"text":"And Hilkiah answered and said to Shaphan the scribe, I have found the book of the law in the house of the LORD. And Hilkiah delivered the book to Shaphan.","words":[["H2518","And Hilkiah",0,11],["H6030","answered",12,20],["H0559","and said",21,29],["H8227","to Shaphan",30,40],["H5608","the scribe",41,51],["H4672","I have found",53,65],["H5612","the book",66,74],["H8451","of the law",75,85],["H1004","in the house",86,98],["H3068","of the LORD",99,110],["H2518","And Hilkiah",112,123],["H5414","delivered",124,133],["H5612","the book",134,142],["H8227","to Shaphan",143,153]]},"34:16":{"text":"And Shaphan carried the book to the king, and brought the king word back again, saying, All that was committed to thy servants, they do it.","words":[["H8227","And Shaphan",0,11],["H0935","carried",12,19],["H5612","the book",20,28],["H4428","to the king",29,40],["H7725","and brought",42,53],["H4428","the king",54,62],["H1697","word",63,67],["H7725","back",68,72],["H0559","again, saying",73,86],["H5414","All that was committed",88,110],["H3027","to",111,113],["H5650","thy servants",114,126],["H6213","they do",128,135]]},"34:17":{"text":"And they have gathered together the money that was found in the house of the LORD, and have delivered it into the hand of the overseers, and to the hand of the workmen.","words":[["H5413","And they have gathered together",0,31],["H3701","the money",32,41],["H4672","that was found",42,56],["H1004","in the house",57,69],["H3068","of the LORD",70,81],["H5414","and have delivered",83,101],["H3027","it into the hand",102,118],["H6485","of the overseers",119,135],["H3027","and to the hand",137,152],["H6213","of the workmen",153,167],["H4399","of the workmen",153,167]]},"34:18":{"text":"Then Shaphan the scribe told the king, saying, Hilkiah the priest hath given me a book. And Shaphan read it before the king.","words":[["H8227","Then Shaphan",0,12],["H5608","the scribe",13,23],["H5046","told",24,28],["H4428","the king",29,37],["H0559","saying",39,45],["H2518","Hilkiah",47,54],["H3548","the priest",55,65],["H5414","hath given",66,76],["H5612","me a book",77,86],["H8227","And Shaphan",88,99],["H7121","read",100,104],["H6440","it before",105,114],["H4428","the king",115,123]]},"34:19":{"text":"And it came to pass, when the king had heard the words of the law, that he rent his clothes.","words":[["H4428","And it came to pass, when the king",0,34],["H8085","had heard",35,44],["H1697","the words",45,54],["H8451","of the law",55,65],["H7167","that he rent",67,79],["H0899","his clothes",80,91]]},"34:20":{"text":"And the king commanded Hilkiah, and Ahikam the son of Shaphan, and Abdon the son of Micah, and Shaphan the scribe, and Asaiah a servant of the king's, saying,","words":[["H4428","And the king",0,12],["H6680","commanded",13,22],["H2518","Hilkiah",23,30],["H0296","and Ahikam",32,42],["H1121","the son",43,50],["H8227","of Shaphan",51,61],["H5658","and Abdon",63,72],["H1121","the son",73,80],["H4318","of Micah",81,89],["H8227","and Shaphan",91,102],["H5608","the scribe",103,113],["H6222","and Asaiah",115,125],["H5650","a servant",126,135],["H4428","of the king's",136,149],["H0559","saying",151,157]]},"34:21":{"text":"Go, enquire of the LORD for me, and for them that are left in Israel and in Judah, concerning the words of the book that is found: for great is the wrath of the LORD that is poured out upon us, because our fathers have not kept the word of the LORD, to do after all that is written in this book.","words":[["H3212","Go",0,2],["H1875","enquire",4,11],["H3068","of the LORD",12,23],["H7604","for me, and for them that are left",24,58],["H3478","in Israel",59,68],["H3063","and in Judah",69,81],["H1697","concerning the words",83,103],["H5612","of the book",104,115],["H4672","that is found",116,129],["H1419","for great",131,140],["H2534","is the wrath",141,153],["H3068","of the LORD",154,165],["H5413","that is poured out",166,184],["H0001","upon us, because our fathers",185,213],["H8104","have not kept",214,227],["H1697","the word",228,236],["H3068","of the LORD",237,248],["H6213","to do",250,255],["H3789","after all that is written",256,281],["H5612","in this book",282,294]]},"34:22":{"text":"And Hilkiah, and they that the king had appointed, went to Huldah the prophetess, the wife of Shallum the son of Tikvath, the son of Hasrah, keeper of the wardrobe; (now she dwelt in Jerusalem in the college:) and they spake to her to that effect.","words":[["H2518","And Hilkiah",0,11],["H4428","and they that the king",13,35],["H3212","had appointed, went",36,55],["H2468","to Huldah",56,65],["H5031","the prophetess",66,80],["H0802","the wife",82,90],["H7967","of Shallum",91,101],["H1121","the son",102,109],["H8616","of Tikvath",110,120],["H8445","of Tikvath",110,120],["H1121","the son",122,129],["H2641","of Hasrah",130,139],["H8104","keeper",141,147],["H0899","of the wardrobe",148,163],["H3427","(now she dwelt",165,179],["H3389","in Jerusalem",180,192],["H4932","in the college",193,207],["H1696",") and they spake",208,224]]},"34:23":{"text":"And she answered them, Thus saith the LORD God of Israel, Tell ye the man that sent you to me,","words":[["H0559","And she answered",0,16],["H0559","them, Thus saith",17,33],["H3068","the LORD",34,42],["H0430","God",43,46],["H3478","of Israel",47,56],["H0559","Tell",58,62],["H0376","ye the man",63,73],["H7971","that sent",74,83]]},"34:24":{"text":"Thus saith the LORD, Behold, I will bring evil upon this place, and upon the inhabitants thereof, even all the curses that are written in the book which they have read before the king of Judah:","words":[["H0559","Thus saith",0,10],["H3068","the LORD",11,19],["H0935","Behold, I will bring",21,41],["H7451","evil",42,46],["H4725","upon this place",47,62],["H3427","and upon the inhabitants",64,88],["H0423","thereof, even all the curses",89,117],["H3789","that are written",118,134],["H5612","in the book",135,146],["H7121","which they have read",147,167],["H6440","before",168,174],["H4428","the king",175,183],["H3063","of Judah",184,192]]},"34:25":{"text":"Because they have forsaken me, and have burned incense unto other gods, that they might provoke me to anger with all the works of their hands; therefore my wrath shall be poured out upon this place, and shall not be quenched.","words":[["H5800","Because they have forsaken",0,26],["H6999","me, and have burned incense",27,54],["H6999","me, and have burned incense",27,54],["H0312","unto other",55,65],["H0430","gods",66,70],["H3707","that they might provoke me to anger",72,107],["H4639","with all the works",108,126],["H3027","of their hands",127,141],["H2534","therefore my wrath",143,161],["H5413","shall be poured out",162,181],["H4725","upon this place",182,197],["H3518","and shall not be quenched",199,224]]},"34:26":{"text":"And as for the king of Judah, who sent you to enquire of the LORD, so shall ye say unto him, Thus saith the LORD God of Israel concerning the words which thou hast heard;","words":[["H0413","And as for",0,10],["H4428","the king",11,19],["H3063","of Judah",20,28],["H7971","who sent",30,38],["H1875","you to enquire",39,53],["H3068","of the LORD",54,65],["H0559","so shall ye say",67,82],["H0559","unto him, Thus saith",83,103],["H3068","the LORD",104,112],["H0430","God",113,116],["H3478","of Israel",117,126],["H1697","concerning the words",127,147],["H8085","which thou hast heard",148,169]]},"34:27":{"text":"Because thine heart was tender, and thou didst humble thyself before God, when thou heardest his words against this place, and against the inhabitants thereof, and humbledst thyself before me, and didst rend thy clothes, and weep before me; I have even heard thee also, saith the LORD.","words":[["H3824","Because thine heart",0,19],["H7401","was tender",20,30],["H3665","and thou didst humble",32,53],["H6440","thyself before",54,68],["H0430","God",69,72],["H8085","when thou heardest",74,92],["H1697","his words",93,102],["H4725","against this place",103,121],["H3427","and against the inhabitants",123,150],["H3665","thereof, and humbledst",151,173],["H6440","thyself before",174,188],["H7167","me, and didst rend",189,207],["H0899","thy clothes",208,219],["H1058","and weep",221,229],["H6440","before",230,236],["H8085","me; I have even heard",237,258],["H5002","thee also, saith",259,275],["H3068","the LORD",276,284]]},"34:28":{"text":"Behold, I will gather thee to thy fathers, and thou shalt be gathered to thy grave in peace, neither shall thine eyes see all the evil that I will bring upon this place, and upon the inhabitants of the same. So they brought the king word again.","words":[["H0622","Behold, I will gather",0,21],["H0001","thee to thy fathers",22,41],["H0622","and thou shalt be gathered",43,69],["H6913","to thy grave",70,82],["H7965","in peace",83,91],["H5869","neither shall thine eyes",93,117],["H7200","see",118,121],["H7451","all the evil",122,134],["H0935","that I will bring",135,152],["H4725","upon this place",153,168],["H3427","and upon the inhabitants",170,194],["H7725","of the same. So they brought",195,223],["H4428","the king",224,232],["H1697","word",233,237],["H7725","again",238,243]]},"34:29":{"text":"Then the king sent and gathered together all the elders of Judah and Jerusalem.","words":[["H4428","Then the king",0,13],["H7971","sent",14,18],["H0622","and gathered together",19,40],["H2205","all the elders",41,55],["H3063","of Judah",56,64],["H3389","and Jerusalem",65,78]]},"34:30":{"text":"And the king went up into the house of the LORD, and all the men of Judah, and the inhabitants of Jerusalem, and the priests, and the Levites, and all the people, great and small: and he read in their ears all the words of the book of the covenant that was found in the house of the LORD.","words":[["H4428","And the king",0,12],["H5927","went up",13,20],["H1004","into the house",21,35],["H3068","of the LORD",36,47],["H0376","and all the men",49,64],["H3063","of Judah",65,73],["H3427","and the inhabitants",75,94],["H3389","of Jerusalem",95,107],["H3548","and the priests",109,124],["H3881","and the Levites",126,141],["H5971","and all the people",143,161],["H1419","great",163,168],["H6996","and small",169,178],["H7121","and he read",180,191],["H0241","in their ears",192,205],["H1697","all the words",206,219],["H5612","of the book",220,231],["H1285","of the covenant",232,247],["H4672","that was found",248,262],["H1004","in the house",263,275],["H3068","of the LORD",276,287]]},"34:31":{"text":"And the king stood in his place, and made a covenant before the LORD, to walk after the LORD, and to keep his commandments, and his testimonies, and his statutes, with all his heart, and with all his soul, to perform the words of the covenant which are written in this book.","words":[["H4428","And the king",0,12],["H5975","stood",13,18],["H5977","in his place",19,31],["H3772","and made",33,41],["H1285","a covenant",42,52],["H6440","before",53,59],["H3068","the LORD",60,68],["H3212","to walk",70,77],["H0310","after",78,83],["H3068","the LORD",84,92],["H8104","and to keep",94,105],["H4687","his commandments",106,122],["H5715","and his testimonies",124,143],["H2706","and his statutes",145,161],["H3824","with all his heart",163,181],["H5315","and with all his soul",183,204],["H6213","to perform",206,216],["H1697","the words",217,226],["H1285","of the covenant",227,242],["H3789","which are written",243,260],["H5612","in this book",261,273]]},"34:32":{"text":"And he caused all that were present in Jerusalem and Benjamin to stand to it. And the inhabitants of Jerusalem did according to the covenant of God, the God of their fathers.","words":[["H4672","And he caused all that were present",0,35],["H3389","in Jerusalem",36,48],["H1144","and Benjamin",49,61],["H5975","to stand",62,70],["H3427","to it. And the inhabitants",71,97],["H3389","of Jerusalem",98,110],["H6213","did",111,114],["H1285","according to the covenant",115,140],["H0430","of God",141,147],["H0430","the God",149,156],["H0001","of their fathers",157,173]]},"34:33":{"text":"And Josiah took away all the abominations out of all the countries that pertained to the children of Israel, and made all that were present in Israel to serve, even to serve the LORD their God. And all his days they departed not from following the LORD, the God of their fathers.","words":[["H2977","And Josiah",0,10],["H5493","took away",11,20],["H8441","all the abominations",21,41],["H0776","out of all the countries",42,66],["H1121","that pertained to the children",67,97],["H3478","of Israel",98,107],["H4672","and made all that were present",109,139],["H3478","in Israel",140,149],["H5647","to serve",150,158],["H5647","even to serve",160,173],["H3068","the LORD",174,182],["H0430","their God",183,192],["H3117","And all his days",194,210],["H5493","they departed",211,224],["H0310","not from following",225,243],["H3068","the LORD",244,252],["H0430","the God",254,261],["H0001","of their fathers",262,278]]},"35:1":{"text":"Moreover Josiah kept a passover unto the LORD in Jerusalem: and they killed the passover on the fourteenth day of the first month.","words":[["H2977","Moreover Josiah",0,15],["H6213","kept",16,20],["H6453","a passover",21,31],["H3068","unto the LORD",32,45],["H3389","in Jerusalem",46,58],["H7819","and they killed",60,75],["H6453","the passover",76,88],["H0702","on the fourteenth",89,106],["H6240","on the fourteenth",89,106],["H7223","day of the first",107,123],["H2320","month",124,129]]},"35:2":{"text":"And he set the priests in their charges, and encouraged them to the service of the house of the LORD,","words":[["H5975","And he set",0,10],["H3548","the priests",11,22],["H4931","in their charges",23,39],["H2388","and encouraged",41,55],["H5656","them to the service",56,75],["H1004","of the house",76,88],["H3068","of the LORD",89,100]]},"35:3":{"text":"And said unto the Levites that taught all Israel, which were holy unto the LORD, Put the holy ark in the house which Solomon the son of David king of Israel did build; it shall not be a burden upon your shoulders: serve now the LORD your God, and his people Israel,","words":[["H0559","And said",0,8],["H3881","unto the Levites",9,25],["H0995","that taught",26,37],["H4000","that taught",26,37],["H3478","all Israel",38,48],["H6918","which were holy",50,65],["H3068","unto the LORD",66,79],["H5414","Put",81,84],["H6944","the holy",85,93],["H0727","ark",94,97],["H1004","in the house",98,110],["H8010","which Solomon",111,124],["H1121","the son",125,132],["H1732","of David",133,141],["H4428","king",142,146],["H3478","of Israel",147,156],["H1129","did build",157,166],["H4853","it shall not be a burden",168,192],["H3802","upon your shoulders",193,212],["H5647","serve",214,219],["H3068","now the LORD",220,232],["H0430","your God",233,241],["H5971","and his people",243,257],["H3478","Israel",258,264]]},"35:4":{"text":"And prepare yourselves by the houses of your fathers, after your courses, according to the writing of David king of Israel, and according to the writing of Solomon his son.","words":[["H3559","And prepare",0,11],["H3559","And prepare",0,11],["H1004","yourselves by the houses",12,36],["H0001","of your fathers",37,52],["H4256","after your courses",54,72],["H3791","according to the writing",74,98],["H1732","of David",99,107],["H4428","king",108,112],["H3478","of Israel",113,122],["H4385","and according to the writing",124,152],["H8010","of Solomon",153,163],["H1121","his son",164,171]]},"35:5":{"text":"And stand in the holy place according to the divisions of the families of the fathers of your brethren the people, and after the division of the families of the Levites.","words":[["H5975","And stand in",0,12],["H6944","the holy",13,21],["H6391","place according to the divisions",22,54],["H1004","of the families",55,70],["H0001","of the fathers",71,85],["H0251","of your brethren",86,102],["H1121","the people",103,113],["H5971","the people",103,113],["H2515","and after the division",115,137],["H0001","of the families",138,153],["H1004","of the families",138,153],["H3881","of the Levites",154,168]]},"35:6":{"text":"So kill the passover, and sanctify yourselves, and prepare your brethren, that they may do according to the word of the LORD by the hand of Moses.","words":[["H7819","So kill",0,7],["H6453","the passover",8,20],["H6942","and sanctify",22,34],["H3559","yourselves, and prepare",35,58],["H0251","your brethren",59,72],["H6213","that they may do",74,90],["H1697","according to the word",91,112],["H3068","of the LORD",113,124],["H3027","by the hand",125,136],["H4872","of Moses",137,145]]},"35:7":{"text":"And Josiah gave to the people, of the flock, lambs and kids, all for the passover offerings, for all that were present, to the number of thirty thousand, and three thousand bullocks: these were of the king's substance.","words":[["H2977","And Josiah",0,10],["H7311","gave",11,15],["H1121","to the people",16,29],["H5971","to the people",16,29],["H6629","of the flock",31,43],["H3532","lambs",45,50],["H1121","and kids",51,59],["H5795","and kids",51,59],["H6453","all for the passover offerings",61,91],["H4672","for all that were present",93,118],["H4557","to the number",120,133],["H7970","of thirty",134,143],["H0505","thousand",144,152],["H7969","and three",154,163],["H0505","thousand",164,172],["H1241","bullocks",173,181],["H4428","these were of the king's",183,207],["H7399","substance",208,217]]},"35:8":{"text":"And his princes gave willingly unto the people, to the priests, and to the Levites: Hilkiah and Zechariah and Jehiel, rulers of the house of God, gave unto the priests for the passover offerings two thousand and six hundred small cattle, and three hundred oxen.","words":[["H8269","And his princes",0,15],["H7311","gave",16,20],["H5071","willingly",21,30],["H5971","unto the people",31,46],["H3548","to the priests",48,62],["H3881","and to the Levites",64,82],["H2518","Hilkiah",84,91],["H2148","and Zechariah",92,105],["H3171","and Jehiel",106,116],["H5057","rulers",118,124],["H1004","of the house",125,137],["H0430","of God",138,144],["H5414","gave",146,150],["H3548","unto the priests",151,167],["H6453","for the passover offerings",168,194],["H0505","two thousand",195,207],["H8337","and six",208,215],["H3967","hundred",216,223],["H7969","small cattle, and three",224,247],["H3967","hundred",248,255],["H1241","oxen",256,260]]},"35:9":{"text":"Conaniah also, and Shemaiah and Nethaneel, his brethren, and Hashabiah and Jeiel and Jozabad, chief of the Levites, gave unto the Levites for passover offerings five thousand small cattle, and five hundred oxen.","words":[["H3562","Conaniah",0,8],["H8098","also, and Shemaiah",9,27],["H5417","and Nethaneel",28,41],["H0251","his brethren",43,55],["H2811","and Hashabiah",57,70],["H3273","and Jeiel",71,80],["H3107","and Jozabad",81,92],["H8269","chief",94,99],["H3881","of the Levites",100,114],["H7311","gave",116,120],["H3881","unto the Levites",121,137],["H6453","for passover offerings",138,160],["H2568","five",161,165],["H0505","thousand",166,174],["H2568","small cattle, and five",175,197],["H3967","hundred",198,205],["H1241","oxen",206,210]]},"35:10":{"text":"So the service was prepared, and the priests stood in their place, and the Levites in their courses, according to the king's commandment.","words":[["H5656","So the service",0,14],["H3559","was prepared",15,27],["H3548","and the priests",29,44],["H5975","stood",45,50],["H5977","in their place",51,65],["H3881","and the Levites",67,82],["H4256","in their courses",83,99],["H4428","according to the king's",101,124],["H4687","commandment",125,136]]},"35:11":{"text":"And they killed the passover, and the priests sprinkled the blood from their hands, and the Levites flayed them.","words":[["H7819","And they killed",0,15],["H6453","the passover",16,28],["H3548","and the priests",30,45],["H2236","sprinkled",46,55],["H3027","the blood from their hands",56,82],["H3881","and the Levites",84,99],["H6584","flayed",100,106]]},"35:12":{"text":"And they removed the burnt offerings, that they might give according to the divisions of the families of the people, to offer unto the LORD, as it is written in the book of Moses. And so did they with the oxen.","words":[["H5493","And they removed",0,16],["H5930","the burnt offerings",17,36],["H5414","that they might give",38,58],["H4653","according to the divisions",59,85],["H0001","of the families",86,101],["H1004","of the families",86,101],["H1121","of the people",102,115],["H5971","of the people",102,115],["H7126","to offer",117,125],["H3068","unto the LORD",126,139],["H3789","as it is written",141,157],["H5612","in the book",158,169],["H4872","of Moses",170,178],["H1241","And so did they with the oxen",180,209]]},"35:13":{"text":"And they roasted the passover with fire according to the ordinance: but the other holy offerings sod they in pots, and in caldrons, and in pans, and divided them speedily among all the people.","words":[["H1310","And they roasted",0,16],["H6453","the passover",17,29],["H0784","with fire",30,39],["H4941","according to the ordinance",40,66],["H6944","but the other holy",68,86],["H1310","offerings sod",87,100],["H5518","they in pots",101,113],["H1731","and in caldrons",115,130],["H6745","and in pans",132,143],["H7323","and divided them speedily",145,170],["H1121","among all the people",171,191],["H5971","among all the people",171,191]]},"35:14":{"text":"And afterward they made ready for themselves, and for the priests: because the priests the sons of Aaron were busied in offering of burnt offerings and the fat until night; therefore the Levites prepared for themselves, and for the priests the sons of Aaron.","words":[["H0310","And afterward",0,13],["H3559","they made ready",14,29],["H3548","for themselves, and for the priests",30,65],["H3548","because the priests",67,86],["H1121","the sons",87,95],["H0175","of Aaron",96,104],["H5927","were busied in offering",105,128],["H5930","of burnt offerings",129,147],["H2459","and the fat",148,159],["H3915","until night",160,171],["H3881","therefore the Levites",173,194],["H3559","prepared",195,203],["H3548","for themselves, and for the priests",204,239],["H1121","the sons",240,248],["H0175","of Aaron",249,257]]},"35:15":{"text":"And the singers the sons of Asaph were in their place, according to the commandment of David, and Asaph, and Heman, and Jeduthun the king's seer; and the porters waited at every gate; they might not depart from their service; for their brethren the Levites prepared for them.","words":[["H7891","And the singers",0,15],["H1121","the sons",16,24],["H0623","of Asaph",25,33],["H4612","were in their place",34,53],["H4687","according to the commandment",55,83],["H1732","of David",84,92],["H0623","and Asaph",94,103],["H1968","and Heman",105,114],["H3038","and Jeduthun",116,128],["H4428","the king's",129,139],["H2374","seer",140,144],["H7778","and the porters",146,161],["H8179","waited at every gate",162,182],["H5493","they might not depart",184,205],["H5656","from their service",206,224],["H0251","for their brethren",226,244],["H3881","the Levites",245,256],["H3559","prepared",257,265]]},"35:16":{"text":"So all the service of the LORD was prepared the same day, to keep the passover, and to offer burnt offerings upon the altar of the LORD, according to the commandment of king Josiah.","words":[["H5656","So all the service",0,18],["H3068","of the LORD",19,30],["H3559","was prepared",31,43],["H3117","the same day",44,56],["H6213","to keep",58,65],["H6453","the passover",66,78],["H5927","and to offer",80,92],["H5930","burnt offerings",93,108],["H4196","upon the altar",109,123],["H3068","of the LORD",124,135],["H4687","according to the commandment",137,165],["H4428","of king",166,173],["H2977","Josiah",174,180]]},"35:17":{"text":"And the children of Israel that were present kept the passover at that time, and the feast of unleavened bread seven days.","words":[["H1121","And the children",0,16],["H3478","of Israel",17,26],["H4672","that were present",27,44],["H6213","kept",45,49],["H6453","the passover",50,62],["H6256","at that time",63,75],["H2282","and the feast",77,90],["H4682","of unleavened bread",91,110],["H7651","seven",111,116],["H3117","days",117,121]]},"35:18":{"text":"And there was no passover like to that kept in Israel from the days of Samuel the prophet; neither did all the kings of Israel keep such a passover as Josiah kept, and the priests, and the Levites, and all Judah and Israel that were present, and the inhabitants of Jerusalem.","words":[["H6453","And there was no passover",0,25],["H3644","like",26,30],["H6213","to that kept",31,43],["H3478","in Israel",44,53],["H3117","from the days",54,67],["H8050","of Samuel",68,77],["H5030","the prophet",78,89],["H6213","neither did",91,102],["H4428","all the kings",103,116],["H3478","of Israel",117,126],["H6213","keep",127,131],["H6453","such a passover",132,147],["H2977","as Josiah",148,157],["H6213","kept",158,162],["H3548","and the priests",164,179],["H3881","and the Levites",181,196],["H3063","and all Judah",198,211],["H3478","and Israel",212,222],["H4672","that were present",223,240],["H3427","and the inhabitants",242,261],["H3389","of Jerusalem",262,274]]},"35:19":{"text":"In the eighteenth year of the reign of Josiah was this passover kept.","words":[["H8083","In the eighteenth",0,17],["H6240","In the eighteenth",0,17],["H8141","year",18,22],["H4438","of the reign",23,35],["H2977","of Josiah",36,45],["H6453","was this passover",46,63],["H6213","kept",64,68]]},"35:20":{"text":"After all this, when Josiah had prepared the temple, Necho king of Egypt came up to fight against Carchemish by Euphrates: and Josiah went out against him.","words":[["H0310","After",0,5],["H2977","all this, when Josiah",6,27],["H3559","had prepared",28,40],["H1004","the temple",41,51],["H5224","Necho",53,58],["H4428","king",59,63],["H4714","of Egypt",64,72],["H5927","came up",73,80],["H3898","to fight",81,89],["H3751","against Carchemish",90,108],["H6578","by Euphrates",109,121],["H2977","and Josiah",123,133],["H3318","went out",134,142],["H7125","against",143,150]]},"35:21":{"text":"But he sent ambassadors to him, saying, What have I to do with thee, thou king of Judah? I come not against thee this day, but against the house wherewith I have war: for God commanded me to make haste: forbear thee from meddling with God, who is with me, that he destroy thee not.","words":[["H7971","But he sent",0,11],["H4397","ambassadors",12,23],["H0559","to him, saying",24,38],["H4428","What have I to do with thee, thou king",40,78],["H3063","of Judah",79,87],["H3117","I come not against thee this day",89,121],["H1004","but against the house",123,144],["H4421","wherewith I have war",145,165],["H0430","for God",167,174],["H0559","commanded",175,184],["H0926","me to make haste",185,201],["H2308","forbear",203,210],["H0430","thee from meddling with God",211,238],["H7843","who is with me, that he destroy",240,271]]},"35:22":{"text":"Nevertheless Josiah would not turn his face from him, but disguised himself, that he might fight with him, and hearkened not unto the words of Necho from the mouth of God, and came to fight in the valley of Megiddo.","words":[["H2977","Nevertheless Josiah",0,19],["H5437","would not turn",20,34],["H6440","his face",35,43],["H2664","from him, but disguised",44,67],["H3898","himself, that he might fight",68,96],["H8085","with him, and hearkened",97,120],["H1697","not unto the words",121,139],["H5224","of Necho",140,148],["H6310","from the mouth",149,163],["H0430","of God",164,170],["H0935","and came",172,180],["H3898","to fight",181,189],["H1237","in the valley",190,203],["H4023","of Megiddo",204,214]]},"35:23":{"text":"And the archers shot at king Josiah; and the king said to his servants, Have me away; for I am sore wounded.","words":[["H3384","And the archers",0,15],["H3384","shot",16,20],["H4428","at king",21,28],["H2977","Josiah",29,35],["H4428","and the king",37,49],["H0559","said",50,54],["H5650","to his servants",55,70],["H5674","Have me away",72,84],["H3966","for I am sore",86,99],["H2470","wounded",100,107]]},"35:24":{"text":"His servants therefore took him out of that chariot, and put him in the second chariot that he had; and they brought him to Jerusalem, and he died, and was buried in one of the sepulchres of his fathers. And all Judah and Jerusalem mourned for Josiah.","words":[["H5650","His servants",0,12],["H5674","therefore took",13,27],["H4818","him out of that chariot",28,51],["H7392","and put",53,60],["H4932","him in the second",61,78],["H7393","chariot",79,86],["H3212","that he had; and they brought",87,116],["H3389","him to Jerusalem",117,133],["H4191","and he died",135,146],["H6912","and was buried",148,162],["H6913","in one of the sepulchres",163,187],["H0001","of his fathers",188,202],["H3063","And all Judah",204,217],["H3389","and Jerusalem",218,231],["H0056","mourned",232,239],["H2977","for Josiah",240,250]]},"35:25":{"text":"And Jeremiah lamented for Josiah: and all the singing men and the singing women spake of Josiah in their lamentations to this day, and made them an ordinance in Israel: and, behold, they are written in the lamentations.","words":[["H3414","And Jeremiah",0,12],["H6969","lamented",13,21],["H2977","for Josiah",22,32],["H7891","and all the singing men",34,57],["H7891","and the singing women",58,79],["H0559","spake",80,85],["H2977","of Josiah",86,95],["H7015","in their lamentations",96,117],["H3117","to this day",118,129],["H5414","and made",131,139],["H2706","them an ordinance",140,157],["H3478","in Israel",158,167],["H3789","and, behold, they are written",169,198],["H7015","in the lamentations",199,218]]},"35:26":{"text":"Now the rest of the acts of Josiah, and his goodness, according to that which was written in the law of the LORD,","words":[["H3499","Now the rest",0,12],["H1697","of the acts",13,24],["H2977","of Josiah",25,34],["H2617","and his goodness",36,52],["H3789","according to that which was written",54,89],["H8451","in the law",90,100],["H3068","of the LORD",101,112]]},"35:27":{"text":"And his deeds, first and last, behold, they are written in the book of the kings of Israel and Judah.","words":[["H1697","And his deeds",0,13],["H7223","first",15,20],["H0314","and last",21,29],["H3789","behold, they are written",31,55],["H5612","in the book",56,67],["H4428","of the kings",68,80],["H3478","of Israel",81,90],["H3063","and Judah",91,100]]},"36:1":{"text":"Then the people of the land took Jehoahaz the son of Josiah, and made him king in his father's stead in Jerusalem.","words":[["H5971","Then the people",0,15],["H0776","of the land",16,27],["H3947","took",28,32],["H3059","Jehoahaz",33,41],["H1121","the son",42,49],["H2977","of Josiah",50,59],["H4427","and made him king",61,78],["H0001","in his father's",79,94],["H3389","stead in Jerusalem",95,113]]},"36:2":{"text":"Jehoahaz was twenty and three years old when he began to reign, and he reigned three months in Jerusalem.","words":[["H3099","Jehoahaz",0,8],["H6242","was twenty",9,19],["H7969","and three",20,29],["H8141","years",30,35],["H1121","old",36,39],["H4427","when he began to reign",40,62],["H4427","and he reigned",64,78],["H7969","three",79,84],["H2320","months",85,91],["H3389","in Jerusalem",92,104]]},"36:3":{"text":"And the king of Egypt put him down at Jerusalem, and condemned the land in an hundred talents of silver and a talent of gold.","words":[["H4428","And the king",0,12],["H4714","of Egypt",13,21],["H5493","put him down",22,34],["H3389","at Jerusalem",35,47],["H6064","and condemned",49,62],["H0776","the land",63,71],["H3967","in an hundred",72,85],["H3603","talents",86,93],["H3701","of silver",94,103],["H3603","and a talent",104,116],["H2091","of gold",117,124]]},"36:4":{"text":"And the king of Egypt made Eliakim his brother king over Judah and Jerusalem, and turned his name to Jehoiakim. And Necho took Jehoahaz his brother, and carried him to Egypt.","words":[["H4428","And the king",0,12],["H4714","of Egypt",13,21],["H0471","made Eliakim",22,34],["H0251","his brother",35,46],["H4427","king",47,51],["H3063","over Judah",52,62],["H3389","and Jerusalem",63,76],["H5437","and turned",78,88],["H8034","his name",89,97],["H3079","to Jehoiakim",98,110],["H5224","And Necho",112,121],["H3947","took",122,126],["H3099","Jehoahaz",127,135],["H0251","his brother",136,147],["H0935","and carried",149,160],["H4714","him to Egypt",161,173]]},"36:5":{"text":"Jehoiakim was twenty and five years old when he began to reign, and he reigned eleven years in Jerusalem: and he did that which was evil in the sight of the LORD his God.","words":[["H3079","Jehoiakim",0,9],["H6242","was twenty",10,20],["H2568","and five",21,29],["H8141","years",30,35],["H1121","old",36,39],["H4427","when he began to reign",40,62],["H4427","and he reigned",64,78],["H0259","eleven",79,85],["H6240","eleven",79,85],["H8141","years",86,91],["H3389","in Jerusalem",92,104],["H6213","and he did",106,116],["H7451","that which was evil",117,136],["H5869","in the sight",137,149],["H3068","of the LORD",150,161],["H0430","his God",162,169]]},"36:6":{"text":"Against him came up Nebuchadnezzar king of Babylon, and bound him in fetters, to carry him to Babylon.","words":[["H5927","Against him came up",0,19],["H5019","Nebuchadnezzar",20,34],["H4428","king",35,39],["H0894","of Babylon",40,50],["H0631","and bound",52,61],["H5178","him in fetters",62,76],["H3212","to carry",78,86],["H0894","him to Babylon",87,101]]},"36:7":{"text":"Nebuchadnezzar also carried of the vessels of the house of the LORD to Babylon, and put them in his temple at Babylon.","words":[["H5019","Nebuchadnezzar",0,14],["H0935","also carried",15,27],["H3627","of the vessels",28,42],["H1004","of the house",43,55],["H3068","of the LORD",56,67],["H0894","to Babylon",68,78],["H5414","and put",80,87],["H1964","them in his temple",88,106],["H0894","at Babylon",107,117]]},"36:8":{"text":"Now the rest of the acts of Jehoiakim, and his abominations which he did, and that which was found in him, behold, they are written in the book of the kings of Israel and Judah: and Jehoiachin his son reigned in his stead.","words":[["H3499","Now the rest",0,12],["H1697","of the acts",13,24],["H3079","of Jehoiakim",25,37],["H8441","and his abominations",39,59],["H6213","which he did",60,72],["H4672","and that which was found",74,98],["H3789","in him, behold, they are written",99,131],["H5612","in the book",132,143],["H4428","of the kings",144,156],["H3478","of Israel",157,166],["H3063","and Judah",167,176],["H3078","and Jehoiachin",178,192],["H1121","his son",193,200],["H4427","reigned",201,208]]},"36:9":{"text":"Jehoiachin was eight years old when he began to reign, and he reigned three months and ten days in Jerusalem: and he did that which was evil in the sight of the LORD.","words":[["H3078","Jehoiachin",0,10],["H8083","was eight",11,20],["H8141","years",21,26],["H1121","old",27,30],["H4427","when he began to reign",31,53],["H4427","and he reigned",55,69],["H7969","three",70,75],["H2320","months",76,82],["H6235","and ten",83,90],["H3117","days",91,95],["H3389","in Jerusalem",96,108],["H6213","and he did",110,120],["H7451","that which was evil",121,140],["H5869","in the sight",141,153],["H3068","of the LORD",154,165]]},"36:10":{"text":"And when the year was expired, king Nebuchadnezzar sent, and brought him to Babylon, with the goodly vessels of the house of the LORD, and made Zedekiah his brother king over Judah and Jerusalem.","words":[["H8141","And when the year",0,17],["H8666","was expired",18,29],["H4428","king",31,35],["H5019","Nebuchadnezzar",36,50],["H7971","sent",51,55],["H0935","and brought",57,68],["H0894","him to Babylon",69,83],["H2532","with the goodly",85,100],["H3627","vessels",101,108],["H1004","of the house",109,121],["H3068","of the LORD",122,133],["H6667","and made Zedekiah",135,152],["H0251","his brother",153,164],["H4427","king",165,169],["H3063","over Judah",170,180],["H3389","and Jerusalem",181,194]]},"36:11":{"text":"Zedekiah was one and twenty years old when he began to reign, and reigned eleven years in Jerusalem.","words":[["H6667","Zedekiah",0,8],["H0259","was one",9,16],["H6242","and twenty",17,27],["H8141","years",28,33],["H1121","old",34,37],["H4427","when he began to reign",38,60],["H4427","and reigned",62,73],["H0259","eleven",74,80],["H6240","eleven",74,80],["H8141","years",81,86],["H3389","in Jerusalem",87,99]]},"36:12":{"text":"And he did that which was evil in the sight of the LORD his God, and humbled not himself before Jeremiah the prophet speaking from the mouth of the LORD.","words":[["H6213","And he did",0,10],["H7451","that which was evil",11,30],["H5869","in the sight",31,43],["H3068","of the LORD",44,55],["H0430","his God",56,63],["H3665","and humbled",65,76],["H6440","not himself before",77,95],["H3414","Jeremiah",96,104],["H5030","the prophet",105,116],["H6310","speaking from the mouth",117,140],["H3068","of the LORD",141,152]]},"36:13":{"text":"And he also rebelled against king Nebuchadnezzar, who had made him swear by God: but he stiffened his neck, and hardened his heart from turning unto the LORD God of Israel.","words":[["H4775","And he also rebelled",0,20],["H4428","against king",21,33],["H5019","Nebuchadnezzar",34,48],["H7650","who had made him swear",50,72],["H0430","by God",73,79],["H7185","but he stiffened",81,97],["H6203","his neck",98,106],["H0553","and hardened",108,120],["H3824","his heart",121,130],["H7725","from turning",131,143],["H3068","unto the LORD",144,157],["H0430","God",158,161],["H3478","of Israel",162,171]]},"36:14":{"text":"Moreover all the chief of the priests, and the people, transgressed very much after all the abominations of the heathen; and polluted the house of the LORD which he had hallowed in Jerusalem.","words":[["H8269","Moreover all the chief",0,22],["H3548","of the priests",23,37],["H5971","and the people",39,53],["H4603","transgressed",55,67],["H4604","very",68,72],["H7235","much",73,77],["H8441","after all the abominations",78,104],["H1471","of the heathen",105,119],["H2930","and polluted",121,133],["H1004","the house",134,143],["H3068","of the LORD",144,155],["H6942","which he had hallowed",156,177],["H3389","in Jerusalem",178,190]]},"36:15":{"text":"And the LORD God of their fathers sent to them by his messengers, rising up betimes, and sending; because he had compassion on his people, and on his dwelling place:","words":[["H3068","And the LORD",0,12],["H0430","God",13,16],["H0001","of their fathers",17,33],["H7971","sent",34,38],["H3027","to them by",39,49],["H4397","his messengers",50,64],["H7925","rising up betimes",66,83],["H7971","and sending",85,96],["H2550","because he had compassion",98,123],["H5971","on his people",124,137],["H4583","and on his dwelling place",139,164]]},"36:16":{"text":"But they mocked the messengers of God, and despised his words, and misused his prophets, until the wrath of the LORD arose against his people, till there was no remedy.","words":[["H3931","But they mocked",0,15],["H4397","the messengers",16,30],["H0430","of God",31,37],["H0959","and despised",39,51],["H1697","his words",52,61],["H8591","and misused",63,74],["H5030","his prophets",75,87],["H2534","until the wrath",89,104],["H3068","of the LORD",105,116],["H5927","arose",117,122],["H5971","against his people",123,141],["H4832","till there was no remedy",143,167]]},"36:17":{"text":"Therefore he brought upon them the king of the Chaldees, who slew their young men with the sword in the house of their sanctuary, and had no compassion upon young man or maiden, old man, or him that stooped for age: he gave them all into his hand.","words":[["H5927","Therefore he brought",0,20],["H4428","upon them the king",21,39],["H3778","of the Chaldees",40,55],["H2026","who slew",57,65],["H0970","their young men",66,81],["H2719","with the sword",82,96],["H1004","in the house",97,109],["H4720","of their sanctuary",110,128],["H2550","and had no compassion",130,151],["H0970","upon young man",152,166],["H1330","or maiden",167,176],["H2205","old man",178,185],["H3486","or him that stooped for age",187,214],["H5414","he gave",216,223],["H3027","them all into his hand",224,246]]},"36:18":{"text":"And all the vessels of the house of God, great and small, and the treasures of the house of the LORD, and the treasures of the king, and of his princes; all these he brought to Babylon.","words":[["H3627","And all the vessels",0,19],["H1004","of the house",20,32],["H0430","of God",33,39],["H1419","great",41,46],["H6996","and small",47,56],["H0214","and the treasures",58,75],["H1004","of the house",76,88],["H3068","of the LORD",89,100],["H0214","and the treasures",102,119],["H4428","of the king",120,131],["H8269","and of his princes",133,151],["H0935","all these he brought",153,173],["H0894","to Babylon",174,184]]},"36:19":{"text":"And they burnt the house of God, and brake down the wall of Jerusalem, and burnt all the palaces thereof with fire, and destroyed all the goodly vessels thereof.","words":[["H8313","And they burnt",0,14],["H1004","the house",15,24],["H0430","of God",25,31],["H5422","and brake down",33,47],["H2346","the wall",48,56],["H3389","of Jerusalem",57,69],["H8313","and burnt",71,80],["H0759","all the palaces",81,96],["H0784","thereof with fire",97,114],["H7843","and destroyed",116,129],["H4261","all the goodly",130,144],["H3627","vessels",145,152]]},"36:20":{"text":"And them that had escaped from the sword carried he away to Babylon; where they were servants to him and his sons until the reign of the kingdom of Persia:","words":[["H7611","And them that had escaped",0,25],["H2719","from the sword",26,40],["H1540","carried he away",41,56],["H0894","to Babylon",57,67],["H5650","where they were servants",69,93],["H1121","to him and his sons",94,113],["H4427","until the reign",114,129],["H4438","of the kingdom",130,144],["H6539","of Persia",145,154]]},"36:21":{"text":"To fulfil the word of the LORD by the mouth of Jeremiah, until the land had enjoyed her sabbaths: for as long as she lay desolate she kept sabbath, to fulfil threescore and ten years.","words":[["H4390","To fulfil",0,9],["H1697","the word",10,18],["H3068","of the LORD",19,30],["H6310","by the mouth",31,43],["H3414","of Jeremiah",44,55],["H0776","until the land",57,71],["H7521","had enjoyed",72,83],["H7676","her sabbaths",84,96],["H3117","for as long as",98,112],["H8074","she lay desolate",113,129],["H7673","she kept sabbath",130,146],["H4390","to fulfil",148,157],["H7657","threescore and ten",158,176],["H8141","years",177,182]]},"36:22":{"text":"Now in the first year of Cyrus king of Persia, that the word of the LORD spoken by the mouth of Jeremiah might be accomplished, the LORD stirred up the spirit of Cyrus king of Persia, that he made a proclamation throughout all his kingdom, and put it also in writing, saying,","words":[["H0259","Now in the first",0,16],["H8141","year",17,21],["H3566","of Cyrus",22,30],["H4428","king",31,35],["H6539","of Persia",36,45],["H1697","that the word",47,60],["H3068","of the LORD",61,72],["H6310","spoken by the mouth",73,92],["H3414","of Jeremiah",93,104],["H3615","might be accomplished",105,126],["H3068","the LORD",128,136],["H5782","stirred up",137,147],["H7307","the spirit",148,158],["H3566","of Cyrus",159,167],["H4428","king",168,172],["H6539","of Persia",173,182],["H5674","that he made a proclamation",184,211],["H6963","that he made a proclamation",184,211],["H4438","throughout all his kingdom",212,238],["H4385","and put it also in writing",240,266],["H0559","saying",268,274]]},"36:23":{"text":"Thus saith Cyrus king of Persia, All the kingdoms of the earth hath the LORD God of heaven given me; and he hath charged me to build him an house in Jerusalem, which is in Judah. Who is there among you of all his people? The LORD his God be with him, and let him go up.","words":[["H0559","Thus saith",0,10],["H3566","Cyrus",11,16],["H4428","king",17,21],["H6539","of Persia",22,31],["H4467","All the kingdoms",33,49],["H0776","of the earth",50,62],["H3068","hath the LORD",63,76],["H0430","God",77,80],["H8064","of heaven",81,90],["H5414","given",91,96],["H6485","me; and he hath charged",97,120],["H1129","me to build",121,132],["H1004","him an house",133,145],["H3389","in Jerusalem",146,158],["H3063","which is in Judah",160,177],["H5971","Who is there among you of all his people",179,219],["H3068","The LORD",221,229],["H0430","his God",230,237],["H5927","be with him, and let him go up",238,268]]}}};
